window.__QUIZ_SUBJECT__=[{"id": "objective>Chemistry>1993>1", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "STATES OF MATTER : KINETIC THEORY OF MATTER.", "question": "Which of the following can be explained by the kinetic theory? I. The physical state of matter II. Diffusion of gases III. Melting of solide IV. Evaporation of liquids", "images": [], "options": {"A": "IV", "B": "I and II", "C": "III aand IV", "D": "I, II, III and IV"}, "answer": "D", "explanation": "The kinetic theory of gases explains the behavior of gases in terms of particles in motion. It can explain the physical state of matter (I), diffusion of gases (II), and the processes of melting (III) and evaporation (IV). Therefore, all four statements can be explained by the kinetic theory, making the correct option 'I, II, III and IV'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>2", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Which of the following species is/are electrically neutral?  ProtonsNeutronsElectronsI. P91010II.Q171818III.R172017IVS121212", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii and iii"}, "answer": "C", "explanation": "In the context of atomic structure, protons are positively charged, electrons are negatively charged, and neutrons are electrically neutral. Therefore, only species Q (17 protons, 18 neutrons, 18 electrons) and R (17 protons, 20 neutrons, 17 electrons) are electrically neutral. Thus, the correct option is 'iii and iv'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>3", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP", "question": "All members of a homologous series I. conform to a general molecular formula. II. show similar chemical properties III. can be obtained by a general method of preparation IV. have the same physical properties.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii and iii"}, "answer": "D", "explanation": "Members of a homologous series share a general molecular formula (I), show similar chemical properties (II), and can be obtained by a general method of preparation (III). However, they do not necessarily have the same physical properties (IV) as these can vary. Therefore, the correct option is 'i, ii and iii'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>4", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following deductions is/are correct of the diagram?    i. The solubility of R is directly proportional to tempera-ture. II. Q is insoluble in water at O0C III. A mixture of R and Q can be separated by fractional crystallization. IV. R is less soluble in hot water than in cold water.", "images": ["Chemistry/imgs/1993/8JHGHC.png"], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii and iii"}, "answer": "C", "explanation": "III. A mixture of R and Q can be separated by fractional crystallization. IV. R is less soluble in hot water than in cold water are correct", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>5", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "The factors which should be taken into consideration when establishing a paint industry include l.energy requirements. II. disposal system for effluents. III. adequacy of water supply. IV. availability of pigments.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii,iii and iv"}, "answer": "D", "explanation": "When establishing a paint industry, all factors listed are important: energy requirements (I), disposal system for effluents (II), adequacy of water supply (III), and availability of pigments (IV). Therefore, the correct option is 'i, ii, iii and iv'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>6", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following can be obtained from its oxide by heating with carbon? I. Lead II. Zinc III. Iron IV. Calcium", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii and iii"}, "answer": "D", "explanation": "Lead (I) and Zinc (II) can be obtained from their oxides by heating with carbon, as carbon can reduce these metal oxides to their respective metals. Iron (III) can also be reduced in this manner, but Calcium (IV) cannot be obtained from its oxide by heating with carbon. Therefore, the correct option is 'i, ii and iii'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>7", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Oxidation is a reaction which can involve I. Loss of electrons. II. increase in oxidation number. III. gain of oxygen. IV. loss of hydrogen.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii,iii and iv"}, "answer": "D", "explanation": "Oxidation is defined as a reaction that involves the loss of electrons (I), an increase in oxidation number (II), the gain of oxygen (III), and the loss of hydrogen (IV). Therefore, all four statements are correct, making option 'i,ii,iii and iv' the correct choice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>8", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Selective discharge of ions during electrolysis depends on the I. position of ions in the electrochemical series. II. nature of the electrodes. III. charge on the ions. IV. quantity of electricity passed through the electroylyte.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii,iii and iv"}, "answer": "D", "explanation": "The selective discharge of ions during electrolysis is influenced by the position of ions in the electrochemical series (I), the nature of the electrodes (II), the charge on the ions (III), and the quantity of electricity passed through the electrolyte (IV). All four factors are relevant, thus option 'i,ii,iii and iv' is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>9", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE", "question": "Which of the following equations illustrate(s) substitution reaction?  I. 2CH_(3CH2OH + 2Na → 2CH3CH2ONa + H2  II. C6H6 + HNO3 → C6H5NO2 + H2O  III. CH_(3CH2OH + HBr → CH_(3CH2Br + H2O  IV. CH4 + Cl2  → CH3Cl + HCl", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii and iii"}, "answer": "C", "explanation": "A substitution reaction involves the replacement of one atom or group in a molecule with another. In the provided equations, only III (CH3CH2OH + HBr → CH3CH2Br + H2O) and IV (CH4 + Cl2 → CH3Cl + HCl) illustrate substitution reactions. Therefore, the correct option is 'iii and iv'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>10", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "Which of the following methods is/are applicable in preventing corrosion of metals? I. storing in oil II. Allowing an inert oxide surface layer to form III. Coating with paint or tar IV. Plating with another metal", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i,ii,iii and iv"}, "answer": "D", "explanation": "Methods to prevent corrosion include storing metals in oil (I), allowing an inert oxide surface layer to form (II), coating with paint or tar (III), and plating with another metal (IV). All these methods are effective in preventing corrosion, making option 'i,ii,iii and iv' the correct choice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>11", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Which of the following separation is routinely applied in the petroleum industry", "images": [], "options": {"A": "Filtration", "B": "Chromatography", "C": "Evaporation", "D": "Fractional distillation"}, "answer": "D", "explanation": "Fractional distillation is a separation process that takes advantage of differences in boiling points of components in a mixture. In the petroleum industry, crude oil is separated into various fractions (like gasoline, kerosene, diesel, etc.) using fractional distillation, making it the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>12", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Starch undergoes complete hydrolysis to produce", "images": [], "options": {"A": "maltose", "B": "lactose", "C": "fructose", "D": "glucose"}, "answer": "D", "explanation": "Starch is a polysaccharide that, upon complete hydrolysis, breaks down into glucose molecules. This process involves the enzymatic or acid-catalyzed breakdown of starch into its monomer units, which are glucose. Therefore, glucose is the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1993>13", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "Which of the following solids has a network structure?", "images": [], "options": {"A": "Diamond", "B": "lodine", "C": "Sulphur", "D": "Graphite"}, "answer": "A", "explanation": "Diamond has a network structure where each carbon atom is tetrahedrally bonded to four other carbon atoms, forming a strong and rigid three-dimensional lattice. This structure gives diamond its exceptional hardness. Thus, diamond is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>14", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Trioxosulphate (lV) acid is not stored for a long period because it", "images": [], "options": {"A": "is a weak dibasic acid", "B": "has bleaching properties", "C": "is unstable and eaily decomposed", "D": "smells strongly of sulphur (lV) oxide"}, "answer": "C", "explanation": "Trioxosulphate (IV) acid, also known as sulfurous acid, is unstable and can decompose over time, especially when exposed to heat or light. This instability makes it unsuitable for long-term storage, which is why the option stating it is unstable and easily decomposed is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>15", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following statements is not correct about the compound represented below?  COOH  |  COOH", "images": [], "options": {"A": "Its basicity is 4", "B": "It is a dicarboxylic acid", "C": "its boiling point is higher than that of the corresponding alkane", "D": "it reacts with alkanols under suitable condittions"}, "answer": "A", "explanation": "The compound represented is a dicarboxylic acid (as it has two -COOH groups). Its basicity is not 4; it is actually 2, as it can donate two protons. Therefore, the statement 'Its basicity is 4' is incorrect, making option 1 the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1993>16", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Alkanes are used mainly", "images": [], "options": {"A": "in the production of plastics", "B": "as domestic and industrial fuels", "C": "in the textile industry", "D": "in the hydrogenation of oils"}, "answer": "B", "explanation": "Alkanes are primarily used as fuels in both domestic and industrial applications due to their high energy content and relatively clean combustion. They are the main components of natural gas and gasoline, making this option the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>17", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.", "question": "Which of the following solids will leave a black residue after being heated strongly?", "images": [], "options": {"A": "Iron(I) tetraoxossulphate(VI)", "B": "Lead (II) trioxocarbonate (IV)", "C": "Copper (II) trioxonitrate (V)", "D": "Calcium trioxocarbonate(IV)"}, "answer": "C", "explanation": "On strong heating, copper(II) nitrate decomposes to give black copper(II) oxide (CuO), along with nitrogen dioxide and oxygen. This black residue makes it the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>18", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The properties of electrovalent compounds include the following except", "images": [], "options": {"A": "high melting point and boiling point", "B": "conduction of electricity in the molten state", "C": "high volatility at room temperature", "D": "ionization in aqueous solution."}, "answer": "C", "explanation": "Electrovalent compounds, also known as ionic compounds, typically have high melting and boiling points, conduct electricity in molten state, ionize in aqueous solution, and can decompose under electric current. However, they are not characterized by high volatility at room temperature, making option 3 the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>19", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "ISOMERISM", "question": "Which of the following pairs illustrates isotopy?", "images": [], "options": {"A": "But-l-ene and but -2-ene", "B": "Ortho-hydrogen and parahydrogen", "C": "Oxygen and ozone", "D": "Hydrogen and deuterium"}, "answer": "D", "explanation": "Isotopes are variants of a particular chemical element that have the same number of protons but different numbers of neutrons. Hydrogen and deuterium are both isotopes of hydrogen; hydrogen has one proton and no neutrons, while deuterium has one proton and one neutron. Therefore, the correct option is 'Hydrogen and deuterium'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>20", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Carbon is often deposited in the exhaust-pipe of cars because of the?", "images": [], "options": {"A": "presence of carbon in petrol", "B": "dehydrogenation of petrol", "C": "incomplete combustion of petrol", "D": "presence of additives in petrol"}, "answer": "C", "explanation": "Carbon is often deposited in the exhaust pipe of cars due to the incomplete combustion of petrol. When combustion is incomplete, not all carbon in the fuel is converted to carbon dioxide, leading to the formation of soot and other carbon deposits. Thus, the correct option is 'incomplete combustion of petrol'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>21", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "What does X atand for in the following expression? X = -Log(10)((H+)", "images": [], "options": {"A": "Enthalpy change (∆H)", "B": "Equilibrium constant (K)", "C": "Solubility product", "D": "Degree of acidity (pH)"}, "answer": "D", "explanation": "In the expression X = -Log_10(H^+), X represents the degree of acidity, commonly known as pH. The pH scale measures how acidic or basic a solution is, with lower values indicating higher acidity. Therefore, the correct option is 'Degree of acidity (pH)'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>22", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : SULPHUR", "question": "Sulphur burns in air to form", "images": [], "options": {"A": "an acidic oxide", "B": "a basic oxide", "C": "an amphoteric oxide", "D": "a neutral oxide"}, "answer": "A", "explanation": "Sulfur burns in air to form sulfur dioxide (SO2), which is an acidic oxide. Acidic oxides are oxides that react with water to form acids. Therefore, the correct option is 'an acidic oxide'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1993>23", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "In which of the following changes is ∆S negative ?", "images": [], "options": {"A": "H2O(l) → H2O(s)", "B": "C(s) + 1/2O2(g) → CO(g)", "C": "PCI5(g) → PCl3(g) + Cl_((2(g))", "D": "NaCl(s) + aq → Na+(aq) + Cl-(aq)"}, "answer": "A", "explanation": "The change H2O(l) → H2O(s) represents the freezing of water, which is a process that decreases the entropy (∆S) of the system because the molecules are moving from a more disordered state (liquid) to a more ordered state (solid). Therefore, the correct option is 'H2O(l) → H2O(s)'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>24", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Chlorine is is used in water treatment as", "images": [], "options": {"A": "a germicide", "B": "a decolorizing agent", "C": "an antioxidant", "D": "a coagulating agent"}, "answer": "A", "explanation": "Chlorine is primarily used in water treatment as a germicide. It effectively kills bacteria and other pathogens in water, making it safe for drinking. The other options do not accurately describe the primary function of chlorine in this context.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1993>25", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : SCIENTIFIC METHODS", "question": "Which of the following pieces of apparatus can be used for drawing a current of air through a liquid?", "images": [], "options": {"A": "Wash bottle", "B": "Aspirator", "C": "Capillary tube", "D": "Thistle funnel"}, "answer": "B", "explanation": "The correct apparatus for drawing a current of air through a liquid is an 'Aspirator'. An aspirator works by creating a vacuum that draws air (or liquid) through a system. It typically uses water flow to create this vacuum, allowing it to pull air through a liquid, which is essential in various laboratory processes. The other options, such as a wash bottle, capillary tube, thistle funnel, and pipette, do not serve this specific function.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1993>26", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "What amount of copper will be deposited if a current of 10A was passed through a solution of copper(ll) salt for 965 seconds? (1F = 96500 C)", "images": [], "options": {"A": "0.005 mole", "B": "0.025 mole", "C": "0.05 mole", "D": "1.00 mole"}, "answer": "C", "explanation": "To calculate the amount of copper deposited, we use the formula: moles = (current in amperes × time in seconds) / (n × F), where n is the number of electrons transferred (for Cu, n=2). Here, moles = (10 A × 965 s) / (2 × 96500 C) = 0.05 moles. Therefore, the correct answer is 0.05 mole.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1993>27", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "Some precious stones such as ruby and sapphire consist of aluminum oxide coloured by traces of the oxides of", "images": [], "options": {"A": "group lV elements", "B": "group l metals", "C": "transition metals", "D": "alkaline earths"}, "answer": "C", "explanation": "Ruby and sapphire are colored by traces of transition metals, such as chromium in ruby and titanium/iron in sapphire. The other groups mentioned do not typically contribute to the coloration of these gemstones.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>28", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the reaction represented by the following equation CaCI2(aq) + H2C2O4(aq) ⇌ CaC2O4(s) + 2HCI(aq). Which of the following would dissolve the precipitate of CaC _2O4 formed?", "images": [], "options": {"A": "Stirring the mixture vigorously", "B": "Adding more calcium chloride solution", "C": "lncreasing the concentration of the ethanedioic acid", "D": "Adding concentrated hydrochloric acid"}, "answer": "D", "explanation": "To dissolve the precipitate of calcium oxalate (CaC2O4), adding concentrated hydrochloric acid would provide additional calcium ions and increase the solubility of the precipitate by shifting the equilibrium. The other options would not effectively dissolve the precipitate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>29", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "The following gases decolorize bromine water except", "images": [], "options": {"A": "C2H6", "B": "C2H4", "C": "C2H2", "D": "C3H4"}, "answer": "A", "explanation": "Ethane (C2H6) does not decolorize bromine water because it is a saturated hydrocarbon and does not have double or triple bonds that can react with bromine. The other gases listed are unsaturated and can react with bromine, leading to decolorization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1993>30", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "What volume of distilled water should be added to 400cm3 of 2.0 mole dm-3 H2SO4 to obtain 0.20 mole dm-3 of solution?", "images": [], "options": {"A": "600cm3", "B": "800cm3", "C": "1,000cm3", "D": "3,600cm3"}, "answer": "D", "explanation": "To find the volume of distilled water to be added, we can use the dilution formula: C1V1 = C2V2, where C1 is the initial concentration (2.0 mole/dm^3), V1 is the initial volume (400 cm^3), C2 is the final concentration (0.20 mole/dm^3), and V2 is the final volume. Rearranging gives V2 = (C1V1) / C2 = (2.0 * 400) / 0.20 = 4000 cm^3. The volume of distilled water to be added is V2 - V1 = 4000 cm^3 - 400 cm^3 = 3600 cm^3. Therefore, the correct option is 3,600 cm^3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1993>31", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Which of the following indicates the correct increasing order of oxidizing power of the halogens?", "images": [], "options": {"A": "F", "B": "l", "C": "I", "D": "Br"}, "answer": "B", "explanation": "The oxidizing power of halogens depends on how easily they gain electrons to form halide ions. As you move up Group 17, atoms become smaller and more electronegative, so they attract electrons more strongly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>32", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : OXYGEN", "question": "Which of the following substances is a peroxide?", "images": [], "options": {"A": "Na2O2", "B": "CuO", "C": "PbO4", "D": "Fe2O"}, "answer": "A", "explanation": "A peroxide is a compound that contains an oxygen-oxygen single bond (O-O). Among the given options, Na2O2 (sodium peroxide) is the only substance that fits this definition. Therefore, the correct option is Na2O2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>33", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume of propane is left unreacted when 20cm3 of oxygen and 20cm3 of propane react according to the following equation? C3H8 + 5(O)2 → 3CO2(g) + 4H2Og", "images": [], "options": {"A": "4cm3", "B": "5cm3", "C": "14cm3", "D": "16cm3"}, "answer": "D", "explanation": "The balanced equation shows that 1 mole of propane reacts with 5 moles of oxygen. Therefore, for every 1 volume of propane, 5 volumes of oxygen are required. Since 20 cm³ of propane is used with only 20 cm³ of oxygen, there is not enough oxygen to react with all the propane. The amount of propane that can react is 20 cm³ of oxygen / 5 = 4 cm³ of propane. Thus, the unreacted propane is 20 cm³ - 4 cm³ = 16 cm³.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1993>34", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : OXYGEN", "question": "The component of air that removed when air is bubbled into alkaline pyrogallol solution is", "images": [], "options": {"A": "carbon(lV) oxide", "B": "oxgyen", "C": "water vapour", "D": "nitrogen"}, "answer": "B", "explanation": "When air is bubbled into alkaline pyrogallol solution, the component of air that is removed is oxygen. Pyrogallol reacts with oxygen to form a colorless solution, effectively removing oxygen from the air. Therefore, the correct option is oxygen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>35", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following will not affect the degree of hardness in a sample of temporarily hard water?", "images": [], "options": {"A": "Addition of washing soda", "B": "Adding of soap", "C": "Treatment with carbon exchange resin", "D": "Filtration"}, "answer": "D", "explanation": "The degree of hardness in temporarily hard water is primarily due to the presence of calcium and magnesium bicarbonates, which can be removed by boiling. The addition of washing soda, soap, or treatment with a carbon exchange resin can affect hardness. However, filtration and distillation do not affect the hardness of temporarily hard water, as they do not remove the dissolved minerals. Therefore, the correct option is filtration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>36", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Examples of polymers include the following except", "images": [], "options": {"A": "starch", "B": "nylon", "C": "wool", "D": "glass"}, "answer": "D", "explanation": "Glass is not a polymer; it is an inorganic solid made from silica and other compounds. Polymers are large molecules made up of repeating structural units (monomers), such as starch, nylon, and wool, which are organic compounds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>37", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "When the trioxonitrate (IV) salt of an alkali metal Y is heated, the formula of the residue is", "images": [], "options": {"A": "Y2O", "B": "YNO2", "C": "Y2O3", "D": "Y(NO2)2"}, "answer": "A", "explanation": "When the trioxonitrate (IV) salt of an alkali metal Y is heated, it typically decomposes to form the metal oxide (Y2O) and nitrogen dioxide (NO2). Therefore, the residue would be Y2O, which is the oxide of the alkali metal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>38", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "Which of the following compounds of tin is a strong reducing agent?", "images": [], "options": {"A": "SnCI2", "B": "SnCI4", "C": "SnO)2", "D": "SnH4"}, "answer": "D", "explanation": "Tin hydride (SnH4) is a strong reducing agent because it can donate electrons easily. It is often used in organic synthesis to reduce various functional groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>39", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following ions has the same electronic structure?  [Use the following information: 147N, 168O, 199 F3115P 8035Br]", "images": [], "options": {"A": "Nitride", "B": "Oxide", "C": "Bromide", "D": "Phosphade"}, "answer": "A", "explanation": "The ions that have the same electronic structure are those that have the same number of electrons. Nitride (N^3-) and Fluoride (F^-) both have 10 electrons, matching the electronic structure of Neon (Ne). Therefore, the correct answer is Nitride.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>40", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "In which of the following pairs are both substances deliquescent?", "images": [], "options": {"A": "CaCI2 and H2SO4", "B": "NaOH and MgSO47H2O", "C": "CaCI2 and NaOH", "D": "CuO and NaCI"}, "answer": "A", "explanation": "Both CaCl2 (calcium chloride) and H2SO4 (sulfuric acid) are deliquescent substances, meaning they can absorb moisture from the air and dissolve in the absorbed water to form a solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>41", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN", "question": "Producer gas is a mixture of", "images": [], "options": {"A": "oxygen and hydrogen", "B": "Hydrogen and nitrogen", "C": "nitrogen and oxygen", "D": "nitrogen and carbon (ll) oxide"}, "answer": "D", "explanation": "Producer gas is obtained when air is passed over red-hot coke (carbon). Since air contains oxygen and nitrogen, the oxygen reacts with carbon to form carbon(II) oxide (CO), while the nitrogen from air remains unchanged.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>42", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "An alkene may be converted to an alkane by", "images": [], "options": {"A": "halogenation", "B": "hydrolysis", "C": "dehydration", "D": "hydrogenation"}, "answer": "D", "explanation": "An alkene can be converted to an alkane through hydrogenation, which involves the addition of hydrogen  across the double bond of the alkene. This process saturates the molecule, turning it into an alkane. Therefore, the correct option is hydrogenation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>43", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Which of the following compounds has the highest ionic character?", "images": [], "options": {"A": "KCls", "B": "BeCl2", "C": "HClg", "D": "AlCl3(s)"}, "answer": "A", "explanation": "The greater the electronegativity difference between the metal and chlorine, the higher the ionic character.    KCl → Potassium is a large Group 1 alkali metal with very low electronegativity. The difference between K (0.8) and Cl (3.0) is very high, making KCl highly ionic.    BeCl₂ and AlCl₃ → small, highly charged cations (Be²⁺, Al³⁺) cause strong polarization of Cl⁻, giving more covalent character.    HCl → a polar covalent molecule, not ionic.    CaCl₂ → ionic, but calcium (1.0) has less difference with chlorine than potassium does.    Therefore, KCl(s) has the highest ionic character among the options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>44", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN", "question": "The following gases are diatomic except", "images": [], "options": {"A": "nitrogen", "B": "helium", "C": "hydrogen", "D": "fluorine"}, "answer": "B", "explanation": "Among the gases listed, helium is the only monatomic gas, while nitrogen, hydrogen, fluorine, and oxygen are all diatomic gases. Diatomic gases consist of two atoms, while monatomic gases consist of single atoms. Thus, the correct option is helium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1993>45", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "Which of the following is correct about the electrons in the 1s orbital? They", "images": [], "options": {"A": "have the same spin", "B": "are easier to remove than those in the 2p orbital", "C": "are closest to the nucleus", "D": "have the same energy as those in the 2s orbital"}, "answer": "C", "explanation": "Electrons in the 1s orbital are indeed closest to the nucleus compared to electrons in higher energy orbitals like 2p or 2s. This proximity results in a stronger attraction to the positively charged nucleus, making them more stable. Therefore, the correct option is that they are closest to the nucleus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>46", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : ALCOHOLS", "question": "The product of the reaction between ethanol and excess acidified K2Cr2O7 is", "images": [], "options": {"A": "ethanal", "B": "ethylethanoate", "C": "ethanoic acid", "D": "ethyne"}, "answer": "C", "explanation": "When ethanol is oxidized by excess acidified potassium dichromate (K2Cr2O7), the product formed is ethanoic acid (acetic acid). This reaction involves the conversion of the alcohol group in ethanol to a carboxylic acid group. Therefore, the correct option is ethanoic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>47", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "RADIAOACTIVITY", "question": "What does the following eqquation illustrate?  23892U → 23490Th + 42He", "images": [], "options": {"A": "Nuclear fission", "B": "Nuclear fusion", "C": "Artificial radioactivity", "D": "Spontaneous disintegration"}, "answer": "D", "explanation": "The equation illustrates the process of spontaneous disintegration, specifically alpha decay. In this reaction, Uranium-238 (23892U) decays into Thorium-234 (23490Th) and an alpha particle (42He). This is a natural process where an unstable nucleus loses energy by emitting radiation, resulting in the transformation of one element into another. The other options do not accurately describe this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>48", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "When ammonium chloride is dissolved in water in a test tube, the tube feels colder showing that", "images": [], "options": {"A": "the solution is unsaturated", "B": "sublimation has ocurred", "C": "ammonia gas is evolved", "D": "the process is endothermic"}, "answer": "D", "explanation": "When ammonium chloride (NH4Cl) is dissolved in water, the process absorbs heat from the surroundings, resulting in a temperature drop that makes the test tube feel colder. This indicates that the dissolution process is endothermic, meaning it requires heat from the environment. Therefore, the correct option is that the process is endothermic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>49", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Zinc displaces copper from an aqueous solution of copper (ll) salt because", "images": [], "options": {"A": "copper is a transition element", "B": "copper is a moderately reactive metal", "C": "Zinc and copper have reducing properties", "D": "zinc is more reactive than copper"}, "answer": "D", "explanation": "Zinc displaces copper from an aqueous solution of copper (II) salt because zinc is more reactive than copper. This is based on the reactivity series of metals, which ranks metals according to their ability to displace other metals from solutions of their ions. Since zinc is higher in the reactivity series than copper, it can displace copper ions from the solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1993>50", "subject": "Chemistry", "year": "1993", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "The alloy used for metal work and plumbing contains", "images": [], "options": {"A": "lead and tin", "B": "iron and carbon", "C": "copper and tin", "D": "aluminium and copper"}, "answer": "C", "explanation": "The alloy used for metal work and plumbing is typically bronze, which is an alloy of copper and tin. This combination provides desirable properties such as corrosion resistance and strength, making it suitable for various applications in plumbing and metal work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1994>1", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "WATER", "question": "The processes involved in the treatment of water for town supply include. I. filtration. II. coagulation. III. chlorination  IV. distillation.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii and iii"}, "answer": "D", "explanation": "The treatment of water for town supply typically includes filtration, coagulation, and chlorination. Filtration removes suspended particles, coagulation helps in aggregating impurities for easier removal, and chlorination disinfects the water. Distillation is not commonly used for large-scale water treatment due to its high energy requirements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>2", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Which of the following processes is/are used to improve the yield and quality of petrol? I. Cracking II. Catalytic reforming III. Use of additives IV. Fractional distillation.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii and iii"}, "answer": "D", "explanation": "To improve the yield and quality of petrol, processes such as cracking (breaking down larger hydrocarbons), catalytic reforming (rearranging molecular structures to improve quality), and the use of additives (to enhance performance) are employed. Fractional distillation is also used to separate different components of crude oil, making it relevant to petrol production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>3", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "Which of the following molecules is/are linear in shape? I. N2 II. CO2 III. NH3 IV. H2O", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii and iii"}, "answer": "B", "explanation": "The molecules N2 and CO2 are linear in shape. N2 consists of two nitrogen atoms bonded together, while CO2 has a central carbon atom double bonded to two oxygen atoms, forming a straight line. NH3 (ammonia) and H2O (water) are not linear; NH3 has a trigonal pyramidal shape, and H2O has a bent shape.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>4", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PERIODICITY OF THE ELEMENTS", "question": "If an atom of an element X is represented as 424 which of the following deductions is/are correct? I. X is chemically inactive II. An atom of X has two neutrons  III. An atom of X has only one shell IV belongs to period one of the Periodic Table", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii, iii and iv"}, "answer": "D", "explanation": "The symbol  424     X means atomic number = 2 (so X is helium) and mass number = 4.    I: Chemically inactive — helium is a noble gas, so true.    II: Neutrons = mass − protons = 4 − 2 = 2, so true.    III: Only one shell — both electrons occupy the first (only) shell, so true.    IV: Belongs to period 1 — elements with electrons only in the first shell are in period 1, so true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>5", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Which of the following can displace copper from non aqueous solution of copper(II) salt? I. Mg II. AI III. Zn IV. Fe", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii, iii and iv"}, "answer": "D", "explanation": "A metal can displace another from its compound if it is more reactive (higher in the reactivity series).    Copper (Cu) is below Mg, Al, Zn, and Fe in the reactivity series.    Therefore, all four metals (Mg, Al, Zn, Fe) can displace copper from its non-aqueous salt solution.     So the correct option is I, II, III, and IV.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>6", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ISOMERISM", "question": "Cis-butenedioic acid and trans-butenedioic acid have the same I. physical properties. II. spatial arrangement III. relative molar mass. IV. functional groups.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii and iii"}, "answer": "C", "explanation": "Geometric isomers (cis/trans) have the same molecular formula, hence the same relative molar mass (III).    They also contain the same functional groups (IV), here –COOH groups.    But they differ in spatial arrangement (II) (cis = same side, trans = opposite sides).    Because of this difference in arrangement, they also differ in physical properties (I) such as melting and boiling points, solubility, etc.    Thus, the correct deductions are III and IV only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>7", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "The properties of aluminium which make the metal useful in the manufacture of cooking utensils includes its I. resistance to corrosion. II. lightness and durability. III. ability to conduct heat and electricity IV. ability to react both acids and bases.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii and iii"}, "answer": "D", "explanation": "Aluminium is useful in cooking utensils due to its resistance to corrosion (I), lightness and durability (II), and ability to conduct heat and electricity (III). However, its ability to react with both acids and bases (IV) is not a property that contributes to its usefulness in cooking utensils. Therefore, the correct answer is 'i, ii and iii'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>8", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "In which of the following is electrolysis not applicable? I. Production of sulphur (IV) oxide II. Extraction of iron III. Extraction of aluminium IV. Purification of copper.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii and iii"}, "answer": "B", "explanation": "I. Production of SO₂ → done by burning sulphur in oxygen, not electrolysis.    II. Extraction of iron → carried out in a blast furnace by reduction with carbon, not electrolysis.    III. Extraction of aluminium → requires electrolysis of alumina (Hall–Héroult process).    IV. Purification of copper → done by electrolysis.    So electrolysis is not applicable in I and II only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>9", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Tin is one of the constituents of I. bronze. II. soft solder.III. duralumin. IV. brass", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii and iii"}, "answer": "B", "explanation": "Tin is a constituent of bronze (I) and soft solder (II), but it is not a component of duralumin (III) or brass (IV). Duralumin is an alloy primarily of aluminium, while brass is an alloy of copper and zinc. Therefore, the correct answer is 'i and ii'. Bronze = Copper + Tin.    Soft solder = Lead + Tin.    Duralumin = Aluminium + Copper + Manganese + Magnesium (no tin).    Brass = Copper + Zinc (no tin).    Therefore, tin is present only in bronze and soft solder.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>10", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "The general methods of preparing salts include I. neutralization. II. precipitation. III. double decomposition IV. action of an acid on a metal.", "images": [], "options": {"A": "iv", "B": "i and ii", "C": "iii and iv", "D": "i, ii, iii and iv"}, "answer": "D", "explanation": "The general methods of preparing salts include neutralization (I), precipitation (II), double decomposition (III), and action of an acid on a metal (IV). All these methods are valid for salt preparation. Therefore, the correct answer is 'i, ii, iii and iv'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>11", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "The components of universal indicator solution can best be separated by", "images": [], "options": {"A": "chromatography", "B": "filtration", "C": "evaporation", "D": "crystallization"}, "answer": "A", "explanation": "The components of a universal indicator solution can best be separated by chromatography. Chromatography is a technique used to separate mixtures into their individual components based on their different affinities to a stationary phase and a mobile phase. In the case of a universal indicator, which is a mixture of various pH-sensitive dyes, chromatography allows for the separation of these dyes effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>12", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The number of replaceable hydrogen atoms in one acid indicates its", "images": [], "options": {"A": "basicity", "B": "acidity", "C": "alkalinity", "D": "reactivity"}, "answer": "A", "explanation": "The basicity of an acid is the number of replaceable hydrogen atoms (ionizable H⁺ ions) present in one molecule of the acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>13", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Catalytic hydrogenation of alkenes produces compounds with the general formula", "images": [], "options": {"A": "CnH2n+1OH", "B": "CnH2n+1", "C": "CnH2n+2", "D": "CnH2n-2"}, "answer": "C", "explanation": "Catalytic hydrogenation of alkenes produces compounds with the general formula CnH2n+2. This process involves the addition of hydrogen (H2) across the double bond of alkenes, converting them into alkanes, which have the formula CnH2n+2. This reflects the saturation of the carbon chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>14", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "A measure of the degree of disorder in a chemical system is known as the", "images": [], "options": {"A": "enthalpy", "B": "free energy", "C": "activation energy", "D": "entrophy"}, "answer": "D", "explanation": "A measure of the degree of disorder in a chemical system is known as entropy. Entropy is a thermodynamic quantity that represents the amount of disorder or randomness in a system. Higher entropy indicates a greater degree of disorder, while lower entropy indicates a more ordered state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>15", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "In any chemical reaction, the total mass of the products is always equal to that of the reactants. This is statement of the law of", "images": [], "options": {"A": "definite proportion", "B": "conservation of matter", "C": "multiple proportions", "D": "reciprocal proportions"}, "answer": "B", "explanation": "In any chemical reaction, the total mass of the products is always equal to that of the reactants. This is a statement of the law of conservation of matter, which states that matter cannot be created or destroyed in an isolated system. Therefore, the mass remains constant throughout the reaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1994>16", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF SODIUM AND ITS COMPOUNDS.", "question": "Which of the following is not a property of magnesium oxide?", "images": [], "options": {"A": "High melting point", "B": "Dissolution in polar solvents", "C": "Presence of ionic bonds", "D": "Low binding energy"}, "answer": "D", "explanation": "Magnesium oxide (MgO) is a strongly bonded ionic compound formed by Mg²⁺ and O²⁻ ions. Its properties include:    High melting point (A): due to strong electrostatic attraction between oppositely charged ions.    Ionic bonds (C): MgO is held together by ionic bonding.    Crystal lattice (D): ions are arranged in a giant ionic lattice.    Interaction with polar solvents (B): though only sparingly soluble, it can react with water to form alkaline Mg(OH)₂.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>17", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "23592U + 10n + 14556Ba + 8736Kr + 10n + energy. The reaction represented by the equation above is", "images": [], "options": {"A": "an alpha particle emission", "B": "an endothermic reaction", "C": "a thermal ionization", "D": "nuclear fission"}, "answer": "D", "explanation": "The reaction represented is a nuclear fission reaction. In this process, a heavy nucleus (Uranium-235) absorbs a neutron and splits into two smaller nuclei (Barium-145 and Krypton-87), along with the release of additional neutrons and energy. This is characteristic of fission, where the nucleus breaks apart, as opposed to fusion, where smaller nuclei combine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>18", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following would increase the rate of reaction of chips of a metal M as shown in the equation below?   M(s) + 2HCI(aq) → MCI2(aq) + H2(g)", "images": [], "options": {"A": "Diluting the hydrochloric acid", "B": "Adding some distilled water", "C": "Decreasing the temperature", "D": "Grinding the metal into powder"}, "answer": "D", "explanation": "Grinding the metal into powder increases the surface area of the metal, which allows for more collisions between the metal and hydrochloric acid, thus increasing the rate of reaction. This is a fundamental concept in reaction kinetics where surface area plays a crucial role.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>19", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE REACTIONS", "question": "The oxidation number of phosphorus in PO43- is", "images": [], "options": {"A": "+1", "B": "+2", "C": "+3", "D": "+5"}, "answer": "D", "explanation": "In the phosphate ion (PO43-), phosphorus has an oxidation state of +5. This can be determined by considering the overall charge of the ion and the typical oxidation states of oxygen, which is -2. Therefore, the oxidation state of phosphorus must be +5 to balance the charge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>20", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The number of atoms in 1.2g of carbon - 12 isotope is", "images": [], "options": {"A": "1.00 x 1022", "B": "6.02 x 1022", "C": "1.20 x 1023", "D": "1.00 x 1023"}, "answer": "B", "explanation": "The number of atoms in 1.2g of carbon-12 can be calculated using Avogadro's number (6.02 x 10^23 atoms/mol). Since 1 mole of carbon-12 weighs 12g, 1.2g corresponds to 1.2/12 = 0.1 moles. Therefore, the number of atoms is 0.1 moles x 6.02 x 10^23 atoms/mol = 6.02 x 10^22 atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>21", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Tetraoxosulphate (lV) acid is described as strong acid because it is highly", "images": [], "options": {"A": "corrosive", "B": "concentrated", "C": "reactive", "D": "ionized in water"}, "answer": "D", "explanation": "Tetraoxosulphate (IV) acid, commonly known as sulfuric acid (H2SO4), is considered a strong acid because it ionizes completely in water, producing a high concentration of hydrogen ions (H+). This complete ionization is what characterizes a strong acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>22", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The following will decolourize acidified potassium tetraoxomanganate (VII) solution except", "images": [], "options": {"A": "sulphur (lV) oxide", "B": "but-3-ene", "C": "pentane", "D": "hydrogen sulphide"}, "answer": "C", "explanation": "Pentane is a saturated hydrocarbon (alkane) and does not react with potassium tetraoxomanganate (VII) solution, which is a strong oxidizing agent. The other options, such as sulphur (IV) oxide, but-3-ene, hydrogen sulphide, and propyne, can undergo oxidation and thus would decolorize the solution.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>23", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Polyatomicity is illustrated by molecules of", "images": [], "options": {"A": "sulphur", "B": "carbon (IV) oxide", "C": "noble gases", "D": "liquefied oxygen"}, "answer": "A", "explanation": "Polyatomicity refers to the presence of multiple atoms in a molecule. Sulphur (S8) is a polyatomic molecule consisting of eight sulfur atoms. The other options either consist of diatomic molecules (like carbon dioxide) or are monoatomic (noble gases).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1994>24", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Calcium is usually extracted by the electrolysis of its", "images": [], "options": {"A": "trioxonitrate (V)", "B": "tetraoxosulphate (IV)", "C": "oxide", "D": "chloride"}, "answer": "D", "explanation": "Calcium is extracted not from its oxide, but by the electrolysis of molten calcium chloride (CaCl₂).    CaO (calcium oxide) has too high a melting point and is not suitable for electrolysis.    In practice, CaCl₂ (sometimes mixed with CaF₂ to lower melting point) is electrolyzed", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>25", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "When naphthalene on heating changes from the solid state directly to the gaseous state it undergoes", "images": [], "options": {"A": "evaporation", "B": "sublimation", "C": "decomposition", "D": "combustion"}, "answer": "B", "explanation": "When naphthalene is heated and changes from solid to gas without passing through a liquid state, it undergoes sublimation. This process is characteristic of certain substances that can transition directly from solid to gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>26", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following occurs when an aqueous solution of sodium hydroxide is electrolysed using graphite electrodes?", "images": [], "options": {"A": "Sodium metal is produced at the anode", "B": "Sodium amalgam is formed at the cathode", "C": "Oxygen gas is produced at the anode", "D": "The grahite anode dissolves"}, "answer": "C", "explanation": "During the electrolysis of an aqueous sodium hydroxide solution using graphite electrodes, oxygen gas is produced at the anode. The reaction involves the oxidation of hydroxide ions to form oxygen gas and water.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>27", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "If the volume of a given mass of gas at 0oC is 27.3cm3, what will be the volume of the gas at 10oC, pressure remaining constant?", "images": [], "options": {"A": "2.73cm3", "B": "28.3cm3", "C": "37.3cm3", "D": "273cm3"}, "answer": "B", "explanation": "To find the volume of a gas at a different temperature while keeping pressure constant, we can use Charles's Law, which states that V1/T1 = V2/T2. Here, V1 = 27.3 cm³, T1 = 273 K (0°C), and T2 = 283 K (10°C). Rearranging gives V2 = V1 * (T2/T1) = 27.3 * (283/273) ≈ 28.3 cm³. Therefore, the correct option is 28.3 cm³.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>28", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Glucose can be obtained from starch by", "images": [], "options": {"A": "hydrogenation", "B": "dissoiation", "C": "hydrolysis", "D": "dialysis"}, "answer": "C", "explanation": "Glucose can be obtained from starch through hydrolysis, which is a chemical process that involves the breakdown of a compound by reaction with water. In this case, starch (a polysaccharide) is hydrolyzed to yield glucose (a monosaccharide). Therefore, the correct option is hydrolysis.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>29", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many faradays of electricity are required to liberate 9g aluminium? (AI = 27)", "images": [], "options": {"A": "0.1", "B": "0.3", "C": "1.0", "D": "2.7"}, "answer": "C", "explanation": "To determine the number of faradays required to liberate 9g of aluminum, we use the formula: Faradays = (mass of substance / molar mass) * n, where n is the number of electrons transferred per atom. For aluminum, n = 3 (Al^3+). Molar mass of Al = 27 g/mol. Thus, Faradays = (9g / 27g/mol) * 3 = 1.0. Therefore, the correct option is 1.0.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>30", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "When water is dropped on calcium carbide, the gaseous product is an", "images": [], "options": {"A": "alkane", "B": "alkene", "C": "alkyne", "D": "alkanol"}, "answer": "C", "explanation": "When water is added to calcium carbide (CaC2), it reacts to produce acetylene gas (C2H2), which is an alkyne. Alkynes are hydrocarbons that contain at least one triple bond between carbon atoms. Therefore, the correct option is alkyne.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>31", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Mg2 + 2HCI(aq) → MgCI2(g) + H2(g)  From the equation above what mass of hydrogen would be produced if 12.0 g of magnesium reacted completely with dilute hydrochloric acid? (H = 1, Mg = 24)", "images": [], "options": {"A": "1.0g", "B": "2.0g", "C": "6.0g", "D": "12.0g"}, "answer": "A", "explanation": "From the balanced equation, 1 mole of magnesium produces 1 mole of hydrogen. The molar mass of magnesium is 24 g, and the molar mass of hydrogen is 2 g. Therefore, 12 g of magnesium (which is 0.5 moles) will produce 0.5 moles of hydrogen, which is 0.5 * 2 g = 1.0 g of hydrogen. Thus, the correct option is 1.0 g.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>32", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC LAW", "question": "The position of an element in the Periodic Table is determined by", "images": [], "options": {"A": "its density", "B": "its atomic radius", "C": "its relative atomic mass", "D": "the number of protons in its atom"}, "answer": "D", "explanation": "The position of an element in the Periodic Table is determined by the number of protons in its atom, which is also known as the atomic number. The atomic number uniquely identifies an element and determines its position in the periodic table.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>33", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following alkanols on oxidation is most likely to yield the compound with formula below?  CH3CHCOOH   |  CH3", "images": [], "options": {"A": "Butanol", "B": "Propan-2-ol", "C": "2-methylbutan-1-ol", "D": "2-methylpropan-1-ol"}, "answer": "B", "explanation": "The compound with the formula CH3CH(COOH)CH3 is 2-propanoic acid (or propanoic acid). The oxidation of propan-2-ol (isopropanol) will yield this compound. The other options do not lead to the formation of this specific carboxylic acid upon oxidation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>34", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "Which of the following electronic structures belongs to a noble gas?", "images": [], "options": {"A": "1s22s2", "B": "1s22s22p4", "C": "1s22s22p63s23p6", "D": "1s22s22p2"}, "answer": "C", "explanation": "The electronic structure 1s22s22p63s23p6 corresponds to the noble gas Argon (Ar), which has a complete outer shell of electrons. Noble gases are characterized by having full valence shells, making them stable and unreactive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>35", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "In a chemical reaction, the reacting species possess energy of motion known as", "images": [], "options": {"A": "potential energy", "B": "free energy", "C": "bond energy", "D": "kinetic energy"}, "answer": "D", "explanation": "In a chemical reaction, the energy of motion possessed by the reacting species is known as kinetic energy. Kinetic energy is the energy that an object has due to its motion, and in the context of chemical reactions, it relates to the movement of molecules and atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>36", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE", "question": "The following compounds will decompose on heating except", "images": [], "options": {"A": "NaHCO3", "B": "K2CO3", "C": "MgCO3", "D": "Ca(HCO3)2"}, "answer": "B", "explanation": "Among the compounds listed, K2CO3 (potassium carbonate) does not decompose upon heating. The other compounds listed, such as NaHCO3 (sodium bicarbonate), MgCO3 (magnesium carbonate), Ca(HCO3)2 (calcium bicarbonate), and ZnCO3 (zinc carbonate), decompose when heated to release gases or form other compounds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>37", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE REACTIONS", "question": "Which of the following reactions is accompanied by the first ionization energy of an element X?", "images": [], "options": {"A": "X+(aq) → X2+(aq) + e-", "B": "X-(g) → X(g) + e-", "C": "X+(g) → X2+ + e-", "D": "X(g) → X+(g) + e-"}, "answer": "D", "explanation": "The reaction X(g) → X+(g) + e- represents the first ionization energy of an element X. Ionization energy is the energy required to remove an electron from a neutral atom in the gas phase, resulting in a positively charged ion.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>38", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "What is the molar mass of an alkyne with the formula CxH14? (H=1, C=12)", "images": [], "options": {"A": "86g", "B": "92g", "C": "98g", "D": "110g"}, "answer": "D", "explanation": "The formula CxH14 indicates that the alkyne has 14 hydrogen atoms. For an alkyne, the general formula is CnH2n-2. Setting 2n-2 = 14 gives n = 8. Therefore, the molar mass is calculated as (8 * 12) + (14 * 1) = 96 + 14 = 110 g. Thus, the correct answer is 110g.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>39", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What is the role of hydrogen sulphide gas in the reaction represented by the following equation?H2SO4(aq) + 3H2S(g) → 4S(s) + 4H2O(l)", "images": [], "options": {"A": "Reducing agent", "B": "A bleaching agent", "C": "A dehydrating agent", "D": "A sulphonating agent"}, "answer": "A", "explanation": "Hydrogen sulphide (H₂S) changes from oxidation state –2 in H₂S to 0 in elemental sulphur (S). This means it is oxidized.    The substance that is oxidized is the reducing agent.    At the same time, H₂SO₄ (sulphur in +6) is reduced to water (sulphur leaves as solid S).    👉 Hence, H₂S acts as the reducing agent because it donates electrons and causes H₂SO₄ to be reduced.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1994>40", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Alkanols have unexpectedly high boiling points relative to their molar masses because of intermolecular", "images": [], "options": {"A": "hydrogen bonding", "B": "metallic bonding", "C": "covalent bonding", "D": "ionic bonding"}, "answer": "A", "explanation": "Alkanols (alcohols) have high boiling points due to hydrogen bonding between their molecules. This type of bonding occurs when a hydrogen atom covalently bonded to a highly electronegative atom (like oxygen) is attracted to another electronegative atom in a different molecule. This strong intermolecular force requires more energy (in the form of heat) to break, resulting in higher boiling points compared to similar-sized molecules that do not exhibit hydrogen bonding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>41", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Sodium chloride is used in the following processes except in the", "images": [], "options": {"A": "treatment of polluted water", "B": "preservation of food", "C": "separation of soap from glycerol", "D": "manufacture of chlorine"}, "answer": "C", "explanation": "Sodium chloride (table salt) is commonly used in the treatment of polluted water, preservation of food, and in the manufacture of chlorine and caustic soda. However, it is not used in the separation of soap from glycerol, which typically involves other methods such as centrifugation or filtration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>42", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN", "question": "The gaseous product formed when ammonia is passed over heated copper (ll) oxide is", "images": [], "options": {"A": "oxygen", "B": "nitrogen", "C": "hydrogen", "D": "nitrogen (l) oxide"}, "answer": "B", "explanation": "When ammonia (NH₃) is passed over heated copper(II) oxide (CuO), the ammonia is oxidized while CuO is reduced. Ammonia (NH₃) acts as the reducing agent because it loses hydrogen and is oxidized.    Copper(II) oxide (CuO) acts as the oxidizing agent because it loses oxygen and is reduced to copper metal.    The final gaseous product is nitrogen (N₂), while copper metal and water are also formed.    Thus, the gaseous product is nitrogen, not oxygen or oxides of nitrogen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>43", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Which of the following is not a halogen?", "images": [], "options": {"A": "Silicon", "B": "Fluorine", "C": "Astatine", "D": "Bromine"}, "answer": "A", "explanation": "Silicon is not a halogen. Halogens are a group of elements in Group 17 of the periodic table, which includes fluorine, chlorine, bromine, iodine, and astatine. Silicon, on the other hand, is a metalloid found in Group 14 and does not share the chemical properties of halogens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1994>44", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "WATER", "question": "Which of the following is likely to have the highest degree of hardness?", "images": [], "options": {"A": "Carbonated water", "B": "Distilled water", "C": "Acidified water", "D": "Lime water"}, "answer": "D", "explanation": "Lime water, which is a saturated solution of calcium hydroxide, is known for its hardness due to the presence of dissolved minerals. In contrast, the other options like carbonated water, distilled water, acidified water, and rainwater generally have lower hardness levels.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1994>45", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS~~CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS~~CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Study the reaction represented by the equation: Alkanol + Alkanoic acid + conc. H2SO4 →  Alkanoate + water.  The type of process involved in the reverse reaction is", "images": [], "options": {"A": "Neutralization", "B": "dehydration", "C": "hydrolysis", "D": "decomposition"}, "answer": "C", "explanation": "The reverse reaction of the given equation involves the hydrolysis of the alkanoate to regenerate the alkanol and alkanoic acid. Hydrolysis is a chemical process that involves the reaction of a compound with water, leading to the breakdown of that compound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>46", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Destructive distillation of coal means", "images": [], "options": {"A": "heating coal in plentiful supply of air", "B": "burning coal in air to produce water and carbon (IV) oxide", "C": "heating coal in the absence of air", "D": "heating coal in limited supply of air"}, "answer": "C", "explanation": "Destructive distillation of coal refers to heating coal in the absence of air. This process breaks down the coal into various products, including coal gas, coal tar, and coke, without combustion occurring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>47", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "When magnesium ribbon burns in air, the products are", "images": [], "options": {"A": "magnesium nitride and magnesium oxide", "B": "magnesium nitride and carbon (ll) oxide", "C": "magnesium oxide and steam", "D": "magnesium nitride and soot"}, "answer": "A", "explanation": "When magnesium ribbon burns in air, it reacts with oxygen to form magnesium oxide (MgO). The presence of nitrogen in the air can lead to the formation of magnesium nitride (Mg3N2) under certain conditions, but the primary product is magnesium oxide.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1994>48", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The following compounds contain the same type of bonds except", "images": [], "options": {"A": "sodium chloride", "B": "hydrogen chloride", "C": "magnesium chloride", "D": "potassium chloride"}, "answer": "B", "explanation": "Most of the compounds listed — sodium chloride (NaCl), magnesium chloride (MgCl₂), potassium chloride (KCl), and lithium chloride (LiCl) — are ionic compounds. They are formed by the transfer of electrons from the metal atom to chlorine, resulting in strong electrostatic forces between oppositely charged ions.    However, hydrogen chloride (HCl) is different. In its gaseous state, HCl is a covalent compound because the hydrogen and chlorine atoms share electrons rather than transferring them. (Only when dissolved in water does it ionize to form H⁺ and Cl⁻ ions, behaving like an acid.)    Therefore, the compound that does not contain the same type of ionic bond as the others is hydrogen chloride (HCl).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1994>49", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "The part labelled X is the", "images": ["Chemistry/imgs/1994/6YN6PJ.jpg"], "options": {"A": "galvanometer", "B": "voltmeter", "C": "ammeter", "D": "salt bridge"}, "answer": "D", "explanation": "A salt bridge is a tube or strip containing an inert electrolyte in a gel or porous medium, which connects the two half-cells of an electrochemical cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1994>50", "subject": "Chemistry", "year": "1994", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The reaction at the zinc anode is", "images": ["Chemistry/imgs/1994/6YN6PJ.jpg"], "options": {"A": "addition", "B": "hydrolysis", "C": "oxidation", "D": "hydration"}, "answer": "C", "explanation": "In an electrochemical cell:    Anode → Oxidation (loss of electrons)    Cathode → Reduction (gain of electrons)    So, in the Daniell cell:    At the zinc anode: Zn → Zn²⁺ + 2e⁻ (oxidation)    At the copper cathode: Cu²⁺ + 2e⁻ → Cu (reduction)  Addition   Addition means combining two or more molecules/atoms to form one product (e.g.,   At the anode, zinc is not combining with anything. Instead, it is losing electrons.  So this is not addition.  Hydrolysis   Hydrolysis means decomposition of a compound by reaction with water (e.g., ester hydrolysis).  The zinc electrode is not reacting with water. It simply dissolves as ions by losing electrons.  So, not hydrolysis.  Oxidation  (Correct)    At the anode, electrons are always lost.    Zinc loses electrons:  This is the definition of oxidation.  Hydration   Hydration means adding water molecules to a compound (e.g., CuSO₄·5H₂O is hydrated copper sulfate).  Zinc is not combining with water molecules; it is just losing electrons.  So, not hydration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>1", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Given the symbol 4020Y, it can be deduced that Y has", "images": [], "options": {"A": "60 neutrons", "B": "an atomic number of 20", "C": "a mass number of 60", "D": "40 electrons"}, "answer": "B", "explanation": "The atomic number of an element is the number of protons in the nucleus of an atom of that element. It is denoted by the subscript in the atomic symbol. In the given symbol 4020Y, the atomic number is 20, which means Y has 20 protons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>2", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "All pure samples of the same chemical compound contain the same elements in the same proportion by mass is a statement of", "images": [], "options": {"A": "the law of conservation of matter", "B": "the law of constant composition", "C": "the law of multiple proportion", "D": "Gay Lussac's law"}, "answer": "B", "explanation": "In chemistry, the law of constant composition (also known as the law of definite proportions) states that samples of a pure compound always contain the same elements in the same mass proportion. This law, together with the law of multiple proportions, is the basis for stoichiometry in chemistry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>3", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "If an element X with electronic configuration 2,8,3, combines with another element Z with electronic configuration 2,8,6, the compound formed will have the formula", "images": [], "options": {"A": "XZ", "B": "XZ2", "C": "X2Z", "D": "X2Z3"}, "answer": "D", "explanation": "Element X has the electronic configuration 2,8,3, which means it has 3 electrons in its outermost energy level. To achieve a stable configuration, it needs to lose 3 electrons. Element Z has the electronic configuration 2,8,6, which means it has 6 electrons in its outermost energy level. To achieve a stable configuration, it needs to gain 2 electrons. This results in the compound having the formula X2Z3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>4", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.", "question": "A beta particle is represented as", "images": [], "options": {"A": "10 n", "B": "0-1 e", "C": "0+1 e", "D": "11 H"}, "answer": "B", "explanation": "A beta particle is a high-energy, high-speed electron or positron that is emitted by certain types of radioactive nuclei such as potassium-40. The beta particle is represented as 0-1 e, where 0 is the atomic mass number (indicating that the beta particle has virtually no mass compared to a proton or a neutron) and -1 is the atomic number (indicating that the beta particle is negatively charged).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>5", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "If a solid has a low melting point and dissolves readily in benzene, it would probably", "images": [], "options": {"A": "contain strong electrostatic forces of attraction", "B": "conduct electricity in the molten state", "C": "dissolve in water", "D": "have covalent bonding"}, "answer": "D", "explanation": "A solid with a low melting point and that dissolves readily in benzene is likely to have covalent bonding. Covalent bonds are formed when two atoms share electrons. This type of bond is common in organic compounds, which are often soluble in organic solvents like benzene. The low melting point suggests weak intermolecular forces, which is characteristic of covalent compounds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>6", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "Which of the following molecules is linear in shape?", "images": [], "options": {"A": "CH4", "B": "H2O", "C": "NH3", "D": "CI2"}, "answer": "D", "explanation": "The molecule Cl2 is linear in shape. This is because it consists of two atoms of the same element, so there is no difference in electronegativity to cause a bend in the molecule. The other options, CH4, H2O, and NH3, are not linear. CH4 is tetrahedral, H2O is bent, and NH3 is trigonal pyramidal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>7", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Which of the following cannot be deduced from the electronic configuration of a transition metal?", "images": [], "options": {"A": "Possession of magnetic property", "B": "Ability to form complex ions", "C": "Position in the Periodic Table", "D": "Variable oxidation states"}, "answer": "A", "explanation": "Possession of magnetic property cannot be deduced from the electronic configuration of a transition metal", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>8", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following is the configuration of sodium ion(Na+) if the atom is represented as 2311Na?", "images": [], "options": {"A": "1s22s22p6", "B": "1s22s22p63s2", "C": "1s22s22p63s1", "D": "1s22s22p63s23p63d24s2"}, "answer": "A", "explanation": "The electronic configuration of a sodium atom (Na) is 1s22s22p63s1. When sodium loses one electron to form a sodium ion (Na+), it loses the electron from the 3s orbital. Therefore, the electronic configuration of a sodium ion (Na+) is 1s22s22p6, which corresponds to the first option.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>9", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is the percentage by mass of copper in copper (l) oxide (CU2O)? [O = 16; Cu =64]", "images": [], "options": {"A": "88.9%", "B": "80.0%", "C": "66.7%", "D": "20.0%"}, "answer": "A", "explanation": "The percentage by mass of copper in Cu2O is calculated as (mass of copper/molar mass of Cu2O) * 100. The molar mass of Cu2O is (2*64) + 16 = 144. The mass of copper in the compound is 2*64 = 128. Therefore, the percentage by mass of copper in Cu2O is (128/144) * 100 = 88.9%.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>10", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A weak acid is one which", "images": [], "options": {"A": "is not corrosive", "B": "is slightly ionizied in water", "C": "does not produce salts with alkalis", "D": "does not conduct an electric current in aqueous solution"}, "answer": "B", "explanation": "A weak acid is defined as an acid that does not completely ionize in a solution. Therefore, a weak acid is slightly ionized in water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>11", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following species is always present in acidified water?", "images": [], "options": {"A": "NH+4", "B": "O2-", "C": "HCl", "D": "H3O+"}, "answer": "D", "explanation": "When water is acidified, it means that a proton (H+) has been added to the water molecules, forming hydronium ions (H3O+). This is a fundamental concept in acid-base chemistry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>12", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "The most suitable method for preparing lead (ll) chloride is by", "images": [], "options": {"A": "action of dilute HCI on PbSO4", "B": "acts of dilute HCI on lead", "C": "action of dilute HCI on PbCO3", "D": "mixing aqueous solutions Pb(NO3)2 and NaCI."}, "answer": "D", "explanation": "The most suitable method for preparing lead (ll) chloride is by mixing aqueous solutions Pb(NO3)2 and NaCI.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>13", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "A positive brown ring test indicates the presence of", "images": [], "options": {"A": "NO3-", "B": "Fe3+", "C": "SO2-3", "D": "Cu+"}, "answer": "A", "explanation": "Brown ring test is used for the detection of nitrate ions in a solution. As the name suggests it detects presence of nitrate ions by formation of brown ring at the interface of two layers of liquid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>14", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Consider the reaction represented by the equation below: XO + YO → X + YO2 In the reaction, YO acts as", "images": [], "options": {"A": "an acidic oxide", "B": "a basic oxide", "C": "a reducing agent", "D": "a weak base"}, "answer": "C", "explanation": "In the given reaction, XO + YO → X + YO2, YO is being oxidized to YO2. This means it is losing electrons and therefore, it is acting as a reducing agent. A reducing agent is a substance that loses electrons in a redox chemical reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>15", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Sodium chloride cannot conduct electricity in the solid state because it", "images": [], "options": {"A": "is a normal salt", "B": "is highly soluble in water", "C": "is an electrovalent compound", "D": "does not contain mobile ions"}, "answer": "D", "explanation": "In the solid state, sodium chloride (NaCl) does not conduct electricity because its ions are not free to move. Electricity is conducted by the movement of free ions, and in the solid state of NaCl, the ions are held together in a lattice structure and are not free to move.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>16", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "What mass of copper will be deposited by the liberation of Cu2+ when 0.1F of electricity flows through an aqueous solution of a copper (ll) salt? [Cu = 64]", "images": [], "options": {"A": "64g", "B": "32g", "C": "12.8g", "D": "3.2g"}, "answer": "D", "explanation": "The amount of substance deposited at an electrode during electrolysis is directly proportional to the quantity of electricity passed through the electrolyte. This is known as Faraday's First Law of Electrolysis. One Faraday (F) of electricity will deposit one mole of a substance. Given that the atomic mass of copper (Cu) is 64, one mole of copper is 64g. Therefore, 0.1F of electricity will deposit 0.1 moles of copper, which is 0.1 * 64g = 6.4g. However, since copper ions in solution are Cu2+, each copper ion accepts two electrons during reduction. Therefore, the actual mass of copper deposited is half of 6.4g, which is 3.2g.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1995>17", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Alums are classified as", "images": [], "options": {"A": "simple salt", "B": "acid salts", "C": "anhydrous salts", "D": "double salts"}, "answer": "D", "explanation": "Double Salts: contain more than one anion or cation. They form when more than one salt is dissolved in a liquid and when together they crystallize in a regular pattern. Alum is an example of a double salt. Alum contains aluminum and sulphate ions. Another example would be potassium sodium tartrate. Epsom salts are an example of a double salt. A double salt is a salt that crystallizes as a single substance but ionizes as two distinct salts when dissolved", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>18", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Aqueous sodium trioxocarbonate (IV) solution is alkaline because the salt is", "images": [], "options": {"A": "hydrolysed in water", "B": "formed from a strong base", "C": "fully ionized in water", "D": "not decomposed by heat"}, "answer": "A", "explanation": "Aqueous sodium trioxocarbonate (IV) solution is alkaline because the salt is hydrolysed in water. Hydrolysis is a reaction involving the breaking of a bond in a molecule using water. The salt, sodium trioxocarbonate (IV), when dissolved in water, undergoes hydrolysis to form sodium hydroxide, which is a strong base, and carbonic acid, which is a weak acid. The solution is therefore alkaline due to the presence of the strong base, sodium hydroxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>19", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Which of the following is not correct of the reaction represented by the equation below? 2C(s) + O2(g) → 2CO(g); ∆H = - xKJ", "images": [], "options": {"A": "there is an increase in entropy", "B": "There is anincrease in gaseous volume", "C": "Carbon (lV) oxide is produced", "D": "The oxidation number of carbon increases from 0 to +2"}, "answer": "C", "explanation": "Carbon (lV) oxide is produced is not correct of the reaction represented by the equation", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>20", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "H3O+(aq) + OH-(aq) → 2H2O(l). The heat change accompanying the process represented by the equation above is the heat of", "images": [], "options": {"A": "neutralization", "B": "formation", "C": "solution", "D": "dilution"}, "answer": "A", "explanation": "The reaction H3O+(aq) + OH-(aq) → 2H2O(l) represents a neutralization reaction. In a neutralization reaction, an acid (in this case, hydronium ion, H3O+) reacts with a base (in this case, hydroxide ion, OH-) to form water. The heat change that accompanies this process is known as the heat of neutralization. Therefore, the correct answer is 'neutralization'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>21", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "The following statements about graphite are correct except that it", "images": [], "options": {"A": "is used as a lubricant", "B": "has a network structure", "C": "contains mobile free electrons", "D": "is good conductor"}, "answer": "B", "explanation": "Graphite does not have a network structure. It has a layered structure where each layer is composed of carbon atoms arranged in a hexagonal lattice. The layers are held together by weak van der Waals forces, allowing them to slide over each other, which is why graphite is used as a lubricant. The delocalized electrons in graphite make it a good conductor of electricity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>22", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following is hydrocarbons is unsaturated?", "images": [], "options": {"A": "Ethane", "B": "Benzene", "C": "Propane", "D": "2 - methylbutane"}, "answer": "B", "explanation": "Benzene is an unsaturated hydrocarbon. Unsaturated hydrocarbons are those that contain double or triple bonds between adjacent carbon atoms. Benzene has a ring structure with alternating single and double bonds, making it an unsaturated hydrocarbon. Ethane, Propane, and 2-methylbutane are all saturated hydrocarbons, meaning they only contain single bonds between carbon atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>23", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "The following can be obtained directly from the destructive distillation of coal except", "images": [], "options": {"A": "ammoniacal liquor", "B": "coke", "C": "producer gas", "D": "coal gas"}, "answer": "C", "explanation": "Destructive distillation of coal produces several byproducts, including coke, coal gas, and ammoniacal liquor. However, producer gas is not directly obtained from the destructive distillation of coal. Producer gas is a type of fuel which is produced by passing air over red-hot coke. Therefore, it is not a direct byproduct of coal distillation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>24", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Fructose and glucose are classified as carbohydrates because they", "images": [], "options": {"A": "are crystalline white solids", "B": "are energy -giving substances", "C": "are naturally occurring organic compounds", "D": "conform to the general formula Cx(H2O)y"}, "answer": "D", "explanation": "Fructose and glucose are classified as carbohydrates because they conform to the general formula Cx(H2O)y", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>25", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Consider the reaction:  CH3-CH=CH2(propene)     &nbsp &nbsp &nbsp &nbsp OH&nbsp&nbspOH  &nbsp &nbsp &nbsp &nbsp &nbsp | &nbsp &nbsp &nbsp &nbsp|  CH3- CH-CH2  Propan-1,2-diol  Which of the following reagents is used for the conversion indicated above?", "images": [], "options": {"A": "Aqueous sodium hydroxide", "B": "Acidified potassium tetraoxomanganate (VII)", "C": "Ammoniacal copper (I) chloride solution", "D": "Aqueous ammonia"}, "answer": "B", "explanation": "The reaction described is an oxidation reaction where propene is converted to propan-1,2-diol. This type of reaction requires a strong oxidizing agent. Acidified potassium tetraoxomanganate (VII) is a strong oxidizing agent that can perform this conversion. It is often used in organic chemistry to oxidize alkenes to diols.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>26", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "The gas produced when a mixture of sodium propanoate and soda lime is heated is", "images": [], "options": {"A": "methane", "B": "pentane", "C": "ethane", "D": "butene"}, "answer": "C", "explanation": "When a mixture of sodium propanoate and soda lime is heated, the gas produced is ethane. This is a decarboxylation reaction, where a carboxyl group is removed from a molecule and replaced with a hydrogen atom. In this case, the sodium propanoate (a salt of a carboxylic acid) loses a carbon dioxide molecule when heated with soda lime, resulting in the formation of ethane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>27", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "What is the relationship between the compounds represented by the following structures?They are  H &nbsp  &nbsp Br  &nbsp\\ &nbsp &nbsp  /   &nbsp C=C  / &nbsp  &nbsp &nbsp  \\  Br &nbsp  &nbsp H    and  H &nbsp  &nbsp H  &nbsp\\ &nbsp &nbsp  /   &nbsp C=C  / &nbsp  &nbsp &nbsp  \\  Br &nbsp  &nbsp Br", "images": [], "options": {"A": "allotropes", "B": "dimers", "C": "polymers", "D": "geometric isomers"}, "answer": "D", "explanation": "Geometric isomers are chemical species with the same type and quantity of atoms as another species, yet having a different geometric structure. Atoms or groups exhibit different spatial arrangements on either side of a chemical bond or ring structure. Geometric isomerism is also called configurational isomerism or cis-trans isomerism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>28", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "In which of the following processes are larger molecules broken down into smaller molecules?", "images": [], "options": {"A": "Vulcanization of rubber", "B": "Hydrogenation of palm oil", "C": "Hydrolysis of starch", "D": "Polymerization"}, "answer": "C", "explanation": "Hydrolysis of starch is the process where larger molecules are broken down into smaller molecules. Hydrolysis is a reaction involving the breaking of a bond in a molecule using water. In the case of starch, it is broken down into smaller glucose units.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>29", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "The following alkanols will yield alkanoic acids on reacting with excess acidified K2Cr2O7 except", "images": [], "options": {"A": "CH3CH2OH", "B": "(CH3)2CHCH2OH", "C": "(CH3)3CCH2OH", "D": "(CH3)3COH"}, "answer": "D", "explanation": "The following alkanols will yield alkanoic acids on reacting with excess acidified K2Cr2O7 except (CH3)3COH", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1995>30", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Which of the following is an alloy of mercury?", "images": [], "options": {"A": "Stainless steel", "B": "Soft solder", "C": "Coinage bronze", "D": "Amalgam"}, "answer": "D", "explanation": "An alloy is a mixture of two or more metals, or a metal and a non-metal. An alloy of mercury is called an amalgam. Therefore, the correct answer is 'Amalgam'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>31", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The function of limestone in the extraction of iron in the blast furnace is", "images": [], "options": {"A": "removal of the earthly impurities", "B": "decomposition of the iron ore", "C": "conversion of iron (lll) to iron (ll) compounds", "D": "generation of heat for the process"}, "answer": "A", "explanation": "The function of limestone in the extraction of iron in the blast furnace is removal of the earthly impurities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>32", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.", "question": "Metals which react with steam only when they are red-hot include", "images": [], "options": {"A": "copper", "B": "sodium", "C": "calcium", "D": "iron"}, "answer": "D", "explanation": "Iron is a metal that reacts with steam only when it is red-hot. This is because the reaction between iron and steam is an endothermic reaction, which means it requires heat to proceed. When iron is red-hot, it has enough energy to react with steam to form iron(III) oxide and hydrogen gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>33", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Copper (ll) tetraoxosulphate (VI) is often added to swimming pools because it", "images": [], "options": {"A": "prevents the growth of algae", "B": "coagulates suspended particles", "C": "neutralizes dissolved gases in water", "D": "reacts with any excess chlorine present"}, "answer": "A", "explanation": "Copper (ll) tetraoxosulphate (VI) is often added to swimming pools because it prevents the growth of algae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>34", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "The following salts dissolve readily in cold water except", "images": [], "options": {"A": "CaCI2", "B": "PbSO4", "C": "(NH4)2SO4", "D": "Na2CO3"}, "answer": "B", "explanation": "PbSO4 or Lead (II) Sulphate does not dissolve readily in cold water. This is because Lead (II) Sulphate is insoluble in cold water due to its high lattice energy which cannot be overcome by the hydration energy of water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>35", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following compounds is not decomposed by heat?", "images": [], "options": {"A": "Sodium trioxocarbonate (V)", "B": "Ammonium trioxocarbonate (V)", "C": "Sodium hydrogentrioxocarbonate (IV)", "D": "Calcium trioxocarbonate (IV)"}, "answer": "A", "explanation": "Sodium trioxocarbonate (V) is not decomposed by heat. The other compounds listed are all decomposed by heat. Sodium trioxocarbonate (V) is a stable compound that does not decompose under normal conditions, including heat. Decomposition is a type of chemical reaction where one compound breaks down into two or more simpler substances, usually with the input of energy such as heat. However, Sodium trioxocarbonate (V) does not undergo this reaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1995>36", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is the amount (in mole) of hydrogen gas that would be produced if 0.6 mole of hydrochloric acid reacted with excess zinc according to the following equation? Zn(s) + 2HCI(aq) → ZnCI2(aq) + H2(g)", "images": [], "options": {"A": "0.1 mole", "B": "0.2mole", "C": "0.3 mole", "D": "1.0 mole"}, "answer": "C", "explanation": "2HCl + Zn → ZnCl2 + H2    2 ; 1 : 1 : 2    so if 2mole of HCl = 1mol of H     0.6mol = 0.6mol X  1mol/2mol =0.3mol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>37", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following oxides is amphoteric?", "images": [], "options": {"A": "Na2O", "B": "Fe2O3", "C": "Al2O3", "D": "CaO"}, "answer": "C", "explanation": "Aluminium oxide is an amphoteric oxide. With sodium hydroxide solution, it produces water and sodium aluminate (NaAlO2). The other common examples of amphoteric oxides include SnO, ZnO, and PbO. Al2O3 is an amphoteric oxide.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1995>38", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Chlorine is prepared on a large scale by the", "images": [], "options": {"A": "electrolysis of concentrated sodium chloride solution", "B": "action of manganese (IV) oxide on hot concentrated hydrochloric acid", "C": "action of concentrated tetraoxosulphate (VI) acid on sodium chloride", "D": "oxidation of concentrated hydrochloric acid with potassium tetraoxomanganate (VII)"}, "answer": "A", "explanation": "Chlorine is prepared on a large scale by the electrolysis of concentrated sodium chloride solution. This process is known as the chlor-alkali process, where the electrolysis of sodium chloride solution produces chlorine gas at the positive electrode (anode) and hydrogen gas at the negative electrode (cathode).", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1995>39", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Which of the following statements is correct about the following system at equilibrium? PCl5(g)  ⇌ PCl3(g)  + Cl2(g); ∆H positive", "images": [], "options": {"A": "increase in temperature increases the yield of PCl5", "B": "PCI5 is less stable at high pressures", "C": "The concentrations of PCI3 and Cl2 increase at higher pressures", "D": "Decrease in pressure favours the forward reaction"}, "answer": "D", "explanation": "Decrease in pressure favours the forward reaction is correct about the following system at equilibrium", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>40", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION", "question": "A sample of air that has been passed through caustic potash will", "images": [], "options": {"A": "contain more oxygen than nitrogen", "B": "rekindle a glowing splint", "C": "have no action on lime water", "D": "contain no water vapour"}, "answer": "C", "explanation": "Caustic potash absorb the Carbon (iv) Oxide in the air which is responsible for the milkiness of lime water. Hence air passed through caustic potash will have no effect on lime water", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>41", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct    Which of the following acids can function both as a drying agent and as a dehydrating agent?I Fuming HNO3, II Glacial CH3COOH III Concentrated HCI IV. Concentrated H2SO4", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "A", "explanation": "One of the best examples of the substance or chemical used both as a drying agent and a dehydrating agent is concentrated sulphuric acid. This acid can act as a drying agent when it is used to remove water from other substances by simply evaporating the water molecules, such as drying gases like hydrogen chloride gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>42", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctWhich of the following statements is/are correct about electrochemical cells? I.Reduction occurs in one half-cell while oxidation occurs in the other II. The electrode in a half-cell may take part in the reaction. IIl Potential difference between two electrodes causes the flow of electric cument IV. Electrical energy is converted into chemical energy", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "e is correct.   I.Reduction occurs in one half-cell while oxidation occurs in the other II. The electrode in a half-cell may take part in the reaction. IIl Potential difference between two electrodes causes the flow of electric cument IV. Electrical energy is converted into chemical energy", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>43", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctWhich of the following compounds has/have the molecular formula C4H10? I. But-2-ene  Il Butanol III 2-methylpropane IV Butane", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "The molecular formula C4H10 corresponds to butane and 2-methylpropane. But-2-ene and butanol have different molecular formulas. Therefore, only III and IV are correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>44", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctIsotopes of a given element have the same I. atomic number. Il electronic configuration. IIl chemical properties IV mass number", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "D", "explanation": "Isotopes are distinct nuclear species (or nuclides, as technical term) of the same element. They have the same atomic number (number of protons in their nuclei) and position in the periodic table (and hence belong to the same chemical element), but differ in nucleon numbers (mass numbers) due to different numbers of neutrons in their nuclei.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>45", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctWhich of the following gases will bleach moist red litmus paper? I CI2 II. SO2 III. SO3 IV. HCI", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "These gases will bleach moist red litmus paper-b is correct", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>46", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctElements which dissolve in hot concentrated sodium hydroxide solution to give hydrogen include   I. aluminium. II zinc III. calcium. IV. iron.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "Aluminium and zinc react with hot concentrated sodium hydroxide solution to produce hydrogen gas. Calcium and iron do not react in the same way. Therefore, only I and II are correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>47", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctElectrolysis is applied in I. tinplating. II purification of copper. IIl extraction of aluminum. IV. manufacture of sodium hydroxide.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "Electrolysis involves using electricity to break down electrolytes to form elements. The products of electrolysis can be predicted for a given electrolyte. Electrolysis is used in electroplating, purifying metals and manufacturing sodium hydroxide from brine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>48", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctWhich of the following statements is/are correct about catalysts? They I. alter the rate of chemical reactions. II. are generally specific in action. III. remain unchanged chemically at the end of the reaction IV shift the equilibrium position in a reversible reaction", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "D", "explanation": "I. alter the rate of chemical reactions. II. are generally specific in action. III. remain unchanged chemically at the end of the reaction", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>49", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctAt a given temperature and pressure, gas A diffuses twice as fast as gas B. It follows that I. gas B is heavier than gas A. Il gas B. is four times as heavy as gas A. IIl gas B is monatomic. IV gas A is diatomic", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "A", "explanation": "gas A is diatomic. A diatomic gas consists of molecules made up of two atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1995>50", "subject": "Chemistry", "year": "1995", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correctIf the change in free energy (∆g) of a reaction is negative, it can be deduced that the reaction will I. not proceed in the direction indicated. Il. be reversible. Ill. not occur at room temperature: IV be feasible.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "A", "explanation": "If the change in free energy (∆g) of a reaction is negative, it can be deduced that the reaction will -IV be feasible", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>1", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.", "question": "The existance of two or more forms of the same element in the same physical state is known as", "images": [], "options": {"A": "allotropy", "B": "resonance", "C": "hybridization", "D": "isotopy"}, "answer": "A", "explanation": "Allotropy is the property of some chemical elements to exist in two or more different forms, in the same physical state, known as allotropes of these elements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>2", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Which of the following denotes an alpha particle?", "images": [], "options": {"A": "10n", "B": "42He", "C": "0-1e", "D": "94Be"}, "answer": "B", "explanation": "An alpha particle is denoted by 42He. An alpha particle is a type of ionizing radiation ejected by certain types of radioactive materials. It consists of two protons and two neutrons bound together into a particle identical to a helium-4 nucleus. It is a highly stable configuration of particles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1996>3", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "When an atom gains an electron, it becomes properties", "images": [], "options": {"A": "chemically inactive", "B": "negatively charged", "C": "oxidized", "D": "a cation"}, "answer": "B", "explanation": "When an atom gains an electron, it becomes negatively charged. This is because electrons are negatively charged particles. When an atom gains an electron, it has more electrons (negative charges) than protons (positive charges), thus it becomes negatively charged.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1996>4", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The alkali metals exhibit similar chemical properties because", "images": [], "options": {"A": "they occur in the combined state", "B": "they have the same number of valence electrons", "C": "they form crystalline salts", "D": "their salts are soluble in water"}, "answer": "B", "explanation": "The alkali metals exhibit similar chemical properties because they have the same number of valence electrons. In the periodic table, alkali metals belong to group 1 and they all have one electron in their outermost shell. This single electron in the outermost shell is responsible for their chemical properties as it is easily lost during chemical reactions, making alkali metals highly reactive.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1996>5", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "What is the likely formula of compound formed between element M in group two and element X in group seven?", "images": [], "options": {"A": "M7X2", "B": "M2X", "C": "M2X7", "D": "MX2"}, "answer": "D", "explanation": "The formula of a compound between any group 2 element, M, and any group 1 7 element, X, will be MX2. An example is calcium chloride CaC l2. M will lose two electrons to complete its octet. It will form M2+ ion. While X will gain an electron to form X- ion to complete its octet and then form an ionic bond with M.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>6", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Equal volumes of all gases at the same temperature and pressure contain the same number of molecules is an expression of", "images": [], "options": {"A": "Charles Law", "B": "Boyle's Law", "C": "Avogadro's Law", "D": "Graham's Law"}, "answer": "C", "explanation": "Avogadro's law states that \" equal volumes of all gases, at the same temperature and pressure, have the same number of molecules\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>7", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "The ideal gas equation can be written as", "images": [], "options": {"A": "V1/T1=V2/T2", "B": "P1V1=P2V2", "C": "V2=P1V1T1/P2T2", "D": "P1V1T2=P2V2T1"}, "answer": "D", "explanation": "The ideal gas equation is PV=nRT, where P is the pressure, V is the volume, n is the number of moles, R is the gas constant, and T is the temperature. If we consider two states of a gas, state 1 and state 2, we can write the equation for each state as P1V1=n1RT1 and P2V2=n2RT2. If the amount of gas and the gas constant are the same in both states, we can equate the two equations and get P1V1T2=P2V2T1, which is option 4.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1996>8", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume of carbon (lV) oxide is produced at s.t.p. when 2.5g of CaCO3 reacts with excess acid according to the following equation? CaCO3 + 2HCI → CaCI2 +H2O + CO2 [CaCO3 = 100; molar volume of a gas at s.t.p = 22.4dm3]", "images": [], "options": {"A": "11.20dm3", "B": "5.60dm3", "C": "2.24dm3", "D": "0.56dm3"}, "answer": "D", "explanation": "n = mass / molar mass    n(CaCO3) = 2.5g / 100g/mol = 0.025 mol    According to the balanced equation, one mole of CaCO3 produces one mole of CO2. Therefore, the number of moles of CO2 produced is also 0.025 mol.    Now, use the molar volume of a gas at s.t.p. (22.4 dm3 per mole) to calculate the volume of CO2 produced:  Volume = moles of CO2 × molar volume at s.t.p.  Volume = 0.025 mol × 22.4 dm3/mol = 0.56 dm3  0.56 dm3.    22.4 × 2.5 = 56  56÷100 = 0.56.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>9", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "Which of the following expressions gives the percentage by mass of nitrogen in NH4NO3?[H=1,N=14,O=16]", "images": [], "options": {"A": "14/48 x 100/1", "B": "14/80 x 100/1", "C": "28/80 x 100/1", "D": "14/100 x 80/1"}, "answer": "C", "explanation": "The formula for calculating the percentage by mass of an element in a compound is (mass of element/molar mass of compound) * 100. The molar mass of NH4NO3 is (1*4 + 14) + (14 + 16*3) = 80g/mol. The mass of nitrogen in NH4NO3 is 14g (from NH4) + 14g (from NO3) = 28g. Therefore, the percentage by mass of nitrogen in NH4NO3 is (28/80) * 100 = 35%.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1996>10", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "A solution of pH 7 is", "images": [], "options": {"A": "acidic", "B": "neutral", "C": "concentrated", "D": "dilute"}, "answer": "B", "explanation": "The pH scale measures how acidic or basic a substance is. It ranges from 0 to 14. A pH of 7 is neutral, which means it is neither acidic nor basic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1996>11", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Which of the following equations represents a neutralization reaction?", "images": [], "options": {"A": "CaCI2 + 2HCI →CI2 +CaCI2 + H2O", "B": "Na2O2 + H2SO4 → Na2SO4 + H2O2", "C": "H2SO4 + KOH → KHSO4 + H2O", "D": "2Na + 2H2O → 2NaOH + H2"}, "answer": "C", "explanation": "A neutralization reaction is a chemical reaction in which an acid and a base react quantitatively with each other. In a reaction in water, neutralization results in there being no excess of hydrogen or hydroxide ions present in the solution. The pH of the neutralized solution depends on the acid strength of the reactants. The third option, H2SO4 + KOH → KHSO4 + H2O, represents a neutralization reaction where sulfuric acid (H2SO4) reacts with potassium hydroxide (KOH) to form potassium hydrogen sulfate (KHSO4) and water (H2O).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>12", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Amphoteric oxides are oxides which", "images": [], "options": {"A": "react with water to form acids", "B": "react with water to form alkali", "C": "show neither acid nor basic properties", "D": "react with acids alkalis"}, "answer": "D", "explanation": "Amphoteric oxides are oxides that can react with both acids and bases to form salts and water. They show both acidic and basic properties. The fourth option, 'react with acids alkalis', is correct. However, it seems to be missing the word 'and' between 'acids' and 'alkalis'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>13", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The following acids are monobasic except", "images": [], "options": {"A": "trioxonitrate (V) acid", "B": "hydrochloric acid", "C": "ethanoic acid", "D": "tetraoxophosphorus (V) acid"}, "answer": "D", "explanation": "Monobasic acids are acids that produce one mole of hydrogen ions per mole of acid in aqueous solution. Trioxonitrate (V) acid, hydrochloric acid, and ethanoic acid are all monobasic acids because they each produce one mole of hydrogen ions per mole of acid in aqueous solution. However, tetraoxophosphorus (V) acid is not a monobasic acid. It is a tribasic acid because it can donate three protons per molecule, hence the correct answer is tetraoxophosphorus (V) acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>14", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "An arrangement of two different metals in aqueous solutions of their salts to produce an electronic current is known as", "images": [], "options": {"A": "electrochemical cell", "B": "activity series", "C": "thermocouple", "D": "voltameter"}, "answer": "A", "explanation": "An arrangement of two different metals in aqueous solutions of their salts to produce an electronic current is known as electrochemical cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>15", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "In which of the following compounds is the oxidation number of nitrogen equal to + 3?", "images": [], "options": {"A": "NO2", "B": "N2O", "C": "NO", "D": "HNO2"}, "answer": "D", "explanation": "The oxidation number of nitrogen in a compound is determined by the sum of the charges of all the atoms in the compound. In HNO2, the oxidation number of hydrogen is +1, oxygen is -2, and the sum of the charges is 0 (since it's a neutral compound). Therefore, the oxidation number of nitrogen is +3 to balance the charges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>16", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following statements is not correct about electrolysis?", "images": [], "options": {"A": "Reduction occurs at the anode", "B": "Anions migrate to the anode", "C": "Positive ions migrate to the cathode", "D": "Concentration affects the discharge of ions"}, "answer": "A", "explanation": "Reduction occurs at the cathode, not the anode. In electrolysis, anions migrate to the anode (positive electrode) where they are oxidized, and cations migrate to the cathode (negative electrode) where they are reduced. Therefore, the statement 'Reduction occurs at the anode' is incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>17", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following is not correct about a catalyst? It", "images": [], "options": {"A": "remains unchanged chemically at the end of a reaction", "B": "helps to establish equilibrium faster reversible reaction", "C": "can start a chemical reaction which will normally not take place", "D": "is usually specific in its action"}, "answer": "C", "explanation": "A catalyst is a substance that speeds up a chemical reaction, but is not consumed by the reaction; hence a catalyst will appear in the physical states. It does not have the ability to start a chemical reaction which will normally not take place. It only speeds up reactions that would have occurred anyway, but at a slower rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>18", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The rate of production of hydrogen gas from the reaction between zinc granules and hydrochloric acid can be increased by", "images": [], "options": {"A": "cooling the reaction mixture", "B": "using zinc powder instead of zinc granules", "C": "using zinc rod instead of zinc granules", "D": "carrying out the reaction at a higher pressure"}, "answer": "B", "explanation": "The rate of production of hydrogen gas from the reaction between zinc granules and hydrochloric acid can be increased by using zinc powder instead of zinc granules. This is because the rate of a chemical reaction depends on the surface area of the reactants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>19", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "What does X represent in the following equation? H2(g) + 1/2O2(g)→ H2O (l); ∆H = xKJ.", "images": [], "options": {"A": "Bond energy", "B": "Activation energy", "C": "Ionization energy", "D": "Enthalpy of formation"}, "answer": "D", "explanation": "In the given equation, X represents the change in enthalpy (∆H) of the reaction, which is the heat content of the products minus the heat content of the reactants. This is also known as the enthalpy of formation, which is the change in enthalpy when one mole of a substance in the standard state (1 atm of pressure and 298.15 K) is formed from its pure elements under the same conditions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1996>20", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which method of separation does the diagram illustrate?", "images": ["Chemistry/imgs/1996/separate.png"], "options": {"A": "Filtration", "B": "Evaporation", "C": "Sublimation", "D": "Magnetization"}, "answer": "C", "explanation": "Sublimation method. Sublimation is a phase transition in which a substance changes directly from a solid to a gas without passing through the liquid state. This method is commonly used to purify certain compounds and separate them from impurities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1996>21", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "If the third member of a homologous series is C3H8, the fifth member will be", "images": [], "options": {"A": "C5H8", "B": "C5H9", "C": "C5H10", "D": "C5H12"}, "answer": "D", "explanation": "If the third member of a homologous series is C3H8, the fifth member will be C5H12.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>22", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : BENZENE", "question": "Which of the following exhibits resonance?", "images": [], "options": {"A": "Benzene", "B": "Butane", "C": "Pentene", "D": "Octane"}, "answer": "A", "explanation": "Resonance is a concept in chemistry where a molecule or ion can be represented by more than one Lewis structure. Benzene is a classic example of a molecule that exhibits resonance. The benzene molecule is often depicted as a ring of six carbon atoms, with alternating single and double bonds, which actually do not exist as such but are a resonance hybrid of multiple forms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>23", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "On exposing palm wine to air for some days, it becomes sour owing to the conversion of", "images": [], "options": {"A": "glucose to ethanol", "B": "glucose to gluconic acid", "C": "ethanol to ethanoic acid", "D": "ethanol to ethanal"}, "answer": "C", "explanation": "When palm wine is exposed to air for some days, the ethanol in it gets oxidized to ethanoic acid, making the wine sour. This is due to the action of bacteria in the air that convert ethanol to ethanoic acid in the presence of oxygen. Therefore, the correct answer is 'ethanol to ethanoic acid'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>24", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "When acidified KMnO4 solution is decolorised by ethene, the gas acts as", "images": [], "options": {"A": "a straight-chain hydrocarbon", "B": "a saturated hydrocarbon", "C": "a reducing agent", "D": "a dehydrating agent"}, "answer": "C", "explanation": "Ethene, a hydrocarbon, acts as a reducing agent when it decolorises acidified KMnO4 solution. A reducing agent is a substance that loses or 'donates' electrons in a chemical reaction, thereby reducing another substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>25", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "What amount of hydrogen will be required for complete hydrogenation of one mole of pent-3-yne?", "images": [], "options": {"A": "1 mole", "B": "2 moles", "C": "3 moles", "D": "5 moles"}, "answer": "B", "explanation": "Pentane is 5 hydrogen molecule, the formula for finding the number of hydrogen required for hydrogenation   is the number of moles - the number of hydrogen atom in its homologous group     5-3=2.  Pent-3-yne=C5H8  C5H8 + H2 → C5H10(pentene)  C5H10 + H2 →  C5H12(pentane)  Two moles of H2 are required", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1996>26", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "When excess carbon (lV) oxide is passed into lime water, the turbidity produced initially disappears due to the formation of", "images": [], "options": {"A": "calcium oxide", "B": "calcium carbide", "C": "calcium hydrogentrioxocarbonate (IV)", "D": "trioxocarbonate (IV) acid"}, "answer": "C", "explanation": "When excess carbon (IV) oxide (CO2) is passed into lime water (Ca(OH)2), it initially forms calcium carbonate (CaCO3) which causes the turbidity. However, with excess CO2, the calcium carbonate reacts further to form calcium hydrogentrioxocarbonate (IV) (Ca(HCO3)2), which is soluble in water and hence the turbidity disappears.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>27", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Which of the following is a disaccharide?", "images": [], "options": {"A": "fructose", "B": "starch", "C": "cellulose", "D": "sucrose"}, "answer": "D", "explanation": "A disaccharide is a sugar (a carbohydrate) composed of two monosaccharides. Sucrose is a disaccharide made up of glucose and fructose. Therefore, the correct answer is sucrose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>28", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Use this following information to answer this question. Compound X was boiled with concentrated hydrochloric acid for a long time. One of the products was found to be a sugar. Compound X was probably", "images": [], "options": {"A": "rubber", "B": "polyethene", "C": "nylon", "D": "cellulose"}, "answer": "D", "explanation": "Cellulose is a complex carbohydrate, or polysaccharide, consisting of 3,000 or more glucose units. When boiled with concentrated hydrochloric acid, it breaks down into its monomer units, which are sugars. Therefore, the correct answer is cellulose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>29", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Use this following information to answer this question. Compound X was boiled with concentrated hydrochloric acid for a long time. One of the products was found to be a sugar. What type of reaction was involved between compound X and concentrated hydrochloric acid?", "images": [], "options": {"A": "Polymerization", "B": "Fermentation", "C": "Hydrolysis", "D": "Neutralization"}, "answer": "C", "explanation": "The reaction described in the question is a hydrolysis reaction. Hydrolysis is a type of reaction where water is used to break down a compound. In this case, the compound X (cellulose) is broken down into its monomer units (sugars) by the action of concentrated hydrochloric acid. Therefore, the correct answer is Hydrolysis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>30", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : OXYGEN", "question": "The component of air that can be removed by alkaline pyrogallol solution is", "images": [], "options": {"A": "oxygen", "B": "nitrogen", "C": "water vapour", "D": "carbon (IV) oxide"}, "answer": "A", "explanation": "A Oxygen is the component of air that can be removed by alkaline pyrogallol solution. Pyrogallol is a reducing agent that can react with oxygen to form water and carbon dioxide. In the presence of an alkali, such as potassium hydroxide, the reaction is accelerated, and oxygen can be rapidly and quantitatively removed from a gas mixture. This reaction is often used to determine the amount of oxygen in a sample of air or other gas mixture, and it is known as the \"pyrogallol method.\" The other components of air, such as nitrogen, water vapor, carbon dioxide, and noble gases, are not affected by this reaction and cannot be removed by pyrogallol solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>31", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "During water treatment for town supply, water is passed through layers of send beds in order to", "images": [], "options": {"A": "soften the water", "B": "filter the water", "C": "decolorize the water", "D": "destroy the germs in the water"}, "answer": "B", "explanation": "Filtration is the process of passing water through material such as a bed of coal, sand, or other granular substance to remove particulate impurities that were not removed during the sedimentation process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>32", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "The cleansing action of soap in hard water is not satisfactory because soap", "images": [], "options": {"A": "forms insoluble calcium and magnesium salts", "B": "is made from fats and oils", "C": "has an organic component", "D": "alters the surface tension of water"}, "answer": "A", "explanation": "The cleansing action of soap in hard water is not satisfactory because soap forms insoluble calcium and magnesium salts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>33", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What is the role of MnO(2) in the reaction represented by the following equation?MnO2 + 4HCI2 + CI2 + 2H2O", "images": [], "options": {"A": "Bleaching agent", "B": "Oxidizing agent", "C": "Amphoteric oxide", "D": "Basic oxide"}, "answer": "B", "explanation": "In the given reaction, MnO2 acts as an oxidizing agent. An oxidizing agent is a substance that has the ability to oxidize other substances, in other words, it accepts electrons from that substance. In this reaction, MnO2 is reduced to Mn2+ by gaining electrons, thus it oxidizes HCl to Cl2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>34", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : NITROGEN", "question": "Nitrogen is prepared on a large scale by the", "images": [], "options": {"A": "fractional distillation of liquefied air", "B": "decomposition of ammonium dioxonitrate (lll)", "C": "electrolysis of brine", "D": "Haber process"}, "answer": "A", "explanation": "Nitrogen is prepared on a large scale by the fractional distillation of liquefied air. Fractional distillation is a process of separation of a mixture into its component parts, or fractions, such as in separating chemical compounds by their boiling point by heating them to a temperature at which one or more fractions of the compound will vaporize. In this case, air is liquefied and then heated so that the different components vaporize at different temperatures, allowing them to be separated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>35", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Ammonia gas is suitable for performing the 'Fountain' experiment because the gas is", "images": [], "options": {"A": "colourless", "B": "a cooling agent", "C": "alkaline to litmus", "D": "very soluble in water"}, "answer": "D", "explanation": "This property of ammonia gas makes it suitable for the 'Fountain' experiment because when the container of ammonia gas is inverted over the container of water, the ammonia gas dissolves in the water, creating bubbles of gas that rise to the surface.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>36", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Which of the following metals will be the most suitable for use where lightness and resistance to corrosion are of importance?", "images": [], "options": {"A": "Lead", "B": "Copper", "C": "Iron", "D": "Aluminium"}, "answer": "D", "explanation": "Aluminum-magnesium alloys (AlMg) offer a good balance between lightness, resistance to corrosion, and mechanical strength.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>37", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "What amount of copper is deposited when 13.0g of zinc reacts with excess copper (ll) tetraoxosulphate (IV) solution according to the following equation? Zn(s) + CuSO4(aq) → ZnSO4(aq) + Cu(s) [Cu =63,5, Zn = 65]", "images": [], "options": {"A": "0.1 mole", "B": "0.2mole", "C": "0.3 mole", "D": "0.4 mole"}, "answer": "B", "explanation": "1 mole of zinc = 1 mole of copper  65 - 63.5  13g - x  Cross multiply  65x = 825.5  x = 12.7g  no of moles = reacting mass/molar mass  nom = 12.7/63.5  n = 0.2 moles", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1996>38", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "The products formed when sodium hydrogen trioxocarbonate (IV) is heated strongly are", "images": [], "options": {"A": "carbon (IV) oxide and sodium hydride", "B": "carbon (IV) oxide and soudium trioxocarbonate (IV)", "C": "sodium trioxocarbonate (IV) and steam", "D": "sodium trioxocarbonate (IV) carbon (IV) oxide and steam"}, "answer": "D", "explanation": "The products formed when sodium hydrogen trioxocarbonate (IV) is heated strongly are sodium trioxocarbonate (IV) carbon (IV) oxide and steam.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>39", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "The following are properties of transition metals except", "images": [], "options": {"A": "variable oxidation states", "B": "tendency to form complext ions", "C": "formation of coloured ions", "D": "low melting points"}, "answer": "D", "explanation": "Transition metals are known for their high melting points due to the strong metallic bonding caused by the delocalized 'sea' of electrons. Therefore, the statement 'low melting points' is not a property of transition metals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>40", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE REACTIONS", "question": "The following salts will produce a gas on reacting with hydrochloric acid except", "images": [], "options": {"A": "CuSO4", "B": "CaCO3", "C": "FeS", "D": "Na2SO3"}, "answer": "A", "explanation": "Copper sulfate (CuSO4) does not react with hydrochloric acid to produce a gas. The other salts listed (calcium carbonate, iron sulfide, and sodium sulfite) all react with hydrochloric acid to produce a gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>41", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STATES OF MATTER : LABORATORY PREPARATION AND PROPERTIES OF SOME GASES.", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct    The method of collection of gas depends on its I. bolling point II. Odour III. Density IV Solubility", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "The method of collection of gas depends on its-c is correct", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>42", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct In which of the following are radioactive isotopes used? I. Scientific research. II. Sterilization III. Dating techniques IV Treatment of cancer", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "e is correct- I. Scientific research. II. Sterilization III. Dating techniques IV Treatment of cancer", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>43", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct Which of the following is/are manufactured by the electrolysis of concentrated sodium chloride solution? I. Chlorine II. Sodium hydroxide Ill Hydrogen IV Sodium oxochlorate (I)", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "D", "explanation": "The electrolysis of concentrated sodium chloride solution produces Chlorine, Sodium hydroxide, and Hydrogen. I. Chlorine - Chlorine is produced at the anode during the electrolysis. II. Sodium hydroxide - Sodium hydroxide is produced in the solution during the electrolysis. III. Hydrogen - Hydrogen is produced at the cathode during the electrolysis. IV. Sodium oxochlorate (I) - This is not produced during the electrolysis of concentrated sodium chloride solution. Hence, the correct option is D which includes I, II, and III.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>44", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct Which of the following metals will produce hydrogen on reacting with dilute hydrochloric acid? I. Zn II. Mg III. Fe IV. Al", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "e is correct. Iron and magnesium will liberate hydrogen gas when reacting with dilute hydrochloric acid where is copper will not. this is because according to the reactivity series of metals iron and magnesium are more reactive than hydrogen where is copper is less reactive and hence iron and magnesium liberate hydrogen gas easily but copper will not.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1996>45", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct The major air pollutants that can result from smoky vehicles include I. acid fumes II. hydrogen sulphide. III. carbon (II) oxide. IV carbon particles", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "The major air pollutants that can result from smoky vehicles include -c is correct", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>46", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct Which of the following reactions at equilibrium will be affected by an increase in pressure? I. N2(g) + 3H2(g) → 2NH3(g) II. 2SO2(g) + O2(g) 2NH3(g) III. N2(g) + O2(g) 2NO(g) IV. CO4(g) + H2O(g)  CO2(g) + H2(g)", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "At equilibrium (b is correct) will be affected by an increase in pressure b is correct", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1996>47", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct Which of the following methods is/are used for the extraction of the alkali metals? I. Reduction by the use of carbon II. Roasting of the ore in air III. Thermal reduction IV Reduction by electolysis", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "A", "explanation": "Alkali metals are highly reactive and cannot be extracted by simple methods like reduction with carbon or roasting in air. They are typically extracted by electrolysis, a process that uses an electric current to drive a non-spontaneous chemical reaction. Therefore, only option IV is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1996>48", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct Which of the following can be deduced from the equation below? XY(aq) + PQ(aq) →XQ(s) + PY(aq) ∆H= -65.700J I. The heat content of the reactants is higher than that of the products. II. The reaction involves double decomposition III. The reaction is slow IV. A large amount of heat is absorbed", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "From the given equation, we can deduce that the reaction involves double decomposition because two compounds (XY and PQ) are reacting to form two new compounds (XQ and PY). This is the definition of a double decomposition reaction. Also, the heat content of the reactants is higher than that of the products because the reaction is exothermic, meaning heat is released during the reaction. Therefore, options I and II are correct. The speed of the reaction and the amount of heat absorbed cannot be determined from the equation, so options III and IV are incorrect.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1996>49", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct Hydrocarbons which exhibit structural isomerism include I. C6H6 II. C3H6 III. C4H8  IV.C5H12", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "c is correct. Structural isomerism refers to a type of isomerism in which compounds have the same molecular formula but differ in the connectivity of their atoms. This results in different chemical structures, and consequently, they often have different physical and chemical properties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1996>50", "subject": "Chemistry", "year": "1996", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct Avogadro number can be defined as the number of I. molecules in 22.4dm3 of a gas at stp. Il Molecules in one mole of a compound. III. Electrons in 96500 coulombs of electricity IV Electrons in the outermost shell of an atom.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "Avogadro's number (6.022 x 10^23) is defined as the number of molecules in one mole of a compound and the number of molecules in 22.4dm^3 of a gas at standard temperature and pressure (STP). Therefore, options I and II are correct. Option III is incorrect because Avogadro's number is not related to the number of electrons in 96500 coulombs of electricity. Option IV is also incorrect because Avogadro's number does not define the number of electrons in the outermost shell of an atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>1", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STATES OF MATTER : KINETIC THEORY OF MATTER.", "question": "The phenomenon observed when dust particles collide randomly in a beam of sunlight is known as?", "images": [], "options": {"A": "Tyndal effect", "B": "diffusion", "C": "osmosis", "D": "brownian movement"}, "answer": "D", "explanation": "The phenomenon observed when dust particles collide randomly in a beam of sunlight is known as Brownian movement. This is a random motion of particles suspended in a fluid (a liquid or a gas) resulting from their collision with the fast atoms or molecules in the gas or liquid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>2", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The mass number of an element is the sum of its", "images": [], "options": {"A": "electrons, neutrons and protons", "B": "electrons and protons", "C": "protons and neutrons", "D": "orbital electrons"}, "answer": "C", "explanation": "The mass number of an element is the sum of its protons and neutrons. This is because protons and neutrons are the particles that contribute to the mass of an atom, while electrons are so light that they don't significantly contribute to the mass.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>3", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "How many unpaired electrons are there in an atom of an element with the following electronic configuration? 1s22s22p6", "images": [], "options": {"A": "0", "B": "1", "C": "2", "D": "6"}, "answer": "A", "explanation": "The electronic configuration 1s22s22p6 indicates that all the electrons are paired. Unpaired electrons are those that occupy an orbital alone. In this configuration, all orbitals are fully occupied, hence there are no unpaired electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>4", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "Radon is used as a tracer in medical research because it", "images": [], "options": {"A": "is monatomic", "B": "is radioactive", "C": "is a noble gas", "D": "has a complete valence shell"}, "answer": "B", "explanation": "Radon is used as a tracer in medical research because it is radioactive. Being radioactive means it emits radiation, which can be detected and measured. This makes it useful in tracing the movement of substances in a system, such as the human body.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>5", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "What is the most probable group of an element which is a soft, silvery white solid and reacts violently with water?", "images": [], "options": {"A": "Group 0", "B": "Group 1", "C": "Group 4", "D": "Group 6"}, "answer": "B", "explanation": "The element described in the question is a soft, silvery white solid and reacts violently with water. These are characteristics of alkali metals, which are found in Group 1 of the periodic table. Therefore, the most probable group of the element is Group 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>6", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "In linear molecules, the bond angle is", "images": [], "options": {"A": "90o", "B": "140o", "C": "109o", "D": "180o"}, "answer": "D", "explanation": "In linear molecules, the bond angle is 180 degrees. The bond angle is the angle formed between three atoms across at least two bonds. For linear molecules, such as carbon dioxide, the atoms are arranged in a straight line, hence the bond angle is 180 degrees.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>7", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "A sodium atom and a sodium ion have the same", "images": [], "options": {"A": "number of neutrons", "B": "number of electrons", "C": "electric charge", "D": "electronic structure"}, "answer": "A", "explanation": "A sodium atom and sodium ion, both have the same nucleus (same number of protons and neutrons). The only difference is that the ion has one less electron than the atom.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>8", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL SYMBOLS", "question": "If the atomic number of an element X is 11 and that of nitrogen is 7, the most likely formula of the nitride of X is", "images": [], "options": {"A": "X3N", "B": "XN3", "C": "X3N2", "D": "N2X"}, "answer": "A", "explanation": "The one with atomic number 11 has its breakdown as 2,8,1 while Nitrogen with atomic number 7 has its breakdown as 2,5. swap the remaining 3 with the first element with atomic number 11 and the 1 with nitrogen making it X3N", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>9", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "An increase in the pressure of a gas results in a decrease in its", "images": [], "options": {"A": "mass", "B": "vapour density", "C": "volume", "D": "temperature"}, "answer": "C", "explanation": "According to Boyle's law, at constant temperature, the volume of a given mass of a gas is inversely proportional to its pressure. This means that if the pressure of a gas increases, its volume decreases, assuming the temperature remains constant. Therefore, an increase in the pressure of a gas results in a decrease in its volume.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>10", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "A given volume of methane diffuses in 20 seconds. How long will it take the same volume of sulphur (IV) oxide to diffuse under the same conditions? [CH4 = 16; SO2 = 64]", "images": [], "options": {"A": "5 seconds", "B": "20 seconds", "C": "40 seconds", "D": "60 seconds"}, "answer": "C", "explanation": "Since the distance and pressure are the same for both gases, the time taken for SO2 to diffuse the same volume as methane would be twice that of methane. Therefore, the time taken for the same volume of SO2 to diffuse under the same conditions as methane would be 2 x 20 = 40 seconds.   or  Relative molecular mass of CH4 = 12 * 1 + 4 = 16  Relative molecular mass of SO2 = 32 + 10 * 2 = 64  tSO2/tCH4 = √MSO2/MCH4  t/20 = √64/16 = √4  t/20 = 2  t = 20 * 2 = 40sec", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>11", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "An acid is a substance which in the presence of water produces", "images": [], "options": {"A": "salts", "B": "oxygen", "C": "effervescence", "D": "hydroxonium ions"}, "answer": "D", "explanation": "An acid is a substance that, when dissolved in water, increases the concentration of hydrogen ions (H+), or more accurately, hydronium ions (H3O+). This is due to the ionization of the acid in water where it donates a proton (H+) to water to form a hydronium ion. Therefore, the correct answer is 'hydroxonium ions'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>12", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following is a general method of preparing acids?", "images": [], "options": {"A": "Direct combination of constituent elements", "B": "Double decomposition involving a salt solution", "C": "Reaction between an anhydride and water", "D": "Reaction between a base and an amphoteric oxide"}, "answer": "C", "explanation": "Acids can be prepared by the reaction of an anhydride with water. An anhydride is a compound that forms an acid or base by adding water. This is a general method of preparing acids. Therefore, the correct answer is 'Reaction between an anhydride and water'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>13", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "The loss of molecules of water of crystallization to the atmosphere by some crystalline salts is known as", "images": [], "options": {"A": "efflorescence", "B": "effervescence", "C": "phosphorescence", "D": "fluorescence"}, "answer": "A", "explanation": "Efflorescence is the process in which water molecules in a hydrated or water-containing crystal are lost to the atmosphere. The water is initially contained in the crystal structure of the salt, but when the salt is exposed to air, the water evaporates, leaving behind a powdery residue on the surface of the crystal. This is different from effervescence, which is the escape of gas from an aqueous solution, and phosphorescence and fluorescence, which are types of luminescence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>14", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following ions will migrate to the cathode during electrolysis?", "images": [], "options": {"A": "Zinc ions", "B": "Chloride ions", "C": "Sulphide ions", "D": "Tetraoxosulphate (Vl) ions"}, "answer": "A", "explanation": "Electrodes in electrolysis process are cathode and anode. The cathode is a - ve electrode i.e., it is connected to negative terminal of battery and Anode is +ve terminal. Since opposite charges attract each other, cations migrate towards the cathode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>15", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What quantity of electrons (in mole) is lost when one mole of iron (ll) ions is oxidized to iron (lll) ions?", "images": [], "options": {"A": "5 mole", "B": "4 mole", "C": "3 mole", "D": "1 mole"}, "answer": "D", "explanation": "The oxidation of iron (II) ions to iron (III) ions involves the loss of one electron per ion. Therefore, when one mole of iron (II) ions is oxidized to iron (III) ions, one mole of electrons is lost. This is because the charge on an ion corresponds to the number of electrons it has lost or gained. In this case, iron (II) has a charge of +2, meaning it has lost two electrons, and iron (III) has a charge of +3, meaning it has lost three electrons. The difference between these two charges is one, indicating that one electron is lost in the oxidation of iron (II) to iron (III).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>16", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The common feature of reactions at the anode is that", "images": [], "options": {"A": "electrons are consumed", "B": "oxidation is involved", "C": "ions are reduced", "D": "the electrode dissolves"}, "answer": "B", "explanation": "In the most basic form, an anode in electrochemistry is the point where an oxidation reaction occurs. Generally, at an anode, negative ions or anions due to its electrical potential tend to react and give off electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>17", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "From the following equations, what is the order of decreasing reactivity of X, Y and Z? Y(s) + X2+(aq) → Y2+(aq) + X(s), X(s) + Z2+(aq) → X2+(aq) + Z(s)", "images": [], "options": {"A": "X>Y>Z", "B": "Y > X > Z", "C": "Z > Y > X", "D": "Y > Z > X"}, "answer": "B", "explanation": "Y is displacing x so Y is > X. X is displacing Z from compound so X>Z", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1997>18", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "What is the value of x in the following equation? MnO- 4 + 4H+ + xe- → MnO2 + 2H2O", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "7"}, "answer": "B", "explanation": "-1 + 4 + x= 0  x+3=0  x=-3  The value of x in the following equation is -3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1997>19", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "If the value of ∆H for a reaction is negative, it means that the reaction is", "images": [], "options": {"A": "slow", "B": "exothermic", "C": "spontaneous", "D": "irreversible"}, "answer": "B", "explanation": "If the value of ∆H for a reaction is negative, it means that the reaction is exothermic. An exothermic reaction is a \"reaction for which the overall standard enthalpy change ΔH is negative. Exothermic reactions usually release heat.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1997>20", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "How much heat will be liberated if 8g of hydrogen burns in excess oxygen according to the following equation? 2H2 + O2→ 2H2O,∆H = -571.7KJ (H = 1)", "images": [], "options": {"A": "1.42.9KJ", "B": "571.7KJ", "C": "1143.4KJ", "D": "285.9KJ"}, "answer": "C", "explanation": "2 moles of H2 that is reacting with O2 to produce steam and liberate 571.7kj of energy.  The 2 moles of H2= 2×(1×2) = 4g.  So if 4g of H2 = 571.7kJ  Then 8g if H2= X.  Cross multiply  X = (571.7×8)÷4  X= 1143.4kj", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1997>21", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "The position of equilibrium in a reversible reaction is affected by", "images": [], "options": {"A": "particle size of the reactants", "B": "change in concentration of the reactants", "C": "change in size of the reaction vessel", "D": "vigorous stirring of the reaction mixture"}, "answer": "B", "explanation": "The position of equilibrium in a reversible reaction is affected by change in concentration of the reactants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>22", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Separation of mixture of solids by physical methods can be based on differences in the following except", "images": [], "options": {"A": "melting point", "B": "solubility", "C": "particle size", "D": "molar mass"}, "answer": "D", "explanation": "Separation of a mixture of solids by physical methods can be based on differences in melting point, solubility, and particle size. However, molar mass is not a physical property that can be used for the separation of a mixture of solids. Molar mass is a chemical property that refers to the mass of one mole of a substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>23", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Ethene undergoes mainly addition reactions because it is", "images": [], "options": {"A": "a gas", "B": "a hydrocarbon", "C": "unsaturated", "D": "easily polymerized"}, "answer": "C", "explanation": "Reactions in which the molecules of a reagent add themselves across the double or triple bonds of an unsaturated compound are known as addition reactions. The presence of double bonds makes the molecule reactive. Because ethene contains a double bond, it undergoes addition reactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>24", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "The reaction between alkanoic acids and alkanols in the presence of a mineral acid is known as", "images": [], "options": {"A": "saponification", "B": "hydrolysis", "C": "polymerization", "D": "esterification"}, "answer": "D", "explanation": "Esterification is the process of combining an organic acid (RCOOH) with an alcohol (ROH) to form an ester (RCOOR)and water; or a chemical reaction resulting in the formation of at least one ester product. Ester is obtained by an esterification reaction of an alcohol and a carboxylic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>25", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following is a secondary alkanol?", "images": [], "options": {"A": "CH3(CH2)2OH", "B": "CH3CH==CHCH2OH", "C": "CH3(CH2)3OH", "D": "CH3CH(OH)CH3"}, "answer": "D", "explanation": "A secondary alkanol is an alcohol where the carbon atom of the hydroxyl group (OH) is attached to two other carbon atoms. In the given options, only CH3CH(OH)CH3 fits this description. The hydroxyl group is attached to the middle carbon atom, which is also attached to two other carbon atoms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>26", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "An elimination reaction occurs when bromoethane is converted to", "images": [], "options": {"A": "1,2-dibromoethane", "B": "ethanol", "C": "ethene", "D": "ethyl ethanoate"}, "answer": "C", "explanation": "An elimination reaction is a type of organic reaction in which two substituents are removed from a molecule in either a one or two-step mechanism. In the case of bromoethane, an elimination reaction would remove a hydrogen atom and a bromine atom, resulting in the formation of a double bond and producing ethene.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>27", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "The ash used for making black soap locally, provides", "images": [], "options": {"A": "glycerol", "B": "sodium-chloride", "C": "potassium ions", "D": "stearic acid."}, "answer": "C", "explanation": "Wood ash is an important source of potassium hydroxide, which is commonly known as caustic potash. Caustic potash is used in the production of soft soaps.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>28", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "Which of the following is the relative molecular mass of a compound which has empirical formula CH2O? (H = 1; C = 12; O = 16)", "images": [], "options": {"A": "42", "B": "45", "C": "126", "D": "180"}, "answer": "D", "explanation": "Empirical formula = CH2O    = 12 + (2 x 1) + 16    = 30    Molecular formula = (CH2O)n  , where n is a whole number.    = 30n  therefore,   From the options, only 180 is a multiple of 30. Hence, that is the only likely molecular mass with respect to CH2O.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>29", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The by-product of the fermentation of sugar to ethanol is", "images": [], "options": {"A": "propane -1,2,3-triol", "B": "ethyl ethanoate", "C": "ethanedioc acid", "D": "carbon (lV) oxide"}, "answer": "D", "explanation": "The by-product of the fermentation of sugar to ethanol is carbon (IV) oxide, also known as carbon dioxide. This is a common process in brewing and winemaking, where yeast ferments the sugars in the grapes or grains, producing ethanol and carbon dioxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>30", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Alkanes react with the halogens mainly by", "images": [], "options": {"A": "oxidation", "B": "polymerization", "C": "addition", "D": "substitution"}, "answer": "D", "explanation": "Alkanes react with halogens mainly by substitution. This is because alkanes are saturated hydrocarbons, meaning they have single bonds between all their carbon atoms. This makes them relatively unreactive, so they don't readily undergo addition or polymerization reactions. However, under certain conditions (like the presence of UV light), a halogen can replace a hydrogen atom in an alkane, which is a substitution reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>31", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following is used widely in the manufacture of flavours and perfumes?", "images": [], "options": {"A": "Alkanoates", "B": "Alkanones", "C": "Alkanes", "D": "Complex sugars"}, "answer": "A", "explanation": "Alkanoates, also known as carboxylic acids, are widely used in the manufacture of flavours and perfumes. They have a wide range of smells and tastes, which makes them suitable for this purpose. The other options, Alkanones, Alkanes, and Complex sugars, are not typically used in the manufacture of flavours and perfumes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>32", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "The use of diamond in abrasives is due to its", "images": [], "options": {"A": "high melting point", "B": "durability", "C": "lustre", "D": "hardness"}, "answer": "D", "explanation": "Diamond is useful as an abrasive because of its hardness. It is the hardest naturally occurring mineral", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>33", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.", "question": "Which of the substance lettered P to V in the equation below would be left on the filter paper if the reaction mixture were filtered? P(aq) + Q(aq) → V(s) + R_(aq) + T(g)", "images": [], "options": {"A": "P", "B": "Q", "C": "V", "D": "T"}, "answer": "C", "explanation": "it is a solid substance that will be left as a residue in the filter paper. When the reaction mixture is filtered, the solid particles are trapped by the filter paper while the liquid and gaseous components pass through. In this case, the solid substance is V (s). Therefore, the substance left on the filter paper would be V.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>34", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "When chlorine is added to slaked lime, the product obtained is", "images": [], "options": {"A": "bleaching powder", "B": "chlorinated water", "C": "hydrochloric acid", "D": "oxochlorate (l) acid"}, "answer": "A", "explanation": "The reaction of chlorine with dry slaked lime produces bleaching powder, which is calcium oxychloride.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>35", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF SODIUM AND ITS COMPOUNDS.", "question": "Which of the following when heated strongly in air will leave a metal as residue?", "images": [], "options": {"A": "Sodium trioxonitrate (V)", "B": "Potassium trioxonitrate (V)", "C": "Silver trioxonitrate (V)", "D": "Lead (ll) trrioxonitrate(V)"}, "answer": "C", "explanation": "Silver trioxonitrate (V) when heated strongly in air will leave a metal as residue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>36", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following is used as water softener?", "images": [], "options": {"A": "Na2CO3.10H2O", "B": "CuSO4. 5H2O", "C": "MgSO4. 7H2O", "D": "CaCI2.2H2O"}, "answer": "A", "explanation": "Sodium carbonate decahydrate (Na2CO3.10H2O), also known as washing soda or soda ash, is used as a water softener. It does this by precipitating the calcium and magnesium ions present in hard water. The other options are not typically used as water softeners.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>37", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The following oxides react with both acids and bases to form salts except", "images": [], "options": {"A": "zinc oxide", "B": "lead (ll) oxide", "C": "aluminium oxide", "D": "carbon (IV) oxide"}, "answer": "D", "explanation": "Carbon (IV) oxide, also known as carbon dioxide, does not react with both acids and bases to form salts. It can react with water to form carbonic acid, but it does not react with bases to form salts. The other oxides listed (zinc oxide, lead (II) oxide, and aluminium oxide) are amphoteric oxides, meaning they can react with both acids and bases to form salts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>38", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following metals is not extracted by electrolysis ?", "images": [], "options": {"A": "lron", "B": "Sodium", "C": "Calcium", "D": "Magnesium"}, "answer": "A", "explanation": "Iron is not typically extracted by electrolysis. Instead, it is usually extracted from its ores (like hematite) using a blast furnace in a process known as smelting. The other metals listed (sodium, calcium, and magnesium) are typically extracted from their ores using electrolysis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>39", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following is an ore of aluminium?", "images": [], "options": {"A": "Haematite", "B": "Magnetite", "C": "Siderite", "D": "Bauxite"}, "answer": "D", "explanation": "Bauxite is an ore of aluminium. It is the world's main source of aluminium. The other options listed (haematite, magnetite, and siderite) are ores of iron, not aluminium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>40", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Lead and tin are the components of", "images": [], "options": {"A": "steel", "B": "bronze", "C": "brass", "D": "soft solder"}, "answer": "D", "explanation": "Lead and tin are the components of soft solder. Soft solder is a type of solder that has a lower melting point than the more-common hard solder. It is commonly used in applications like electronics and jewelry making.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1997>41", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct    Factors which can contribute to environmental pollution include I. overpopulation II. chemical warfare III. agricultural activities IV. Industrialization", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "Factors which can contribute to environmental pollution include (e is correct)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>42", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Which of the following solids is/are expected to have a relatively high melting point on the basis of the structure? I. Calcium oxide II. Sodium chloride III. Sulphur IV. lodine.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "Calcium oxide and Sodium chloride are expected to have a relatively high melting point on the basis of the structure. This is because they are ionic compounds, and ionic compounds generally have high melting points due to the strong electrostatic forces of attraction between the positive and negative ions. On the other hand, Sulphur and Iodine are covalent molecular substances, which have relatively low melting points because the forces between molecules (intermolecular forces) are generally weaker than the ionic or covalent bonds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>43", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : AMINO ACIDS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  The functional group (s) present in amino acids is/are  I. -CONH2 II. -CHO III.-NH2 IV. COOH", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "Amino acids are natural compounds composed of amine (-NH2) and carboxylic acid (-COOH) functional groups, linked to the same carbon atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>44", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Which of the following pairs of compounds are isomers? I. Butane and 2-methylpropane Il. Glucose and fructose III. Ethanol and methanol IV. But-1-ene and but-2-yne", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "Isomers are compounds with the same molecular formula but different structural formulas. Butane and 2-methylpropane are isomers (both have the formula C4H10 but different structures). Glucose and fructose are also isomers (both have the formula C6H12O6 but different structures). Ethanol and methanol, and But-1-ene and but-2-yne are not isomers as they have different molecular formulas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>45", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Which of the following statements is/are correct about the average kinetic energy of the molecules of a gas? I. Remains constant at constant temperature II. Decreases with a fall in temperature III. Increases with a decrease in volume IV. Increases with an increase in pressure", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "B", "explanation": "The average kinetic energy of the molecules of a gas is directly proportional to the temperature of the gas. Therefore, it remains constant at constant temperature (option I) and decreases with a fall in temperature (option II). The average kinetic energy of a gas does not depend on the volume or pressure of the gas, so options III and IV are not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>46", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Scientists whose experiments gave evidence about the nature and structure of the atom include I. JJ Thompson II. Lord Rutherford III. Le Chatelier IV. Robert Boyle", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "J.J. Thomson and Lord Rutherford were indeed scientists whose experiments gave evidence about the nature and structure of the atom. J.J. Thomson is known for his discovery of the electron and his 'plum pudding' model of the atom, while Lord Rutherford is known for his gold foil experiment which led to the discovery of the atomic nucleus. However, Le Chatelier is known for Le Chatelier's principle in chemical equilibrium, not atomic structure. Robert Boyle is considered one of the founders of modern chemistry, but his work didn't directly involve the structure of the atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>47", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  2p and 3p orbitals have the same I. principal quantum number II. energy III. Maximum number of electrons. IV. Shape", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "2p and 3p orbitals have the same maximum number of electrons (6 electrons) and the same shape (dumbbell shape). However, they do not have the same principal quantum number (the principal quantum number of 2p is 2 and that of 3p is 3) and they do not have the same energy (3p has higher energy than 2p because it is further from the nucleus).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>48", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Which of the following statements is/are correct about metals? I. They are good conductors of electricity. II. have mobile electrons III. are reducing agents IV. form acidic oxides", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "D", "explanation": "Metals are indeed good conductors of electricity due to their mobile electrons, which is why I II and III are correct. They are also reducing agents because they can donate electrons to other substances in a chemical reaction. However, metals generally form basic oxides, not acidic ones. Therefore, IV is incorrect. The correct answer is D, which corresponds to only I, II and III being correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>49", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Stages in the extraction of tin from tinstone include I. washing with water. II. crushing the ore III. smelting the ore. IV. Electrolytic purification", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "The extraction of tin from tinstone involves all the stages listed: washing with water to remove impurities, crushing the ore to increase the surface area for further chemical reactions, smelting the ore to extract the metal, and electrolytic purification to further refine the metal. Therefore, all I, II, III, and IV are correct. The correct answer is E, which corresponds to all options being correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1997>50", "subject": "Chemistry", "year": "1997", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  In which of the processes represented by the following equations will the rate be affected by the surface area of the starting materials?   I. Zn(s) + H2SO4(aq) → ZnSO4(aq) + H2(g) NaCl(aq)  II. NaCl(s) + H2O →  NaCl(aq)  III. NaOH(aq) + HCl(aq) → NaCl(aq) + H2O(l)  IV. Ca(OH)2(aq) + CO2(g) → CaCO3(s) + H2(l)", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "The rate of a chemical reaction can be affected by the surface area of the starting materials. In the given equations, I and II involve solid reactants (Zn and NaCl respectively) that can be affected by surface area. III and IV involve only aqueous or gaseous reactants, which are not affected by surface area. Therefore, the correct answer is B, which corresponds to only I and II being correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>1", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "An atom with 17 protons, 17 electrons and 18 neutrons has a mass number of", "images": [], "options": {"A": "17", "B": "18", "C": "34", "D": "35"}, "answer": "D", "explanation": "A particle X has :- 17 protons 17 electrons 18 neutrons. Mass number is nothing but the sum of number of electrons or protons and number of neutrons. So, Mass number = 17 + 18 = 35 a.m.u. Atomic number is the number of protons or electrons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>2", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "If an element R belongs to the same group as sodium, an aqueous solution of ROH will", "images": [], "options": {"A": "be neutral", "B": "be acidic", "C": "be coloured", "D": "have pH greater than 7"}, "answer": "D", "explanation": "If an element R belongs to the same group as sodium, an aqueous solution of ROH will have pH greater than 7.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>3", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Element X, with electronic configuration 2,8,2 and element Y with electronic configuration 2,8,7 are likely to combine by", "images": [], "options": {"A": "metallic bonding", "B": "covalent bonding", "C": "electrovalent bonding", "D": "dative bonding"}, "answer": "C", "explanation": "Electrovalent bonding arises from complete transfer of one or more electrons from one atom to another.  -An Ionic bond is the bond formed by the complete transfer of valence electron to attain stability  -his type of bonding leads to the formation of two oppositely charged ion", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>4", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "The valence electrons of the element 12Mg are in the", "images": [], "options": {"A": "1s orbital", "B": "2s orbital", "C": "2px orbital", "D": "3s orbital"}, "answer": "D", "explanation": "The element with atomic number 12 is Magnesium (Mg). The electron configuration of Magnesium is 1s2 2s2 2p6 3s2. The valence electrons (the outermost electrons) are in the 3s orbital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>5", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "What is element Y in the following equation? 147N + 42He → 11H + Y", "images": [], "options": {"A": "Fluorine", "B": "Sodium", "C": "Chlorine", "D": "Oxygen"}, "answer": "D", "explanation": "The element Y in the equation is determined by balancing the atomic numbers and mass numbers on both sides of the equation. The atomic number of Y is 7 (14 - 4 - 1 - 2) and the mass number is 17 (14 - 4 - 1). The element with atomic number 8 and mass number 17 is Oxygen.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1998>6", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following Group 1 elements has the highest ionization energy?", "images": [], "options": {"A": "55CS", "B": "37RD", "C": "19K", "D": "3Li"}, "answer": "D", "explanation": "Ionization energy is the energy required to remove an electron from an atom or ion. It generally increases across a period (from left to right) and decreases down a group (from top to bottom) on the periodic table. Therefore, among the Group 1 elements listed, Lithium (3Li) has the highest ionization energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>7", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Which of the following statements is correct about sodium chloride in the solid state?", "images": [], "options": {"A": "It exists as aggregrates of ions.", "B": "It conducts electricity.", "C": "Its melting point is below 100oC", "D": "It exists as discrete molecules"}, "answer": "A", "explanation": "Ionic compounds contain ions and are held together by ionic bond, the attractive forces among the oppositely charged ions. sodium chloride does not exist as molecules but aggregates of oppositely charged ions", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>8", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "Boyle's law can be expressed mathematically as", "images": [], "options": {"A": "V α 1/P(T constant)", "B": "V1/T1=V2/T2", "C": "V α T(P constant)", "D": "P α V(T constant)"}, "answer": "A", "explanation": "Boyle's law can be expressed mathematically as V α 1/P(T constant). Boyle's law is a gas law which states that the pressure exerted by a gas (of a given mass, kept at a constant temperature) is inversely proportional to the volume occupied by it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>9", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume of oxygen at s.t.p. would react with carbon to form 4.40g of CO2 according to the following equation? C(s) + O2(g) → CO2(g) [O=16; C=12 1 mole of a gas occupies 22.4dm3 at s.t.p.]", "images": [], "options": {"A": "0.224dm3", "B": "2.24dm3", "C": "4.40dm3", "D": "4.48dm3"}, "answer": "B", "explanation": "From the equation, C + O2 → CO2 : 22.4dm3 of oxygen is required to form 44g of CO2 the volume of O2 required to produce 4.4gm is x, :. x = 4.4/44 X 22.4dm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1998>10", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "A mixture of NaCI and CaCO3(s) is best separated by", "images": [], "options": {"A": "dissolution followed by filtration", "B": "sublimation followed by crystallization", "C": "dissolution followed by evaporation", "D": "dissolution followed by crystallization"}, "answer": "A", "explanation": "A mixture of NaCI and CaCO3(s) is best separated by dissolution followed by filtration. Dissolution: When the mixture is dissolved in water, NaCl, which is highly soluble, will dissolve completely, forming a homogeneous solution. On the other hand, CaCO3 is sparingly soluble in water, and most of it will remain undissolved in the form of solid particles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>11", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "What is the basicity of the acid in the following reaction? Na2CO3 + 2CH3COOH → 2CH3 COONa + H2O + CO2", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": "A", "explanation": "The basicity of an acid is the number of replaceable hydrogen ion in on mole of the acid whereas carboxylic acid CH3COOH has 4 hydrogen ions only one of them is replaceable therefore giving it a basicity of one", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>12", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "An aqueous solution is acidic if", "images": [], "options": {"A": "its pH value is high", "B": "it s corrosive", "C": "it changes the colour of litmus", "D": "it contains more H3O+ than OH-"}, "answer": "D", "explanation": "An aqueous solution is acidic if it contains more hydronium ions (H3O+) than hydroxide ions (OH-). This is because the presence of more H3O+ ions increases the acidity of the solution. The pH scale is used to measure the acidity or basicity of a solution, with lower pH values indicating higher acidity. However, the options 'its pH value is high' and 'it changes the colour of litmus' are not specific enough to be correct, and 'it's corrosive' is not necessarily true for all acidic solutions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>13", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The following oxides react with water except", "images": [], "options": {"A": "Na2O", "B": "SO3", "C": "NO2", "D": "CuO"}, "answer": "D", "explanation": "The following oxides react with water except CuO.  Acidic Oxides: Generally formed from nonmetals and can react with water to form acids.  Basic Oxides: Typically formed from metals and react with water to form bases (alkaline solutions).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>14", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following is not a property of trioxonitrate (V) salts?", "images": [], "options": {"A": "Positive reaction to the brown ring test", "B": "Ability to dissolve in cold water", "C": "Decomposition on being strongly heated", "D": "Production of effervescence with saturated Na2CO3 solution"}, "answer": "D", "explanation": "Production of effervescence with saturated Na2CO3 solution   is not a property of trioxonitrate (V) salts", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>15", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following methods is suitable for the preparation of an insoluble salt?", "images": [], "options": {"A": "Action of an acid on a metal", "B": "Double decomposition", "C": "Neutralisation", "D": "Action of an acid on a trioxocarbonate (IV)"}, "answer": "B", "explanation": "The preparation of an insoluble salt is best achieved through double decomposition. Double decomposition is a type of chemical reaction where two compounds react, and positive ions and the negative ions of the two reactants switch places, forming two new compounds. One of these new compounds is usually insoluble and precipitates out of the solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>16", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : SULPHUR", "question": "What is the function of sulphur (IV) oxide in the reaction represented by the following equation? SO2(aq) + 2H2S(g) → 3S(s) + 2H2O(l)", "images": [], "options": {"A": "Dehydrating agent", "B": "Oxidising agent", "C": "Bleaching agent", "D": "Acid"}, "answer": "B", "explanation": "SO2 is reduced in the equation by lossing Oxygen. while H2S is being oxidized by losing Hydrogen. Sulphur (IV) Oxide is the Oxidizing Agent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>17", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following will produce oxygen and hydrogen during its electrolysis using platinum electrode?", "images": [], "options": {"A": "Glucose solution", "B": "Aqueous copper (ll) tetraoxosulphate (IV)", "C": "Dilute sodium chloride solution", "D": "Concentrated hydrochloric acid"}, "answer": "C", "explanation": "During electrolysis, water (H2O) is decomposed into hydrogen and oxygen gases. This process is known as electrolysis of water. Dilute sodium chloride solution, when electrolyzed, produces hydrogen gas at the cathode and oxygen gas at the anode. The other options do not produce both hydrogen and oxygen during electrolysis.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1998>18", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "What mass of copper would be deposited by a current of 1.0 ampere passing for 965 seconds through copper (ll) tetraoxosulphate (IV) solution? [Cu = 63.5; 1F = 96500C]", "images": [], "options": {"A": "0.318g", "B": "0.635g", "C": "18g", "D": "6.35g"}, "answer": "A", "explanation": "Cu2+ + 2e- → Cu, From the equation 2 Faraday will liberate 63.5gm of copper The quantity of electricity passed (Q) Q = 1.0 X 965 = 965 coulomb :. 2 x 96500 → 63.5, 965 → x. x = 965 / 2x96500 x 63.5 = 0.3175g ≈ 0.318", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>19", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "How many electrons are removed from Cr2+ when it is oxidized to CrO42-?", "images": [], "options": {"A": "0", "B": "2", "C": "4", "D": "8"}, "answer": "C", "explanation": "4 electrons are removed when it is oxidized to CrO42-", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>20", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "Substances which absorb water from the atmosphere without dissolving in it are said to be", "images": [], "options": {"A": "anhydrous", "B": "hygroscopic", "C": "insolube", "D": "hydrated"}, "answer": "B", "explanation": "Hygroscopy is the phenomenon when a substance is exposed to the atmosphere it absorbs water or gains water of crystallization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>21", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION", "question": "Pipe-borne water is usually chlorinated in order to", "images": [], "options": {"A": "improve the teste of the water", "B": "remove the hardness in the water clear", "C": "coagulate sediments in the water", "D": "kill harmful bacteria in the water"}, "answer": "D", "explanation": "Pipe-borne water is usually chlorinated in order to kill harmful bacteria in the water.To prevent contamination with germs, water companies add a disinfectant—usually either chlorine or chloramine—that kills disease-causing germs", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>22", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "What is the value of the heat change for the reaction represented by the following energy profile diagram?", "images": ["Chemistry/imgs/1998/path.png"], "options": {"A": "-50kJmol-1", "B": "-10kJmol-1", "C": "10kJmol-1", "D": "15kJmol-1"}, "answer": "A", "explanation": "∆Hproduct - ∆Hreactant=(50-100)K Joule/mol=-50KJmol-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1998>23", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following can be added to dissolve the precipitate formed in the reaction represented by the following equation? CaCl2(aq) + H2CO4(aq) ⇌ CaC2O4(s) + 2HCl(aq)", "images": [], "options": {"A": "Calcium chloride solution", "B": "Concentrated hydrochloric acid", "C": "Ethanol", "D": "Aqueous ammonia"}, "answer": "B", "explanation": "The precipitate formed in the reaction represented by the equation is calcium oxalate (CaC2O4). To dissolve this precipitate, concentrated hydrochloric acid can be added. The acid will react with the calcium oxalate to form calcium chloride and oxalic acid, both of which are soluble in water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>24", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "The spontaneity of a chemical reaction is determined by the change in the", "images": [], "options": {"A": "concentration of the reactants", "B": "temperature of the system", "C": "free energy of the system", "D": "pressure applied to the system"}, "answer": "C", "explanation": "The spontaneity of a chemical reaction is determined by the change in the free energy of the system. Spontaneous reactions release free energy as they proceed. The determining factors for spontaneity of a reaction are the enthalpy and entropy changes that occur for the system.  The free energy change of a reaction is a mathematical combination of the enthalpy change and the entropy change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>25", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION", "question": "Two metallic ions commonly present in hard water are", "images": [], "options": {"A": "Ca2+ and Zn2+", "B": "Cu2+ and Na+", "C": "Mg2+ and Ca2+", "D": "Fe2+ and Na+"}, "answer": "C", "explanation": "The most common ions found in hard water are the metal cations calcium (Ca 2+) and magnesium (Mg2+), though iron, aluminum, and manganese may also be found in certain areas. These metals are water soluble, meaning they will dissolve in water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>26", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is the percentage by mass of sulphur in Al2(SO4)3? [Al2SO4)3= 342g mole-; S=32]", "images": [], "options": {"A": "9.36%", "B": "14.71%", "C": "21.33%", "D": "28.07%"}, "answer": "D", "explanation": "Al: (mass of 27 * 2) = 54  S: (mass of 32 * 3) = 96  O: (mass of 16 * 12) = 192  The equation for mass percent is as follows.  Mass % = (mass of element of interest / Mass of entire compound) * 100%    Mass % = (mass of S / (mass of Al + mass of S + mass of O)) * 100%  Mass % = (96 / (54 + 96 + 192)) * 100%  Mass % = 28.07%", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>27", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Rusting of iron is an example of", "images": [], "options": {"A": "deliquescence", "B": "decomposition", "C": "displacement reaction", "D": "redox reaction"}, "answer": "D", "explanation": "Rusting of iron is an example of a redox reaction. A redox reaction is a type of chemical reaction where oxidation and reduction occur simultaneously. In the case of rusting, iron reacts with oxygen in the presence of water to form hydrated iron(III) oxide, commonly known as rust. During this process, iron is oxidized (loses electrons) and oxygen is reduced (gains electrons).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>28", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Aluminium is extracted from", "images": [], "options": {"A": "magnetite", "B": "cryolite", "C": "duralumin", "D": "bauxite"}, "answer": "D", "explanation": "Aluminium is extracted from bauxite. Aluminium ore. is called bauxite. The bauxite is purified to yield a white powder – aluminium oxide (also known as alumina ) – from which aluminium can be extracted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>29", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Metals are said to be malleable because they", "images": [], "options": {"A": "are good conductors heat", "B": "are good conductors of electricity", "C": "can be beaten into sheets", "D": "can be alloyed"}, "answer": "C", "explanation": "Metals are said to be malleable because they can be beaten into sheets. Malleability is a property of metals that allows them to be hammered, rolled or pressed into thin sheets without breaking. This property is due to the ability of metal atoms to slide over each other into new positions without breaking their metallic bonding.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>30", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STATES OF MATTER : LABORATORY PREPARATION AND PROPERTIES OF SOME GASES.", "question": "A device used in the laboratory for intermittent production of gases without heating is", "images": [], "options": {"A": "Leibing condenser", "B": "aspirator", "C": "delivery tube", "D": "Kipp's apparatus"}, "answer": "D", "explanation": "A device used in the laboratory for intermittent production of gases without heating is Kipp's apparatus. Kipp's apparatus, also called Kipp generator, is an apparatus designed for preparation of small volumes of gases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>31", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "The liquid product of the destructive distillation of coal is", "images": [], "options": {"A": "kerosene", "B": "ethanol", "C": "ammoniacal liquor", "D": "paraffin oil"}, "answer": "C", "explanation": "The liquid product of the destructive distillation of coal is ammoniacal liquor. Destructive distillation is the chemical process involving the decomposition of unprocessed material by heating it to a high temperature; the term generally applies to processes not involving oxidation. In the case of coal, the output includes coal gas, coal tar, coke, and ammoniacal liquor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>32", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Which of the following alkanes has the highest boiling point?", "images": [], "options": {"A": "pentane", "B": "ethane", "C": "propane", "D": "hexane"}, "answer": "D", "explanation": "Hexane has the highest boiling point among the given options. The boiling point of alkanes increases with the increase in the number of carbon atoms. This is due to the increase in the size of the molecule and the increase in the strength of the London dispersion forces, which are weak intermolecular forces that exist between all atoms and molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>33", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following can undergo both addition reactions and substitution reactions?", "images": [], "options": {"A": "Benzene", "B": "Pentane", "C": "Propene", "D": "Hexane"}, "answer": "A", "explanation": "Benzene . Being an aromatic hydrocarbon it undergoes both addition and substitution reactions. With its major reactions being substitution and a few addition reactions.    Example of substitution reaction benzene undergoes is its reaction with halogens e.g chlorine to produce chlorobenzene and HCl.It also reacts with ethene to give ethylbenzene.    Example of addition reaction involving benzene is its reaction with hydrogen gas to produce cyclohexane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>34", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Petrol consists mainly of", "images": [], "options": {"A": "polymers", "B": "alkanoates", "C": "hydrocarbons", "D": "alkanols"}, "answer": "C", "explanation": "Petrol, also known as gasoline, is a mixture of hydrocarbons. Hydrocarbons are organic compounds consisting entirely of hydrogen and carbon. They are the main component of fossil fuels, which include petrol, diesel, and natural gas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>35", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Dehydration of ethanol produces", "images": [], "options": {"A": "ethanoic acid", "B": "propan-1,2,3-triol", "C": "ethene", "D": "ethanal"}, "answer": "C", "explanation": "Dehydration of ethanol produces ethene. Dehydration is a chemical reaction that involves the removal of a water molecule from a substance. When ethanol (C2H5OH) is dehydrated, a water molecule (H2O) is removed, resulting in the formation of ethene (C2H4).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>36", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "When alkanols react with sodium, the gas evolved is", "images": [], "options": {"A": "hydrogen", "B": "oxygen", "C": "methane", "D": "ethyne"}, "answer": "A", "explanation": "When alkanols react with sodium, the gas evolved is hydrogen. This is because alkanols are a type of alcohol, and when alcohols react with active metals such as sodium, they produce hydrogen gas and a corresponding alkoxide.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>37", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "What is the IUPAC name of the following compound?", "images": ["Chemistry/imgs/1998/butene1.png"], "options": {"A": "Pent-1-ene", "B": "But-1-ene", "C": "2-methylbutane", "D": "2-methylbut-1-ene"}, "answer": "B", "explanation": "IUPAC name  is But-1-ene. The IUPAC name but-1-ene refers to a specific alkene with the following characteristics:    Characteristics of But-1-ene  Structure:    But-1-ene is a straight-chain alkene with four carbon atoms.  It has a double bond between the first and second carbon atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>38", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "The products of the reaction between CH3CH2COOH and CH3OH are H2O and", "images": [], "options": {"A": "CH3CH2COOCH3", "B": "CH3CH2COOCH2CH3", "C": "CH3CH2CH2COOH3", "D": "CH3CH2OH"}, "answer": "A", "explanation": "The products of the reaction between CH3CH2COOH and CH3OH are H2O and CH3CH2COOCH3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>39", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "A positive reaction to Fehling's test indicates the presence of", "images": [], "options": {"A": "starch", "B": "reducing sugars", "C": "oxidizing agents", "D": "alkanoic acids"}, "answer": "B", "explanation": "A positive reaction to Fehling's test indicates the presence of reducing sugars. Fehling's test is a chemical test used to differentiate between water-soluble carbohydrate and ketone functional groups, and also as a test for monosaccharides. The test is positive if the solution turns from blue to orange-red (brick red) precipitate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>40", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Which of the following compounds is used as a gaseous fuel?", "images": [], "options": {"A": "CH3-COO-CH2-CH3", "B": "CH3-CH2-CH2-CH3", "C": "CHCI3", "D": "CH3-CH2-COOH"}, "answer": "B", "explanation": "The compound CH3-CH2-CH2-CH3, also known as butane, is commonly used as a gaseous fuel. It is a hydrocarbon, which means it is composed of hydrogen and carbon atoms. When burned, it releases a large amount of heat energy, making it an effective fuel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>41", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct    Which of the following pairs are allotropes? I. Water and hydrogen peroxide II. Coal tar and coal gas III. Diamond and graphite IV Rhombic sulphur and monoclinic sulphur.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "Allotropes are different structural modifications of an element; the atoms of the element are bonded together in a different manner. In this case, Diamond and graphite (III) are allotropes of carbon, and Rhombic sulphur and monoclinic sulphur (IV) are allotropes of sulphur. Water and hydrogen peroxide (I) are not allotropes, they are different compounds of hydrogen and oxygen. Coal tar and coal gas (II) are not allotropes, they are different products obtained from coal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>42", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Molecules which are non-linear include I. methane II. ammonia III. hydrogen IV oxygen", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "B", "explanation": "Non-linear molecules are those in which the atoms do not all lie along a straight line. Methane (I) and ammonia (II) are examples of non-linear molecules. Methane has a tetrahedral shape, and ammonia has a trigonal pyramidal shape. Hydrogen (III) and oxygen (IV) are linear molecules because they only contain two atoms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>43", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Given only the atomic number of an element, it is possible to determine the number of I. protons in its nucleus. II. unpaired electrons present. III. electrons in its outermost shell. IV. neutrons in its nucleus", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "D", "explanation": "It is possible to determine the number of (d is correct)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>44", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  The factors which affect the preferential discharge of ions during electrolysis include I. concentration of the ions present. II. nature of the electrode being used. III. relative position in the electrochemical series. IV. charge on the ion.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "D", "explanation": "The factors which affect the preferential discharge of ions during electrolysis include (d is correct).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>45", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  In which of the following reactions is ethanoic acid showing acidic property? I. CH3 COOH + NaOH→ CH3COONa + H2O II. CH3COOH + KOH → CH3 COOK + H2O III. 2CH3 COOH + Na2CO3 → 2CH3 COONa+ CO2 + H2O IV. 2CH3 COOH + 2Na→ 2CH3COONa+ H2", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "Ethanoic acid is showing acidic property in (e is correct)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>46", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  A chemical reaction can be made to proceed faster by I. lagging the reaction vessel. II. conducting it in a bigger vessel. III. Grinding the reactant (s) If solid (IV) increasing the reaction temperature.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "A chemical reaction can be made to proceed faster by (c is correct)", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>47", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Which of the following will decrease in mass when heated in air? I. Magnessium ribbon II. Powdered sulphur III. Calcium trioxocarbonate (IV) IV. Magnesium tetraoxosulphate (VI) heptahydrate.", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "C", "explanation": "(c is correct) will decrease in mass when heated in air", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>48", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Crude oil spillage on a river can be dispersed by spraying the water with I. disinfectant II. kerosene III. ammonia IV. detergent", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "A", "explanation": "The correct option is IV, which corresponds to option A in the given options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1998>49", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Which of the following is/are manufactured by electrolysis? I. Calcium II. Chlorine III. Aluminium IV. Iron", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "d"}, "answer": "D", "explanation": "(d is correct) is/are manufactured by electrolysis", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1998>50", "subject": "Chemistry", "year": "1998", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Each question is followed by four responses labelled I to IV pick A if only IV is correct pick B if only I and II are correct, pick C if only Ill and IV are correct, pick D if only I, II and Ill are correct, pick E if, I,II,III and IV are all correct  Aqueous sodium hydroxide can be used to test for the presence of I. Ca2+ II. Zn2+ III. NH4+ IV. Cu2+", "images": [], "options": {"A": "a", "B": "b", "C": "c", "D": "e"}, "answer": "D", "explanation": "Aqueous sodium hydroxide can be used to test for the presence of all the ions listed: Ca2+, Zn2+, NH4+ and Cu2+. Sodium hydroxide is a strong base and it reacts with these ions to form precipitates of different colors, which can be used to identify the ions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>1", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following atoms contains the highest number of electrons in the outermost shell?", "images": [], "options": {"A": "8O", "B": "10Ne", "C": "15P", "D": "19K"}, "answer": "B", "explanation": "Neon because Oxygen (O) has 6 in it's outermost shell,Phosphorus (P) has 5 in it's outermost shell,Potassium (K) has only 1 in it's outermost shell while Neon (Ne) has 8 in it's outermost shell", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>2", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "What is the electronic configuration of an element represented as 199X?", "images": [], "options": {"A": "1s22s22p5", "B": "1s22s23s23p3", "C": "1s22s22p33s2", "D": "1s22s22p63s23p64s1"}, "answer": "A", "explanation": "1s22s22p5 is the electronic configuration of an element represented as 199X", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>3", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RULES AND PRINCIPLES FOR FILLING IN ELECTRONS.", "question": "Pauli Exclusion Principle is related to", "images": [], "options": {"A": "quantum numbers of electrons", "B": "reversiblility of equlibrium reactions", "C": "electronegativity values of elements", "D": "collision theory of reaction rates"}, "answer": "A", "explanation": "Pauli Exclusion Principle is related to quantum numbers of electrons. The Pauli Exclusion Principle states that in an atom or molecule, no two electrons can have the same four electronic quantum numbers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>4", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "Which of the orbitals 4s, 4p, 4d and 4f has the lowest energy?", "images": [], "options": {"A": "4f", "B": "4p", "C": "4d", "D": "4s"}, "answer": "D", "explanation": "4s electron spends more time close to the nucleus and has a lower energy level. Next comes the 4p, then the 4d, and the furthest out 4f orbital has the highest energy of the group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>5", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.", "question": "Which of the following has neither mass nor charge?", "images": [], "options": {"A": "Alpha particle", "B": "Deuterium", "C": "Gamma ray", "D": "Neutron"}, "answer": "C", "explanation": "Gamma rays are a type of electromagnetic radiation, and like other forms of light, they do not have mass or charge. Alpha particles, deuterium, and neutrons all have mass and alpha particles and deuterium have charge.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>6", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Two radioactive elements Q and S have half-life periods of 10 hours and 20 hours respectively. Therefore", "images": [], "options": {"A": "S decays faster than Q", "B": "Q is twice as stable as S", "C": "Q emits fewer particles than S", "D": "S is more stable than Q"}, "answer": "D", "explanation": "The half-life of a radioactive element is the time it takes for half of the atoms in a sample to decay. Therefore, if element S has a longer half-life than element Q, it means that S is more stable than Q because it decays slower.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>7", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Calcium atom ionizes by", "images": [], "options": {"A": "gaining two electrons", "B": "losing two electrons", "C": "sharing two electrons", "D": "gaining two protons"}, "answer": "B", "explanation": "Calcium atom ionizes by losing two electrons. Ionization is the process by which an atom or a molecule acquires a negative or positive charge by gaining or losing electrons, often in conjunction with other chemical changes. In the case of calcium, it has two valence electrons in its outermost shell, and it tends to lose these electrons in order to have a full outer shell, thus becoming a positively charged ion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>8", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following properties increases down a group in the Periodic Table?", "images": [], "options": {"A": "Atomic radius", "B": "Electronegativity", "C": "Electon affinity", "D": "Ionization energy"}, "answer": "A", "explanation": "The properties that increase down a column in the periodic table are ionic radii, atomic radius, number of shells or energy levels, electropositivity, and metallic character.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>9", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "In the Periodic Table, the elements that loss electrons most readily belong to", "images": [], "options": {"A": "Group I A", "B": "Group II A", "C": "Group III A", "D": "Group VII A"}, "answer": "A", "explanation": "The elements that lose electrons most readily belong to Group I A (alkali metals) in the Periodic Table. This is because these elements have only one electron in their outermost shell, and they can achieve a stable electron configuration by losing this electron. As a result, they are very reactive and readily lose their outer electron to form positive ions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>10", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Which of the following reactions is not feasible?", "images": [], "options": {"A": "Cl2 + 2Kl → 2KCI + I2", "B": "Cl2 + 2NaF → 2NaCI + F2", "C": "Zn + CuCI2 ZnCl2 + Cu", "D": "Zn + 2AgNO3 → Zn(NO3)2 + 2Ag"}, "answer": "B", "explanation": "The reaction Cl2 + 2NaF → 2NaCl + F2 is not feasible. This is because fluorine (F) is more electronegative than chlorine (Cl), meaning it has a greater tendency to attract electrons. Therefore, chlorine cannot displace fluorine from a compound. In the other reactions, a more reactive element displaces a less reactive one, which is feasible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>11", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following halogens is the most reactive?", "images": [], "options": {"A": "F2", "B": "Br2", "C": "I2", "D": "Cl"}, "answer": "A", "explanation": "Fluorine > Chlorine > Bromine > Iodine. Fluorine is the most reactive of the halogens and, in fact, of all elements, and it has certain other properties that set it apart from the other halogens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>12", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "The crystal layers in graphite are held together by", "images": [], "options": {"A": "electrostatic forces", "B": "van der Waals' forces", "C": "hydrogen bonds", "D": "covalent bonds"}, "answer": "B", "explanation": "The crystal layers in graphite are held together by  van der Waals' forces.  In graphite the layers are held together by weak van der Waals forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>13", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "What type of bond is indicated by the arrow in the following structure?", "images": ["Chemistry/imgs/1999/bondion.png"], "options": {"A": "covalent bond", "B": "ionic bond", "C": "dative bond", "D": "hydrogen bond"}, "answer": "C", "explanation": "Dative bond is indicated. A dative bond (also known as a coordinate bond) is a type of covalent bond in which both electrons in the bond originate from the same atom. This occurs when one atom (the donor) donates a pair of electrons to another atom (the acceptor) that has an empty orbital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>14", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Which of the following compounds KCl has the highest ionic character?", "images": [], "options": {"A": "PCI5", "B": "SiCI4", "C": "AICI3", "D": "KCl"}, "answer": "D", "explanation": "KCl (Potassium Chloride) has the highest ionic character among the given compounds. Ionic character is determined by the difference in electronegativity between the two atoms involved. In KCl, the difference in electronegativity between K (Potassium) and Cl (Chlorine) is quite high, making it more ionic in character compared to the other compounds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>15", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "If an element with high electron affinity combines with another element with low ionization energy the bond formed will be mainly", "images": [], "options": {"A": "covalent", "B": "ionic", "C": "dative", "D": "metallic"}, "answer": "B", "explanation": "An element with high electron affinity tends to attract and accept electrons, while an element with low ionization energy tends to lose electrons easily. When these two types of elements combine, the one with high electron affinity will accept the electrons lost by the one with low ionization energy, leading to the formation of ions. The bond formed between these ions is an ionic bond. Therefore, the correct answer is 'ionic'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>16", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "One mole of a compound M(HCO3)2 has a mass of 162g. Calculate the relative atomic mass of M. [H = 1, C =12, O = 16]", "images": [], "options": {"A": "122", "B": "101", "C": "53", "D": "40"}, "answer": "D", "explanation": "One of the mole of M(HCO3)2 = 162g; M +(1 + 12 + 16 x 3) x 2 = 162; M +122 = 162,:. M = 162 - 122 = 40g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1999>17", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Exhaust fumes discharged from a smoky vehicle gradually become invisible as a result of", "images": [], "options": {"A": "diffusion", "B": "combustion", "C": "absorption", "D": "emission"}, "answer": "A", "explanation": "Exhaust fumes from a smoky vehicle gradually become invisible because of diffusion. Diffusion is the movement of particles from an area of high concentration to an area of low concentration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>18", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following movements can be described as random motion?", "images": [], "options": {"A": "wheelbarrow being pushed", "B": "car travelling on a straight line", "C": "Gas molecules colliding in a flask", "D": "Planets going round the sun"}, "answer": "C", "explanation": "Random motion refers to the unpredictable, haphazard movement of particles, especially when they are in a state of chaos or disarray. In the context of the question, gas molecules colliding in a flask best describes random motion. This is because gas molecules move freely and randomly in all possible directions and frequently collide with each other and the walls of the container.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>19", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "Equal volumes of CO2 and CO at s.t.p have the same", "images": [], "options": {"A": "mass", "B": "density", "C": "rate of diffusion", "D": "number of molecules"}, "answer": "D", "explanation": "According to Avogadro's law, equal volumes of all gases, at the same temperature and pressure, have the same number of molecules. Therefore, equal volumes of CO2 and CO at standard temperature and pressure (s.t.p) have the same number of molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>20", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Gas molecules are said to be perfectly elastic because", "images": [], "options": {"A": "they collide without loss of energy", "B": "they move about in straight lines", "C": "the distances between them are negligible", "D": "the volume occupied by them is negligible"}, "answer": "A", "explanation": "Gas molecules are said to be perfectly elastic because they collide without loss of energy. In an elastic collision, the total kinetic energy of the system (in this case, the gas molecules) is conserved before and after the collision. This means that no kinetic energy is lost to sound, heat, or deformation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>21", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume of hydrogen is produced at s.t.p. When 2.60 g of zinc reacts with excess HCI according to the following equation? Zn(s) + 2HCI(aq) → ZnCI2(aq) + H2(g) [Zn = 65; 1 mole of a gas occupies 22.4dm3 at s.t.p]", "images": [], "options": {"A": "0.040dm3", "B": "0.896dm3", "C": "5.82dm3", "D": "8.62dm3"}, "answer": "B", "explanation": "Zn + 2HCI → ZnCI2 + H2; 65g of Zn produces 22.4 dm3 of H2; .: 2.6g of Zn will produce = 2.6/65 x 22.4 = 0.896 dm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1999>22", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN", "question": "Helium is preferred to hydrogen in filling balloons because hydrogen", "images": [], "options": {"A": "is inflammable", "B": "is diatomic", "C": "exhibits isotopy", "D": "is a component of water"}, "answer": "A", "explanation": "Helium is preferred to hydrogen in filling balloons because hydrogen is inflammable. Hydrogen is lighter than air but it is flammable and as oxygen is present in the air, so the risk of explosion and fire is there. Helium is lighter than air and it is a non-combustible gas so it used to fill balloons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>23", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "30cm3 of hydrogen at s.t.p combine with 20cm3 of oxygen to form steam according to the following equation 2H2(g) + O2(g) → 2H2O(g).Calculate the total volume of the gaseous mixture at the end of the reaction", "images": [], "options": {"A": "50cm3", "B": "35cm3", "C": "30cm3", "D": "25cm3"}, "answer": "B", "explanation": "2H2(g) + O2(g) → 2H2O(g).      2 volumes of H2(g) and 1 volume of O2(g) produced 2 volumes of H2O(g)      ratio of reacting volumes    30cm3 + 15cm3 → 30cm3      30cm3   of Hydrogen requires 15cm3   of oxygen to produce 30cm3   of water.    Excess oxygen: 20cm3   – 15cm3   = 5cm3      Total volume of gaseous mixture: 5cm3   of Oxygen + 30cm3   of Water = 35cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1999>24", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "An exothermic reaction is one which involves", "images": [], "options": {"A": "attainment of dynamic equilibrium", "B": "loss of heat to the surrounding", "C": "evolution of gas as it proceeds", "D": "positive change in value of enthalpy"}, "answer": "B", "explanation": "An exothermic reaction is a chemical reaction that releases energy by light or heat. It is the opposite of an endothermic reaction. Expressed in a chemical equation, reactants turn into products plus heat. So, the correct answer is 'loss of heat to the surrounding'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>25", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following is an acid salt?", "images": [], "options": {"A": "NH4CI", "B": "MgSO4 7H2O", "C": "CH3COONa", "D": "NaHCO3"}, "answer": "D", "explanation": "An acid salt is a class of salts that produces an acidic solution after being dissolved in a solvent. Its acidic nature is due to the presence of replaceable hydrogen ions. NaHCO3 or Sodium bicarbonate is an example of an acid salt. When it is dissolved in water, it produces a mildly acidic solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>26", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Body Fluid pH RangeGastric juice 1.6-1.8Bile7.8-8.6Urine 5.5-7.0  Use the data below to arrange the body fluids mentioned in order of increasing acidity", "images": [], "options": {"A": "Bile", "B": "Gastric juice", "C": "Bile", "D": "urine"}, "answer": "C", "explanation": "Bile is slightly alkali{7.8-8.6}, urine is acidic (5.5-7.0) while gastric juice is the most acidic with 1.6-1.8.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>27", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following compounds dissolves in water to form a solution with pH below 7?", "images": [], "options": {"A": "Sodium tetraoxosulphate (VI)", "B": "Potassium hydroxide", "C": "Ammonium chloride", "D": "Sodium trioxocarbonate (IV)"}, "answer": "C", "explanation": "Ammonium chloride is an acidic salt. When it dissolves in water, it forms a solution with a pH below 7. This is because it reacts with water to form ammonium hydroxide and hydrochloric acid. The hydrochloric acid lowers the pH of the solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>28", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "If the solubility of KHCO3 is 0.40 mole dm-3 at room temperature , calculate the mass of KHCO3 in 100dm3 of the solution at this temperature. [KHCO3 = 100gmol-]", "images": [], "options": {"A": "4.0g", "B": "10.0g", "C": "40.0g", "D": "100.0g"}, "answer": "A", "explanation": "0.4mole produces 40g at 1000dm3  what is the mass at 100dm3  40g=1000dm3  x=100dm3  x= 40×100/1000= 4g.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>29", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "The property of calcium chloride which makes it useful as a drying agent is that it is", "images": [], "options": {"A": "ionic", "B": "deliquescent", "C": "a strong electrolyte", "D": "a normal salt"}, "answer": "B", "explanation": "The property of calcium chloride which makes it useful as a drying agent is that it is deliquescent.  It is an ionic compound of chlorine and calcium. At room temperature, it is a crystalline solid white in colour. It is highly soluble in water and hence is hygroscopic in nature. It is odourless and has a very high enthalpy changeof solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>30", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following lowers the activation energy of a chemical reaction?", "images": [], "options": {"A": "Freezing mixture", "B": "Reducing agent", "C": "Water", "D": "Catalyst"}, "answer": "D", "explanation": "The catalysts are used in the reaction to lower the activation energy for the reaction so that the reaction can occur at a faster rate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>31", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Consider the reaction represented by the following equation: H2(g) + 12(g) → 2HI(g). The number of effective collisions of molecules of the reactants decreases as", "images": [], "options": {"A": "the temperature is raised", "B": "the pressure increased", "C": "the volume of the system is increased", "D": "a catalyst is intoduced into the system"}, "answer": "C", "explanation": "The number of effective collisions of molecules of the reactants decreases as the volume of the system is increased", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1999>32", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "What will be the effect of increase in pressure on the following system at equilibrium? 2NH3(g) ⇌ N2(g) + 3H2(g)", "images": [], "options": {"A": "Activation energy will decrease", "B": "the forward reaction will be favoured", "C": "the concentration of ammonia will increase", "D": "the reaction will go to completion"}, "answer": "C", "explanation": "An increase in pressure will lead to an increase in concentration i.e favouring the backward reaction", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>33", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Which of the following is not correct about oxidation number convention? The oxidation number of a/an", "images": [], "options": {"A": "element in the free state is zero", "B": "monatomic ion is equal to its charge", "C": "alkali meta like sodium in its compounds is + 1", "D": "atom of a diatomic molecules is + 2"}, "answer": "D", "explanation": "The oxidation number of an atom in a diatomic molecule is not necessarily +2. The oxidation number of an atom in a molecule is determined by the difference in electronegativity between the atoms. For example, in a molecule of oxygen (O2), the oxidation number of each oxygen atom is 0, not +2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>34", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Equal volumes of water were added to one mole of each of the following compounds. Which of them produced the largest number of ions", "images": [], "options": {"A": "Glucose", "B": "Sodium trioxonitrate (V)", "C": "Ethananoic acid", "D": "Silver chloride"}, "answer": "B", "explanation": "Sodium trioxonitrate (V) is an ionic compound that dissociates into three ions in solution: one sodium ion and one nitrate ion. Therefore, it produces the largest number of ions per mole when dissolved in water. Glucose is a covalent compound and does not dissociate into ions. Ethananoic acid only partially ionizes in water, and silver chloride is insoluble in water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>35", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "When dilute copper (ll) chloride solution is electrolysed, the reaction at the cathode is represented by the equation", "images": [], "options": {"A": "Cu → Cu2+ + 2e-", "B": "Cu2+ + 2e- → Cu", "C": "4OH- - 4e- → O2 + 2H2O", "D": "2CI- → CI2 + 2e-"}, "answer": "B", "explanation": "When copper (II) chloride solution is electrolyzed, copper ions (Cu2+) are reduced at the cathode to form copper metal. This is represented by the equation Cu2+ + 2e- → Cu. The other options represent oxidation reactions or reactions that occur at the anode.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>1999>36", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "The set-up shown in the diagram represents a/an", "images": ["Chemistry/imgs/1999/bulb.png"], "options": {"A": "secondary cell", "B": "electrochemical cell", "C": "Daniel cell", "D": "electrolytic cell"}, "answer": "D", "explanation": "The set-up shown in the diagram represents a/an electrolytic cell", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>37", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The bulb in the set-up will not light if K is", "images": ["Chemistry/imgs/1999/bulb.png"], "options": {"A": "molten sodium chloride", "B": "acidified water", "C": "tetrachlorometane", "D": "ethanoic acid"}, "answer": "C", "explanation": "The bulb in the set-up will not light if K is tetrachlorometane because it is a covalent compound and as such doesn't have mobile ions to conduct electricity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>38", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "A metal which can be used as sacrificial anode for preventing corrosion of a length of iron pipe is", "images": [], "options": {"A": "copper", "B": "magnesium", "C": "silver", "D": "lead"}, "answer": "B", "explanation": "A metal which can be used as sacrificial anode for preventing corrosion of a length of iron pipe is magnesium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>39", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Separating funnel is used for separating a mixture of", "images": [], "options": {"A": "liquids with different boiling point", "B": "sediments in a liquid", "C": "liquids with different", "D": "liquids that are immiscible"}, "answer": "D", "explanation": "A separating funnel is used to separate immiscible liquids, that is, liquids that do not mix. The liquids form separate layers in the funnel due to their different densities. The liquid with the higher density forms the bottom layer. The tap of the funnel can then be opened to allow the bottom layer to run out, separating the two liquids. The other options are incorrect because they describe methods of separation that are not typically performed using a separating funnel.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>40", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "How many carbon atoms are present in one molecule of 2-methylpropane?", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "C", "explanation": "2-methylpropane, also known as isobutane, is a branched-chain alkane with four carbon atoms. The '2-methyl' part of the name indicates that there is a methyl group (CH3) attached to the second carbon atom of the propane chain. This means that there is one additional carbon atom, making a total of four. The other options are incorrect because they do not correctly represent the number of carbon atoms in 2-methylpropane.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>1999>41", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Which of the following is the most reactive towards bromine?", "images": [], "options": {"A": "Methane", "B": "Benzene", "C": "Ethyne", "D": "Hexane"}, "answer": "C", "explanation": "Ethyne is the most reactive towards bromine. This is because ethyne is an alkyne, which contains a triple bond. The triple bond is more reactive than the single bonds in methane and hexane, and the delocalized pi bonds in benzene. Bromine can add across the triple bond in a reaction known as halogen addition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>42", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following compounds is unsaturated?", "images": [], "options": {"A": "2-methylbutane", "B": "Chloromethane", "C": "Methylbenzene", "D": "1,2-dibromoethane"}, "answer": "C", "explanation": "Methylbenzene is an unsaturated compound. An unsaturated compound is a compound that contains at least one double or triple bond. Methylbenzene contains a benzene ring, which is a ring of six carbon atoms with alternating single and double bonds, making it unsaturated. The other options are all saturated compounds, meaning they contain only single bonds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>43", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Consider the following compound: The compound with the structure is an", "images": ["Chemistry/imgs/1999/cor.png"], "options": {"A": "alkanoate", "B": "alkanal", "C": "alkanol", "D": "alkanone"}, "answer": "D", "explanation": "The compound with the structure is an alkanone which is characterized by the functional group C=O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>44", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following compounds reacts with sodium hydroxide to form a salt?", "images": [], "options": {"A": "CH3CH2COOH", "B": "(CH3)3COH", "C": "CH3CH=CH2", "D": "C6H12O6"}, "answer": "A", "explanation": "CH3CH2COOH, also known as propanoic acid, reacts with sodium hydroxide to form a salt. This is because it is a carboxylic acid, and carboxylic acids react with bases such as sodium hydroxide in a neutralization reaction to form a salt and water. The other options are not acids and therefore do not react with bases to form salts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>45", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Alkanoates are produced from alkanols by", "images": [], "options": {"A": "fermentation", "B": "saponification", "C": "oxidation", "D": "esterification"}, "answer": "D", "explanation": "alkanoates are produced from alkanols by esterification, which involves combining an alkanol with a carboxylic acid to form an alkanoate and water, catalyzed by an acid catalyst.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>46", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following is a secondary alkanol?", "images": [], "options": {"A": "OHCH2-CH2OH", "B": "H2C=CH-CH2OH", "C": "CH3-CH(OH)-CH3", "D": "CH3-(CH2)3-CH2OH"}, "answer": "C", "explanation": "A secondary alkanol is an alcohol where the carbon atom of the hydroxyl group (OH) is attached to two other carbon atoms. It is represented as R2CHOH. In the given options, CH3-CH(OH)-CH3 is a secondary alkanol because the carbon atom of the hydroxyl group is attached to two other carbon atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>47", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Geometric (cis-trans) isomerism is exhibited by", "images": [], "options": {"A": "C2H2CI2", "B": "C2H5CI", "C": "C4H10", "D": "C5H12"}, "answer": "A", "explanation": "Geometric (cis-trans) isomerism is exhibited by compounds that have a double bond or a ring structure. This type of isomerism arises due to the restricted rotation about the double bond or the ring structure. In the given options, C2H2CI2 can exhibit geometric isomerism because it has two different groups (H and Cl) attached to each carbon of the double bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>48", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following is needed to produce slag during the extraction of iron in the blast furnace?", "images": [], "options": {"A": "Cryolite", "B": "Limestone", "C": "Carbon", "D": "Sulphur"}, "answer": "B", "explanation": "During the extraction of iron in the blast furnace, limestone is added which reacts with the sand (silicon dioxide) present in the iron ore to produce slag. Slag is a molten mixture of calcium silicate and is lighter than the iron, so it floats on top of the iron and can be easily removed. Therefore, limestone is needed to produce slag.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>49", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Environmental pollution problems are generally more severe in countries which have", "images": [], "options": {"A": "dense population", "B": "low birth rate", "C": "great land mass", "D": "limited industries"}, "answer": "A", "explanation": "Environmental pollution problems are generally more severe in countries which have dense population", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>1999>50", "subject": "Chemistry", "year": "1999", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "The greenhouse effect is a climatic condition associated with the presence of excess", "images": [], "options": {"A": "carbon (IV) oxide", "B": "hydrogen sulphide", "C": "nitrogen (ll) oxide", "D": "ammonia gas"}, "answer": "A", "explanation": "The greenhouse effect is a climatic condition associated with the presence of excess carbon (IV) oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>1", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The atom of four elements are represented as 20Q, 16R, 10S and 8T. Which of the elements would be inactive ?", "images": [], "options": {"A": "Q", "B": "R", "C": "S", "D": "T"}, "answer": "C", "explanation": "20Q  : 2,8,2 ;A group 2 metals which is  reactive group.  16R : 2,8,6 ; A goup 6 element which is also a reactive group.  10S : 2,8 ; A group 8/0 element .The elements in the group unreactive of their complete duplet or octet configuration.  8T : 2,6 ; Also a group 6 element", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>2", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following represent the ground state electronic configuration of an element with atomic number 6?", "images": ["Chemistry/imgs/2000/v6.png", "Chemistry/imgs/2000/v7.png", "Chemistry/imgs/2000/v8.png", "Chemistry/imgs/2000/v9.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "6X  : 1s2 2S2 2P2 (Aufbau's principle)     This obeys hund's rule of maximum multiplicity which states that when filling electrons in the degenerate orbitals, pairing is not allowed until each orbital has singlely filled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>3", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Chlorine atom forms Cl-", "images": [], "options": {"A": "losing one electron", "B": "sharing one electron", "C": "donating lone pair electron", "D": "gaining one electron"}, "answer": "D", "explanation": "17Cl  Proton number : 17  Electron number : 17    Cl-  Proton number : 17  Electron number  18  An atom becomes negatively charged by gaining electron(s). Cl is formed which cl gains one electron", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>4", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "An element Z has a combining power of 3. Which of the following formulae is correct of its compounds?", "images": [], "options": {"A": "ZSO3", "B": "Z3Cl", "C": "Z2O3", "D": "ZS3"}, "answer": "C", "explanation": "As demonstrated above, the correct option is Z2O3 formed as a result of valence crossing of Z with a combining power of 3 and 0 with a combining power of 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>5", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Electrovalent compounds are charaterised by", "images": [], "options": {"A": "solubility in ethanol", "B": "high molar mass", "C": "high melting point", "D": "Strong oxidizing ability"}, "answer": "C", "explanation": "Differences between covlent and electrovalent compounds    Electrovalent Covalenti) they consist of ions They consist of moleculesii) They are solube in water They are not.iii)   They conduct electricity in aqeous form They do not.iv) They have high melting point they have low melting point.v)  They have high melting point Thy have low boiling point.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>6", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The type of chemical bond that exists between potassium and oxygen is potassium oxide in", "images": [], "options": {"A": "ionic", "B": "metalic", "C": "covalent", "D": "dative"}, "answer": "A", "explanation": "Potassium is highly electropositive metal  Oxygen is highly electronegative non-metal  Hence , the bond between them is electrovalent or ionic", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>7", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "Which of the following contains coordinate covalent bond?", "images": [], "options": {"A": "HCl", "B": "CH4", "C": "NH4+", "D": "Na+Cl"}, "answer": "C", "explanation": "Coordinate covalent bond or dative vond is a covalent bond in which the shared pair of electron come from the same atom, in the formation of NH4+, pair of electron shared were donated by NH3 to H+. Hence , the formation of NH4+ as the electron s were shared between NH3 and H+", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>8", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Electrostatic force of attraction between sodium ion and halide ion is greatest in", "images": [], "options": {"A": "NaCl", "B": "NaBr", "C": "NaF", "D": "Nal"}, "answer": "C", "explanation": "Electronegativity  is a measure of the tendency of an atom to gain electron , it increase across the period and decreases down the group , in group7, the element are F,Cl, Br, I. But F will be the most electronegative element . This also will make it to have highest bond with metals", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>9", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "which of the following non-metals reacts most readily with metals?", "images": [], "options": {"A": "Nitrogen", "B": "chlorine", "C": "sulphur", "D": "carbon"}, "answer": "B", "explanation": "The most electronegative element is fluorine followed by chlorine then oxygen. Hence , chlorine is the non metal which reacts readily with metals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>10", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "A radioactive solid is best stored.", "images": [], "options": {"A": "under parafin oil", "B": "under ultraviolet light", "C": "in a cool dark cupboard", "D": "in a box lined with lead"}, "answer": "D", "explanation": "The radioactive substance which has the highest penetrating is Gamma ray and it can be stored by thick lead block . Hence, boxlined with lead will be the best option", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>11", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "What are values of X and Y in the following equation ?  23490Th →yxPa + B - particle", "images": [], "options": {"A": "x     y 91 234", "B": "x      y92 235", "C": "x      y89 236", "D": "x      y88 238"}, "answer": "A", "explanation": "β-particles are stream of electrons, An electron is represnted as -10e.For a balanced radiactive equation the sum of the atomic number on the left hand side be equal to that of the right hand side , the same goes for mass nuber too   90234Th →yxPa + -10e + Energy  90 = x - 1  x=91    234 = y + 0  y = 234", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2000>12", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "What is the shape of a molecule of CCl4?", "images": [], "options": {"A": "Pyramidal", "B": "tetrahedral", "C": "trigonal planar", "D": "linear"}, "answer": "B", "explanation": "All alkane members have tetrahedral shape .CCl4 is tetrachloromethane , which is an alkane member.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>13", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "Which of the following increase as boiling water changes to steam?", "images": [], "options": {"A": "Temperature of system", "B": "Degree of disorder in the system", "C": "number of molecules", "D": "Activation energy"}, "answer": "B", "explanation": "Entropy is the degree of disorderliness of a system , As water turn to vapour , it become disorderly due to the increase in the kinetic energy of its molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>14", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following statement is not correct about systems I and II below, other conditions remaining constant", "images": ["Chemistry/imgs/2000/v10.png"], "options": {"A": "The molecule collide with one another frequently in II than in I", "B": "The pressure exerted by the molecules in I is less than in II", "C": "The distance between the molecules in I is shorter than in II", "D": "The average kinetic energy of the molecules in I is the same as in II"}, "answer": "A", "explanation": "According to Boyle's Law, the volume in I is lesser than the volume in II. Hence, the pressure in I is greater than the pressure in II. This means the molecules in I will collide more frequently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>15", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "If the temperature T∘C of an ideal gas is increased to 3/2 T∘C at constant volume V, its pressure P will change to", "images": [], "options": {"A": "2/3 P", "B": "p(273+3/2T)273+T", "C": "1/2 P(273 + T)", "D": "3P/2T"}, "answer": "B", "explanation": "T1 = T + 273,  T2=32T+273 (since the temperture must be in kelvin)  P1= P ; P2 = ?  From pressure law  P α T  P=KT;K=PT  For two cases ;   P1T1=P2T2  PT+273=P23/2+273  P2=(3/2T+273)PT+273", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2000>16", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "9.60g of a gas X occupies the same volume as 0.30g of the hydrogen under the same conditions. calculate the molar mass of X [H = 1]", "images": [], "options": {"A": "8g mol-1", "B": "16g mol-1", "C": "32g mol-1", "D": "64g mol-1"}, "answer": "D", "explanation": "From Avogadro's law both gases will have the same number of molecules since they are equal volume.  Noofmole,n=Mass,mMolar mass,m.m  For hydrogen   n=0.32  n = 0.15    For gas x  n=9.6M.M  0.15=9.6M.M  M.M=9.60.15=64kgmol", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>17", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN", "question": "Which of the following gases is colourless, odourless and soluble in potassium hydroxide solution?", "images": [], "options": {"A": "NO2", "B": "SO2", "C": "NH3", "D": "CO2"}, "answer": "D", "explanation": "NO2 is a reddish brown pungent gas   SO2 is a colourless gas with a pungent odour (like burning match)  NH3 is a colourless gas with a pungent odour (like unrine)  Co2 is a colourless and odourless gas", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>18", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The gas evolved when the dilute tetraoxosulphate(VI) acid reacts  with sodium hydrogen trioxocarbonate (IV)is", "images": [], "options": {"A": "hydrogen", "B": "oxygen", "C": "carbon (IV)oxide", "D": "Sulphur (VI)"}, "answer": "C", "explanation": "When dilute tetraoxosulphate(VI) acid (H2SO4) reacts with sodium hydrogen trioxocarbonate (IV) (NaHCO3), the products are sodium sulphate, water, and carbon (IV) oxide (CO2). The balanced chemical equation for this reaction is: H2SO4 + 2NaHCO3 -> Na2SO4 + 2H2O + 2CO2. Therefore, the gas evolved is carbon (IV) oxide.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>19", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following is an acid salt?", "images": [], "options": {"A": "(NH4)2CO3", "B": "CH3COONa", "C": "KHSO4", "D": "MgSO4.7H2O"}, "answer": "C", "explanation": "Acid salts are salts that contains ionizable proton (H+) . They are charaterized by the presence of one or more ionizable hydrogen atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>20", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "If a solution has a pH of 2, it can be concluded that it", "images": [], "options": {"A": "is a weak electrolyte", "B": "has hydrogen ion concentration of 0.2mol dm-3", "C": "is twice as acidic as a solution of pH 1", "D": "will produce effervesence with magnesium ribbion"}, "answer": "D", "explanation": "A solution with a pH of 2 is highly acidic (strong acid), they react with metals to liberate hydrogen gas. The liberation of this gas will be associated with effervescence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>21", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Which of the following compounds dissolve in water to give alkaline solution?", "images": [], "options": {"A": "ammonium chloride", "B": "sodium chloride", "C": "sulphur (IV) oxide", "D": "potassium oxide"}, "answer": "D", "explanation": "A   NH4Cl + H2O →NH4OH(weak base) + Cl(strong acid)  B   NaCl + H2O → NaOH(strong base) + HCl(strong acid)  C SO2 + H2O →H2SO3(acidic)  D K2O + H2O → KOH (Alkaline)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>22", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following salts is stable to heat?", "images": [], "options": {"A": "K2CO3", "B": "(NH4)2SO4", "C": "NaHCO3", "D": "AgNO3"}, "answer": "A", "explanation": "Trioxocarbonate  IV sats decompose upon heating to liberate CO2 gas  with the exception Na2CO3 and K2CO3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>23", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "The decomposition of organic substance in the absence of air is?", "images": [], "options": {"A": "Redox reaction", "B": "Destructive distillation", "C": "Dehydration", "D": "neutralization"}, "answer": "B", "explanation": "Destructive  distillation is the decomposition of organic substances such as wood, coal, and oil by heat in the absence of air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>24", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "chemical equilibrium is attained when", "images": [], "options": {"A": "reactant in the system are used up", "B": "concentration of the products are greater than", "C": "concentration of the reactants and products remain constant", "D": "reactant stop forming the products."}, "answer": "C", "explanation": "Chemical equilibrum occurs when the rate of forward reaction equals the rate of backward reaction in a reversible system. hence , ther is no observable change in the property of the system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>25", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "What is the effect of using vanadium (V) oxide as catalyst in the reaction represent by the following equation?  2SO2 + O2 ⇌ 2SO3; ∆H = -xKjmol-1", "images": [], "options": {"A": "Decreases the values of ∆H", "B": "increase the collision rate of reactant particles", "C": "shift equillibrum position to the right", "D": "reduces the time for attainment of equilibrium"}, "answer": "D", "explanation": "Catalyst speeds up reaction rate by lowering the activation energy. it doesn't have effect on the equilibrum position but rather allows the reaction to reach equilibrium more rapidily.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2000>26", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "A finely divided  form of a metal burns more readily in air than the rod form because the rod has", "images": [], "options": {"A": "higher molar mass", "B": "smaller surface area", "C": "protective oxide coating", "D": "different chemical properties"}, "answer": "B", "explanation": "reactant (solids ) in powder from make reaction to be very fast because of large surface area being exposed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>27", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Which of the following will displace copper from a solution of copper(II) salt?", "images": [], "options": {"A": "Aluminium ions", "B": "magnesium", "C": "silver", "D": "zinc ions"}, "answer": "B", "explanation": "Elements which are high in the electrochemical series can displace elements that are low . Among the listed elements, magnesium is the highest. Hence it is the most electropositive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>28", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "What is the value of x in the following equation?  Cr2O72- + 14H+ + xe →2Cr3+ + 7H2O", "images": [], "options": {"A": "1", "B": "6", "C": "8", "D": "12"}, "answer": "B", "explanation": "Cr2O72- + 14H + xe- →2Cr3+ + 7H2O  multipy their charge with their number of mole .  -2 + 14 - x = 6 + 0  12 - x = 6   12 - 6 = x  x = 6 mole of e-", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>29", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "in which of the following is the oxidation number of sulphur equals to -2?", "images": [], "options": {"A": "S8", "B": "H2S", "C": "SO2", "D": "SO32"}, "answer": "B", "explanation": "Oxidation number of H+ is  + 1  H2 : 1 x 2 + S = 0  2 + S = 0  s  -2  The oxidation number od sulphur in H2S is -2  It is O is S8, 4 in SO2 and 4 is SO32-", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>30", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "An iron nail placed in a solution of copper(II) tetraoxosulphate (VI) is soon covered with deposit of copper. which of the following equations represent the reaction?", "images": [], "options": {"A": "Fe+2(aq) + Cu(s)→Fe+3(aq) + Cu+2(aq)", "B": "Fe+2(aq) + Cu(s)→Fe(s) + Cu+2(aq)", "C": "Fe((s)) + Cu+2(s)→Fe+2(aq) + Cu+2(aq)", "D": "Fe(s) + Cu+2(aq)→Fe+2(aq) + Cu(aq)"}, "answer": "D", "explanation": "The reaction between iron nail and copper I tetraoxosulphate VI solution is a redox reaction, iron is oxidated (increase in Oxidation number) while copper is reduced (decrease in oxidation number).  Fe + CuSO4 →Fe So4 + Cu  Cu2+ + 2e- →Cu (reduction)  Fe →Fe2+ (oxidation)  Cu2+ + Fe + 2e-→Cu + Fe2+ + 2e-  Fe (s) + Cu2+ → Fe2+ + Cu(s)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>31", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "0.10 mol dm3 NaOH conducts better than 0.10 mol dm3 CH3COOH because the solution of NaCl", "images": [], "options": {"A": "contains more ions", "B": "is neutral to litmus", "C": "has a lower molar mass", "D": "has a higher pH"}, "answer": "A", "explanation": "Nacl is a strong base , hence it ionizes completely giving out more lens for conduction while CH3COOH is a weak acid which ionizes partially hence, there ,are few ions for conduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>32", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following occurs when a solution CuSO4 is electrolysed using copper electrodes?", "images": [], "options": {"A": "The cathode becomes coated with copper", "B": "both electrode gains electrons", "C": "The blue colour of the solution fades gradually", "D": "the anode increases in mass"}, "answer": "C", "explanation": "When a solution of CuSO4 is electrolysed using copper electrodes, copper ions from the solution are reduced at the cathode and deposited as copper metal. At the same time, copper atoms from the anode are oxidized to copper ions and go into the solution. This maintains the concentration of copper ions in the solution, so the blue colour of the solution (due to the presence of Cu2+ ions) fades gradually.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>33", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following procedure is suitable for identifying the food colouring added to a pastry sample?", "images": [], "options": {"A": "carry out some food test", "B": "Examine the pastry sample under a microscope", "C": "Do a chromatograph extract", "D": "Determine the molar mass of the colouring"}, "answer": "C", "explanation": "Chromatography is a technique used to separate and identify components in a mixture. In the case of identifying food colouring added to a pastry sample, a chromatograph extract would be the most suitable procedure. The different food colourings will move at different rates on the chromatography paper, allowing them to be identified.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>34", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "C8H18 will undergo the following reaction except", "images": [], "options": {"A": "Cracking", "B": "combustion", "C": "substitution", "D": "addition"}, "answer": "D", "explanation": "C8H18 is octane which is an alkane member , alkane do not undergo addition reaction because thay are saturated hydrocarbon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>35", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following is correct about both compounds shown below?  CH3CH2CH2OH:CH3CH2CH(OH)CH3", "images": [], "options": {"A": "They have identical physical properties", "B": "They are structural isomer", "C": "their general molecular formula is the same", "D": "they are oxidized to alkanones"}, "answer": "C", "explanation": "Both compounds belong to alkanol family , all members of the same family do not have physical properties but similar chemical property, prepared by similar methods and have the same general molecular formular CnH2n+1OH.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>36", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "2 moles of hydrogen gas will reacts completely with one mole of", "images": ["Chemistry/imgs/2000/v11.png"], "options": {"A": "", "B": "CH3-CH=CH2", "C": "C6H5-CH", "D": "CH≡C-CH2-CH3"}, "answer": "D", "explanation": "Alkynes are formed from Alkanes by removing 2 moles of H2 or when 2 moles of H2 reacts with Alkynes, Alkanes are formed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>37", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "what process is involved in the reaction represent by the equation below?", "images": ["Chemistry/imgs/2000/s28.png"], "options": {"A": "saponification", "B": "esterification", "C": "fermentation", "D": "Dehydration"}, "answer": "B", "explanation": "Alkanols  + Alkanoic acid ⇄ alkanaote  + H2O.  This reacton is called Esterification reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>38", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "What is the product of the reaction between ethanol and excess acidified KMnO4 solution?", "images": [], "options": {"A": "CH2=CH2", "B": "CH3COOH", "C": "CH3-CH3", "D": "CH3OCH3"}, "answer": "B", "explanation": "Reaction between Alkanol and KMnO4 is oxidation reaction. they are oxidized to give Alkanol and finally Alkanoic acid.  C2H5OH + ([0]) → Ch3CHO →CH3COOH", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>39", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Which of the following needs to be hydrolysed before it shows reducing property?", "images": [], "options": {"A": "Glucose", "B": "maltose", "C": "sucrose", "D": "Fructose"}, "answer": "C", "explanation": "A reducing sugar is any sugar that is capable of acting as a reducing agent because of its free aldehyde or ketone group. All monsaccharides are while maltose and sucrose are dissacharide. Sucrose is a non-reducing sugar and must first be hydroyzed to its components , glucose and fructose before it can be measured in assay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>40", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "What is the IUPAC name of the following compound?", "images": ["Chemistry/imgs/2000/v18.png"], "options": {"A": "2-chloro-3-methylbutane", "B": "2-methy-3-chlorobutane", "C": "2.3-chloromethylbutane", "D": "3-chloro-3-methylbutane"}, "answer": "A", "explanation": "- Two attachments, chlorine and,methyl  on 2nd and 3rd carbons respectively   2-Chloro-3-Methylbutane      - Since it has single bond al through , it is an alkane family    -Longest carbon to carbon continous chain consist of four carbons (Butane)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>41", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Consider the reaction below  H2: Ni catalyst  Vegeable oil high temperature→H2,Ni catalyst product  The reaction is applied in the manufacture of", "images": [], "options": {"A": "soapy detergent", "B": "drugs", "C": "parafin wax", "D": "margarine"}, "answer": "D", "explanation": "The reaction described in the question is hydrogenation, where hydrogen is added to an unsaturated compound in the presence of a catalyst. This process is used in the manufacture of margarine from vegetable oils. So, the correct answer is 'margarine'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>42", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES~~BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS", "question": "The organic substance are labelled K and L .if K gave a blue-black colour with iodine solution and L gave a deep red precipitate with millions reagent, it can be concluded that", "images": [], "options": {"A": "K is a carbohydrate and L is a protein", "B": "K is alkaline and L is acidic", "C": "K is unsaturated and L is a reducing sugar", "D": "K is reducing agent and L is an amino acid"}, "answer": "A", "explanation": "When carbohydrates reacts with iodine solution iodine solution , iodine turn a blue-black coclour .  Million's reagent is used to test for the presence of soluble protein , it reacts with tyrosine amino acids , common to most protein and result in the formation of a deep red precipate .", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>43", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A colourless odourless liquid T, gives effervescence with sodium trioxocarbonate(IV) and a white precipitate with silver trioxonitrate(V) solution. T is most probably", "images": [], "options": {"A": "Sodium chloride solution", "B": "barium chloride solution", "C": "dilute trioxonitrate (V)acid", "D": "dilute hydrochloric acid"}, "answer": "D", "explanation": "Chloride gives white precipate with AgNO3 while acids reacts with Trioxocarbonates IV to give CO2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>44", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "When sodium hydroxide solution is added to a solution of Zinc salt, white preciptate formed redisolved in the excess sodium hydroxide because", "images": [], "options": {"A": "sodium is more reactive than zinc", "B": "sodium hydroxide is a strong alkali", "C": "Zinc hydroxide is amphopteric", "D": "zinc hydroxide is unstable"}, "answer": "C", "explanation": "Zinc hydroxide is amphoteric, meaning it can act as both an acid and a base. When sodium hydroxide is added to a solution of zinc salt, a white precipitate of zinc hydroxide is formed. However, when excess sodium hydroxide is added, the zinc hydroxide dissolves because it reacts with the sodium hydroxide to form a complex ion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>45", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "in the electrolytic extraction of aluminium from purified alumina, molten cryolite is added in order to", "images": [], "options": {"A": "lower the melting point of the alumina", "B": "prevent the aerial oxidation of the molten aluminium", "C": "lower the activation energy of the reaction", "D": "from a protective crust on top of electrolyte"}, "answer": "A", "explanation": "Aluminium is extracted  using electrolysis, but the aluminium oxide must be melted so that electricity can pass through it. Due to high meltig point of aluminium oxide , Croyolite (AlF3) is added to reduce the melting point of alumina (Al2O3)", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2000>46", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "If 20cm3 of distilled water is added to 80cm3 of 0.50 mol dm-3hydrochloric acid, the concentration of the acid will change to", "images": [], "options": {"A": "0.20 mol dm-3", "B": "0.40 mol dm-3", "C": "2.00 mol dm-3", "D": "5.00 mol dm-3"}, "answer": "B", "explanation": "C1V1 = C2V2  V1 = 80cm3 = 80/1000 = 0.08dm3  v2 = (80+20)cm3 = 100cm3 = 100/1000 = 0.1dm3  C1 = 0.50moldm-3  C1V1 = C2V2  C2 = C2 x 0.1  C2=0.08 x 0.50.1  C2 = 0.4moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>47", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following, on burning in air, contributes to acid rain?", "images": [], "options": {"A": "sulphur", "B": "magnesium", "C": "Alminium", "D": "zinc"}, "answer": "A", "explanation": "S + O2 →SO2  SO2 + H2O → H2 SO3 (acid)  SO2(g) is an acid anhydride, it reacts with water to form an acid", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>48", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "which of the following pollutant encourage the growth of algae in rivers?", "images": [], "options": {"A": "Oil spills", "B": "phosphates from detergent", "C": "suspended solid", "D": "pesticide residue"}, "answer": "B", "explanation": "When phosphate attaches to sediment and the dissolved oxygen concentration is low in the water , sediments release phosphate into water , which encourages the growth of algae.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2000>49", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Biotechnology  is applied in the following except", "images": [], "options": {"A": "baking industry", "B": "wine production", "C": "production of antibiotic", "D": "manufacture of soap"}, "answer": "D", "explanation": "Biotechnology is the use of  living organism to make technological advances and adapt those technologies to various different fields. Meanwhile , soap is the compound made from oil fats and caustic alkali. Hence , biotechnology is not used in making or manufacturing soap.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2000>50", "subject": "Chemistry", "year": "2000", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "A plastic which cannot be softened by heat is described as", "images": [], "options": {"A": "thermosetting", "B": "non-biodegradable", "C": "thermoplastic", "D": "malleable"}, "answer": "A", "explanation": "Thermosetting is a material hat strenghtens when heated but cannot be remolded while thermoplastic can be reheated , remolded and softened by heat.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2001>1", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "Allotropes of elements differ in their", "images": [], "options": {"A": "physical properties", "B": "chemical properties", "C": "mass numbers", "D": "electronic configuration"}, "answer": "A", "explanation": "Allotropes is the existence of an element in two or more forms in the same physical state . Allotropes of an element will show the same chemical properties but their physical properties varies e.g colour , density e.t.c", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>2", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "What is the mass number of an element if its atom contains 10 protons: 10 electrons and 12 neutrons", "images": [], "options": {"A": "32", "B": "22", "C": "20", "D": "10"}, "answer": "B", "explanation": "Mass number = proton number  + neutron number    = 10 + 12   = 22", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2001>3", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Given that the electronic configuration of an element X is 1S22S22p63S23P4, it can be deducted that X.", "images": [], "options": {"A": "belongs to group VI in the periodic table", "B": "Belongs to period 4 in periodic table", "C": "contain three unpaired electrons in the ground state.", "D": "has atomic number 27"}, "answer": "A", "explanation": "1S22s22P63S23P4  X = 2, 8 , 6 (conforming to element in each shell)  X has atomic number of 16. since it has 6 electron in its outermost shell, X belongs to groups 6.  Since it has 3 shells, it belongs to period 3 of periodic table.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>4", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "P,Q,R and S are metals in the same group in the periodic table but in periods 3,4,5 and 6 respectively. Which of them loses electron least readily ?", "images": [], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "A", "explanation": "Ionization energy is the energy required for a gaseous atom to lose electron and become a gaseous ion . It decreases down the group and increases across the period, the metal that releases its electron least readily is the one with the highest ionization energy which is the metal in period 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>5", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Element which belong to same group in the periodic table are charaterised by", "images": [], "options": {"A": "Difference of +1 in the oxidation number of successive member", "B": "Presence of same number of outermost electrons in the respective atoms", "C": "different of 14 atomic number mass unit between successive members", "D": "presence of the same number of electron shells in the respective atoms"}, "answer": "B", "explanation": "Elements in the same group have the same number of of outermost electron i.e have the same valence electron.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>6", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The atoms of an element X has two electrons in its outermost shell. What is the formula of the compound formed when X combine with aluminium(13AI)?", "images": [], "options": {"A": "AlX2", "B": "Al2X", "C": "Al2X2", "D": "Al2X3"}, "answer": "D", "explanation": "The formula of the compound formed when X combine with aluminium is Al2X3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>7", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "The presence of unpaired electrons in an atom of a transistion metals gives rise to", "images": [], "options": {"A": "paramagnetism", "B": "melleability", "C": "ductility", "D": "shiny appearance"}, "answer": "A", "explanation": "paramagnetism refer to the magnetic state of an atom with one or more unpaired electron . the unpaired electron are attracted by a magnetic field due to the electrons magnetic dipole moments", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2001>8", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "What is responsible for metallic bonding?", "images": [], "options": {"A": "sharing of electrons between the metals atoms", "B": "attraction between the atomic nuclei and cloud of electrons", "C": "transfer of electrons from one atoms to another", "D": "attraction between positive and negative ions"}, "answer": "B", "explanation": "Metallic bonding is the result of the attraction between the atomic nuclei and a cloud of electrons. This is often referred to as the 'sea of electrons' model. In this model, the electrons are delocalized, meaning they are free to move and are not associated with individual cations, but with the lattice as a whole. This results in the characteristic properties of metals, such as high electrical and thermal conductivity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2001>9", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following compounds is covalent?", "images": [], "options": {"A": "CACl2", "B": "MgO", "C": "NaH", "D": "CH4"}, "answer": "D", "explanation": "Covalent bonding is a type of chemical bonding which involves sharing of equal umber electrons donated by each participants , it usually occurs between two non-metals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>10", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.", "question": "A sheet of paper is placed in the path of beam from a radioactive source. the emissions that pass through the paper consist of", "images": [], "options": {"A": "Alpha particle and gamma rays", "B": "alpha and beta particlea", "C": "beta particles and gamma rays", "D": "alpha particles only"}, "answer": "C", "explanation": "Radiactivity emissions are Alpha particles, Beta particle and Gamma ray. The first is stopped by him sheet of paper , while the later two are stopped by Aluminium sheet and lead block respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>11", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "Which of the following features of a human skeleton can be determined by carbon-dating?", "images": [], "options": {"A": "Height", "B": "mass", "C": "age", "D": "race"}, "answer": "C", "explanation": "Carbon dating, also known as radiocarbon dating, is a method used by scientists to determine the age of organic material. It works by comparing the amount of Carbon-14 (an isotope of carbon that is present in all living things and decays over time) in the sample to the amount in the atmosphere. This allows scientists to determine when the organism that the sample came from died, and therefore, its age.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>12", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following statement about ideal gases is/are correct?  i. The cohesive forces between their particles are negligible  ii. they have no definite volume, but occupy the volume of their containers  iii. They are not compressible  Their particles collide with loss of energy", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "I, II and III only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "Properties of Ideal gases  - They are always in motion , colliding elastically within a container  - They take the shape of the container  -No force act on the molecules excepts during elastic collision of negligibe duration.  -both pressure and volume are directly proportional to temperature   - They are compressible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>13", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "P = P1 + P2 + P3 + ...Pn where Ptotalis the pressure of a mixture of gases. The equation above is an expression of", "images": [], "options": {"A": "Graham's law", "B": "Gay-lussac's law", "C": "Boyle's law", "D": "Dalton law's"}, "answer": "D", "explanation": "Dalton's law of partial pressure states that for gases which do not react chemically , the total pressure of the gases is sum of the partial pressure of individal gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>14", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "If 1.0 dm3 of gas X diffuse through a porous plug in 60 seconds while the same volume of hydrogen diffuses in 15 seconds under same conditions, calculate the relative molecular mass of X [H = 1.0]", "images": [], "options": {"A": "4.0", "B": "8.0", "C": "16", "D": "32"}, "answer": "D", "explanation": "Rate, R = Vol(V)/Time(t)  By cross multiplication , v = RT  Since volume is the same    RxTx=RHTH  RxRH=THTx  RxRH=1560  RxRH=14  From Graham's law of diffusion   RxRH=√RMMHRMMx  14=√2RMMx  Square both sids  1/16 =2/Rmmx  Rmmx = 32", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2001>15", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "which of the following pairs of reagent react to produce hydrogen?", "images": [], "options": {"A": "zinc and concentrated trioxonitrate(V)", "B": "water and calcium dicarbide", "C": "copper and dilute hydrochloric acid", "D": "magnesium and dilute tetraoxosulphate(VI) acid"}, "answer": "D", "explanation": "A. Zn + HNO3 →Zn(NO3)2 + H2O  B. H2O + CaC2 →CaO + C2H2  C. Cu + Hcl → no reaction  D. Mg + H2SO4 → MgSO4 + H2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>16", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "A mixture of calcuim chloride and calcium trioxocarbonate (IV)in water can be seperated by", "images": [], "options": {"A": "evaporation", "B": "sublimation", "C": "distillation", "D": "filtration"}, "answer": "D", "explanation": "A mixture of calcium chloride and calcium trioxocarbonate (IV) in water can be separated by filtration. Calcium chloride is soluble in water while calcium trioxocarbonate (IV) is not. Therefore, when the mixture is filtered, the calcium chloride will pass through the filter, leaving the calcium trioxocarbonate (IV) on the filter paper.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>17", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following would dissolve in warm dilute H2SO4 without effervecene, to give a blue solution ?", "images": [], "options": {"A": "copper turnings", "B": "copper(II)trioxocarbonate(IV)", "C": "copper(II)oxide", "D": "copper alloy"}, "answer": "C", "explanation": "Effervescene means evolution of gas  CuO + H2SO4 →CuSO4 + H2O(l) which after a whil may give CuSO4 . 5H2O (blue)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>18", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "in which of the reaction represented by the following equation is HNO3 behaving as a typical acid?", "images": [], "options": {"A": "CaO + 2HNO3 → Ca(NO3)2 + H2O", "B": "Cu + 4HNO3 →Cu(NO3)2 + 2H2O + 2NO2", "C": "S + 6HNO3 →H2SO4 + 6NO2 + 2H2O", "D": "P + 5HNO3 →H3PO4 + 5NO2 + H2O"}, "answer": "A", "explanation": "In option B, HNO3 acts as oxidizng agent by incrasing the oxidation number of Cu fro 0 to + 2. In option c, HNO3 also serves as oxidizing agaent. it increases oxidation nuber of S from 0 to +6. Also in option D, HNO3 serves as an oxidizing agent by increasing the oxidation agent by increasing  the oxidation number of P from 0 to +5  CaO + 2HNO3 → Ca(NO3)2 + H2O    CaO acts as a base while HNO3 is an acid , a neutralisation process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>19", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A gas was evolved when a sample of gastric juice reacted with sodium trioxocarbonate(IV)    The gas evolved was", "images": [], "options": {"A": "NH3", "B": "SO2", "C": "HCl", "D": "CO2"}, "answer": "D", "explanation": "Gastric juice consists of organic acid which reacts with trixocarbonate IV salt to liberate CO2 gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>20", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "It can be concluded that gastric juice", "images": [], "options": {"A": "contain enzymes", "B": "is acidic", "C": "is a mixture", "D": "has pH value of 7"}, "answer": "B", "explanation": "Electron affinity is the gastric acid is an acid and acid reacts with trioxocarbonate IV salts to liberate CO2g  CO32- + 2H3O+ → CO2g + 3H2Ol", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>21", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "What does ∆H represent in the following equation ? Cl(g) + e- → Cl- ; ∆H = -363 kJ mol-1", "images": [], "options": {"A": "ionization  energy", "B": "electron affinity", "C": "dissociation energy", "D": "Heat of atomization"}, "answer": "B", "explanation": "Electron affinity is the amount of energy released when an electron is added to a neutral atom to make it negativity charged , since energy is released , it is an exothermic reaction . This energy is given a neagtive sign.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>22", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "consider the following equation Ag+(aq) + Cl-(aq) → Ag+Cl(s); ∆H = -65.7 kJ mol-1. from the equation, it can be deducted that", "images": [], "options": {"A": "direct combination is involved and the reaction is endothermics", "B": "a solid is formed and heat is evolved", "C": "activation energy is high and catalyst is required.", "D": "the reaction is endothermics and occur at high teperature"}, "answer": "B", "explanation": "The equation shows that a solid (AgCl) is formed from the reaction of Ag+ and Cl- ions in aqueous solution. The negative ∆H value indicates that the reaction is exothermic, meaning heat is released during the reaction. An exothermic reaction is one in which energy is released to the surroundings, usually in the form of heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>23", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "A reaction is represented by the equation below A2(g) + B2(g) ⇌ 2AB(g) ; ∆H = xkJ mol-1  which of the following staement  about the system is correct?", "images": [], "options": {"A": "The forward reaction is exothermic", "B": "The reaction goes to completion at equilibrium", "C": "Pressure has no effect on the equilibrium mixture", "D": "At equilibrium increase in temperature favours the reverse reaction"}, "answer": "C", "explanation": "Pressure has no effect when there is no change in volume (i.e gases). when the number of mole of gaseous molecules at the reactant does not match product side ,only will pressure have effect.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2001>24", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What is the oxidation number of nitrogen in Al(NO3)3?", "images": [], "options": {"A": "+1", "B": "+3", "C": "+5", "D": "+6"}, "answer": "C", "explanation": "Al(NO3)3  Al = +3 , O = +2  Since the compound doesn't carry a charge , its  oxidation number is 0  +3 + [N + (-2 x 3)]3  = 0  3 + 3[N-6] = 0  3+3N - 18 = 0  3N - 15 = 0  3N = 15  N = +5", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>25", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Which is oxidized in the reaction represented by the following equation?   3Cu + 8HNO3 →3Cu(NO3)2 + 2NO + 4H2O", "images": [], "options": {"A": "Oxygen", "B": "hydrogen", "C": "nitrogen", "D": "copper"}, "answer": "D", "explanation": "In the given reaction, copper (Cu) is oxidized. Oxidation is a process where a substance loses electrons. In this reaction, copper (Cu) changes from an uncharged state to a charged state (Cu2+), indicating that it has lost electrons and thus has been oxidized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>26", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following substance decomposes when an electric current is passed through it?", "images": [], "options": {"A": "Glucose solution", "B": "Zinc rod", "C": "Hydrochloric acid", "D": "tetrachloromethane"}, "answer": "C", "explanation": "An electrolyte decomposes when current passes through it . An electrolysis is an ionic compound or polar compound", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>27", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "A concentrated solution containing H+, Cu2+, OH- and Cl was electrolyzed using platinum electroes. Which of the ions will be discarged  at the cathode?", "images": [], "options": {"A": "H+", "B": "Cu2+", "C": "OH-", "D": "Cl-"}, "answer": "B", "explanation": "H+ and Cu migrates to the cathode but copper is discharged in prefernce to H+ because, it is lower in the electrochemical series.  Cu2+ + 2e- → Cu", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>28", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Given that the order of reactivity of four metals is p> Q>R>S, which of the following reaction is feasible?", "images": [], "options": {"A": "S + p+ →P + S+", "B": "Q + S+ → S + Q+", "C": "R + P+ →P + R+", "D": "S + Q+ →Q + S+"}, "answer": "B", "explanation": "In a reactivity series, a more reactive metal can displace a less reactive metal from its salt solution. Given the order of reactivity as p> Q>R>S, metal Q is more reactive than metal S. Therefore, Q can displace S from its salt solution. Hence, the reaction Q + S+ → S + Q+ is feasible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>29", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "In the electrolysis of CuSo4(aq) using electrodes the reaction at the anode is", "images": [], "options": {"A": "Discharge  of SO42-", "B": "Discharge of OH-", "C": "Dissolution of copper electrode", "D": "evolution of oxygen"}, "answer": "C", "explanation": "ions  : Cu2+, So42-, H+, OH-  At the anoe :  Istead of discharging any of the ions (OH- and SO2-4), The anode (copper rod) dissolves togies its own ion solution.   Cu →Cu2+ + 2e-.  the idea is this , whenever the ion of the anode is present in solution , the anode dissolves into the solution and it is deposited at the cathode", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2001>30", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "A feasible cell was constructed by joining the two half cell below Cu+ + 2e- →Cu(s) E∘ = + 0.34v ; Zn2+(aq) + 2e- → Zn(s)E∘ = -0.76v what is the standard e.m.f of the the cell?", "images": [], "options": {"A": "-1.1v", "B": "-0.42v", "C": "+0.42v", "D": "+1.1v"}, "answer": "D", "explanation": "The standard electromotive force (E°) of a cell is calculated by subtracting the standard reduction potential of the anode from that of the cathode. In this case, Cu is the cathode and Zn is the anode. Therefore, E°cell = E°cathode - E°anode = (+0.34v) - (-0.76v) = +1.1v. Hence, the standard e.m.f of the cell is +1.1v.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2001>31", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Hydrogenation of butene yields", "images": [], "options": {"A": "butyne", "B": "butane", "C": "pentene", "D": "butanol"}, "answer": "B", "explanation": "C4H8 + H2 →C4H10(Butane)When one mle of H2 is added to any alkene member , it yield its corresponding alkane member .  CnH2n + H2 →CnH2n+2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>32", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : BENZENE", "question": "Benzene produces more soot then ethane on burning because benzene", "images": [], "options": {"A": "has a higher molar mass", "B": "has a higher degree of unsaturation", "C": "undergoes both substitution  and addition reactions", "D": "is a liquid at room temperature"}, "answer": "B", "explanation": "Presence of multiple bonds makes a compound to burn smoky sooty flame, unsaturation means multiple bonds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>33", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "", "images": ["Chemistry/imgs/2001/v21.png"], "options": {"A": "tetiary alkanol", "B": "alkanone", "C": "alkanoic acid", "D": "alkanoate"}, "answer": "D", "explanation": "CH3COOC3H7.This can be generally written as RCOOR.Hence , the compound is an alkanoate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2001>34", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Which of the following fraction of crude oil is likely to contain the hydrocarbon C12H26?", "images": [], "options": {"A": "kerosine", "B": "Naphtha", "C": "Gas oil", "D": "fuel oil"}, "answer": "A", "explanation": "Naptha consists 5 - 6 carbons  Fuel oil consists 15 - 18 carbons   Kerosene consists 10 - 16 carbon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>35", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : AMINO ACIDS", "question": "What is the IUPAC name of the compound below", "images": ["Chemistry/imgs/2001/v20.png"], "options": {"A": "1-aminoethanoic acid", "B": "1-aminomethanoic acid", "C": "2-aminoethanoic acid", "D": "3-aminoethanoic acid"}, "answer": "C", "explanation": "Th compound is an alkanoic family compound due to the presence of (-COOH), in which an amino group (-NH2) is attached , hence the name of the compound is 2-aminoethanoic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>36", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following compound exhibit both structural isomerism and cis-trans isomerism?", "images": [], "options": {"A": "C4H8", "B": "CH3OCH3", "C": "C5H12", "D": "C6H6"}, "answer": "A", "explanation": "C4H8 can exhibit both structural isomerism and cis-trans isomerism. Structural isomerism occurs when two or more compounds have the same molecular formula but different structural formula. Cis-trans isomerism, also known as geometric isomerism, is a type of stereoisomerism where the spatial arrangement of atoms differs, but the order of atomic connectivity remains the same.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>37", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "IF X reacts with excess acidified k2 Cr2O7 to produce an alkanoic acid, X is an", "images": [], "options": {"A": "alkanol", "B": "alkene", "C": "amino acid", "D": "alkanone"}, "answer": "A", "explanation": "Alkanol is oxidized to alkanoic acid with the help of acidified K2Cr2O7  C2H5OH (ethanol) + 20 →CH3COOH (ethanoic acid) + H2O", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>38", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "One of the products of combustion of pentane in excess air is", "images": [], "options": {"A": "pentanol", "B": "pentene", "C": "nitrogen(II)oxide", "D": "carbon(IV)oxide"}, "answer": "D", "explanation": "One of the products of combustion of pentane in excess air is carbon(IV)oxide. Combustion is a high-temperature exothermic redox chemical reaction between a fuel and an oxidant, usually atmospheric oxygen, that produces oxidized, often gaseous products, in a mixture termed as smoke. In complete combustion, the reactant burns in oxygen, and produces a limited number of products. When a hydrocarbon burns in oxygen, the reaction will primarily yield carbon dioxide and water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>39", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Which is the following polymers contain nitrogen?", "images": [], "options": {"A": "Nylon", "B": "polyvinyl chloride", "C": "polyethene", "D": "cellulose"}, "answer": "A", "explanation": "A polymer is a substance made of any repeating chemical units or molecules . Most polymer contains carbon and hydrogen, though they may also have oxygen , chlorine , fluorine, nitrogen , silicon, sulphur and phosphorus , Nylon contains nitrogn , polyvinychloride  contains chlorine , Tiflon contains fluorine, polyster and polyster and polycarbonate contains oxygen.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2001>40", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "What is the function of H2SO4 in the following reaction? C12H22O11 →con. H2SO4 12C + 11H2O", "images": [], "options": {"A": "oxidation  agent", "B": "strong acid", "C": "Dehydrating agent", "D": "catalyst"}, "answer": "C", "explanation": "C12H22O11  →con.H2SO4 12C + 11H2O  H2SO4 removes water content from sugar and turns it to charcoal which is dehydration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>41", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Which is the following establishments uses the process of fermentation in its operation?", "images": [], "options": {"A": "fetilizer plant", "B": "textile industry", "C": "Brewery", "D": "soap manufacturing industry"}, "answer": "C", "explanation": "Fermentation of starch  gives ethanol , this is the foaming that occurs during the manufacture of wine and beer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>42", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Sugar can be hydrolyzed at room temperature by the action of", "images": [], "options": {"A": "mineral acids", "B": "strong bases", "C": "enzymes", "D": "oxidants"}, "answer": "C", "explanation": "Simple sugar molecules (monosaccharide ) when combined to form larger molecules (dissacharides or polysaccharides) is called condenation , water molecules is generated in the process, the reverse process is known as hydrolysis. sugar can be hydrolyszed at room temperature by the action of enzymes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>43", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "which of the following constitute an advantage in the use of hard water?", "images": [], "options": {"A": "formation of scum with soap", "B": "furring of kettles", "C": "blockage of water pipes", "D": "formation of strong bones"}, "answer": "D", "explanation": "Advantages of hard water  - it taste better due to the presence of dissolved minerals  - It helps to reduced heart disease  - It strengthen bone and teeth since it contains dissolved calcium    Disadvantage of hard water   - It does'nt form lather with soap   - It stains cloths due scum formation  - It cause furring of kettle   - It can clog and corrode pipes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>44", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following compound is readily soluble in water?", "images": [], "options": {"A": "CuO", "B": "AgCl", "C": "NaSO4", "D": "CaCO3"}, "answer": "C", "explanation": "Among the given options, NaSO4 or Sodium Sulfate is readily soluble in water. Solubility is the property of a solid, liquid, or gaseous chemical substance called solute to dissolve in a solid, liquid, or gaseous solvent. The solubility of a substance fundamentally depends on the physical and chemical properties of the solute and solvent as well as on temperature, pressure and the pH of the solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2001>45", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Calculate the mass of ZnSO4Produced when excess of ZnCO3 is added to 50.0cm3 of 4.00 mol dm-3  H2SO4. The equation for the reaction is ZnCO3 + H2SO4 →ZnSO4 + CO2 + H2O [ZNSO4 = 161g mol-1]", "images": [], "options": {"A": "0.200g", "B": "1.29g", "C": "32.2g", "D": "39.0g"}, "answer": "C", "explanation": "ZnCO3 + H2SO4 →ZnSO4 + CO2 + H2O  Since ZnCO3 is in excess, we'll use H2SO4 which is the limited reagent   Mass,m of ZnSO4 = ?  Vol, V of H2SO4, v= 50cm3 = 50/1000 = 0.05dm   concentration, C of H2SO4, C = 4.00moldm-3  But , n  =CV   = 4 x 0.05   = 0.2 mol    1mole of H2SO4 gives 1 mole of ZnSO4  0.2 mol of H2SO4 will give 0.2 mol of ZnSO4  n=mass, mmolar mass, mm  Molar mss of ZnSO4 = 161gmol-1  0.2=m161  m = 0.2 x 161  m = 32.2g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2001>46", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "if 10cm3 of distilled water is added to 10cm3of an aqueous salt solution, the concentration of the solution", "images": [], "options": {"A": "increase", "B": "decreases", "C": "remains constant", "D": "doubles"}, "answer": "B", "explanation": "According to dilution theory , when certain amount of diluted water is added to a standard solutin ,the concentration decreases due to the increase in its volume but the number of moles of the solute remains the same.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>47", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which  of the following reaction represent the change that occurs when a photographic film is exposed to sunlight ?", "images": [], "options": {"A": "Ag→Ag++ e-", "B": "Ag+ + e- →Ag", "C": "2Ag + Br2 →AgBr", "D": "Ag+ + Br → AgBr"}, "answer": "B", "explanation": "AgBr, AgCl and AgI are the three silver halide compound used in photography , when exposed to light,chemical reaction darken the film to produce an image.If AgCl for example is used and the film containing Ag+ and Cl- is exposed to light energy the chlorine ions extra electrons is ejected and then captured by a silver ions  Ag+ + e- →Ag (reduction)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>48", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The main type of reaction that occurs in the blast furnace during the extraction of iron is", "images": [], "options": {"A": "reduction reaction", "B": "decomposition", "C": "exothermic reaction", "D": "combustion"}, "answer": "A", "explanation": "The main reaction taking place in a blast furnace prodcing molten iron Fe2O3 + 3CO →2Fe + 3CO2 this reaction is a reduction process since the oxidation of Fe is reduced from +3 to 0", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2001>49", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Acidic industrial waste can be treated with", "images": [], "options": {"A": "lime", "B": "brine", "C": "water", "D": "ethanol"}, "answer": "A", "explanation": "Acidic industrial waste can be treated with lime this is often to adjust the pH of water and soils containing acidic component.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2001>50", "subject": "Chemistry", "year": "2001", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Waste plastic accumulate in the soil and pollutes the environment because plastic materials aare", "images": [], "options": {"A": "insoluble in water", "B": "non-biodegradable", "C": "easily affected by heat", "D": "inflammable"}, "answer": "B", "explanation": "Waste plastics accumate in the soil and polute the environment because they are non-biodegradeable, hey cannot be decomposed or broken release toxic chemical that   are deposited in soil and water surface when burnt.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>1", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.", "question": "If the relative molecular mass of an element is not a whole number . it can be deducted that the element is", "images": [], "options": {"A": "naturally radioactive", "B": "Abundant in nature", "C": "a transition metal", "D": "an isotopic mixture"}, "answer": "D", "explanation": "The relative atomic mass of an element is the average value of its isotopic mixture , it is the weighted average of masses of the atoms of he isotopes", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>2", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Th atom of an element X is represented as yzX  the basic chemical properties of X depends on the value of", "images": [], "options": {"A": "Y", "B": "Z", "C": "Y-Z", "D": "Z-Y"}, "answer": "B", "explanation": "The periodic law states that the properties of elements are periodic functon of their Atomic number (Z)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>3", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The atomic number of chlorine is 17. what is the number of electrons in a chlorine ion ?", "images": [], "options": {"A": "16", "B": "17", "C": "18", "D": "19"}, "answer": "C", "explanation": "A neutral atom of chlorine has 17 electrons since its atomic number is 17, its chlorine ion is formed when it gains 1 electron. Therefore , it electron becomes 18 in number.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>4", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "A hydrogen atom which has lost an electron contains", "images": [], "options": {"A": "one proton only", "B": "B one neutron only", "C": "one proton and one neutron", "D": "one proton , one electron and neutron."}, "answer": "A", "explanation": "Hydrogen atom is represented as 11H , meaning 1 Proton , 1electron , 0 neutron , so if it loses one electron , it becomes ,1 proton, 0 electron ,0 neutron", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>5", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following element has a ground state electronic configuration with an incomplete penultimate shell?", "images": [], "options": {"A": "iron", "B": "sodium", "C": "Aluminium", "D": "calcium"}, "answer": "A", "explanation": "26Fe  The electronic configuration is     Since the 4s orbitals are higher in energy than Orbitals, therefore it becomes [Ar]3d64S2  Th penultimate shell 3d has incomplete electrons of 6 instead of 10 electrons, which is its maximum number of electron.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>6", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "The conclusion from Rutherford's alpha scattering experiment is that", "images": [], "options": {"A": "atoms are mostly empty space with small nucleus", "B": "emission from radioactive substance consist of three main components", "C": "there is a nuclear pull on orbital", "D": "electron are deflected by magnetic and electic field"}, "answer": "A", "explanation": "Alpha scattering experiment told us that the atom is an hollow empty space because most of the bombarded alpha particles went through the gold foil undeviated . However , few of it were deflected which reveals tht the atom consist of a small nucleus which has similar charge with the alpha particles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>7", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z    which of the letters indicate element which exist as diatomic gases", "images": [], "options": {"A": "W and Z", "B": "M and J", "C": "M and Y", "D": "Y and Q"}, "answer": "C", "explanation": "All the group 7 are diatomic but not all are gases, so M is a period III which is Cl2, a greenish yellow gas .Also Y is H2, a colourless gas", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>8", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z   which of the following pairs of letters denotes elements containing thhe same number of electrons in their outermost shells", "images": [], "options": {"A": "J and X", "B": "M and Q", "C": "W and Z", "D": "W and Y"}, "answer": "C", "explanation": "Elements with the same number of electrons in their outermost shell are located in the same group", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>9", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z   what letter represent an element that participate in covalent rather than ionic bonding?", "images": [], "options": {"A": "x", "B": "Q", "C": "Z", "D": "J"}, "answer": "A", "explanation": "Groups 3,4 and 5 elements participates in covalent bonding while groups ,1,2,6 and 7 are ionic", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>10", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z   Which of the letter represent an alkaline earth metal?", "images": [], "options": {"A": "M", "B": "Q", "C": "J", "D": "X"}, "answer": "C", "explanation": "In the periodic table, alkaline earth metals are found in Group II. Therefore, J, which is in Group II, represents an alkaline earth metal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>11", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "An element Y as the electronic configuration 1s22s22p63s23p4 to what period does it belong in the periodic table?", "images": [], "options": {"A": "3", "B": "4", "C": "5", "D": "6"}, "answer": "A", "explanation": "The element is 2+2+6+2+4 = 16  i.e sulphur  16S : 2,8,6. since it has 3 shells i.e K,Lm shells, then it belongs to period table", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>12", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "If a metal R form a compound with formula R(NO3)2, the formula of its tetraoxosulphate(IV) is", "images": [], "options": {"A": "R(SO4)2", "B": "RSO4", "C": "R2SO6", "D": "R2(SO4)3"}, "answer": "B", "explanation": "R(NO3)2 when dissociated will be R2+ NO3-. So,when R2+ combines with SO42-, it will be RSO4 after valence crossing must taking place", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>13", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following decrease when a given mass of gas is compressed to half its initial volume?", "images": [], "options": {"A": "Average intermolecular distance", "B": "Frequency of collisions", "C": "Number of molecules present", "D": "Atomic radius of each particle"}, "answer": "A", "explanation": "When the volumes is half (B), the number of molecules however remains the same but the frequency of collision increass which in turn increases pressure. From the diagram . distance between molecules have been reduced due to less space", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>14", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE", "question": "What volume of hydrogen will be produced if 100cm3 of ammonia is completely decomposed at constant temperature and pressure ?. the equation for the reaction is 2NH3(g) → N2(g) + 3H2(g)", "images": [], "options": {"A": "50cm3", "B": "150cm3", "C": "200cm3", "D": "300cm3"}, "answer": "B", "explanation": "2NH3 → N2 + 3H2  2 moles of NH3 → 3 moles of H2  100cm3 wll give x of H2  2x = 100 x 3  x = 150cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>15", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "calculate the mass of chlorine gas which occupies a volume of 1.12 dm3 at s.t.p  [Cl = 35.5; 1 mole of gas occupies 22.4 dm at s.t.p]", "images": [], "options": {"A": "1.80g", "B": "3.55g", "C": "7.10g", "D": "15.50g"}, "answer": "B", "explanation": "Noofmole,n=mass,mmolar mass,MM  Also,n=Volume,vmolar volume,MV  n=1.1222.4=0.05mol  Fromn=mMM0.05=m71  m = 0.05 x 71   = 3.55 g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2002>16", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.", "question": "Determine the mass of sulphur(IV) oxide obtained when 91.0 g of oxygen reacts completely with sulphur according to the following  equation.  S(s) + O2(g) → SO2(g) [S = 32; O = 16]", "images": [], "options": {"A": "123g", "B": "139g", "C": "155g", "D": "182g"}, "answer": "D", "explanation": "Ss + O2g → SOg  32gmol-1 of S reacts with O2 to roduce 64gmol-1 of SO2  91g of S reacts with O2 to produce xg of SO2  xg=91x6432   = 1182g", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>17", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The gas off when NH4Cl is heat with an alkali is", "images": [], "options": {"A": "H2", "B": "Cl2", "C": "N2", "D": "NH3"}, "answer": "D", "explanation": "When ammonium chloride (NH4Cl) is heated with an alkali, the gas evolved is ammonia (NH3). This is because the alkali provides a source of hydroxide ions (OH-) which react with the ammonium ions (NH4+) in the ammonium chloride to produce water (H2O) and ammonia gas. The reaction can be represented as follows: NH4Cl + OH- → NH3(g) + H2O. Therefore, the correct answer is NH3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>18", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "A major factor considered in selecting a suitable method for preparing a simple salt is its", "images": [], "options": {"A": "crystalline form", "B": "melting point", "C": "reactivity with dilute acids", "D": "solubility in water"}, "answer": "D", "explanation": "The solubility of a salt in water is a major factor considered in selecting a suitable method for its preparation. This is because the solubility of the salt determines whether it can be prepared by a precipitation reaction, which involves mixing two solutions to form a precipitate (an insoluble salt), or by an evaporation method, which involves dissolving the salt in water and then evaporating the water to leave behind the salt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>19", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following acids forms normal salts only", "images": [], "options": {"A": "tetraoxosulphate (VI)acids", "B": "Trioxosulphate(IV) acid", "C": "Tetraoxophosphate(V)acid", "D": "Trioxonitrate(V)acid"}, "answer": "D", "explanation": "Monobasic acids will give rise to normal salt acidic salt . HNO3 is the only monobasic acid the options.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>20", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "A substance is said to be hygroscopic if it absorbs", "images": [], "options": {"A": "water from the atmosphere to form a solution", "B": "heat from the surounding", "C": "carbon(IV)oxide from the atmosphere", "D": "moisture from the atosphere without dissolving"}, "answer": "D", "explanation": "A substance is said to be hygroscopic if it absorbs moisture from the atmosphere without dissolving. Hygroscopic substances have a high affinity for water molecules and can attract and hold water molecules from the surrounding environment. However, they do not dissolve in the absorbed water. Instead, they may form a solution if the amount of water absorbed is sufficient. The other options do not correctly define a hygroscopic substance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>21", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "which of the following substance increases in mass when heated in air?", "images": [], "options": {"A": "sodium chloride", "B": "iodine crystals", "C": "magnesium ribbon", "D": "copper (II) oxide"}, "answer": "C", "explanation": "When magnesium ribbon is heated in air, it reacts with oxygen to form magnesium oxide. This reaction is an oxidation reaction, where magnesium is oxidized to magnesium oxide. The mass of the magnesium ribbon increases because oxygen from the air is being added to the magnesium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>22", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Calculate the mass of sodium hydroxide in 5.00 dm3 of a 0.125 mol dm-3 solution [NaOH = 40g mol-1]", "images": [], "options": {"A": "0.0156g", "B": "0.625g", "C": "1.00g", "D": "25.0g"}, "answer": "D", "explanation": "Molar mass of NaOH =23+16g + 1 = 40g/mol  No of mole , n  = concentration , c x volume v\\n = 0.125 x 5   = 0.625 mol  Fromn=Massmolar mass  0.625=m40  m = 40 x 0.625   = 25g", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>23", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following salt solution will have a pH greater than 7?", "images": [], "options": {"A": "NaCl(aq)", "B": "Na2CO3(aq)", "C": "Na2SO(aq)", "D": "NaHSO4(aq)"}, "answer": "B", "explanation": "NaCl  +H2O   ⇌   NaOH + HCl  NaCO3 + H2O ⇌ NaOH + H2CO3  Na2SO4 + H2O ⇌ NaOH + H2SO4  NaHSO4 + H2O ⇌ NaOH + H2SO4  Only option B gives a strong base and weak acid .Hence a strong base and a weak acid gives a salt which is basic  i.e has a pH greater than 7", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>24", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "What will happen if more heat is applied to the followig system at equilibrium?  X2(aq) + 3y ⇋ 2XY3(g) ; ∆H = -xkJmol-1", "images": [], "options": {"A": "The yield of XY, will increase", "B": "more of XY, will decompose", "C": "more of XY, will react", "D": "The forward reaction will go to completion"}, "answer": "B", "explanation": "Since the reaction is exothermic i.e ∆H ≺ 0 ncreases in temperature favours the backward reaction , it should be noted that increase in temperature favours a side that is endothermic which decrease in temperature favours the side that is exothermic", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>25", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "What is the expression for the equilibrum contant (Kc) for the following reaction ?  N2(g) + O2(g) ⇋ 2NO(g)", "images": [], "options": {"A": "(NO)2(N2)+(O2)", "B": "(2NO)2(N2)(O2)", "C": "(N2)+(O2)2(NO)2", "D": "(NO)2(N2)(O2)"}, "answer": "D", "explanation": "N2(g) +O2(g) ⇋ 2NO(g)  Equilibriumconstant,kc=(NO)2(N2)(O2)  in determining equilibrium constant , only gaseous and aqueous substances are considered.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2002>26", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Equal amount of marble chip react separately with 100cm3 of hydrochloric acid of different concentrations if all the marble chips reacted, which of the following reamined the same in each case.", "images": [], "options": {"A": "Average rate of evolution of gas", "B": "total mass of gas evolved during the reaction", "C": "time taken for the reaction to reach completion", "D": "initial reaction rates"}, "answer": "B", "explanation": "The total mass of gas evolved during the reaction will remain the same in each case. This is because the amount of marble chips is the same in each case, and the reaction goes to completion. Therefore, the same amount of gas will be produced in each case, regardless of the concentration of the hydrochloric acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>27", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "CuSO4.5H2O can be obtained from an aqueous solution of copper (II) tetraoxosulphate(VI) by", "images": [], "options": {"A": "evapouration to dryness", "B": "using chromatography", "C": "precipitation", "D": "crytallization"}, "answer": "D", "explanation": "Crystallization is a separation technique that is used to separate a solid that has dissolved in a liquid and made a solution. The solution is warmed in an open container, allowing the solvent to evaporate, leaving a saturated solution. When the saturated solution cools, the solid comes out of solution and crystals form. In this case, CuSO4.5H2O can be obtained from an aqueous solution of copper (II) tetraoxosulphate(VI) by crystallization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>28", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Which of the following compound will leave a metal residue when heated?", "images": [], "options": {"A": "CU(NO3)2", "B": "AgNO3", "C": "K2CO3", "D": "CaCO3"}, "answer": "B", "explanation": "Cu(NO3)2 →∆CuO + NO2 + O2  AgNO3 →∆Ag + NO2 + O2  K2CO3 →∆ can't decompose   CaCO3 →∆CaO + CO2", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>29", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "A visible change is observed when a strip of iron is placed in an aqueous solution of", "images": [], "options": {"A": "FeSO4", "B": "ZnSO4", "C": "CuSO4", "D": "MgSO4"}, "answer": "C", "explanation": "When a strip of iron is placed in an aqueous solution of copper(II) sulfate (CuSO4), a visible change is observed. This is due to a displacement reaction where iron displaces copper from copper sulfate solution to form iron sulfate (FeSO4) and copper (Cu). The blue solution of copper sulfate turns green due to the formation of iron sulfate and reddish-brown copper is deposited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>30", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Consider the following   Cr2O2-7(aq) + 14H+(aq) + 6e- →2Cr3+(aq) + 7H2O(l)  The oxidation number of chromium changes from", "images": [], "options": {"A": "-2 to +3", "B": "-2 to +6", "C": "+6 to +3", "D": "+7 to +6"}, "answer": "C", "explanation": "Cr2O72- + 14H+ + 6e- →2Cr3+ + 7H2O  to get the oxidation state in Cr2O72-  2Cr + (-2 x 7) = 2  2Cr = 12  Cr = 12/2  Cr = +6  the oxidation state of Cr in Cr3+ is +3  The oxidation number of Cr chnages from +6 to +3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>31", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following ions require the largest quantity of electricty for discharge at an electrodes?", "images": [], "options": {"A": "2.0 mole of Q3+", "B": "2.5 mole of R2+", "C": "3.0 mole of T-", "D": "4.0 mole of Y-"}, "answer": "A", "explanation": "1 mole of Q3+ → 3 faraday  (since 1e- = 1 faraday)  2 moles of Q3+ will need  →2 x 3F  = 6F  2 moles of Q3+ will require the largest quantity of electricity", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2002>32", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "If two metallic ions of the same concentration migrate to graphite  cathode, this one that would be preferentially discharged is the one that has the", "images": [], "options": {"A": "A smaller mass", "B": "lower electrical", "C": "greater stability in solution", "D": "Stronger tendency to acdept electrons"}, "answer": "D", "explanation": "Factors that affect is charge of ion are concentrations, position of ion the electrochemical series and nature of the electrode. The position of ion in the in the electrochmical series is th tendency of the ion to accept electrons to become a neutral atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>33", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "When concentrated sodium chlorine solution is electrolysed using inert electrodes, the products are", "images": [], "options": {"A": "oxygen and hydrogen", "B": "hydrogen and chlorine", "C": "sodium and oxygen", "D": "sodium and chlorine"}, "answer": "B", "explanation": "At the cathode :  Na+ and H+ migrate to the cathode where H+ is discharged because it is lower in the electrochemical series.  2H+ + 2e- →H2  At the anode :  cl- and OH- migrate to anode where C- is discharged because of its concentration   2Cl- →Cl2 + 2e-  The products are H2 and Cl2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>34", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "Which of the following processes takes place during the production of margarine from vegetable oils?", "images": [], "options": {"A": "Esterification", "B": "hydrolysis", "C": "hydrogenation", "D": "saponification"}, "answer": "C", "explanation": "The process that takes place during the production of margarine from vegetable oils is hydrogenation. Hydrogenation is a chemical reaction between molecular hydrogen and another compound or element, usually in the presence of a catalyst. In the case of margarine production, the vegetable oils (which are unsaturated fats) are hydrogenated to convert them into saturated fats, which are solid at room temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>35", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following compouds can be represented by molecular formula C2H6O", "images": [], "options": {"A": "Propanol", "B": "Ethanol", "C": "methanoic acid", "D": "Glucose"}, "answer": "B", "explanation": "C2H6O  can be written as C2H5OH which is ethanol which follows the general molecular formular of alkanol CnH2n+1OH", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>36", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "When alkynes are hydrogenated completely, they produced compounds with the generals molecular formula", "images": [], "options": {"A": "CnHn", "B": "CnH2n+2", "C": "CnH2n", "D": "CnH2n-2"}, "answer": "B", "explanation": "Hydrogenation of Alkynesgives Alkene , further hydrogenation gives Alkanes  Taking ethyne (C2H2) as a case study  C2H2 →C2H4 (ethene)  C2H4 + H2 → C2H6  Alkanes have general molecular formular CnH2n+2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>37", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "The following compound are hydrocarbons except", "images": [], "options": {"A": "methylpropanoate", "B": "2-methylbutane", "C": "benzene", "D": "cyclohexane"}, "answer": "A", "explanation": "Hydrocarbons are compounds that have hydrogen and carbons Only. Alkanoates are writte as RCOOR . hence , they do not have only carbon and hydrogen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>38", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "The reaction between ethene and chlorine to form 1,2-dichloroethane is", "images": [], "options": {"A": "oxidation", "B": "polymerization", "C": "addition", "D": "substitution"}, "answer": "C", "explanation": "Addition reaction is undergone by unsaturated hydrocarbon . The bond is broken and more saturated hydrocarbon is formed", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>39", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Which of the following statement about soapless detergents is correct? they", "images": [], "options": {"A": "lather readily with hard water", "B": "increase the surface tension of water", "C": "caused hydrolysis of salts in water", "D": "form a curdy precipitate with soft water"}, "answer": "A", "explanation": "Soapless detergents, also known as synthetic detergents, are surfactants that do not form a precipitate with hard water. They lather readily with hard water because they do not react with the calcium and magnesium ions in hard water to form insoluble salts, unlike soaps. This makes them more effective cleaning agents in hard water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>40", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Determine the molar mass of the following compounds  [H = 1; C = 12; O = 16]", "images": ["Chemistry/imgs/2002/v24.png"], "options": {"A": "45g mol-1", "B": "61g mol-1", "C": "122g mol-1", "D": "123g mol-3"}, "answer": "C", "explanation": "The ring is a benzene (C6H6) ring in which one hydrogen aomhas been replaced with (CooH).The molecular formular can be written as C6H5COOH.The molecular formula can be written as C6H5COOH  Molar mass = (12 x 6) + (1 x 5) + 12 +16 + 1   122 g/mol", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>41", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "Which of the following types of alkanols undergo oxidation to produce alkanoic acids?  I. primary alkanols  II. secondary alkanols  III. Tetiary alkanols", "images": [], "options": {"A": "I,II and III", "B": "I and II only", "C": "II only", "D": "I only"}, "answer": "D", "explanation": "Primary alkanols udergo oxidation to give alkanals and finally alkanoic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>42", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A suitable reagent for distinguishing between ethanoic acids and ethanol is", "images": [], "options": {"A": "bromine water", "B": "Fehling`s solution", "C": "sodium hydrogentrioxocarbonate (IV)", "D": "ammoniacal silver trioxonitrate (V)."}, "answer": "C", "explanation": "Sodium hydrogentrioxocarbonate (IV) is a suitable reagent for distinguishing between ethanoic acids and ethanol. Ethanoic acid reacts with Sodium hydrogentrioxocarbonate (IV) to produce carbon dioxide gas that can be observed as effervescence, while ethanol does not react.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>43", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "The reaction of sucrose with HCl Produces", "images": [], "options": {"A": "an alkanoate", "B": "glucose and fructose", "C": "a black mass of carbon", "D": "a polysaccharide"}, "answer": "B", "explanation": "Sucrose is protonated by Hcl then undergoes hydrolysis reaction to yield glucose and frutose as a final products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>44", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "use the structue to answer question below      What is the IUPAC name of the compound with this structure", "images": ["Chemistry/imgs/2002/CYF4X6.png"], "options": {"A": "3-methylbutane", "B": "3-methylpentane", "C": "2-methylbutane", "D": "2-methylpropane"}, "answer": "C", "explanation": "It is an alkane family because of carbon to carbon single throughout . The longest carbon to carbon chain consist of 4 carbon i.e butane , the attachment CH3(methyl) is on the 2nd and 3rd carbon when numbered L-R and R-L respectively , the rule says a smaller value is choosen .The name is 2-methylbutane", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>45", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "use the structue to answer question below    Which of the following compounds is its structural isomer", "images": ["Chemistry/imgs/2002/CYF4X6.png"], "options": {"A": "2,2-dimethylpropane", "B": "2-ethylpropane", "C": "1,2 dimethyl propane", "D": "2 - methylpentane"}, "answer": "A", "explanation": "2,2-dimethylpropane     2,2-Dimethylpropane is a branched-chain alkane and is a structural isomer of pentane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>46", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "The energy value of petrol can be determine by a", "images": [], "options": {"A": "bomb calorimeter", "B": "catalytic cracker", "C": "fractionating column", "D": "thermometer"}, "answer": "A", "explanation": "The energy level of organic compound is the mass content according to Albert Einstein.  E = ∆mc2.  Bomb calorimeter is a closed rigid vessel that can used to determine the heat of fraction of a liquid or solid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>47", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "use the solubility curve of X and Z       Which of the following statement about X and Z is correct?", "images": ["Chemistry/imgs/2002/LH7EKT.jpg"], "options": {"A": "X is the more soluble solidat all temperatures", "B": "X and z are insoluble at 0∘C", "C": "0.20 mol dm-3 solution of Z at 10∘C is unsaturated", "D": "Z is more soluble than X at temperature below 20∘C"}, "answer": "D", "explanation": "At a temperature below 20∘c, the solubility of Z is around 0.20moldm-3 while that of X is less than that.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2002>48", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "use the solubility curve of X and Z     What is the solubility of Z at 50∘C?", "images": ["Chemistry/imgs/2002/LH7EKT.jpg"], "options": {"A": "0.20 mol dm-3", "B": "0.25 mol dm-3", "C": "0.35 mol-3", "D": "0.50 mol dm-3"}, "answer": "D", "explanation": "This is determined by tracing 50∘ to Z  curve and tracing it solubility axis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2002>49", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "iron is often galvanized in order to", "images": [], "options": {"A": "makes it more malleable", "B": "remove the impurities in it", "C": "protect it against corrosion", "D": "render it passive"}, "answer": "C", "explanation": "Iron is often galvanized to protect it against corrosion. Galvanization is the process of applying a protective zinc coating to iron or steel, to prevent rusting. The most common method is hot-dip galvanization, in which the parts are submerged in a bath of molten zinc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2002>50", "subject": "Chemistry", "year": "2002", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "One of the methods used for combating air pollution is", "images": [], "options": {"A": "burning of solid waste", "B": "provision of sanitary land fills", "C": "legislation against some industrial practices", "D": "scavenging of refuse dumps"}, "answer": "C", "explanation": "One of the methods used for combating air pollution is legislation against some industrial practices. This can include laws that regulate the amount of pollutants that can be released into the air, require the use of certain pollution control technologies, or mandate the cleanup of polluted areas. These laws can be enforced by government agencies and can result in penalties for non-compliance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>1", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The electronic configuration of an element is 1s22s22p63s23p3. Where is the element located in the periodic table?", "images": [], "options": {"A": "Group III, period 3", "B": "Group III, period 5", "C": "Group V, period 3", "D": "Group V, period 5"}, "answer": "C", "explanation": "1s22s22p63s23p3  The last five electrons are found on M shell which is the 3 in the electronic configuration, which stands for period 3, while the 5 electrons represent group 5.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>2", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The electrons that are most easily moved from 2412Mg are in which orbital?", "images": [], "options": {"A": "1s", "B": "2s", "C": "2p", "D": "3s"}, "answer": "D", "explanation": "2412Mg  Atomic number 12: 1s2 2s2 2p6 3s2  The electrons that are most easily removed are located in the outermost shell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>3", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Group O element are unreactive because", "images": [], "options": {"A": "their outermost shells contain equal number", "B": "their highest occupied energy level is full", "C": "they are monatomic gases", "D": "they are non-metals"}, "answer": "B", "explanation": "Group 0 elements, also known as noble gases, are unreactive because their highest occupied energy level is full. This means they have a stable electron configuration and do not need to gain or lose electrons to achieve stability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>4", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Which of the particles indicated below represents an ion with a charge of 2+?", "images": [], "options": {"A": "Protons = 6, Electrons = 6", "B": "Protons = 6, Electrons = 8", "C": "Protons = 12, Electrons = 10", "D": "Protons = 16, Electrons = 18"}, "answer": "C", "explanation": "A charge of 2+ means 2 electrons have been lost from the neutral atom which have equal number of protons and electrons. Therefore, the number of protons", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>5", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Sodium (atomic number 11) and caesium (atomic number 55) are in Group I in the periodic table.  Which of the following statements is correct?", "images": [], "options": {"A": "Sodium has the higher electronegativity value.", "B": "Caesium contains the higher number of valence electrons.", "C": "Sodium has the lower ionization energy.", "D": "Caesium has the lower reducing ability."}, "answer": "A", "explanation": "Across a period, the electronegativity increases from left to rest and decreases down a group. Hence, sodium has higher electronegativity than Caesium since sodium is in period 2 and caesium is in period 6.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>6", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "An element X with electronic configuration 1s22s22p63s2 combines with another element Y with the configuration 1s22s22p63s23p5. What is the formula of the compound formed?", "images": [], "options": {"A": "X2Y5", "B": "X2Y3", "C": "XY3", "D": "XY2"}, "answer": "D", "explanation": "X - 1s2 2s2 2p6 3s2 ; 12X  Y - 1s2 2s2 2p6 3s2 3p5 ; 17Y     Element X will transfer one electron each to two of element Y for them to be stable.      XY2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>7", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "Which of the following statements about dative bonding is not correct?", "images": [], "options": {"A": "There is sharing of electrons", "B": "An atom must possess a lone pair of electrons", "C": "Each participating atom contributes one electron", "D": "It can be formed between molecules"}, "answer": "C", "explanation": "Dative bond is otherwise known as coordinate covalent bond. It involves the sharing of electrons, just that the shared pair of electrons are usually donated by only one of the participating atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>8", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.", "question": "Which of the following conversions involves a beta particles emission?", "images": [], "options": {"A": "23490U → 2309Th", "B": "23880Hg → 23881TI", "C": "23892U → 23490Th", "D": "342He → 126C"}, "answer": "B", "explanation": "A beta particle is represented as 0-1e. Therefore, the new element formed has its atomic number increased by 1 while its mass number remains the same.    23880Hg → 23881TI + 0-1e", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>9", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Study the table and use it to answer this question  ElementMelting Point (°c)Physical state of its oxideElectrical conductivity of the elementI-39SolidVery goodII112.8GasNilIII97.5Solid Good  Which of the elements in the table above can be classified as metal?", "images": [], "options": {"A": "II only", "B": "II and III only", "C": "I and III only", "D": "III only"}, "answer": "C", "explanation": "Some properties of metals are:  - They are good conductor of heat and electricity  - They are solid at room temperature except mercury  - They have high boiling point and melting point.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>10", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "If 11g of a gas occupies 5.6dm3 at s.t.p calculate its vapour density. [1.0 mole of gas occupies 22.4 dm3 at s.t.p.]", "images": [], "options": {"A": "22", "B": "44", "C": "66", "D": "88"}, "answer": "A", "explanation": "If 1 mole = 22.4dm3 at s.t.p  then x = 5.6dm3  x=5.622.4=0.25mol  But,numberofmole,n=mass, mMolar Molar, M.M  0.25=11M.M  M.M=110.25=44  ∴ Relative Molecular Mass, RMM of the gas is 44  Recall,  VapourDensity,VD=R.M.M2  =442 = 22", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>11", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Which of the following quantities is the same for one mole of Br2(l) and one mole of He(g)?", "images": [], "options": {"A": "Number of molecules", "B": "Number of atoms", "C": "Total mass of the particles", "D": "Volume occupied at s.t.p."}, "answer": "A", "explanation": "One mole of any substance contains Avogadro's number (6.022 x 10^23) of particles (atoms, molecules, ions, etc.). Therefore, one mole of Br2(l) and one mole of He(g) both contain the same number of molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>12", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "If 100cm3 of hydrogen diffused through a porous pot in 1.0 second, how long will it take the same volume of oxygen to diffuse through the same pot under the same conditions? [H = 1.0, O = 16.0]", "images": [], "options": {"A": "2.5s", "B": "4.0s", "C": "16.0s", "D": "25.0s"}, "answer": "B", "explanation": "Graham's law of diffusion states that the rate of diffusion of a gas at a given temperature is inversely proportional to the square root of its molecular mass.  Rα1&radic;MM&nbsp;  R=k&radic;MM&nbsp;  k = R&radic;MM&nbsp;  R1&radic;MM1&nbsp; = R2&radic;MM2&nbsp;  R=Volume, Vtime, t  R1=RH=1001=100cm3/s  R2=R0=100t  MMH = H2 = 1 × 2 = 2  MMO = O2 = 16 × 2 = 32  RHRO=&radic;MMOMMH&nbsp;  100÷100t=&radic;322&nbsp;  100×t100=&radic;16&nbsp;  t = 4.0s", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>13", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following acids is dibasic?", "images": [], "options": {"A": "hydrochloric acid", "B": "Trioxosulphate (IV) Acid", "C": "Dioxonitrate (III) acid", "D": "Ethanoic acid"}, "answer": "B", "explanation": "A dibasic acid has two replaceable hydrogen atoms. it gives two free hydrogen ions in solution for each molecule of acid ionized.  The correct is H2SO3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>14", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "Bees inject an acidic substance when they sting. Which of the following chemical could be used to treat bee stings?", "images": [], "options": {"A": "CH3COOH", "B": "NaHCO3", "C": "C2H5OH", "D": "H2O2"}, "answer": "B", "explanation": "Bee sting contain formic acid or methanoic acid (CH2O2 or HCOOH) which is harmful for human body. Baking soda (NaHCO3) can be applied to the affected area to neutralize the acid effect of the formic acid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>15", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following salts can be prepared by reacting the metal with dilute H2SO4?", "images": [], "options": {"A": "CuSO4", "B": "MgSO4", "C": "BaSO4", "D": "PbSO4"}, "answer": "B", "explanation": "Magnesium is higher than hydrogen in the activity/electrochemical series. Hence, it can displace hydrogen from H2SO4  Mg + H2SO4 → MgSO4 + H2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>16", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Which of the following solutions will give a precipitate with dilute tetraoxosulphate (VI) acid?  I. Lead (II) trioxonitrate (V) solution  II. Barium chloride solution  III. Sodium chloride solution", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and II only", "D": "II and III only"}, "answer": "B", "explanation": "it is only Barium chloride solution that will give precipitate with dilute tetraoxosulphate(IV) acid", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>17", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Substance Q reacts with cold water to form a solution which turns red litmus blue. Substance Q could be", "images": [], "options": {"A": "zinc", "B": "phosphorus", "C": "lead", "D": "sodium"}, "answer": "D", "explanation": "Since the solution turns red litmus paper blue, then it is \"basic solution\".  Na + H2O → NaOH + H2", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>18", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "What term is used to describe an oxide whose aqueous solution turns blue litmus red?", "images": [], "options": {"A": "Strong electrolyte", "B": "Acid anhydride", "C": "Amphoteric oxide", "D": "Basic oxide"}, "answer": "B", "explanation": "A solution which turns blue litmus red is acidic. Acid anhydrides are non-metal oxides which react with water to form an acid solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>19", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "The pH of 0.50 moldm-3 solutions of HCl, H2SO4 and CH3COOH were measured. Which of the following statements about the values obtained is correct?", "images": [], "options": {"A": "The pH value was equal to 5 in each case.", "B": "The pH values of the HCl and H2SO4 solutions were equal.", "C": "Their pH values added up to 14", "D": "The pH value of the CH3COOH was the highest"}, "answer": "D", "explanation": "[H+] = 0.50 moldm-3  pH = -log[H+]  HCl ⇌ H+ + Cl-  pH = -log[0.50]  pH = -(-0.301)  pH = 0.301  H2SO4 ⇌ 2H+ + SO42-  pH = -log[2 × 0.50]  ⇒ -log[1]  pH = 0    CH3COOH ⇌ CH3OO- + H+  pH = -log[0.5]  pH = 0.301", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>20", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Which of the following process involves neutralization?", "images": [], "options": {"A": "Hardening of oils", "B": "Souring of milk", "C": "Charring of sugar", "D": "Liming of soil"}, "answer": "D", "explanation": "Neutralization is a chemical reaction in which an acid and a base react to form a salt and water. Liming of soil is a process that involves the addition of a base (lime) to acidic soil to neutralize its acidity. Therefore, the process that involves neutralization is liming of soil.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>21", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Sea shells contain mainly CaCO3. Calcium Oxide can be prepared from sea shells by", "images": [], "options": {"A": "adding dilute acid", "B": "heating at a high temperature", "C": "reduction with CO", "D": "adding dilute NaOH(aq)"}, "answer": "B", "explanation": "Calcium Oxide (CaO) can be prepared from Calcium Carbonate (CaCO3) by heating at a high temperature. This process is known as calcination, which is the thermal decomposition of a material. In this case, when CaCO3 is heated, it decomposes to form CaO and CO2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>22", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "In which of the following experimental set-ups is the reaction fastest?", "images": ["Chemistry/imgs/2003/img1a.png", "Chemistry/imgs/2003/img1b.png", "Chemistry/imgs/2003/img1c.png", "Chemistry/imgs/2003/img1d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "Increase in concentration increases the rate of a reaction since the effective collision of its particles per unit time is increased. Also, the Mg powder reacts faster because more of the power have contact with the HCl at a time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>23", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the equilibrium reaction below.  2SO2(g) + O2(g) ⇌ 2SO3(g); ΔH = -xkjmol-1  The amount of sulphur (VI) oxide produced will increase if", "images": [], "options": {"A": "the pressure is decreased", "B": "more heat is applied", "C": "the temperature is reduced", "D": "a catalyst is added"}, "answer": "C", "explanation": "The temperaure is reduced, since it is an exothermic reaction decrease in temperature will favour the forward reaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>24", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following statements about an exothermic reaction is correct?", "images": [], "options": {"A": "The products have less heat content than the reactants", "B": "The system absorbs heat from the surrounding", "C": "The activation energy is high", "D": "The enthalpy change is positive"}, "answer": "A", "explanation": "Exothermic reaction releases heat to the environment. Therefore, the heat content of the product is less than the reactants. In this case, the enthalpy change is negative i.e ΔH = -x KJmol-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>25", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "A reducing agent is expected to", "images": [], "options": {"A": "decolorize acidified KMnO4 solution", "B": "decolorize acidified FeSO4 solution", "C": "liberate CI2 from a chloride", "D": "liberate CO2 from NaHCO3"}, "answer": "A", "explanation": "A reducing agent is a substance with reduces other substance but itself is oxidized. E.g SO2, a reducing agent decolourizes purple acidified kMnO4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>26", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Consider the electrochemical cell represented below:  Zn(s) / Zn2+(aq) // Cu2+(aq) / Cu(s)  Which of the following equations describes the reaction occurring in the cell?", "images": [], "options": {"A": "Cu(s) + Zn2+(aq) → Cu2+(aq) + Zn(s)", "B": "Cu(s) + Zn(s) → Cu2+(aq) + Zn2+(aq)", "C": "Zn(s) + Cu2+(aq) → Zn2+(aq) + Cu(s)", "D": "Zn2+(aq) + Cu2+(aq) → Zn(s) + Cu(s)"}, "answer": "C", "explanation": "Zn(s) / Zn2+(aq) // Cu2+(aq) / Cu(s)  Oxidation takes place at the anode while reduction takes place at the cathode.  Anode reaction: Zn(s) → Zn2+(aq) + 2e-  Cathode reaction: Cu2+(aq) + 2e- → Cu(s)  Net reaction: Zn(s) + Cu2+(aq) → Zn2+(aq) + Cu(s)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>27", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Use the following information to answer this question.  Five metals represented by the letters V to Z are arranged in order of their reactivity as shown below:  V > W > X > Y > Z    Which of the metals cannot displace Y from an aqueous solution of its salt?", "images": [], "options": {"A": "V", "B": "W", "C": "X", "D": "Z"}, "answer": "D", "explanation": "V > W > X > Y > Z  V is the most reactive while Z is the least reactive. It is only a more reactive metal that can displace a less reactive metal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>28", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Use the following information to answer this question.  Five metals represented by the letters V to Z are arranged in order of their reactivity as shown below:  V > W > X > Y > Z  Which of the metal is most likely extracted by the electrolysis of its fused chloride?", "images": [], "options": {"A": "V", "B": "W", "C": "X", "D": "Y"}, "answer": "A", "explanation": "In the extraction of metals, the method used depends upon the reactivity of the metal. The more reactive the metal, the more difficult it is to extract from its ore. Highly reactive metals such as aluminium and sodium cannot be extracted by reduction with carbon, so they are extracted by electrolysis of their fused chloride. Here, V is the most reactive metal.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>29", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following statements is/are correct about tin plating?  I. The electrolyte must be a soluble salt of tin  II. The object to be plated is made the cathode  III. The anode is made of tin  IV. The negative electrode dissolves.", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "I, II and III only", "D": "I, II and IV only"}, "answer": "C", "explanation": "In electroplating, the metal which is to be used for plating is made the anode while the object to be plated is made the cathode. Also, the electrolyte must be a soluble salt of the metal which is to be used for the plating. In the process, the anode dissolves and is deposited at the cathode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>30", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Use the sketch below to answer this question.      Why is it necessary to heat the PbBr2? To", "images": ["Chemistry/imgs/2003/img2.png"], "options": {"A": "melt it and make it conduct", "B": "increase the reaction rate", "C": "produce electrons which will carry the current", "D": "vaporize the products at the electrodes"}, "answer": "A", "explanation": "The electrolysis will only take place when electricity is passed through the molten lead bromide. Melting it breaks down the strong ionic bonding sufficiently to allow the ions to freely move around and carry the electric current.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>31", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Use the sketch below to answer this question.    What is the product at the positive electrode?", "images": ["Chemistry/imgs/2003/img2.png"], "options": {"A": "Lead", "B": "Oxygen", "C": "Hydrogen", "D": "Bromine"}, "answer": "D", "explanation": "The negative bromide ions are attracted to the positive anode electrode and discharged to form bromine vapour.  2Br-(aq) → Br2(g) + 2e-", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>32", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Determine the amount of electrons needed to deposit 6.4g of copper during the electrolysis of copper (II) tetraoxosulphate (VI) solution. [Cu = 64]", "images": [], "options": {"A": "0.10 mole", "B": "0.20 mole", "C": "1.0 mole", "D": "2.0 mole"}, "answer": "B", "explanation": "Cu2+ + 2e- → Cu  2 moles of electrons (2e-) is needed to deposit 64g of copper.  2e- → 64g  y → 6.4g  y=2e- × 6.464  y = 0.20e-  ∴ 0.20 mole of electron is needed to deposit   6.4g of copper.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>33", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The equation for the reaction at the anode during the electrolysis of concentrated sodium chloride solution is", "images": [], "options": {"A": "2Cl-(aq) → Cl2(g) + 2e-", "B": "4OH-(aq) → 2H2O(l) + O2(g) + 4e-", "C": "Na+(aq) + e- → Na(s)", "D": "2H+(aq) + 2e → H2(g)"}, "answer": "A", "explanation": "Since the solution is concentrated, the anode is surrounded by lots of chlorides and extremely few hydroxides, so it's almost as if the hydroxides are not there and the chlorides are discharged.  2Cl-(aq) → Cl2(g) + 2e-", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>34", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : BENZENE", "question": "Which of the following compounds has the same empirical formular as benzene?", "images": [], "options": {"A": "C2H2", "B": "C2H4", "C": "C4H6", "D": "C6H12"}, "answer": "A", "explanation": "Benzene has a molecular formula of C6H6, and when reduced can give C2H2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>35", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "A given fuel has octane number of 100. This means that", "images": [], "options": {"A": "the knocking tendency of the fuel is low.", "B": "the fuel is a mixture of several hydrocarbons.", "C": "a large amount of alkanes is present in the fuel.", "D": "the fuel needs to be cracked before use"}, "answer": "A", "explanation": "The quality of petrol is determined on a scale that measures its octane number, heptane assigned a value of 0 and 2, 2, 4 - trimethylpentane assigned a value of 100. Petrols containing a predominant amount of straight chains have higher knocking tendency than branched ones.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>36", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following statements about X and Y below is correct? They are    &nbsp &nbsp &nbsp", "images": ["Chemistry/imgs/2003/img3a.png", "Chemistry/imgs/2003/img3b.png"], "options": {"A": "equivalent structures of the same compound", "B": "similar in their physical properties", "C": "geometric isomers", "D": "unsaturated hydrocarbons"}, "answer": "C", "explanation": "Isomers are molecules that have the same molecular formula but have different structural formula. Geometric isomers occur when there is restricted rotation somewhere in a molecule. In one, the two chlorine atoms are locked on opposite sides of the double bond. This is known as the trans-isomer. The other has the two chlorine atoms locked on the same side of the double bond.  This is known as Cis isomer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>37", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Wine containing 8% to 17% ethanol can be converted to gin containing about 40% ethanol by", "images": [], "options": {"A": "evaporation", "B": "distillation", "C": "fermentation", "D": "oxidation"}, "answer": "B", "explanation": "Liquor (such as gin, brandy, whisky) is obtained by distillation from wine or other fermented fruit. The alcoholic content of distilled liquor is higher than that of beer or wine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>38", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "What is the IUPAC name for the following compound?", "images": ["Chemistry/imgs/2003/img4.png"], "options": {"A": "Ethylmethanoate", "B": "Ethanoic acid", "C": "Propan -2 - ol", "D": "Propanoic acid"}, "answer": "D", "explanation": "The compound has a functional group \"-COOH\", which makes it an alkanoic acid.  It has three carbon atoms including the one in the functional group, and that is \"prop\".  Therefore, its name is propanoic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>39", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following substances could be responsible for the banana taste of a food flavour?", "images": [], "options": {"A": "Methylbenzene", "B": "Butanol", "C": "Ethanol", "D": "Pentylethanoate"}, "answer": "D", "explanation": "Esters are organic compounds which often have a pleasant characteristics, fruity smell. Pentylethanoate [CH3COO(CH2)4CH3] has banana odour / flavour / smell.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>40", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "What is the organic product of the reaction of C2H5OH with excess acidified K2Cr2O7(aq)?", "images": [], "options": {"A": "CH3COOH", "B": "C2H5OC2H5", "C": "HCOOCH3", "D": "C2H5CHO"}, "answer": "A", "explanation": "A primary alkanol when oxidized gives an alkanol which on further oxidation gives an alkanoic acid.  C2H5OH + K2Cr2O7 (excess) → CH3COOH   (in the presence of Δ & H2SO4)", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>41", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "The reaction of vegetable oil with a solution of wood ash is", "images": [], "options": {"A": "saponification", "B": "neutralization", "C": "hydrogenation", "D": "esterification"}, "answer": "A", "explanation": "Saponification is a process that involves conversion of fat or oil into soap and alcohol by the action of heat in the presence of aqueous alkali. Soap an also be made from wood ash but the soap will be softer and more oily.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>42", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "What process does the following equation represent?  (C6H10O5)n + nH2O → nC6H12O6", "images": [], "options": {"A": "Polymerization of glucose", "B": "Hydrolysis of starch", "C": "Fermentation of sugar", "D": "Dehydration of carbohydrates"}, "answer": "B", "explanation": "This is hydrolysis (addition of water) of starch, (C6H10O5)n to form glucose nC6H12O6.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>43", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "When excess ethene is shaken with acidified KMnO4 solution, the product obtained is", "images": [], "options": {"A": "ethane", "B": "ethanal", "C": "ethane -1, 2 - diol", "D": "ethanoic acid"}, "answer": "C", "explanation": "This reaction is known as hydroxylation. The product is used in anti-freeze mixtures for car radiators.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>44", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "What is the monomer unit of the polymer represented below:", "images": ["Chemistry/imgs/2003/img5.png"], "options": {"A": "Ethene", "B": "Ethane", "C": "Propene", "D": "Propane"}, "answer": "D", "explanation": "The monomer has single bonds throughout, hence, it is an alkane family. It has three carbon atom, hence, the name \"prop\".  Therefore, it is propane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>45", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume of 0.20 mol d-3 NaOH solution would yield 5.0g of NaOH on evaporation to dryness?  [NaOH = 40g mol-1]", "images": [], "options": {"A": "400cm3", "B": "625cm3", "C": "1000cm3", "D": "1600cm3"}, "answer": "B", "explanation": "n = ?, C = 0.20moldm-3, m = 5.0g  Molar Mass, MM = 40gmol-1, V = ?  recall;  n=mMM  =540  n = 0.125mol.  Also recall,  Molarconc.,C=nV  0.20=0.125V  V=0.1250.20=0.625dm3 = 625 cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2003>46", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "What is the main impurity in haematite?", "images": [], "options": {"A": "CaSiO3", "B": "CaCO3", "C": "SiO2", "D": "Fe2O3"}, "answer": "C", "explanation": "Iron is extracted from its ore in the blast furnace. The iron ore contains impurities mainly silica (silicon dioxide), SiO2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>47", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which is the main following compounds is used for removing impurities from bauxite?", "images": [], "options": {"A": "NaOH", "B": "CaCO3", "C": "Na3Al6", "D": "H2SO4"}, "answer": "A", "explanation": "The separation of the alumina from the impurities in the bauxite ore is usually accomplished by the Bayer process. In this process, the ground bauxite is leached with caustic soda (NaOH) to produce soluble sodium aluminate (NaAlO2), leaving the impurities in the insoluble residue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>48", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION", "question": "When a sample of water was boiled, it lathered more readily with soap. It can be concluded that the sample most likely contained.", "images": [], "options": {"A": "magnesium tetraoxosulphate (IV)", "B": "suspended solids", "C": "organic impurities", "D": "calcium hydrogentrioxocarbonate (IV)"}, "answer": "D", "explanation": "Temporary hard water is water whose hardness is due primarily to bicarbonate ions e.g Ca(HCO3)2 which can simply be softened by boiling.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2003>49", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "What are the two gases associated with the formation of acid rain?", "images": [], "options": {"A": "CO2 and HCl", "B": "CO2 and N2", "C": "SO2 and NO2", "D": "HCl and SO2"}, "answer": "C", "explanation": "These gases are acid anhydrides which react with water to form acid  SO2 + H2O → H2SO3  NO2 + H2O → HNO3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2003>50", "subject": "Chemistry", "year": "2003", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following processes will pollute water", "images": [], "options": {"A": "Exposure of a body of water to ultraviolet rays", "B": "Discharge of industrial effluents into water ways", "C": "Passage of river water through a sand bed", "D": "Addition of a measured quantity of chlorine to water"}, "answer": "B", "explanation": "Water can be polluted by man through sources like industrial effluents, domestic wastes, agricultural practices, underground storage leaks etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2004>1", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The mass of an element is 27 and its atomic number is 13.   What is the composition of the nucleus of its atom?", "images": [], "options": {"A": "13 electrons and 14 protons", "B": "13 neutrons and 14 protons", "C": "13 protons and 14 neutrons", "D": "13 electrons and 14 neutrons"}, "answer": "C", "explanation": "The nucleus of an atom is composed of protons and neutrons. The atomic number of an element represents the number of protons in the nucleus. The mass number is the sum of protons and neutrons. Therefore, if the atomic number is 13, there are 13 protons. And if the mass number is 27, there are 27 - 13 = 14 neutrons. So, the nucleus of this atom contains 13 protons and 14 neutrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>2", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "If an atom is represented as 3919X, which of the following deductions is correct?", "images": [], "options": {"A": "It contains 20 protons", "B": "It forms a covalent chloride", "C": "Its atomic number is 39", "D": "It is an alkali metal"}, "answer": "D", "explanation": "Its atomic number is 19  2, 8, 8, 1  K  L  M  N  Its valence shell has only one electron. This makes it a group 1 element which is called Alkali metal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>3", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Two elements X and Y combine to form a compound with formula X2Y3. Which of the following representations would fit the configurations of X and Y?", "images": [], "options": {"A": "X  2,2Y  2,3", "B": "X  2,6Y  2,5", "C": "X  2,8,2Y  2,8,3", "D": "X  2,8,3Y  2,6"}, "answer": "D", "explanation": "From valence crossing, 3 must have come from X i.e X3+ and 2 must have come from Y i.e Y2-.  X3+ means X has lost 3 electrons.  Y2- means Y has gained 2 electrons.  Only X2, 8, 3 has the ability to have lost 3 electrons to become X3+  Only Y2, 6 has the ability to gained 2 electrons to become Y2-.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>4", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following electron transitions results in the emission of energy?", "images": [], "options": {"A": "3p to 3s", "B": "3p to 4p", "C": "2s to 2p", "D": "1s to 2s"}, "answer": "A", "explanation": "1s 2s 2p 3s 3p 4s 3d 4p 5s   &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp →  increasing energy  An electron emits energy when it moves from a higher energy level to a lower energy level.  3p has higher energy than 3s.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>5", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following properties of elements decreases generally across a period in the Periodic Table?", "images": [], "options": {"A": "Electronegativity", "B": "Electron affinity", "C": "Atomic radius", "D": "Ionization energy"}, "answer": "C", "explanation": "Atomic radius decreases across a period due to the increase in nuclear pull as a result of increase in valence electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>6", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the electrons in the following orbitals will experience the greatest nuclear attraction?", "images": [], "options": {"A": "1s electron of helium", "B": "1s electron of potassium", "C": "2s electron of boron", "D": "2s electron of carbon"}, "answer": "B", "explanation": "Electrons closest to the nucleus experience the greatest nuclear attraction. 1s electrons experience the greatest nuclear attraction especially that of potassium since more electrons are involved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>7", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "A nuclide emits a beta-particle 0-1e. In the process, the atomic number", "images": [], "options": {"A": "increases by 1 while the mass number remains constant", "B": "decreases by 2 while the mass number remains constant", "C": "remains constant while the mass number decreases by 2", "D": "remains constant while the mass number increases by 1"}, "answer": "A", "explanation": "abX → mnY + 0-1e  From above, element X emits beta particle to give Y.  a = m + o  ∴ m = a    Also,  b = n + (-1)  b = n - 1  b + 1 = n  n = b + 1    It can be seen that the atomic number increases by 1 and mass number remains constant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>8", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "One of the characteristics of transition metals is", "images": [], "options": {"A": "reducing ability", "B": "ductility", "C": "ability to conduct electricity", "D": "formation of coloured ions"}, "answer": "D", "explanation": "Transition elements form coloured ions e.g Cu2+ (blue), Fe2+ (green), Cr3+ (yellow), Cr6+ (yellow) e.t.c.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>9", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "How many electrons are in the L shell of 3115P?", "images": [], "options": {"A": "2", "B": "5", "C": "8", "D": "16"}, "answer": "C", "explanation": "3115P  2, 8, 5  K  L  M    using the formula 2n2  where for k shell n = 1  for L shell, n = 2  for M shell, n = 3", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2004>10", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Use the following information to answer this question  A metal X forms two chlorides with the formulae XCl2 and XCl3.    Where is X in the Periodic Table?", "images": [], "options": {"A": "Group II", "B": "Group III", "C": "d-block", "D": "s-block"}, "answer": "C", "explanation": "X is a metal  From valence crossing, XCl2 was from X2+ Cl-  From valence crossing, XCl3 was from X3+ Cl-  X2+ and X3+ have lost 2 and 3 electrons respectively.  Since X has variable oxidation states i.e +2 and +3, it must be a transition metal. Hence, it belongs to d-block of the periodic table.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>11", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Use the following information to answer this question  A metal X forms two chlorides with the formulae XCl2 and XCl3.  What type of bonding exists between X and chlorine in each of the chlorides?", "images": [], "options": {"A": "Metallic bonding", "B": "Ionic bonding", "C": "Covalent bonding", "D": "Dative bonding"}, "answer": "B", "explanation": "Ionic bonding exists between aggregate of ions. It involves transfer of electron(s) from a metal to non-metal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>12", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "RADIAOACTIVITY", "question": "Which of the following equipment is not used to detect radioactivity?", "images": [], "options": {"A": "Wilson cloud chamber", "B": "Geiger-Muller Counter", "C": "Mass spectrometer", "D": "Photographic plate"}, "answer": "C", "explanation": "Mass spectrometer is used to determine the molecular weight of compounds by separating molecular ions on the basis of their mass and charge.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2004>13", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "The method of collection of gases prepared in the laboratory depend on their", "images": [], "options": {"A": "odour and atomicity", "B": "colour and odour", "C": "atomicity and density", "D": "solubility and density"}, "answer": "D", "explanation": "Method of collection of gases   prepared in the laboratory depend on their solubility and density which can either by   - collection by downward delivery  - collection over water or  - collection by upward delivery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>14", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following pairs of salts undergo hydrolysis?", "images": [], "options": {"A": "AlCl3 and NH4Cl", "B": "AlCl3 and NaCl", "C": "FeCl3 and KCl", "D": "Na2SO4 and K2SO4"}, "answer": "A", "explanation": "Salt hydrolysis is a reaction in which one of the ions from a salt reacts with water, forming either an acid or basic solution. For a salt to undergo hydrolysis, at least one of the parent compounds (either the acid or the base or both) should be weak.  Al and NH4 are from weak base Al(OH)3 and NH4OH respectively while Cl is from a strong acid HCl.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>15", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "The alloy used extensively in the building industry is", "images": [], "options": {"A": "steel", "B": "bronze", "C": "duralumin", "D": "type metal"}, "answer": "A", "explanation": "The metals commonly used are steel, aluminium and copper due to their durability, strength and resistance to weather.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2004>16", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following salts is not prepared by precipitation?", "images": [], "options": {"A": "Lead (II) trioxocarbonate (IV)", "B": "Barium trioxocarbonate (IV)", "C": "Sodium trioxocarbonate (IV)", "D": "Calcium trioxocarbonate (IV)"}, "answer": "C", "explanation": "An insoluble salt is prepared by precipitation. All sodium, potassium and ammonium salts are soluble. Hence, they can't be prepared by precipitation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>17", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume of hydrogen would be left over when 300 cm3 of oxygen and 1000 cm3 of hydrogen are exploded in a sealed tube?  [2H2(g) + O2(g) → 2H2O(g)]", "images": [], "options": {"A": "200 cm3", "B": "400 cm3", "C": "600 cm3", "D": "700 cm3"}, "answer": "B", "explanation": "2H_(2(g) + O2(g) → 2H2O  Available volume → 1000cm3 &nbsp 300cm3 &nbsp &nbsp -  Used volume → 600cm3 &nbsp 300cm3 &nbsp 600cm3  Unused volume → 400cm3 &nbsp 0    The law applied is Gay Lussac's law of combining volume.  The volume of hydrogen left is (1000 - 600)cm3 = 400cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2004>18", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.", "question": "What are the values x, y and z respectively in the following equation?  MnO2(s) + xHCl(aq) → MnCl2(aq) + yH2O(l) + zCl2(g)", "images": [], "options": {"A": "4, 1, 2", "B": "1, 2, 1", "C": "2, 1, 2", "D": "4, 2, 1"}, "answer": "D", "explanation": "MnO2(s) + 4HCl(aq) → MnCl2(aq) + 2H2O(l) + Cl2(g)  From the above equation,  1 mole of Mn is on each side  2 moles of O are on each side  4 moles of H are on each side  4 mole of Cl are on each side    ∴ x = 4, y = 2 and z = 1", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2004>19", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following substances will not produce effervescence with dilute hydrochloric acid?", "images": [], "options": {"A": "Copper(II)trioxocarbonate(IV)", "B": "Potassium hydrogentrioxocarbonate (IV)", "C": "Zinc granules", "D": "Sodium chloride"}, "answer": "D", "explanation": "Sodium chloride will not produce effervescence with dilute hydrochloric acid. Effervescence is the formation of gas bubbles in a liquid by a chemical reaction. In this case, the other three options are carbonates or metals that react with hydrochloric acid to produce a gas (usually carbon dioxide in the case of carbonates), but sodium chloride is a salt that does not react in the same way.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>20", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "What quantity of electrons in moles is needed to discharge two moles of aluminium from aluminium oxide (Al2O3)?", "images": [], "options": {"A": "1", "B": "2", "C": "4", "D": "6"}, "answer": "D", "explanation": "Al3+(aq) + 3e- → Al(s)  Aluminium ion, Al3+ needs 3 moles of electrons to liberate 1 mole of aluminium (Al). Therefore, for 2 moles of aluminium ion, 6 moles of electrons are needed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>21", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Two solutions containing Pb2+ and Al3+ respectively can be distinguished using", "images": [], "options": {"A": "NaOH(aq)", "B": "NH3(aq)", "C": "conc. HNO2", "D": "conc. HCl"}, "answer": "D", "explanation": "Pb2+ forms white precipitate with HCl, whereas Al3+ forms no precipitate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>22", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.", "question": "A solution of zinc chloride should not be stored in a container made of", "images": [], "options": {"A": "tin", "B": "copper", "C": "aluminium", "D": "lead"}, "answer": "C", "explanation": "Aluminium is more reactive than zinc, therefore ZnCl2 solution should not be stored in an aluminium container because the aluminium will displace the zinc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>23", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Glucose gives a brick-red precipitate with Fehling's solution because it is", "images": [], "options": {"A": "a carbohydrate", "B": "an alkanoate", "C": "a reducing sugar", "D": "a non-electrolyte"}, "answer": "C", "explanation": "Glucose is a reducing sugar. Reducing sugars are capable of acting as a reducing agent because they have a free aldehyde group or a free ketone group. Fehling's solution is used to differentiate between water-soluble carbohydrate derivatives. When heated with Fehling's solution, reducing sugars produce a brick-red precipitate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>24", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "What is the IUPAC name of CH3 CH2 COOCH3?", "images": [], "options": {"A": "Ethylethanoate", "B": "Methylethanoate", "C": "Methylpropanoate", "D": "Propylmethanoate"}, "answer": "C", "explanation": "This is an alkanoate compound, which is generally represented as RCOOR' where R and R' are alkyl group.  R' is methyl which is named first. Hence, the name is methyl propanoate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>25", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The mass of 800 cm3 of a gas X at s.t.p. is 1.0g. What is the molar mass of X?  [1 mole of a gas at s.t.p. occupies 22.4 dm3]", "images": [], "options": {"A": "18.0 g mol-1", "B": "22.4 g mol-1", "C": "28.0 g mol-1", "D": "36.0 g mol-1"}, "answer": "C", "explanation": "Volume, V = 800cm3  mass, m = 1.0g  Molar mass, M.M = ?  Molar volume, MV = 22.4dm3 = 22400cm3  number of mole, n = ?  Recall,  n=VMV  =80022400 = 0.036mol    Also,  n=mMM  0.036=1MM  0.036MM = 1  MM=10.036  ∴ MM = 28gmol-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2004>26", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following compounds is a soapless detergent?", "images": [], "options": {"A": "C12H25OSO3Na", "B": "C17H35COONa", "C": "C6H5OH", "D": "C4H9COOC2H5"}, "answer": "A", "explanation": "Soapless detergents are made from crude oil or synthetic materials and are mixed with high amount of sulphuric acid, as well as sodium hydroxide. Soapless detergents do not form scum when used with hard water.    Alkanol + conc. surphuric acid → alkyl hydrogen sulphate (VI) + water  R - OH + H2SO4 → R - O - SO3H + H2O  The alkyl hydrogen sulphate (VI) is then neutralized with sodium/potassium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>27", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The reaction that takes place at the cathode when an aqueous solution of NaCl is electrolysed using carbon electrodes is", "images": [], "options": {"A": "2H+(aq) + 2e- → H2(g)", "B": "Na+(aq) + e- → Na(s)", "C": "4OH- → 2H2O(l) + O2(g) + 4e-", "D": "2Cl- → Cl2(g) + 2e-"}, "answer": "A", "explanation": "Na+ from NaCl and H+ fro H2O migrate to the cathode (negative electrode) but H+ is preferentially discharged, by gaining electron and liberated as hydrogen gas.  2H+(aq) + 2e- → H2(g)", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2004>28", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Which of the following pairs of acids and bases will produce a solution with pH less than 7 at equivalence point?", "images": [], "options": {"A": "HNO3 and NaOH", "B": "H2SO4 and KOH", "C": "HCl and Mg(OH)2", "D": "HNO3 and KOH"}, "answer": "C", "explanation": "A pH less than 7 is acidic. This can be achieved when a strong acid react with a weak base. All the acids are strong and all the base are strong except Mg(OH)2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2004>29", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Aqueous copper (II) tetraoxosulphate (VI) was electrolysed using the following pairs of electrodes. In which case was there a decrease in the mass of the anode?", "images": [], "options": {"A": "CathodeAnodeGraphiteGraphite", "B": "CathodeAnodePlatinumPlatinum", "C": "CathodeAnodeCopperCopper", "D": "CathodeAnodeGraphitePlatinum"}, "answer": "C", "explanation": "When the salt of the anode is used as the electrolyte, the anode becomes active and gradually dissolves into the solution and deposited at the cathode. Therefore, there is a decrease in the mass of the anode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>30", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following salts is readily soluble in water?", "images": [], "options": {"A": "PbCl2", "B": "Pb(NO3)2", "C": "PbSO4", "D": "PbCO3"}, "answer": "B", "explanation": "Pb(NO3)2 is readily soluble in water. This is because nitrates (NO3-) are generally soluble in water. The other salts listed contain ions (Cl-, SO4^2-, CO3^2-) that form insoluble compounds with lead (Pb^2+).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2004>31", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following factors that affect the rate of chemical reactions can be explained in terms of the collision theory?  I. Concentration  II. Pressure  III. Temperature  IV. Catalyst", "images": [], "options": {"A": "I and II only", "B": "I, II and III only", "C": "I and III only", "D": "I, III and IV only"}, "answer": "D", "explanation": "concentration, temperature and catalyst affects the rates of reaction interms of the collision theory, The collision theory acn be used to explain how changes in temperature , concentration , nature of reactants and presence of catalyst affects the rates of chemical reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>32", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "An orange drink concentrate is suspected to contain traces of poisonous green dye and a harmless dye having the same boiling point. Which of the following techniques is most suitable for isolating the dyes?", "images": [], "options": {"A": "Fractional distillation", "B": "Paper chromatography", "C": "Coagulation", "D": "Recrystallization"}, "answer": "B", "explanation": "Since the two dyes have the same boiling point, the principle of their separation is based on the relative migration of their constituents of mixture over an adsorbent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>33", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "If 60cm3 of a gas is heated from 27°C to 50°C, what is the new volume of the gas at constant pressure?", "images": [], "options": {"A": "32.4 cm3", "B": "55.7 cm3", "C": "64.6 cm3", "D": "111.1 cm3"}, "answer": "C", "explanation": "V1 = 60cm3, V2 = ?  T1 = 27°C = 27 + 273 = 300K  T2 = 50°C = 50 + 273 = 323K  Using charles' law  V1T1=V2T2  60300=V2323  V2=60×323300=64.6cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>34", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "When ammonium trioxocarbonate (IV) solution is added to separate solutions of calcium, zinc and sodium salts, precipitate could be formed in the case of", "images": [], "options": {"A": "calcium only", "B": "zinc only", "C": "calcium and zinc only", "D": "sodium and zinc only"}, "answer": "C", "explanation": "All trioxocarbonate IV, CO32- salts are insoluble except those of Na+, K+ and NH4+. Therefore CaCO3 and ZnCO3 will form precipitate since they are insoluble.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>35", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Consider the cell represented below.  Zn/Zn2+(aq)  // Cu2+(aq) / Cu(s)  Which of the following statements is correct about the cell?", "images": [], "options": {"A": "Zn is oxidized to Zn2+", "B": "Cu is oxidized to Cu2+", "C": "It is an electrolytic cell", "D": "Each single line represents a salt bridge"}, "answer": "A", "explanation": "Oxidation is loss of electron.  Zn is oxidized by losing two electrons to become Zn2+.  Zn(s) → Zn2+(aq) + 2e-", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>36", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Consider the following electronegative values:  HWXYZ2.11.21.52.13.5    Which of the elements represented by the letters W to Z will combine with hydrogen (H) to form a purely covalent compound?", "images": [], "options": {"A": "W", "B": "X", "C": "Y", "D": "Z"}, "answer": "C", "explanation": "Electronegativity is the tendency of an atom to attract electrons when bonded.  If two atoms have similar values for electronegativity, they will be covalently bonded.  H and Y will form covalent compound since they have the same electronegativity value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2004>37", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : AMINO ACIDS", "question": "The condensation of several amino acids molecules gives", "images": [], "options": {"A": "long chain alkanoic acids", "B": "secondary alkanols", "C": "alkanoates", "D": "proteins"}, "answer": "D", "explanation": "A condensation reaction is a reaction in which molecules combine to form a single molecule. Amino acids join together to form a molecule called a dipeptide. A lengthy molecule forms a protein.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>38", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following statements is true about endothermic reaction?  I. Heat is absorbed from the surrounding.  II. The heat content of the products is more than that of the reactants.  III. The enthalpy change is positive.  IV. The surrounding is at a lower temperature than the system.", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "I, II and III only", "D": "I, II, III and IV"}, "answer": "C", "explanation": "In an endothermic reaction, heat is absorbed from the surroundings (I), the heat content (enthalpy) of the products is more than that of the reactants (II), and the enthalpy change is positive (III). However, the surrounding temperature does not necessarily have to be lower than the system (IV). Therefore, statements I, II, and III are correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>39", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What is the change in the oxidation number of 1- in the reaction represented by the following equation?  5I-1(aq) + 6H+(aq) + IO-3(aq) → 3I2(g) + 3H2O(l)", "images": [], "options": {"A": "-5 to -3", "B": "-1 to 0", "C": "+5 to +3", "D": "-1 to +2"}, "answer": "B", "explanation": "From I- to I.  The oxidation number of an ion is the charge on the ion. Therefore, the oxidation number of I- is -1.  The oxidation number of a free element in an uncombined state is zero. Therefore, the oxidation number of I is O.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2004>40", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "The key factor to be considered in siting a chemical industry is", "images": [], "options": {"A": "favourable climatic conditions", "B": "the availability of space to store raw materials", "C": "its nearness to other industrial establishments", "D": "its nearness to the source of raw materials"}, "answer": "D", "explanation": "The key factor to be considered in siting a chemical industry is its nearness to the source of raw materials. This is because the cost and logistics of transporting raw materials can significantly impact the profitability and efficiency of the industry. While other factors like favourable climatic conditions, availability of space to store raw materials, and its nearness to other industrial establishments can also be important, they are not the key factor.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2004>41", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Which of the following reactions will be affected by change in pressure at equilibrium?", "images": [], "options": {"A": "X(g) + Y(g) ⇋ W(g) + Z(g)", "B": "X(g) + 2Y(g) ⇋ W(g) + Z(g)", "C": "2X(g) ⇋ W(g) + Z(g)", "D": "2Y(g) ⇋ W(g) + Z(g)"}, "answer": "B", "explanation": "For pressure to affect a chemical reaction at equilibrium, there must be gaseous molecules, and the number of mole of the molecules on both sides must not be the same.    X(g) + 2Y(g) ⇋ W(g) + Z(g) has 3 moles of gaseous molecules on the left hand side and 2 moles on the right hand side. Hence, pressure will affect it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>42", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Which of the following petroleum fractions yields vaseline and paraffin wax on redistillation?", "images": [], "options": {"A": "Diesel oil", "B": "Lubrication oil", "C": "Petrol", "D": "Kerosine"}, "answer": "B", "explanation": "Lubricating oil as one of the factions of petroleum distills over between 350°C and 500°C. Further distillation gives fuel oil, grease and vaseline, and paraffin wax.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>43", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "What is the IUPAC name of", "images": ["Chemistry/imgs/2004/img43.png"], "options": {"A": "2- methylethyne", "B": "Prop - 2- yne", "C": "Pent - 3 -yne", "D": "Propyne"}, "answer": "D", "explanation": "The longest carbon to carbon continuous chain comprises of three carbon. This is called \"prop\".  The functional group is carbon to carbon triple bond, hence, the compound is an alkyne family.  Counting from the left to the right, the functional group is on the second carbon, which is prop - 2 - yne but counting from right to left, the functional group is on the first carbon atom, which is prop-1-yne or simply propyne. A shorter number is chosen, which is propyne or prop-1-yne.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>44", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : OXYGEN", "question": "Which of the following compounds is not suitable for the preparation of oxygen by heating?", "images": [], "options": {"A": "KClO3", "B": "H2O2", "C": "NaNO3", "D": "AgNO3"}, "answer": "D", "explanation": "When AgNO3 is heated, it decomposes to liberate oxygen gas and Nitrogen(IV)oxide which is an impurity to oxygen.  2AgNO3(s) → 2Ag(s) + O2(g) + 2NO2(g)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>45", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "During the extraction of iron, the limestone fed into the blast furnace produces CaO which removes", "images": [], "options": {"A": "excess air", "B": "unburnt coke", "C": "earthy impurities", "D": "molten iron"}, "answer": "C", "explanation": "Calcium oxide (CaO) reacts with silica (sand) impurities in the haematite, to product slag, which is calcium silicate.  CaO(s) + SiO2(s) → CaSiO3(l)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>46", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "What is the product CxHy) in the following equation?  C10H22 → C8H18 + CxHy", "images": [], "options": {"A": "Butene", "B": "Octane", "C": "Ethene", "D": "Decane"}, "answer": "C", "explanation": "C10H22 → C8H18 + xHy  10 = 8 + x &nbsp &nbsp 22 = 18 + y  10 - 8 = x &nbsp &nbsp 22 - 18 = y  2 = x &nbsp &nbsp 4 = y  ∴ x = 2 &nbsp &nbsp y = 4  CxHy is C2H4  C2H4 is ethene which conforms to the general molecular of alkene, CnH2n", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>47", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following are required in an experiment to determine the enthalpy of solution of anhydrous CuSO4?  I. Mass of the anhydrous CuSO4  II. Volume of water in which the CuSO4 is dissolved  III. Initial temperature of water  IV. Final temperature of the solution", "images": [], "options": {"A": "I and II only", "B": "III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "D", "explanation": "Heat of solution or enthalpy of solution is the energy released or absorbed when the solute dissolutes in the solvent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>48", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following pollutants is biodegradable?", "images": [], "options": {"A": "Domestic sewage", "B": "Metal scraps", "C": "Radioactive waste", "D": "Plastic foil"}, "answer": "A", "explanation": "Biodegradable substances are substances which are capable of being decomposed or broken down by the action of microorganisms.  Examples include  - Human and animal waste  - Plant products, wood, paper, food waste, leaves etc.  - Remains from the death of living creatures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>49", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The process of \"seeding\" during the extraction of aluminium involves the addition of pure Al(OH)3 crystals in order to", "images": [], "options": {"A": "lower the temperature", "B": "increase the concentration", "C": "facilitate the precipitation of solid", "D": "reduce the viscosity of the solution"}, "answer": "C", "explanation": "Pure aluminium hydroxide is added to bring about formation of aluminium hydroxide already added to separate the impurities  from bauxite.  Aluminium hydroxide is then filtered off, wash and dry and heated to form Aluminium oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2004>50", "subject": "Chemistry", "year": "2004", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following measures is not suitable for controlling water pollution?", "images": [], "options": {"A": "Treating industrial effluent and domestic sewage before discharge into water", "B": "Controlling the use of agrochemicals", "C": "Recycling industrial and agricultural wastes", "D": "Burning industrial and agricultural wastes before discharge into water ways"}, "answer": "D", "explanation": "Burning industrial and agricultural wastes before discharging into water ways is not a suitable measure for controlling water pollution. Burning these wastes can release harmful pollutants into the air, which can then be deposited into water bodies through precipitation. The other options, such as treating industrial effluent and domestic sewage before discharge, controlling the use of agrochemicals, and recycling industrial and agricultural wastes, are all suitable measures for controlling water pollution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>1", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The electronic configuration of an element X is 1s2 2s2 2p6 3s2 3p4. It can be deduced that X", "images": [], "options": {"A": "belongs to group 6 of the Periodic Table", "B": "belongs to period IV of the Periodic Table", "C": "has 3 unpaired electrons in its atom", "D": "has relative molecular mass of 16"}, "answer": "A", "explanation": "1s2 2s2 2p6 3s2 3p4 ⇒ 2, 8, 6  ∴ X belongs to period 3, group 6 in the periodic table. Atomic number is 16 and has 2 unpaired electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>2", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "What is the mass number of an element having 20 neutrons, 15 protons and 15 electrons?", "images": [], "options": {"A": "15", "B": "30", "C": "35", "D": "50"}, "answer": "C", "explanation": "The mass number of an element is the sum of the number of protons and neutrons in the nucleus of an atom. Given that the element has 20 neutrons and 15 protons, the mass number is 20 + 15 = 35.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>3", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following sets of elements are arranged in order of decreasing atomic size in the Periodic Table?", "images": [], "options": {"A": "6C, 4Be, 7N, 8O", "B": "4Be, 6C, 7N, 8O", "C": "8O, 7N, 6C, 4Be", "D": "7N, 8O, 6C, 4Be"}, "answer": "B", "explanation": "Atomic size increases down the group but decreases across the period.  The elements involved are:  4Be = 2, 2  7N = 2, 5  6C = 2, 4  8O = 2, 6    All the elements are in the same period 2. Since atomic size decreases across the period, then the arrangement in decreasing order is   Be > C > N > O", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>4", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.", "question": "Which of the following changes is characteristic of an alpha-particle emission?", "images": [], "options": {"A": "The nucleus loses two protons and two neutrons", "B": "A proton combines with an electron giving off heat", "C": "The nucleus splits into equal parts", "D": "Four neutrons are lost"}, "answer": "A", "explanation": "An alpha particle is a type of radioactive decay where an atomic nucleus emits an alpha particle and transforms or 'decays' into an atom with a mass number 4 less and atomic number 2 less. An alpha particle is identical to the nucleus of a helium atom, which consists of two protons and two neutrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>5", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "An element X has an atomic number of 16. What is its most likely oxidation state in its binary compounds?", "images": [], "options": {"A": "-3", "B": "-2", "C": "+2", "D": "+4"}, "answer": "B", "explanation": "16X - 2, 8, 6  It needs 2 electrons to attain an octet configuration. Therefore, the oxidation state is -2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>6", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Consider the table below:  ElementElectronic ConfigurationJ  K  L  M2, 3  2, 8, 2  2, 8, 3  2, 8, 4  Which pair of elements are in the same group in the Periodic Table?", "images": [], "options": {"A": "J and", "B": "K and L", "C": "J and L", "D": "K and M"}, "answer": "C", "explanation": "Elements in the same group have the same valance electrons i.e electrons in their outermost shell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>7", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The type of bonding between calcium and oxygen in calcium oxide is", "images": [], "options": {"A": "metallic", "B": "covalent", "C": "ionic", "D": "coordinate covalent"}, "answer": "C", "explanation": "Calcium is a group 2 element i.e a strong metal (highly electropositive) and oxygen is a group 6 element, a strong non-metal (highly electronegative). The bond between such is ionic or electrovalent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>8", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The properties of four compounds P, Q, R and S are shown in the below. Which of them is ionic?", "images": [], "options": {"A": "CompoundElectrical conductance in the molten stateMelting PointPFairly good28°C", "B": "CompoundElectrical conductance in the molten stateMelting PointQNil97°C", "C": "CompoundElectrical conductance in the molten stateMelting PointRPoor158°C", "D": "CompoundElectrical conductance in the molten stateMelting PointSFairly good2015°C"}, "answer": "D", "explanation": "Ionic compounds are characterized by high melting point and high boiling point.  They conduct electricity in their molten state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>9", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "An element which can exist in two or more forms in the same physical state, exhibits", "images": [], "options": {"A": "isotopy", "B": "structural isomerism", "C": "allotropy", "D": "variable valency"}, "answer": "C", "explanation": "An element which can exist in two or more forms in the same physical state exhibits allotropy. Allotropy is the property of some chemical elements to exist in two or more different forms, in the same physical state, known as allotropes of the elements. Allotropes are different structural modifications of an element; the atoms of the element are bonded together in a different manner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>10", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following can be used to predict the type of bonding in HCl?", "images": [], "options": {"A": "pH value", "B": "Electronegativity difference", "C": "Heat of neutralization", "D": "Heat of solution"}, "answer": "B", "explanation": "Difference in electronegativity predicts the bond type of a compound. The higher the electronegativity difference, the stronger the bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>11", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "Which of the following molecules has a linear structure?", "images": [], "options": {"A": "NH3", "B": "H2O", "C": "CO2", "D": "CH4"}, "answer": "C", "explanation": "CompoundsShapeNH3  H2O  CO2  CH4Trigonal Pyramidal  Angular or V-shape or Bent  Linear  Tetrahedral", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>12", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "The volume occupied by a given mass of gas depends on its", "images": [], "options": {"A": "diffusion rate", "B": "temperature and pressure", "C": "degree of solubility", "D": "relative density"}, "answer": "B", "explanation": "Volume depends on temperature according to charles' law and also depends on pressure according to Boyle's law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>13", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume of hydrogen at s.t.p. will be produced when 48g of magnesium reacts completely with dilute hydrochloric acid according to the following equation?  Mg(s) + 2HCl(aq) → MgCl2(aq) + H2(g)  [Mg = 24.1 mole of hydrogen occupies 22.4 dm3 at s.t.p.]", "images": [], "options": {"A": "11.2 dm3", "B": "22.4 dm3", "C": "33.6 dm3", "D": "44.8 dm3"}, "answer": "D", "explanation": "Mg + 2HCl → MgCl2 + H2  1 &nbsp &nbsp &nbsp &nbsp &nbsp  &nbsp &nbsp&nbsp 2 &nbsp &nbsp &nbsp &nbsp &nbsp1 &nbsp &nbsp &nbsp &nbsp 1  No.ofmoleofMg=MassMolar mass  =4824 = 2 moles    From the equation;  1 mole of Mg = 1 mole of H2  2 moles of Mg = x  x = 2 moles of H2  No.ofmoles=VolumeMolar volume  2=Vol22.4  Vol = 44.8dm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2005>14", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "In which of the following reactions is the position of equilibrium not affected by an increase in pressure?", "images": [], "options": {"A": "3Fe(s) + 4H2O(g) ⇋ Fe3O4(s) + 4H2(g)", "B": "2NO2(g) ⇋ N2O4(g)", "C": "3H2(g) + N2(g) ⇋  2NH3(g)", "D": "2SO2(g) + O2(g) ⇋  2SO3(g)"}, "answer": "A", "explanation": "Pressure has no effect if there is no change in volume. Change in volume deals with gaseous state alone.  From options 'a - d', in option 'a', there are equal moles of gaseous product and reactant i.e 4 moles of gaseous product and reactant i.e 4 moles each, so pressure has no effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>15", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The activation energy of a reaction can be altered by", "images": [], "options": {"A": "adding a reducing agent", "B": "applying a high pressure", "C": "using a catalyst", "D": "changing the temperature"}, "answer": "C", "explanation": "The activation energy of a reaction is the minimum amount of energy required for the reaction to occur. It can be altered by using a catalyst, which provides an alternative reaction pathway with a lower activation energy. This is why catalysts are often used to speed up reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>16", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following factors does not affect the rate of reaction of CaCO3 with HCl?", "images": [], "options": {"A": "Temperature of the reaction", "B": "Solubility of the CaCO3", "C": "Concentration of the HCl", "D": "Surface area of the CaCO3"}, "answer": "B", "explanation": "Factors that affect rate of chemical reactions are:  Surface area, concentration, pressure, light, catalyst, temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>17", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "When X is heated with manganese (IV) oxide, oxygen is produced. X is", "images": [], "options": {"A": "KCl", "B": "KClO3", "C": "CaCO3", "D": "ZnCO3"}, "answer": "B", "explanation": "2KClO3 → 2KCl + 3O2  This is a way of preparing oxygen in the laboratory.  MnO2 acts as the catalyst.  X can also be hydrogen peroxide  2H2O → 2H2O + O2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>18", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STATES OF MATTER : KINETIC THEORY OF MATTER.", "question": "Which of the following statements is not a postulate of the kinetic theory of gases?", "images": [], "options": {"A": "Molecules move with the same speed", "B": "Intermolecular forces are negligible", "C": "Molecules are in a state of constant random motion", "D": "Collision between molecules is elastic"}, "answer": "A", "explanation": "Kinetic theory explains the three states of matter using the arrangement of molecules, the force of attraction between the molecules and, the speed of molecules.  In gases, molecules move in random motion colliding with one another  and collision is perfectly elastic. The force of attraction is also negligible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>19", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "HNO3 does not usually react with metals to liberate hydrogen because HNO3 is", "images": [], "options": {"A": "a strong acid", "B": "a corrosive acid", "C": "an oxidizing agent", "D": "a nitrating agent"}, "answer": "C", "explanation": "HNO3 is an highly oxidizing acid. When metals react with acid, they form salt and liberate hydrogen.  Zn + HCl → ZnCl2 + H2  with HNO3, the hydrogen produced is quickly oxidized to form water.  Zn + HNO3 → ZnCl2 + H2O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>20", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "Which of the following is not an acid anhydride?", "images": [], "options": {"A": "P2O5", "B": "NO2", "C": "SO2", "D": "CO"}, "answer": "D", "explanation": "Acid anhydrides are oxides of non-metals. They dissolve in water to give acid. CO is a neutral oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>21", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "NaHCO3(s) can be distinguished from Na2CO3(s) by the action of", "images": [], "options": {"A": "dilute hydrochloric acid", "B": "carbon (IV) oxide", "C": "aqueous ammonia", "D": "heat"}, "answer": "D", "explanation": "Na2CO3 and K2CO3 are thermally stable i.e they can't be decomposed. But NaHCO3 will be decomposed to liberate CO2 gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>22", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "What process is involved in the reaction represented by the following equation?  AlCl3  3H2O(l) → Al(OH)3(s)  3HCl(g)", "images": [], "options": {"A": "Dehydration", "B": "Hydrolysis", "C": "Double decomposition", "D": "Neutralization"}, "answer": "B", "explanation": "- Hydrolysis is the addition of water.  - Dehydration is the removal of water  - Double decomposition is a reaction between two soluble salts to give one soluble and one insoluble salt.  - Neutralization is the reaction between acids and bases to form salt and water only.  Therefore AlCl3 + 3H2O → Al(OH)3 + 3HCl is hydrolysis reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>23", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "A salt that absorbs moisture from the atmosphere without forming a solution is said to be", "images": [], "options": {"A": "efflorescent", "B": "deliquescent", "C": "hygroscopic", "D": "insoluble"}, "answer": "C", "explanation": "Deliquescent salts absorb water of crystallization from the atmosphere and turns into solution. Hygroscopic salts absorb water of crystallization from the atmosphere and turns sticky. Efflorescent salts lose water of crystallization to the atmosphere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>24", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Consider the reation represented by the equation below.  xNH3(g) + yCl2(g) → zHCl(g) + N2(g)  The values of x, y and z are respectively:", "images": [], "options": {"A": "2, 4, 6", "B": "3, 2, 4", "C": "2, 3, 6", "D": "3, 2, 6"}, "answer": "C", "explanation": "xNH3 + yCl2 → zHCl + N2  2NH3 + 3Cl2 → 6HCl + N2  x = 2, y = 3, z = 6", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2005>25", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following compounds dissolves readily in water?", "images": [], "options": {"A": "BaSO4", "B": "CuCO3", "C": "NH4Cl", "D": "AgCl"}, "answer": "C", "explanation": "Rules of Solubility  - All SO42- salts are soluble except Ca2+, Ba2+, Pb2+, Ag+, Hg2+, Cu2+    - All CO32- salts are insoluble except Na+, K+ and NH4+    - All Cl- salts are soluble except Pb2+, Ag+, Cu2+, Hg+    - All salts of Na+, K+ and NH4+ are soluble.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>26", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "When ice is changing to water, its temperature remains the same because the heat gained is", "images": [], "options": {"A": "used to separate the molecules", "B": "lost partially to the atmosphere", "C": "used to increase the volume of ice", "D": "less than the activation energy"}, "answer": "A", "explanation": "When heat is applied to the ice, the temperature increases and this also increases the mobility of its molecules. At 0°C, the molecules in the ice have become as fast at it gets while being bond into a solid configuration and the only way to speed them up further is to break the bonds first. The heat involved is called Latent Heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>27", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following methods is suitable for preparing insoluble salts?", "images": [], "options": {"A": "Thermal decomposition", "B": "Oxidation", "C": "Double decomposition", "D": "Neutralization"}, "answer": "C", "explanation": "Salts are prepared depending on the solubility. Soluble salts are prepared from;  - Neutralization  - Metals reacting with acid    Insoluble salts are prepared from   - Double decomposition  - Direct combination of constituent elements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>28", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "A solution of sodium hydroxide containing 6.0g in 250 cm3 of solution has a concentration of   [molar mass of NaOH = 40g mol-1]", "images": [], "options": {"A": "0.04 mol dm3", "B": "0.60 mol dm3", "C": "0.96 mol dm3", "D": "0.15 mol dm3"}, "answer": "B", "explanation": "Mass, m = 6g  Volume,V=250cm3=2501000=0.25dm3  No.ofmole=massmolar mass  Molar mass = NaOH = 23 + 16 + 1 = 40g/mol  No.ofmole=640 = 0.15 mole  Also, no. of mole = concentration × volume  n = cv  c=nv  c=0.150.25  c = 0.6 moldm-3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2005>29", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "In which of the following reactions is sulphur (IV) oxide acting as an oxidizing agent?", "images": [], "options": {"A": "2HNO3(aq) + SO2(g) → H2SO4(aq) + 2NO2(g)", "B": "2MnO4(aq) + 5SO2(g) + 2H2O(l) → K2SO4(aq) + MnSO4(aq) + 2H2SO4(aq)", "C": "FeCl3(aq) + SO2(g) + 2H2O(l) → FeCl2(aq) + 2HCl(g) + H2SO4(aq)", "D": "2H2S(g) + SO2(g) → 2H2O(l) + 3S(s)"}, "answer": "D", "explanation": "In most redox reactions, SO2 acts as a reducing agent. It behaves as an oxidizing agent only when it reacts with H2S. Moreso, an oxidizing agent oxidizes other substances and itself is reduced. In option D, sulphur is reduced because removal of oxygen is reduction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2005>30", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : OXYGEN", "question": "Which of the following elements will burn in excess oxygen to form a product that is neutral to litmus?", "images": [], "options": {"A": "Carbon", "B": "Hydrogen", "C": "Sulphur", "D": "Sodium"}, "answer": "B", "explanation": "Reactions of the following elements in excess oxygen is given below.  C + O2 → CO2  H2 + O2 → H2O  S + O2 → SO2  2Na + O2 → Na2O2 (Sodium peroxide)  Neutral oxides are CO, H2O and N2O. They do not react with acids nor base.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>31", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Which of the following equation represent a redox reaction?", "images": [], "options": {"A": "Pb(NO3)2(aq) + 2HCl(aq) → PbCl3(s) + 2HNO3(aq)", "B": "H2S(g) + Cl2(g) → 2HCl(g) + S(s)", "C": "AgNO3(aq) + NaCl(aq) → AgCl(s) + NaNO3(aq)", "D": "BaCl2(aq) + K2SO4(aq) → BaSO4(s) + 2KCl(aq)"}, "answer": "B", "explanation": "A redox reaction is a reaction that has both oxidation and reduction processes. Two of the reactants act as oxidizing agent and reducing agent. Also, there is change in oxidation state of some ions.    A. Pb(NO3)2(aq) + 2HCl(aq) → PbCl3(s) + 2HNO3(aq)  Pb2+ → Pb2+ (No change in oxidation state).    B. H2S(g) + Cl2(g) → 2HCl(g) + S(s)  S2- → S (sulphur increases in oxidation state from -2 to 0)    Cl2 → Cl- (There is change from 0 to -1)  ∴ It is a redox reaction  H2S serves as reducing agent  Cl2 serves as oxidizing agent.    C. AgNO3(aq) + NaCl(aq) → AgCl(s) + NaNO3(aq)  Ag+ → Ag+ (There are no change in oxidation state)  Na+ → Na+    This reaction is a double double decomposition reaction.    BaCl2(aq) + K2SO4(aq) → BaSO4(s) + 2KCl(aq)  Ba2+ → Ba2+ (No change in oxidation state)  K+ → K+", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>32", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Determine the mass of copper deposited by 4.0 moles of electrons in the reaction represented by the equation below.  Cu2+(aq) + 2e- → Cu(s)", "images": [], "options": {"A": "32", "B": "64", "C": "128", "D": "256"}, "answer": "C", "explanation": "Cu2+ + 2e- → Cu  1 mole of Cu requires 2 Faradays  x → 4 Faradays  2x = 4   x = 2 moles of Cu  No.ofmoles=massmolar mass  2=mass64  m = 128g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2005>33", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "The main difference between a primary cell and a secondary cell is that the primary cell", "images": [], "options": {"A": "is an electrolytic cell but the secondary is not", "B": "cannot be recharged but the secondary cell can", "C": "can be recharged but the secondary cell cannot", "D": "contains electrodes but the secondary cell does not"}, "answer": "B", "explanation": "Primary cells are cells that CANNOT be recharged after being discharged while secondary cells are cells that can be recharged when used up.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>34", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "A solid can be obtained from its saturated solution by", "images": [], "options": {"A": "filtration", "B": "crystallization", "C": "condensation", "D": "decomposition"}, "answer": "B", "explanation": "A solid can be obtained from its saturated solution by crystallization. Crystallization is a separation technique that is used to separate a solid that has dissolved in a liquid and made a solution. The solution is warmed in an open container, allowing the solvent to evaporate, leaving a saturated solution. When the saturated solution cools, the solid comes out of solution and crystals begin to grow.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>35", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "What is the reducing agent in the reaction represented by the following equation?  Fe3+(aq) + H2S(g) → 2Fe2+(aq) + 2H+(aq) + S(s)", "images": [], "options": {"A": "Fe3+(aq)", "B": "H2S(g)", "C": "Fe2+(aq)", "D": "S(s)"}, "answer": "B", "explanation": "H2S always behaves as a reducing agent. It reduces Fe3+ to Fe2+ (Reddish brown to green). A reducing agent reduces other substance while itself is oxidized, hence the oxidation of H2S to S, which removal of hydrogen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>36", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Reactions undergone by compounds with the general formular CnH2n + 2 include", "images": [], "options": {"A": "addition", "B": "esterification", "C": "substitution", "D": "dehydration"}, "answer": "C", "explanation": "Organic compounds with general molecular formula CnH2n + 2 are Alkanes. They are saturated hydrocarbons. Hence, they will undergo substitution reaction. This implies their hydrogen atoms can only be replaced by other atoms and not added.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>37", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "What is X in the reaction represented by the equation below?  C10H22 → C5H12 + C2H4 + X", "images": [], "options": {"A": "Propene", "B": "Propanol", "C": "Hexene", "D": "Hexane"}, "answer": "A", "explanation": "C10H22 → C5H12 + C2H4 + C3H6  X is propene", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>38", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "What is the major product formed when C2H5OH reacts with CH3COOH?", "images": [], "options": {"A": "C2H5COOCH3", "B": "C2H5COCH3", "C": "CH3COOC2H5", "D": "C3H7COOH"}, "answer": "C", "explanation": "The reaction between C2H5OH (ethanol) and CH3COOH (acetic acid) is an esterification reaction. In this reaction, an ester is formed by the removal of a water molecule. The ester formed in this case is ethyl acetate, which is CH3COOC2H5.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>39", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "What is the IUPA name of the compound with the structure below?", "images": ["Chemistry/imgs/2005/img1.png"], "options": {"A": "1, 2 - dibromoethane", "B": "Methyl dibromoethane", "C": "Trans - bromoethane", "D": "2 - dibromoethane"}, "answer": "A", "explanation": "The compound is ethane whose two of its hydrogen atoms have been replaced with bromine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>40", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Which of the following substances is a non-reducing sugar?", "images": [], "options": {"A": "Sucrose", "B": "Glucose", "C": "Fructose", "D": "Maltose"}, "answer": "A", "explanation": "Reducing sugar gives positive test with Tollen's reagent and Fehling solution. Non reducing sugar do not. Sucrose is a non-reducing sugar.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>41", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "The colour of the solution formed when ethyne reacts with an acidic solutions of potassium tetraoxomanganate(VII) is", "images": [], "options": {"A": "purple", "B": "colourless", "C": "green", "D": "pink"}, "answer": "B", "explanation": "Unsaturated hydrocarbons decolourize KMnO4. They also decolourize chlorine water, bromine water and change the colour of K2Cr2O7 from orange to green. These are tests to distinguish saturated from unsaturated hydrocarbons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>42", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Consider the reaction represented by the equation below:  CH4(g) + 2O2(g) → O2(g) + 2H2O(l)  How many moles of carbon (IV) oxide will be produced from 32g of methane?  [H = 1, C = 12, O = 16]", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "8"}, "answer": "A", "explanation": "CH4 + 2O2 → CO2 + 2H2O  1 &nbsp &nbsp &nbsp &nbsp 2 &nbsp &nbsp &nbsp &nbsp 1 &nbsp &nbsp &nbsp &nbsp 2  Noofmoleofmethane,CH4=massmolar mass  Molar mass of CH4 = 12 + (4 × 1) = 16gmol-1  NoofmoleofCH4=3216= 2 moles    From the equation:  1 mole of CH4 → 1 mole of CO2  ∴ 2 moles of CH4 → x  x = 2 moles of CO2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>43", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "Fats are classified as", "images": [], "options": {"A": "hydrocarbons", "B": "alkanoates", "C": "alkanols", "D": "carbohydrates"}, "answer": "B", "explanation": "Fats are esters of long-chain carboxylic acids (fatty acids) and glycerol. Therefore, they are classified as alkanoates, which are esters of carboxylic acids.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>44", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "Ethyne undergoes the following reactions except", "images": [], "options": {"A": "polymerisation", "B": "addition", "C": "substitution", "D": "esterification"}, "answer": "D", "explanation": "- Polymerization is the joining together of several moles of a compound to form giant molecule. It is a condensation reaction. Ethyne undergoes polymerization to form benzene  3[C2H2] → C6H6    - Addition reaction is a reaction undergone by unsaturated hydrocarbon to become saturated or less saturated. Ethyne undergoes addition reaction with halogens, halides, hydrogen  C2H2 + H2 → C2H4  C2H2 + Cl2 → C2H2Cl2    - Substitution reaction is a reaction for saturated hydrocarbon. Though ethyne is an unsaturated hydrocarbon but terminal alkynes do. Ethyne is a terminal alkyne, so it undergoes substitution reaction with Ammoniacal silver I chloride or Ammoniacal copper I chloride.  H - C ≡ C - H + AgCl → H - C ≡ C - Ag (in the presence of NH3)    - Esterification reaction is a reaction between Alkanols and Alkanoic acid to give Alkanoates and water. It is not a reaction for Alkynes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>45", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following compounds has the highest percentage of carbon?  [H = 1, C = 12, O = 16]", "images": [], "options": {"A": "C2H2", "B": "C2H4", "C": "C2H6", "D": "C2H6O"}, "answer": "A", "explanation": "To get the one with the highest % of carbon, we find the % by mass of carbon in each compound.    A. C2H2  Molar mass = (12 × 2) + (1 × 2) = 26gmol-1  %ofC=2426×100=92.3%    B. C2H4  Molar mass = (12 × 2) + (1 × 4) = 28gmol-1  % of C = 24/28 × 100 = 85.7%    C. C2H6  Molar mass = (12 × 2) + (1 × 6) = 30 gmol-1  %ofC=2430×100=80%    D. C2H6O  Molar mass = (12 *time* 2) + (1 × 6) + 16 = 46gmol-1  %ofC=2446×100=52.2%", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>46", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION", "question": "Hardness in water can be removed by adding", "images": [], "options": {"A": "copper (II) tetraoxosulphate (IV)", "B": "sodium trioxocarbonate (IV)", "C": "sodium chloride", "D": "alum"}, "answer": "B", "explanation": "Hardness of water can be removed by   - Addition of washing soda (Na2CO3)  - Addition of slaked lime [Ca(OH)2]  - Addition of permutit & zeolite  - Use of ion exchange resins  - Boiling (only for temporary hardness)", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>47", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following pairs of solutions will produce a precipitate when mixed?", "images": [], "options": {"A": "Pb(NO3)2(aq) and NaCl(aq)", "B": "MgSO4(aq) and HCl(aq)", "C": "ZnCl2(aq) and NaSO4(aq)", "D": "NaOH(aq) and HNO3(aq)"}, "answer": "A", "explanation": "The one that will give a precipitate is the reaction that is DOUBLE DECOMPOSITION, a reaction between two soluble salts to give a precipitate (insoluble salt) and a soluble salt.    A. Pb(NO3)2(aq) + NaCl(aq) → PbCl2 + NaNO3  &nbsp &nbsp &nbsp (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (ppt) &nbsp &nbsp &nbsp  &nbsp &nbsp &nbsp (sol)    B. MgSO4 + HCl → MgCl2 + H2SO4  &nbsp &nbsp &nbsp (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (acid) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (acid)    C. ZnCl2 + Na2SO4 → ZnSO4 + NaCl  &nbsp &nbsp &nbsp (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (sol)    D. NaOH + HNO3 → NaNO3 + H2O  &nbsp &nbsp &nbsp (Base) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (acid) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (sol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (water)    Option 'B' is nullified because HCl is an acid.  Option 'C' is nullified because ALL are soluble salts   Option 'D' is also nullified because NaOH is a base.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2005>48", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "The diagram below represents the reaction profile for an exothermic reaction    Which of the following do P, Q and R represent?", "images": ["Chemistry/imgs/2005/img2.png"], "options": {"A": "Activated complex, heat of reaction, activation energy", "B": "Heat of reaction, activated energy, activated complex", "C": "Activation energy, heat of reaction, activated complex", "D": "Activated complex, activation energy, heat of reaction"}, "answer": "D", "explanation": "Activation energy is the energy required to break the bond of reactants in order for new bonds to be formed i.e product. It is given by  Activation energy = Energy of activated complex - energy of reactant.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2005>49", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Which of the following substances is an alloy of lead?", "images": [], "options": {"A": "Brass", "B": "Duralumin", "C": "Stainless steel", "D": "Soft solder"}, "answer": "D", "explanation": "Duralumin ⇒ Copper + Aluminium + Manganese + Magnesium  Brass ⇒ Copper + Zinc   Stainless steel ⇒ Iron + Carbon + Chromium  Soft solder ⇒ tin + Lead", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2005>50", "subject": "Chemistry", "year": "2005", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "In which of the following process is biotechnology not applied?", "images": [], "options": {"A": "Manufacture of drugs", "B": "Treatment of domestic sewage", "C": "Production of alcoholic beverages", "D": "Electroplating of metals"}, "answer": "D", "explanation": "Biotechnology is technology that utilizes biological systems, living organisms or parts of this to develop or create different products. It is not used in electroplating of metals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>1", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "How many orbitals are in the d-sub shell?", "images": [], "options": {"A": "1", "B": "3", "C": "5", "D": "7"}, "answer": "C", "explanation": "The d-subshell has 5 degenerate orbitals.  The s subshell has 1 orbital that can hold up to 2 electrons, the p subshell has 3 orbitals that can hold up to 6 electrons, the d subshell has 5 orbitals that hold up to 10 electrons, and the f subshell has 7 orbitals with 14 electrons", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>2", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.", "question": "An element X has isotopic masses of 6 and 7. If the relative abundance is 1 to 12.5 respectively, what is the relative atomic mass of X?", "images": [], "options": {"A": "6.0", "B": "6.1", "C": "6.9", "D": "7.0"}, "answer": "C", "explanation": "Given:  * Two isotopic samples of masses, m1 and m2 as 6 and 7 respectively.  * The atomic mass of the element = unknown  * The respective relative abundances of samples 1 and 2 as 1 and 12.5  Recall that: RAM = m1α1 + m2α2  α1=R1R1 + R2andα2=R2R1 + R2  R.A.M=6×113.5+7×12.513.5  R.A.=613.5+87.513.5=93.513.5=6.9", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>3", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.", "question": "An atom 23892X decays by alpha particle emission to give an atom Y. The atomic numbers and mass number of Y are", "images": [], "options": {"A": "90 and 234 respectively", "B": "91 and 238 respectively", "C": "92 and 236 respectively", "D": "93 and 238 respectively"}, "answer": "A", "explanation": "Alpha decay is a type of radioactive decay in which an atomic nucleus emits an alpha particle (consisting of two protons and two neutrons) and transforms into an atom with a mass number 4 less and atomic number 2 less. Therefore, if atom X has a mass number of 238 and atomic number of 92, after alpha decay, atom Y will have a mass number of 238 - 4 = 234 and atomic number of 92 - 2 = 90.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>4", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "An element with mass number 133 and atomic number 55 has", "images": [], "options": {"A": "55 electrons and 55 neutrons", "B": "55 electrons and 78 neutrons", "C": "78 electrons and 78 neutrons", "D": "78 electrons and 55 neutrons"}, "answer": "B", "explanation": "Given an element say P which has an atomic number of 55 and a mass number of 133  amP  Recall that: a = atomic number = number of protons = 55  m = mass number = number of proton + number of neutron = 133  Also, Recall that: number of proton = number of electron = 55  Hence, mass number = number of electron + number of neutron  133 = 55 + number of neutron  number of neutron = 78  Hence, P has 55 electron and 78 neutron.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>5", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following pairs of species contains the same  number of electrons? [6C, 8O, 10Ne, 11Na, 12Mg, 13Al, 17Cl]", "images": [], "options": {"A": "Mg2+ and Al3+", "B": "Cl- and Ne", "C": "Na+ and Mg", "D": "C and O2-"}, "answer": "A", "explanation": "The atomic number of Mg is 12 and Al is 13. When Mg loses 2 electrons to form Mg2+, it has 10 electrons. Similarly, when Al loses 3 electrons to form Al3+, it also has 10 electrons. Therefore, Mg2+ and Al3+ have the same number of electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>6", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "An element X has electronic configuration 1s22s22p63s23p64s2. To which group of the periodic table does X belong?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "Given:  X has an electronic configuration: 1s2 2s2 2p6 3s2 3p6 4s2.  X has (2 + 2 + 6 + 2 + 6 + 2) electrons = 20 electrons  The distribution of the 20 electrons into main orbitals = 2, 8, 8, 2.  Hence, X belongs to group 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>7", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following sets of elements is arranged in order of increasing first ionization energies?", "images": [], "options": {"A": "11Na, 3Li, 19K, 37Rb", "B": "37Rb, 19K, 3Li, 11Na", "C": "3Li, 19K, 11Na, 37Rb", "D": "37Rb, 19K, 11Na, 3Li"}, "answer": "D", "explanation": "Ionization energy decreases down a group. All the elements given belong to group 1.  Hence: In order of increasing ionization energy we have   37Rb, 19K, 11Na, 3Li", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>8", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following electronic configurations represent that of a noble gas?", "images": [], "options": {"A": "2, 8, 8, 2", "B": "2, 8, 2", "C": "2, 8", "D": "2, 6"}, "answer": "C", "explanation": "The answer has a complete number of electrons in the L-shell making it 10 electrons, i.e Neon. Neon is a noble gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>9", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "Diamond is a hard substance because its carbon atoms are held by", "images": [], "options": {"A": "delocalised electrons", "B": "strong electrostatic forces", "C": "van der walls forces", "D": "strong directional covalent bonds"}, "answer": "D", "explanation": "Diamond is a form of carbon in which each carbon atom is connected to four other carbon atoms through strong covalent bonds. These bonds are very strong and directional, which gives diamond its hardness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>10", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "The presence of unpaired electrons in an atom of a d-block element accounts for its", "images": [], "options": {"A": "ductility", "B": "lustre", "C": "malleability", "D": "paramagnetism"}, "answer": "D", "explanation": "Paramagnetism is a form of magnetism whereby certain materials are attracted by an externally applied magnetic field, and form internal, induced magnetic fields in the direction of the applied magnetic field. This is due to the presence of unpaired electrons in the d-block element.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>11", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Elements which belong to the same group in the periodic table are characterized by", "images": [], "options": {"A": "difference of +1 in the oxidation numbers of successive members", "B": "presence of the same number of outermost electrons in the respective atoms", "C": "difference of 14 atomic mass units between successive members", "D": "presence of the same number of electron shells in the respective atoms"}, "answer": "B", "explanation": "Elements that belong to the same group have the same number of valence electrons.  Valence electrons: These are electrons that are found in the outermost shell of the atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>12", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The atomic numbers of element X and Y are 20 and 17 respectively. Which of the following compounds is likely to be formed by the combination of the two elements?", "images": [], "options": {"A": "XY", "B": "XY2", "C": "XY3", "D": "X2Y"}, "answer": "B", "explanation": "Given: Two elements X and Y with atomic numbers 20 and 17 respectively   X is calcium since the atomic number is 20  Y is chlorine since the atomic number is 17  Calcium will combine with chlorine in an electrovalent bond to form CaCl2 = XY2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>13", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "What type of bond will be formed between elements P and Q if their electronegativity values are 0.8 and 4.0 respectively?", "images": [], "options": {"A": "Covalent bonding", "B": "Co-ordinate bond", "C": "Ionic bond", "D": "Metallic bond"}, "answer": "C", "explanation": "Ionic bond usually between atoms of large electronegativity difference, Δx ≥ 0.7. The electronegativity difference is very wide. Hence the bond is ionic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>14", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "What type of chemical bonding is involved in the formation of NH+4 from a molecule of ammonia and a proton?", "images": [], "options": {"A": "Covalent bonding", "B": "Co-ordinate covalent bonding", "C": "Electrovalent bonding", "D": "Hydrogen bonding"}, "answer": "B", "explanation": "The type of chemical bonding involved in the formation of NH4+ is coordinate covalent bonding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>15", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "What is responsible for metallic bonding?", "images": [], "options": {"A": "Attraction between the delocalized electrons and fixed positive lattice points (cations)", "B": "Attraction between positive and negative ions", "C": "Sharing of electrons between the metal atoms", "D": "Transfer of electrons from one atom to another"}, "answer": "A", "explanation": "The metallic bonding is the attraction between the delocalised electrons and fixed lattice points (cations).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>16", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Use the following portion of the period table to answer this question      Which of the letters indicate elements which exist as diatomic gases?", "images": ["Chemistry/imgs/2006/pix1.png"], "options": {"A": "B and G", "B": "A and F", "C": "C and A", "D": "A and E"}, "answer": "B", "explanation": "Only F which is group Vii (Halogen) and A in group 1 that is diatomic", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>17", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Use the following portion of the period table to answer this question    Which of the letters represents an alkaline earth metal?", "images": ["Chemistry/imgs/2006/pix1.png"], "options": {"A": "F", "B": "E", "C": "D", "D": "C"}, "answer": "D", "explanation": "Elements in group II are called \"Alkaline Earth Metals\". C belongs to group II", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>18", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Use the following portion of the period table to answer this question    Which of the following pairs of letters denotes elements containing the same number of electrons in their outermost shells?", "images": ["Chemistry/imgs/2006/pix1.png"], "options": {"A": "C and D", "B": "E and F", "C": "B and G", "D": "A and B"}, "answer": "C", "explanation": "Elements containing the same number of electrons in their outer most shells belong to the same group. B and G belong to the same group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>19", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "If 1 mole of sodium contains 6 ×1023 atoms, how many atoms are contained in 0.6g of sodium?  [Na = 23]", "images": [], "options": {"A": "1.56 × 1023", "B": "1.56 × 1022", "C": "3.6 × 1023", "D": "3.6 × 1022"}, "answer": "B", "explanation": "1 mole of sodium contains 6 × 1023 atoms   1 mole of sodium = 23g  ∴ 23g of sodium contains 6 × 1013 atoms   0.6g of sodium contains x atoms   230.6=6 × 1023x  23x = 3.6 × 1023  x=3.6 × 102323=3.62.3×1022  x = 1.56 × 1022 atoms", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>20", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "If 20cm3 of distilled water is added to 80cm3 of 0.50 mol/dm3 hydrochloric acid, the new concentration of the acid will be", "images": [], "options": {"A": "0.10 moldm-3", "B": "0.20 moldm-3", "C": "0.40 mol/dm-3", "D": "2.00 mol/dm-3"}, "answer": "C", "explanation": "Given:  Initial concentration, C1 = 0.50moldm-3  Final concentration, C2 = C2  Volume of water added, x = 20cm3  Initial volume of the solution, V1 = 80cm3  Recall that,  C1V1 = C2V2  V2 = V1 + x   ∴ C1V1 = C2(V1 + x)  0.5 × 80 = C2 (80 + 20)  40 = C2(100)  C2 = 0.4 moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>21", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Consider the reaction represented by the equation:  2NaHCO3(s) → Na2CO3(s) + CO2(g) + H2Og  Heat as a catalyst.  What volume of carbon(IV)oxide at s.t.p is evolved when 0.5 moles of NaHCO3 is heated?  [Molar volume = 22.4dm3 at s.t.p]", "images": [], "options": {"A": "1.12dm3", "B": "2.24dm3", "C": "5.6dm3", "D": "56.0dm3"}, "answer": "C", "explanation": "Given:  2NaHCO3(s) → Na2CO3(s) + H2O(g) + CO2(g).  * When 2 moles of NaHCO3 is heated 1 mole of CO2(g) is formed   * 1 mole of CO2(g) = 22.4dm3  ∴ 2 moles of NaHCO3 produces 22.4dm3  0.5 mole of NaHCO3 will produce x dm3  20.5=22.4x  2x = 11.2  x = 5.6 dm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2006>22", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases will have the lowest rate of diffusion under the same conditions?  [N = 14, O = 16, Cl = 35.5, Ar = 40]", "images": [], "options": {"A": "Argon", "B": "Chlorine", "C": "Nitrogen", "D": "Oxygen"}, "answer": "B", "explanation": "The higher than the mass, the slower the rate of diffusion and vice versa. Chlorine gas, Cl2 has the highest mass, 71gmol-1. Hence, it has the slowest rate of diffusion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>23", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Consider the reaction: H+(aq) + OH-(aq) → H2Ol   The energy change taking place in the reaction above is enthalpy of", "images": [], "options": {"A": "formation", "B": "hydration", "C": "neutralization", "D": "solution"}, "answer": "C", "explanation": "Given: the reaction  H+ + OH- → H2O  The reaction above is a neutralization reaction as it involves the reaction between the proton (H+) of an acid and an hydroxyl ion (OH-) from a base.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>24", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following processes is an endothermic reaction?", "images": [], "options": {"A": "Dissolving NH4Cl crystals in water", "B": "Addition of concentrated H2SO4 to water", "C": "Dissolving NaOH pellets in water", "D": "Passing SO3 gas into water"}, "answer": "A", "explanation": "An endothermic reaction is a reaction that absorbs heat from the surroundings. When NH4Cl crystals are dissolved in water, the system absorbs heat from the surroundings to break the ionic bonds in NH4Cl, making it an endothermic process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>25", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "In the energy profile diagram below, which letter represents the activation energy for the reverse reaction?", "images": ["Chemistry/imgs/2006/pix2.png"], "options": {"A": "X", "B": "Y", "C": "Z", "D": "P"}, "answer": "A", "explanation": "Given:  The energy profile diagram; The activation energy = The activation complex  - Heat content of the reaction. For the reverse reaction, the difference between the activation complex and that of the reactant is Y. For the forward reaction, the difference between the activation complex and that of the reactant is X.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2006>26", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Which of the following aqueous solutions turns red litmus to blue?", "images": [], "options": {"A": "NaCl", "B": "CH3COONa", "C": "AlCl3", "D": "NH4Cl"}, "answer": "B", "explanation": "A solution which turns red litmus blue is a basic solution. CH3COONa is basic. This is because it is formed from a strong base and a weak acid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>27", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "Which of the following methods cannot be used to distinguish between a strong acid and a weak acid?", "images": [], "options": {"A": "Conductivity measurement", "B": "Measurement of pH", "C": "Measurement of heat of neutralization", "D": "Action on starch iodide paper"}, "answer": "D", "explanation": "Action of acids on starch iodide paper is not used to distinguish between a strong acid and a weak acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>28", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "The indicator used in neutralizing CH3COOH and NaOH solutions has pH range of", "images": [], "options": {"A": "3 - 5", "B": "7 - 8", "C": "8 - 10", "D": "10 - 12"}, "answer": "C", "explanation": "CH3COOH is a weak acid and NaOH a strong base. Conventionally, the pH range when a weak acid and a strong base react is 7 to 11.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>29", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "PERIODIC CHEMISTRY : REACTIONS BETWEEN ACIDS AND METALS, THEIR OXIDES AND TRIOXOCARBONATES (IV).", "question": "When aqueous ammonia is added to one of the following solutions, a white precipitate which dissolves in excess ammonia is formed. Identify the solution.", "images": [], "options": {"A": "ZnCl2(aq)", "B": "Pb(NO3)2(aq)", "C": "CuSO4(aq)", "D": "FeSO4(aq)"}, "answer": "A", "explanation": "Zn2+ ion in solution forms a white precipitate with aqueous ammonia and the precipitate is soluble in excess ammonia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>30", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "When 50cm3 of a saturated solution of KNO3 at 25°C was evaporated to dryness, 10g of dry salt was obtained. What is the solubility of KNO3 at 25°C?  [KNO3 = 101]", "images": [], "options": {"A": "0.10 mol dm-3", "B": "2.0 mol dm-3", "C": "5.0 mol dm-3", "D": "10.0 mol dm-3"}, "answer": "B", "explanation": "Given:  The mass of KNO3 = 10g  The volume of KNO3 solution = 50cm3  The molar mass of KNO3 = 101gmol-1  The number of mole of KNO3 = 10/101 = 0.1mole  ∴ 0.1mole of KNO3 is in 50cm3  x mole of KNO3 is in 1000cm3  0.1x=120  x = 2.0 mol/1000 cm3  1000 cm3 = 1 dm3  x = 2.0moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>31", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "Which of the following compounds absorbs moisture from the atmosphere and dissolves in it?", "images": [], "options": {"A": "FeCl3", "B": "MgSO4.7H2O", "C": "Na2SO4", "D": "KCl"}, "answer": "A", "explanation": "The compound analysed is a deliquescent compound. Iron III Chloride, FeCl3 is a deliquescent compound.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>32", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Consider the diagram below:    The set-up is used for the preparation of a salt by", "images": ["Chemistry/imgs/2006/pix3.png"], "options": {"A": "double decomposition", "B": "crystallization", "C": "neutralization", "D": "direct combination"}, "answer": "C", "explanation": "The reaction above represents a neutralization reaction as it involves an acid and a base (sodium hydroxide).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>33", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the equation for the equilibrium reaction  N2(g) + 3H2(g) ⇔ 2NH3(g); ΔH = -92 kJmol-1  The equilibrium constant for the reaction can be expressed as", "images": [], "options": {"A": "Kc=2(NH3 )3( H2 )(N2)", "B": "Kc=(NH3 )2 (N2)(H2)3", "C": "Kc=3(H2)(N2 )2(NH3)", "D": "Kc=(N2)(H2)3(NH3)3"}, "answer": "B", "explanation": "Given:  The equilibrium reaction.  N2(g) + 3H2(g) ↔ 2NH3(g)  kc=(NH3)2(N2)(H2)3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2006>34", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the reaction represented by the equation:  2SO2(g) + O2(g) ⇔ 2SO3(g): ΔH = -197 kJmol-1  Which of the following conditions will not increase the yield of sulphur(VI)oxide?", "images": [], "options": {"A": "Increase in temperature", "B": "Decrease in temperature", "C": "Increase in pressure", "D": "Addition of O2 into the mixture"}, "answer": "A", "explanation": "Given:  - The reversible reaction  2SO2(g) + O2(g) ↔ 2SO3(g) ΔH = 197kJmol-1. 197kJmol-1 means that the reaction is exothermic. According to Le chatellier's principle, an increase in temperature will not increase the yield of Sulphur(IV) Oxide, SO2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>35", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Electrolysis is applied in the following processes except", "images": [], "options": {"A": "electroplating", "B": "extraction of aluminium", "C": "extraction of iron", "D": "purification of copper"}, "answer": "C", "explanation": "Electrolysis is a process that uses electric current to drive a non-spontaneous chemical reaction. It is used in electroplating, extraction of aluminium, and purification of copper. However, the extraction of iron is done through the blast furnace method, which involves reduction of iron ores, not electrolysis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>36", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of iodine in the iodate ion (IO3-) is", "images": [], "options": {"A": "-5", "B": "-1", "C": "+1", "D": "+5"}, "answer": "D", "explanation": "Given:  The radical, (IO3-)  The oxidation number of the radical is -1  The oxidation number of the radical = Sum of the oxidation numbers of the constituents  Hence, -1 = O.N(I) + 3 × 0.4(0)  -1 = O.N(I) + 3(-2)  -1 = O.N(I) - 6  O.N(I) = 5  Therefore, the oxidation number of Iodine = 5", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>37", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Metals can be extracted from their ores by a process involving", "images": [], "options": {"A": "reduction", "B": "oxidation", "C": "hydrolysis", "D": "decomposition"}, "answer": "A", "explanation": "Metals can be extracted from their ores by reduction. This is one of the principles of metal extraction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>38", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Consider the reaction:  2Al(s) + 6H+(aq) → 2Al3+(aq) + 3H2(g)  What is the total number of moles of electrons transferred from the aluminium atoms to the hydrogen ions?", "images": [], "options": {"A": "3", "B": "4", "C": "5", "D": "6"}, "answer": "D", "explanation": "Given: The equation  2Al(s) + 6H+(aq) → 2Al3+(aq) + 3H2(g) ......(i)  (1) 2Al - 6e- → 2Al3+ (Half - cell equation)  (2) 6H+ + 6e- → 3H2  from Aluminium atom  2Al → 2Al3+ + 6e-  ......(i)  6H+ + 6e- → 3H2  ......(ii)  2Al + 6H+ + 6e- → 2Al3+ + 6e- + 3H2  cancel 6e- on both sides   2Al + 6H+ → 2Al3+ + 3H2  ......(i)  Therefore, 6 moles of electrons is transferred from aluminium atom to hydrogen ion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>39", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "In the reaction represented by the equation:  5Fe2+(aq) + MnO-4(aq) + 8H+(aq) → 5Fe3+(aq) + Mn2+(aq) + 4H2O(l)   Which species is reduced?", "images": [], "options": {"A": "Fe2+", "B": "MnO-4", "C": "H+", "D": "Fe3+"}, "answer": "B", "explanation": "Given: The Redox reaction  5Fe2+(aq) + MnO4-(aq) + 8H+(aq) → 5Fe3+(aq) + Mn2+(aq) + 4H2O(l)  MnO4- is reduced because the oxidation of Mn has reduced from +7 to +2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>40", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Use the structure of the compound below to answer this question      The name of the compound is", "images": ["Chemistry/imgs/2006/pix4.png"], "options": {"A": "2, 3-dimethybutan-1-ol", "B": "2, 3-dimethylbutan-4-ol", "C": "2-methylpentan-1-ol", "D": "3-methylpentan-1-ol"}, "answer": "A", "explanation": "Given: The compound    - Numbering from right to left, the functional group, -OH - as it falls on the first carbon. The attachments are on the 2nd and 3rd carbon and the longest continuous carbon chain is 4. Hence, the root name is butan-1-ol. Hence the name of the compound is 2, 3-dimethylbutan-1-ol", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>41", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "The product of the complete oxidation of the compound will be an", "images": [], "options": {"A": "alkane", "B": "alkanal", "C": "alkanoic acid", "D": "alkanone"}, "answer": "C", "explanation": "The compound in question 40 is an alkanol. When alkanols are oxidized completely, they give alkanoic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>42", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following industrial processes is chlorine not used?", "images": [], "options": {"A": "Production of polyvinylchloride (PVC)", "B": "Manufacturing of hydrochloric acid", "C": "Manufacturing of common salt", "D": "Manufacturing of domestic bleach"}, "answer": "C", "explanation": "Chlorine is not used in the manufacturing of common salt. Common salt, also known as sodium chloride, is a naturally occurring mineral that is harvested from salt mines or sea water through evaporation, and does not require the use of chlorine in its production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>43", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "What type of reaction occurs between vegetable oil and plant ash extract?", "images": [], "options": {"A": "Displacement", "B": "Dehydration", "C": "Neutralization", "D": "Saponification"}, "answer": "D", "explanation": "Saponification is the reaction that occurs between plants ash and vegetable oil. Saponification reaction involves the production/manufacture of soap.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>44", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following compounds is an alkanoate?", "images": [], "options": {"A": "CH3COOH", "B": "CH3COOCH3", "C": "CH3CH2OH", "D": "CH3CH2COOH"}, "answer": "B", "explanation": "Alkanoates usually have the structure R COOR', where R represents an alkyl. In view of this, the chosen answer conforms with the structural formula.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>45", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "What is CaHb in the following equation?  CaHb + 5O2 → 3CO2 + 4H2O", "images": [], "options": {"A": "C3H4", "B": "C3H6", "C": "C3H8", "D": "C5H10"}, "answer": "C", "explanation": "Given: The reaction  CaHb + 5O2 → 3CO2 + 4H2O  → The reaction above is the oxidation process of hydrocarbons  - Conventionally, it is given as:  CxHy=x+y4O2→xCO2+y2H2O  Where CxHy is an hydrocarbon.  From the equation above, a = x and b = y  x+y4=5......(i)  x = 3 and y/2 = 4  ∴ x = 3 and y = 8  CxHy = C3H8 = CaHb", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2006>46", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Which of the following equations represents a substitution reaction?", "images": [], "options": {"A": "C4H10(g) + Cl2(g) → C4H9Cl(g) + HCl(g)", "B": "C2H4(g) + HCl(g) → C5H5Cl(l)", "C": "C2H2(g) + 2H2(g) → C2H6(g)", "D": "C3H4(g) + 4O2(g) → 3CO2(g) + 2H2O(g)"}, "answer": "A", "explanation": "A substitution reaction is a chemical reaction during which one functional group in a chemical compound is replaced by another functional group. In the given options, C4H10(g) + Cl2(g) → C4H9Cl(g) + HCl(g) is a substitution reaction. In this reaction, one hydrogen atom in butane (C4H10) is replaced by a chlorine atom to form chlorobutane (C4H9Cl) and hydrogen chloride (HCl).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>47", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Greenhouse effects can be reduced by controlling", "images": [], "options": {"A": "water evaporation", "B": "burning of wood and fossil fuel", "C": "the use of aerosols", "D": "the use of artificial fertilizers"}, "answer": "B", "explanation": "The greenhouse effect can be reduced by controlling the burning of wood and fossil fuels. The burning of these materials releases carbon dioxide, a greenhouse gas, into the atmosphere. The greenhouse effect is the process by which radiation from a planet's atmosphere warms the planet's surface to a temperature above what it would be without this atmosphere. Therefore, by reducing the burning of wood and fossil fuels, we can reduce the amount of carbon dioxide released into the atmosphere and thus reduce the greenhouse effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>48", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Waste plastics accumulate in the soil and pollute the environment because plastic materials are", "images": [], "options": {"A": "insoluble in water", "B": "non-biodegradable", "C": "easily affected by heat", "D": "inflammable"}, "answer": "B", "explanation": "Waste plastics accumulate in the soil and pollute the environment because plastic materials are non-biodegradable. Non-biodegradable substances are those that cannot be broken down by natural processes into more basic components. Plastics are made from long chains of polymers that most organisms cannot break down and use as a source of energy or raw materials. As a result, plastics remain in the environment for a long time, leading to pollution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2006>49", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following substances is an ore of iron?", "images": [], "options": {"A": "Bauxite", "B": "Cassiterite", "C": "Haematite", "D": "Steel"}, "answer": "C", "explanation": "Haematite, Fe2O3.2H2O is an ore of iron. An ore is the natural form in which a metal exist.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2006>50", "subject": "Chemistry", "year": "2006", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "The ammonium compound used in the manufacture of dry cells is", "images": [], "options": {"A": "NH4NO3", "B": "(NH4)2SO4", "C": "NH4Cl", "D": "(NH4)2CO3"}, "answer": "C", "explanation": "Ammonium chloride, NH4Cl is used as electrolyte in dry cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>1", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "When sodium atom forms the ion Na+,", "images": [], "options": {"A": "it gains one electron", "B": "it gains one proton", "C": "it achieves a noble gas configuration", "D": "its atomic number increases"}, "answer": "C", "explanation": "When sodium atom forms the ion, Na+ it loses one electron, i.e it achieves a noble gas electronic configuration. It will lose one of its 11 electrons to have 10 electrons like neon which is its noble gas neighbour.  Na - e- → Na+  Na → Na+ + e-", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>2", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "PERIODIC CHEMISTRY : THE NOBLE GASES", "question": "Which of the following statements about rare gases are correct?  I. Their outermost shells are fully filled  II. They are generally unreactive  III. Their outermost shells are partially filled  IV. They have lone pair of electrons in their outermost shell", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I, II and III only", "D": "I, II, III and IV"}, "answer": "A", "explanation": "Rare gases, also known as noble gases, are known for their low reactivity. This is because their outermost shells are fully filled, making them stable and unlikely to react with other elements. Therefore, statements I and II are correct. Statement III is incorrect because the outermost shells of rare gases are not partially filled, but fully filled. Statement IV is also incorrect because rare gases do not have lone pairs of electrons in their outermost shell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>3", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "How many electrons are in the ion F-? [199F]", "images": [], "options": {"A": "8", "B": "9", "C": "10", "D": "19"}, "answer": "C", "explanation": "Given: F- (a fluoride ion)  199F. The atomic number of F = number of electrons of F = 9  F + e- → F-  9e- + e- → 10e-  F- has 10e- (10 electrons)", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>4", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "What is the value of x in the following nuclear reaction equation?  115B + 25198Cf → x103Lr + 310n", "images": [], "options": {"A": "241", "B": "259", "C": "261", "D": "265"}, "answer": "B", "explanation": "Given: THe nuclear reaction:  115B + 25198Cf → x103Lr + 3 10n  Balance the mass numbers on both sides   ∴ 11 + 251  = x + 3(1)  262 = x + 3  x = 259", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2007>5", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following properties is characteristic of the halogens?", "images": [], "options": {"A": "Ability to accept electrons readily", "B": "Ability to donate electrons readily", "C": "Ability to form basic oxides", "D": "Formation of coloured compounds"}, "answer": "A", "explanation": "Halogens are elements in Group 17 (VIIA) of the periodic table. They have seven valence electrons and need one more electron to achieve a stable octet configuration. Therefore, they have a strong tendency to gain or accept one electron, making them good oxidizing agents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>6", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "In which of the following atoms is the ionic radius larger than the atomic radius? [11Na, 12Mg, 13Al, 17Cl]", "images": [], "options": {"A": "Aluminium", "B": "Chlorine", "C": "Magnesium", "D": "Sodium"}, "answer": "B", "explanation": "All the elements given belong to the same period because they have the same number of electronic shells.  * 11Na → 12Mg →13Al → 17Cl in order of decreasing atomic radius, because atomic radius decreases across a period.  * Chlorine has a larger ionic radius than the atomic radius since it will accept electron.  N.B: Atomicradiusα1Ionic radius", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>7", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "A transition metal would be expected to", "images": [], "options": {"A": "form oxides with different formulae", "B": "have strong oxidizing ability", "C": "have low density", "D": "have an atomic structure with an incomplete outermost shell"}, "answer": "A", "explanation": "Transition metals are known for their ability to form a variety of different compounds due to their variable oxidation states. This means they can form oxides with different formulae. The other options are not generally true for all transition metals. For example, not all transition metals have strong oxidizing ability, low density, or an atomic structure with an incomplete outermost shell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>8", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which the following properties of atoms generally increases down a group in the periodic table?", "images": [], "options": {"A": "Electron affinity", "B": "Electronegativity", "C": "Ionic radius", "D": "Ionization energy"}, "answer": "C", "explanation": "As you move down a group in the periodic table, the number of energy levels increases, so the electrons are found further from the nucleus. This means that the ionic radius (size of an ion) increases. The other properties like electron affinity, electronegativity, and ionization energy generally decrease down a group in the periodic table.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>9", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Which of the following statements about sodium is not true?", "images": [], "options": {"A": "Na+ is smaller in size than Na", "B": "Na is smaller in size than Na+", "C": "Na+ has fewer electrons than Na", "D": "The effective nuclear charge in Na+ is greater than in Na"}, "answer": "B", "explanation": "The statement 'Na is smaller in size than Na+' is not true. When a sodium atom loses an electron to form a sodium ion (Na+), it actually becomes smaller. This is because the electron is removed from the outermost shell, which results in a decrease in the size of the electron cloud around the nucleus. Therefore, Na+ is smaller in size than Na.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>10", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "If the difference between the electro negativities of two elements is large, the type of bond that can be formed between them is", "images": [], "options": {"A": "covalent", "B": "dative", "C": "ionic", "D": "metalic"}, "answer": "C", "explanation": "Ionic bond is usually formed between two elements with large electro negativity difference that combine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>11", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "Which of the following species does not contain a coordinate bond?", "images": [], "options": {"A": "Al2Cl6", "B": "CCl4", "C": "H3O+", "D": "NH4+"}, "answer": "B", "explanation": "CCl4 does not contain a co-ordinate bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>12", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following compounds has hydrogen bonds between its molecules?", "images": [], "options": {"A": "HF", "B": "HBr", "C": "HCl", "D": "HI"}, "answer": "A", "explanation": "Hydrogen bonding is a special type of dipole-dipole attraction between molecules, when hydrogen is bonded to a highly electronegative atom such as fluorine (F), nitrogen (N) or oxygen (O). Among the given options, only HF (Hydrogen Fluoride) has hydrogen bonded to a highly electronegative atom (Fluorine), hence it can form hydrogen bonds between its molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>13", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "14.8g of a salt (z)  dissolved in 250cm3 of distilled water gives a concentration of 0.80 mol dm-3. Calculate the molar mass of salt (z).", "images": [], "options": {"A": "13.5 g mol-1", "B": "18.5 g mol-1", "C": "47.4 g mol-1", "D": "74.0 g mol-1"}, "answer": "D", "explanation": "Given:  The mass of the salt = 14.8g  Volume of distilled water = 250cm3 = 0.25dm3  Concentration of the salt = 0.80moldm-3    Recall that: Concentration in gdm-3 = Concentration in moldm-3 × molar mass  14.8g is present in 0.25dm3  xg is present in 1 dm3  0.25 x = 14.8  x=14.80.25  x = 59.2g/dm3  59.2 = 0.80 × molar mass  molarmass=59.20.80=74gmol-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2007>14", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many atoms are there in one mole of hydrogen gas? [Avogadro's constant = 6.02 ×  1023 mol-1]", "images": [], "options": {"A": "1.2 × 10-23", "B": "6.0 × 1023", "C": "1.2 × 1024", "D": "6.0 × 1024"}, "answer": "C", "explanation": "1 mole of hydrogen gas contains 2 atoms of hydrogen   1 atom of hydrogen = 6.02 × 1023  2 atoms of hydrogen = 2 × 6.02 × 1023  = 12.04 × 1023 = 1.204 × 1024", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>15", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "What is the percentage composition of oxygen in K2Cr2O7?  [K2Cr2O7 = 294; O = 16; K = 39; Cr = 52]", "images": [], "options": {"A": "14.20%", "B": "26.53%", "C": "35.37%", "D": "38.09%"}, "answer": "D", "explanation": "Given: The compound K2Cr2O7  Molar mass of K2Cr2O7 = 294  Mass of Oxygen in K2Cr2O7 = 7 × 16 = 112  %compositionofoxygen=112294×100=38.0%", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>16", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "What is the IUPAC name of the compound represented by the molecular formular NaClO4?", "images": [], "options": {"A": "Sodium tetraoxochlorate (I)", "B": "Sodium tetraoxochlorate (IV)", "C": "Sodium tetraoxochlorate (VI)", "D": "Sodium tetraoxochlorate (VII)"}, "answer": "D", "explanation": "Given: The compound, NaClO4  We must find the oxidation number of chlorine so as to know whether it is chlorate I, II, III or IV  +1 + Cl + 4(-2) = 0  1 + Cl - 8 = 0  Cl = 7.  It is chlorate 7  Hence: The name of the compound is Sodium tetraoxochlorate(VII)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>17", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "When air is successively passed through sodium hydroxide solution, alkaline pyrogallol and then concentrated tetraoxosulphate (VI) acid, its remaining  are", "images": [], "options": {"A": "oxygen and water vapour", "B": "oxygen and nitrogen", "C": "carbon(IV)oxide and noble gases", "D": "nitrogen and noble gases"}, "answer": "D", "explanation": "Air contains, O2, CO2, water vapour, noble gases and Nitrogen. When it is passed through sodium hydroxide, CO2 is dried, when it is passed through alkaline pyrogallol, O2 is removed (dried) and when it is passed through conc. H2SO4, water vapour is dried.  Hence, the remaing components of air that are include: Noble gases and Nitrogen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>18", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases is lighter than air?", "images": [], "options": {"A": "CO2", "B": "SO2", "C": "HCl", "D": "NH3"}, "answer": "D", "explanation": "Ammonia, NH3 is lighter than air. This is why it is usually collected by downward displacement of air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>19", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STATES OF MATTER : KINETIC THEORY OF MATTER.", "question": "Which of the following statement is true of the molecules of a gas under ideal conditions? The molecules", "images": [], "options": {"A": "move at random", "B": "undergo inelastic collisions", "C": "attract each other", "D": "occupy a large volume"}, "answer": "A", "explanation": "In an ideal gas, the molecules move at random. This is one of the assumptions of the kinetic molecular theory, which describes the behavior of ideal gases. The theory assumes that gas molecules are in constant, random motion and that they frequently collide with each other and the walls of their container. The other options are incorrect because in an ideal gas, the molecules do not attract each other (they are assumed to be point particles with no volume), they undergo elastic not inelastic collisions (meaning they conserve kinetic energy), and they do not occupy a large volume (the volume of the gas molecules themselves is assumed to be negligible compared to the volume of the container).", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2007>20", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "In which of the following compound(s) will heat be absorbed on adding water?  I. KNO3  II. Concentrated H2SO4  III. NH4Cl", "images": [], "options": {"A": "I only", "B": "III only", "C": "I and III only", "D": "II and III only"}, "answer": "B", "explanation": "KNO3 and concentrated H2SO4 on dilution with water is exothermic while NH4Cl upon dilution is endothermic", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>21", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "25cm3 of 0.80moldm-3 hydrochloric acid neutralized 20cm3 of sodium hydroxide solution. What is the concentration of sodium hydroxide in moldm-3?  NaOH(aq) + HCl(aq) → NaCl(aq) + H2O(l)", "images": [], "options": {"A": "0.08", "B": "0.10", "C": "0.80", "D": "1.00"}, "answer": "D", "explanation": "Given:  The volume of the acid = 25cm3 = VA  The concentration of the acid = 0.80moldm-3 = CA  The volume of the base = 20cm3 = VB  The concentration of the base = ? = CB  The equation of the reaction  NaOH(aq) + HCl(aq) → NaCl(aq) + H2O(l)  Recall that:  CAVACBVB=nAnB......(i)  nA = Number of moles of acid used = 1  nB = Number of moles of base used = 1  Equation (1) becomes:  0.80 × 25CB × 20=11  20CB = 20  CB = 1.00moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>22", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Consider the reaction represented by the equation:  Ca(OH)2(aq) + CO2(g) → CaCO3(g) + H2O_((l)  In the reaction above, CO2 acts as", "images": [], "options": {"A": "an acidic oxide", "B": "an oxidizing agent", "C": "a basic oxide", "D": "a dehydrating agent"}, "answer": "A", "explanation": "Given: The equation of the reaction  Ca(OH)2(aq) + CO2(g) → CaCO3 + H2O  CO2 reacts with Ca(OH)2 to form CaCO3 and H2O (water). This is a framework of the neutralization reaction  ∴CO2 acts as an acidic oxide", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>23", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Which of the following compounds is a basic salt?", "images": [], "options": {"A": "Mg(NO3)2", "B": "(NH4)2SO4", "C": "K4Fe(CH)6", "D": "Zn(OH)Cl"}, "answer": "D", "explanation": "Zn(OH)Cl is a basic salt as it still contains an ionizable OH- ion. The presence of OH- ion is a basic characteristic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>24", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "What process is illustrated below?  S(s) ⇌ S(aq).", "images": [], "options": {"A": "Decomposition of a solid", "B": "Melting of a solid", "C": "Formation of saturated solution of a solid", "D": "Sublimation of a solid"}, "answer": "C", "explanation": "Given: The equation  S_((s) ↔ S(aq) (in the presence of H2O)  The solid form has changed to an aqueous solution upon dissolution on water. Due to the presence of the reversible reaction arrow ↔, the solution (aqueous) formed is a saturated solution, this is because a saturated solution is an equilibrium system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>25", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "A solution of a salt X reacts with AgNO3 solution to give white precipitate which dissolves in excess aqueous ammonia. X contains", "images": [], "options": {"A": "Cl-", "B": "Pb2+", "C": "SO42-", "D": "Zn2+"}, "answer": "D", "explanation": "Zn2+ is suspected. The observation confirms the presence of zinc ion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>26", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the reaction represented by the following equation:   N2(g) + 3H2(g) ⇔  2NH3(g) ; ΔH = -92 kJmol-1  Finely divided iron is used as catalyst in the reaction in order to", "images": [], "options": {"A": "lower the value of ΔH", "B": "increase the time for attainment of equilibrium", "C": "shorten the time for attainment of equilibrium", "D": "decrease the yield of ammonia"}, "answer": "C", "explanation": "Given: The equation of the reaction:  N2(g) + 3H2(g) ↔ 2NH3(g), Δ = -92kJmol-1  Finely divided iron is used as catalyst, so as to increase the rate of the equilibrium reaction by reducing or shortening the time of attainment of equilibrium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>27", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following factors will affect the rate of formation of S(s) in the reaction represented by the equation below?  S2O32-(aq) + 2H+aq → SO2(q) + H2O2(l) + S(s)", "images": [], "options": {"A": "Increase in temperature", "B": "Increase in pressure", "C": "Removal of H2O(l)", "D": "Use of a catalyst"}, "answer": "C", "explanation": "The removal of H2O will affect the rate of formation of S(s)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>28", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "In four separate experiments, the same quantity of magnesium ribbon was added to an excess of hydrochloric acid. In which of the experiments will hydrogen be given off most rapidly?  ExperimentVolume of acid  (cm3Concentration of acid  (mol dm-3W101.0X200.5Y302.0Z501.0", "images": [], "options": {"A": "W", "B": "X", "C": "Y", "D": "Z"}, "answer": "C", "explanation": "At Y, the concentration of the acid is the highest. Hence, the production of hydrogen will be rapid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>29", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of these cell notations is the correct representation of a Daniel cell?", "images": [], "options": {"A": "ZN(s) / Zn2+(aq) // Cu2+(aq) / Cu(s)", "B": "Cu(s) / Cu2+(aq) // Zn2+(aq) / Zn(s)", "C": "Zn2+(aq) / Zn(s) // Cu2+(aq) / Cu(s)", "D": "Cu2+(aq) / Cu(s) // Zn(s) / Zn2+(aq)"}, "answer": "A", "explanation": "Daniel cell can be represented symbolically as: Zn(s)/Zn2+(aq) //Cu2+(aq)/Cu(s).  In general: the symbolic representation of an electrochemical cell : Anode/Anode electrolyte//Cathode electrolyte/Cathode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>30", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Which species undergoes reduction in the reaction represented by the equation below?  H2S(aq) + 2FeCl3(aq) → S(s) + 2HCl(aq) + 2FeCl2(aq)", "images": [], "options": {"A": "Fe3+", "B": "H2S", "C": "Cl-", "D": "S"}, "answer": "A", "explanation": "Given: The equation of the reaction  H2S(aq) + 2FeCl3(aq) → S(s) + 2HCl(aq) + 2FeCl2(aq)  At the reactant side, the oxidation number of iron in FeCl3 is +3 and it reduces to +2 in FeCl2 at the product side. Fe3+ (the iron ion at the reactant side) is reduced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>31", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What is the oxidation number of chromium in K2CrO4?", "images": [], "options": {"A": "+1", "B": "+2", "C": "+4", "D": "+6"}, "answer": "D", "explanation": "The oxidation number of chromium in K2CrO4 is +6. This is because the oxidation number of oxygen is usually -2, and potassium is +1. In K2CrO4, there are 2 potassium atoms (+2 total) and 4 oxygen atoms (-8 total). For the compound to be neutral, the oxidation number of chromium must be +6.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>32", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "What product is formed at the cathode during the electrolysis of concentrated sodium chloride solution using carbon electrodes?", "images": [], "options": {"A": "Chlorine", "B": "Hydrogen", "C": "Oxygen", "D": "Sodium"}, "answer": "B", "explanation": "At the cathode: H+ is preferentially discharged although the concentration of Na+ is far greater. Hence, the great distance between the positions of Na+ and H+ in the series makes the effect of concentration less important.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>33", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following substances is a suitable solvent for perfumes?", "images": [], "options": {"A": "Benzene", "B": "Ethanol", "C": "Turpentine", "D": "Water"}, "answer": "B", "explanation": "Perfumes are typically made from organic compounds, which are best dissolved in organic solvents. Ethanol is an organic solvent that is commonly used in perfumes because it is less toxic and has a lower boiling point than other organic solvents, allowing the perfume to evaporate more quickly and disperse the scent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>34", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : BENZENE", "question": "The complete hydrogenation of C6H6 in the presence of nickel catalyst at 200°C gives", "images": [], "options": {"A": "C6H8", "B": "C6H10", "C": "C6H12", "D": "C6H14"}, "answer": "C", "explanation": "The product if the catalytic hydrogenation of benzene is cyclohexane.   The reaction is represented as:    In the presence of Nickel at 200°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>35", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "What is the empirical formula of a hydrocarbon containing 0.08 moles of carbon and 0.32 moles of hydrogen?", "images": [], "options": {"A": "CH2", "B": "CH3", "C": "CH4", "D": "C2H4"}, "answer": "C", "explanation": "Given: A hydrocarbon, CxHy  - Number of moles of carbon = 0.08moles  - Number of moles of hydrogen = 0.32moles  Recallthat:Numberofmoles=massmolarmass      Empirical formula = CH4", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>36", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "Which of the following pairs of substances can be distinguished by use of NaHCO3 solution?", "images": [], "options": {"A": "CH3CH2OH and HCOOCH3", "B": "CH3CH2OH and CH3COOH", "C": "CH3COOH and HCOOH", "D": "CH3CH2OH and CH3OH"}, "answer": "B", "explanation": "CH3CH2OH is alkanol and CH3COOH is an alkanoic acid. Alkanol and alkanoic acids are usually distinguished using NaHCO3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>37", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the molecules below are geometric isomers?", "images": ["Chemistry/imgs/2007/pix5.png", "Chemistry/imgs/2007/pix6.png", "Chemistry/imgs/2007/pix7.png", "Chemistry/imgs/2007/pix4s.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "Bromo ethene is a geometric isomer. Geometric isomers can also be called \"Cis-trans isomers\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>38", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Alkenes undergo the following reactions except", "images": [], "options": {"A": "addition", "B": "hydration", "C": "polymerization", "D": "substitution"}, "answer": "D", "explanation": "Alkenes do not undergo substitution reaction. Alkanes and benzene are the only hydrocarbons that undergo substitution reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>39", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Hydrocarbons which react with ammoniacal copper(I)chloride solution conform to the general molecular formula", "images": [], "options": {"A": "CnHn", "B": "CnH2n", "C": "CnH2n + 2", "D": "CnH2n - 2"}, "answer": "D", "explanation": "Hydrocarbons which react with ammoniacal copper(I)chloride solution are terminal alkynes. Alkynes have the general molecular formula CnH2n - 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>40", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "Consider the reaction below:  Vegetable oil H2:,Catalyst→high temperature Product  H2, Ni catalyst & High temperature are the catalyst used for this reaction.  The reaction is applied in the manufacture of", "images": [], "options": {"A": "drugs", "B": "margarine", "C": "paraffin", "D": "soapy detergents"}, "answer": "B", "explanation": "Given: The reaction   Vegetable oil ↔ Product   Note: (H2:Ni catalyst with the presence of high temperature)  The reaction above is the hardening of vegetable oil by hydrogenation. The product is margarine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>41", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "What is the product of the reaction between ethanol and excess acidified KMnO4 solution?", "images": [], "options": {"A": "CH2 = CH2", "B": "CH3COOH", "C": "CH3 - CH", "D": "CH3OCH3"}, "answer": "B", "explanation": "KMnO4 is an oxidizing agent. When ethanol reacts with excess KMnO4, the product is CH3COOH (ethanoic acid).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>42", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following compounds reacts readily with sodium to liberate hydrogen?", "images": [], "options": {"A": "CH3CH2CH3", "B": "CH3COCH3", "C": "CH3CH(OH)CH3", "D": "CH3CH2CHO"}, "answer": "C", "explanation": "Sodium reacts with alcohols to produce sodium alkoxide and hydrogen gas. In the given options, CH3CH(OH)CH3 is an alcohol and hence, it will react with sodium to liberate hydrogen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>43", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Glucose reduces Fehling's solution on warming to", "images": [], "options": {"A": "copper(I)oxide", "B": "copper(II)oxide", "C": "copper(I)chloride", "D": "copper(II)hydroxide"}, "answer": "A", "explanation": "Glucose is a reducing sugar. When it is heated with Fehling's solution, it reduces the blue solution of copper(II) ions to a red precipitate of copper(I) oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>44", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following activities is not a source of air pollution?", "images": [], "options": {"A": "Cigarette smoking", "B": "Carbon dating", "C": "Domestic fires", "D": "Coal powered station"}, "answer": "B", "explanation": "Carbon dating is a method used to determine the age of ancient artifacts and fossils. It does not involve the release of pollutants into the atmosphere, unlike the other options which involve combustion and can release pollutants such as carbon monoxide, sulfur dioxide, and particulate matter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>45", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "From which of the following ores is iron extracted?  I. Haematite  II. Bauxite  III. Magnetite  IV. Cassiterite", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "I, II and III only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "Iron can be extracted from haemetite and magnetite. Haemetite, Fe2O3 and Magnetite Fe3O4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>46", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following methods can be used to separate a mixture of two miscible liquids with different boiling points?", "images": [], "options": {"A": "Decantation", "B": "Distillation", "C": "Evaporation", "D": "Filtration"}, "answer": "B", "explanation": "Distillation is used to separate two miscible liquids. The difference in the boiling points of these liquids is the factor considered in separation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>47", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "The following substances are heavy chemicals except", "images": [], "options": {"A": "sodium trioxocarbonate(IV)", "B": "tetraoxosulphate(VI) acid", "C": "lead(IV)tetraethyl", "D": "sodium hydroxide"}, "answer": "C", "explanation": "Heavy chemicals are industrial products that are produced in large quantities and are often used as raw materials for other industrial and consumer products. Sodium trioxocarbonate(IV), tetraoxosulphate(VI) acid, and sodium hydroxide are all examples of heavy chemicals. Lead(IV)tetraethyl, on the other hand, is not considered a heavy chemical.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>48", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Pig-iron is brittle because it contains", "images": [], "options": {"A": "a high percentage of carbon as impurity", "B": "calcium trioxosilicate(IV)", "C": "unreacted haematitie", "D": "undecomposed limestone"}, "answer": "A", "explanation": "Pig iron is brittle because it contains a high percentage of carbon as impurity. The carbon makes the iron hard but also makes it less ductile (or more brittle). The other options listed do not contribute to the brittleness of pig iron.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2007>49", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Which of these metals will not liberate hydrogen from dilute HCl?", "images": [], "options": {"A": "Copper", "B": "Iron", "C": "Magnesium", "D": "Zinc"}, "answer": "A", "explanation": "Copper does not react with dilute HCl to liberate hydrogen gas. This is because copper is less reactive than hydrogen and cannot displace hydrogen from its compounds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2007>50", "subject": "Chemistry", "year": "2007", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What volume will 0.5g of H2 occupy at s.t.p.?  [H = 1; 1 mole of a gas occupy 22.4dm3 at s.t.p.]", "images": [], "options": {"A": "2.24dm3", "B": "5.60dm3", "C": "11.20dm3", "D": "44.80dm3"}, "answer": "B", "explanation": "Given:  The mass of hydrogen gas H2 = 0.5g  * 1 mole of any gas at S.T.P will occupy 22.4dm3  Since H2 is a gas, 1 mole of H2 will occupy 22.4dm3  1 mole of H2  = 2g  ∴ 2g of H2 will occupy 22.4dm3  0.5g of H2 will occupy x dm3  20.5=22.4x  4=22.4x  4x = 22.4  x = 5.6dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>1", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The mass spectrometer can be used to measure mass of", "images": [], "options": {"A": "an atom", "B": "an electron", "C": "a proton", "D": "a neutron"}, "answer": "A", "explanation": "A mass spectrometer is an instrument used to measure the masses and relative concentrations of atoms and molecules. It makes use of the basic magnetic force on a moving charged particle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>2", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Find the number of neutrons in an atom represented by 4521X.", "images": [], "options": {"A": "21", "B": "24", "C": "45", "D": "66"}, "answer": "B", "explanation": "Given: The atom of X.  4521X  - The atomic number = 21  - The mass number = 45  ∴ 21 = Number of proton (since atomic number is defined as the number of proton in the nucleus of an atom)  45 = Number of proton + Number of neutro (since mass number is defined as the number of proton and neutron in the nucleus of an atom)  ∴ 45 = 21 + Number of neutrons; Number of neutron = 24", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>3", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The valence electrons in a chloride ion are [17Cl]", "images": [], "options": {"A": "2p electrons only", "B": "3s and 3p electrons only", "C": "3p and 3d electrons only", "D": "3p electrons only"}, "answer": "B", "explanation": "The chloride ion (Cl-) has gained one electron to achieve a stable electron configuration. This electron is added to the 3p subshell, making a total of 5 electrons in the 3p subshell and 2 electrons in the 3s subshell. Therefore, the valence electrons in a chloride ion are 3s and 3p electrons only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>4", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "What is the atomic number of an element whose cation Y+ has the electronic configuration 1s22s22p6?", "images": [], "options": {"A": "9", "B": "10", "C": "11", "D": "12"}, "answer": "C", "explanation": "Y+ = 1S22S22p6 = 10. This is the atomic number after it has lost one electron. Therefore the original atomic number of the element is 11", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>5", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Atom 23488Q decay by alpha emission to give an atom R.   The atomic number and mass number of atom R are respectively", "images": [], "options": {"A": "86 and 230", "B": "87 and 234", "C": "88 and 233", "D": "90 and 238"}, "answer": "A", "explanation": "Given: 23488Q decays to give 42He (alpha particle) and klR   23488Q → 42He + klR  - Balancing up the mass numbers.  * 234 = 4 + k; k = 230  * Balancing up the atomic numbers  88 = 2 + L ; L = 86  Hence, klR = 23086R", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>6", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following statements is not true of halogens?", "images": [], "options": {"A": "They exist in different physical states", "B": "They exist as diatomic molecules", "C": "Their ionic radii decrease down the group", "D": "Their melting and boiling points increase down the group"}, "answer": "C", "explanation": "Their ionic radii decrease down the group, their ionic radi is suposed to increase down the gorup because each row adds a new electron shell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>7", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Elements in the same group of the periodic table have", "images": [], "options": {"A": "the same number of valence electrons", "B": "the same number of electron shells", "C": "different chemical behaviour", "D": "the same atomic size"}, "answer": "A", "explanation": "Elements in the same group of the period have the same number of valence electrons. Valence electrons are the electrons in the outermost shell of an atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>8", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Consider the following elements and their electronic configurations  W: 1s2 2s2  X: 1s2 2s2 2p6  Y: 1s2 2s2 2p6 3s2  Z: 1S2 2s2 2p6 3s2 3p2  Which of the elements belong to the same group in the period table?", "images": [], "options": {"A": "W and X only", "B": "Y and Z only", "C": "W and Y only", "D": "W, Y and Z only"}, "answer": "C", "explanation": "The elements with the same number of valence electrons will belong to the same group.  - W has 2 valence electrons   - X has 8 valence electrons   - Y has 2 valence electrons  - Z has 4 valence electrons  ∴ W and Y belong to the same group.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>9", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Arrange the following elements in order of increasing electron affinity: Br2, Cl2, I2, F2.", "images": [], "options": {"A": "I2, Cl2, B2, F2", "B": "I2, Br2, Cl2, F2", "C": "Cl2, I2, Br2, F2", "D": "Br2, Cl2, I2, F2"}, "answer": "B", "explanation": "Electron affinity generally increases across a period from left to right and decreases down a group. Therefore, the order of increasing electron affinity among the given elements (all belong to the same group but different periods) is I2, Br2, Cl2, F2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2008>10", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Water molecules are held together by", "images": [], "options": {"A": "covalent bond", "B": "hydrogen bond", "C": "ionic force", "D": "van der waals forces"}, "answer": "B", "explanation": "Water molecules are held together by hydrogen bond.  - Hydrogen bond exist between hydrogen and highly electronegative elements.  - Water is composed of hydrogen and oxygen which is highly electronegative.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>11", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The compound formed by two elements X and Y with the electronic configuration 1s22s22p4 and 1s22s22p63s2 respectively is", "images": [], "options": {"A": "XY", "B": "YX", "C": "X2Y3", "D": "Y2X2"}, "answer": "B", "explanation": "Given: Two elements, X and Y  The E-configuration of X = 1s2 2s2 2p4  The E-configuration of Y = 1s2 2s2 2p6 3s2  X has 8 electrons and Y has 12 electrons   ∴ X is oxygen, O and Y is Magnesium, Mg.  MgO = YX", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>12", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "The force of attraction between covalent molecules is", "images": [], "options": {"A": "dative bonding", "B": "hydrogen bonding", "C": "ionic force", "D": "van der waals forces"}, "answer": "A", "explanation": "The force of attraction between covalent molecules is dative bonding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>13", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is the mass of 6.02 × 1024 atoms of magnesium?  [Mg = 24, Avogadro constant = 6.02 × 1023 atoms mol-1]", "images": [], "options": {"A": "240g", "B": "24g", "C": "2.4g", "D": "0.24g"}, "answer": "A", "explanation": "1 mole of any substance contains 6.02 × 1023 particles   1 mole of magnesium contains 6.02 × 1023 atoms   1 mole of magnesium = 24g  ∴ 24g of magnesium contains 6.02 × 1023 atoms  x g of magnesium contains 6.02 × 1024 atoms   24x=6.02×10236.02×1024  24x=10-1  x = 240g", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>14", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following compounds with the corresponding masses contain the highest percentage of Nitrogen? [N = 14]", "images": [], "options": {"A": "NH3 = 17", "B": "NH4Cl = 53.5", "C": "NH4NO3 = 80", "D": "(NH3)2SO4 = 132"}, "answer": "A", "explanation": "Given: The compounds, NH3, NH4Cl, NH4NO3, (NH3)2SO4   NH3 = 17; NH4Cl = 53.5, NH4NO3 = 80 and (NH3)2SO4 = 132  - %ofNinNH3=1417×100=82.35  -%ofNinNH4Cl=1453.5×100=26.17  - %ofNinNH4NO3=2880×100=35  - %ofNin(NH3)2SO4=28132×100=21.2  ∴ The percentage composition is the highest in NH3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>15", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "If 5.00cm3 of 0.20 moldm-3 Na2CO3 was diluted with distilled water to obtain 250cm3 solution, what is the concentration of the resulting solution?", "images": [], "options": {"A": "0.004 mol dm-3", "B": "0.02 mol dm-3", "C": "0.20 mol dm-3", "D": "0.40 mol dm-3"}, "answer": "A", "explanation": "Given:  - The initial concentration, C1 = 0.20 moldm-3  - The initial volume, V1 = 5.00 cm3  - The final concentration, C2 = C2  - The final volume, V2 = 250cm3  Recall that   C1V1 = C2V2 (Dillution theory)  (0.20)(5) = C2(250)  1 = C2(250)  C2=1250=0.004moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>16", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Consider the reaction represented by the following equation:  Zn(s) + 2HCl(aq) → ZnCl2(aq) + H2(g)  What volume of hydrogen gas is produced at s.t.p. when 3.25g of zinc reacts with excess dilute HCl?  [Zn = 65, Molar gas volume at s.t.p = 22.4dm3]", "images": [], "options": {"A": "1.12 dm3", "B": "2.24 dm3", "C": "4.48 dm3", "D": "8.96 dm3"}, "answer": "A", "explanation": "Given: The equation of the reaction  Zns + 2HCl(aq) → ZnCl2(aq) + H2(g)  * Since the question says \"excess dilute HCl\", HCl will not be considered; because excess reagents do not react.  → From the equation above:  65g of Zinc will produce 1 mole of H2(g)  1 mole of any gas at s.t.p = 22.4dm3  ∴ 65g of zinc will produce 22.4dm3 of H2(g)  3.25g of zinc will produce x dm3 of H2(g)  653.25=22.4x  20=22.4x  20x = 22.4  x = 1.12dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>17", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases has the lowest rate of diffusion under the same conditions of temperature and pressure?  [H = 1, O = 16, Ne = 20, Cl = 35.5]", "images": [], "options": {"A": "Chlorine", "B": "Hydrogen", "C": "Neon", "D": "Oxygen"}, "answer": "A", "explanation": "Given: Four gases which include:  Neon, Ne = 20gmol-1  Chlorine, Cl2 = 71gmol-1  Hydrogen, H2 = 2gmol-1  Oxygen, O2 = 32gmol-1  According to Graham's Law of diffusion, the higher the mass, the slower the rate of diffusion, i.e Rα1&radic;M&nbsp;  - The gas with the highest mass will have the lowest rate of diffusion  ∴ Chlorine has the lowest rate of diffusion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>18", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "In a fixed volume of gas, an increase in temperature results in an increase in pressure due to an increase in the", "images": [], "options": {"A": "number of collisions between the gas molecules", "B": "number of repulsion between the gas molecules", "C": "number of collisions between the gas molecules and the walls of the container", "D": "kinetic energy of the gas"}, "answer": "C", "explanation": "In a fixed volume of gas an increase in temperature will result in an increase in pressure due to an increase in the number of collisions between the gas molecules and the walls of the container.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>19", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "When concentrated H2SO4 is added to the NaCl(s), the gas evolved", "images": [], "options": {"A": "bleaches damp blue litmus paper", "B": "forms a white precipitate with AgNO3(aq)", "C": "forms a white precipitate with BaCl2(aq)", "D": "turns moist red litmus paper blue"}, "answer": "A", "explanation": "When concentrated H2SO4 is added to NaCl, the reaction produces Hydrogen Chloride (HCl) gas. This gas is known to bleach damp blue litmus paper, hence the correct answer is option 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>20", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The collision theory proposes that", "images": [], "options": {"A": "reactants collide more frequently to bring about reduction in the reaction rate", "B": "all collisions of reactants are effective", "C": "reactants must collide with a certain minimum amount of energy to form products", "D": "the fever collisions the faster the reaction rate"}, "answer": "C", "explanation": "The collision theory proposes that reactants must collide with a certain minimum amount of energy. This energy is called the \"activation energy\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>21", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "Diamond does not conduct electricity because it", "images": [], "options": {"A": "has no free valence electrons", "B": "is a giant molecule", "C": "contains no bonded electrons", "D": "is a solid at room temperature"}, "answer": "A", "explanation": "Diamond does not conduct electricity because it has no free valence electrons. In diamond, each carbon atom is covalently bonded to four other carbon atoms in a tetrahedral structure. This means that all four outer electrons in the carbon atom are involved in bonding, leaving no free electrons to conduct electricity. This is why diamond is a good electrical insulator.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>22", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following set of equations could be used to represent the standard enthalpy of formation of glucose?", "images": [], "options": {"A": "6C(s) + 6H2(g) + 3O2(g) → C6H12O_(6(s)", "B": "6CO2(g) + 6H2O(l) → C6H12O6(s) + 6O2(g)", "C": "6C(g) + 6H2(g) + 3O2(g) → C6H12O6(s)", "D": "6C(g) + 6H2(g) + 3O2(g) → C6H12O6(aq)"}, "answer": "B", "explanation": "6CO2(g) + 6H2O(l) → C6H12O6(s) + 6O2(g)  The equation above is conventionally used to represent the formation of glucose.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>23", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "The colour of phenolphthalein indicator in dilute HNO3(aq) is", "images": [], "options": {"A": "colourless", "B": "orange", "C": "pink", "D": "purple"}, "answer": "A", "explanation": "Phenophtalein is colourless in acidic solution, red in basic solution and pink in neutral solution. HNO3(aq) is an acidic solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2008>24", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "An aqueous solution of CaCl2 is", "images": [], "options": {"A": "acidic solution", "B": "alkaline solution", "C": "a buffer solution", "D": "a neutral solution"}, "answer": "D", "explanation": "An aqueous solution of CaCl2 is neutral, since it is formed from a strong acid and a strong base.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2008>25", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following compounds would dissolve in water to give a solution whose pH is less than 7?", "images": [], "options": {"A": "Al(NO3)3", "B": "KNO3", "C": "N2O", "D": "NH3"}, "answer": "A", "explanation": "A solution with a pH less than 7 is acidic. When Al(NO3)3 dissolves in water, it forms Al3+ and NO3- ions. The Al3+ ions react with water to form Al(OH)3 and H+ ions. The presence of H+ ions makes the solution acidic, hence the pH is less than 7.  KNO3 dissolves in water to produce a neutral solution   N2O does not dissolve in water  NH3 is a basic gas and as such dissolves in water to form a basic solution with pH above 7", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>26", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Consider the reaction represented by the equation below:  KOH(aq) + HCl(aq) → KCl(aq) + H2O(l)  What volume of 0.25mol dm-3 KOH would be required to completely neutralize 40cm3 of 0.10mol dm-3 HCl?", "images": [], "options": {"A": "40cm3", "B": "32cm3", "C": "24cm3", "D": "16cm3"}, "answer": "D", "explanation": "Given: The neutralization reaction  KOH(aq) + HCl(aq) → KCl(aq) + H2O(l)  Number of mole(s) of acid, nA = 1  Number of mole(s) of base, nB = 1  Concentration of acid, CA = 0.10moldm-3; Volume of acid, VA = 40cm3  Concentration of base, CB = 0.25moldm-3; Volume of base, VB = VB  Recallthat:CAVACBVB=nAnB  ∴0.10×400.25×VB=11  4 = 0.25VB  VB = 16cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>27", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "When 100cm3 of a saturated solution of KClO3 at 40oC is evaporated, 14g of the salt is recovered. What is the solubility of KClO3 at 40°C?  [KClO3 = 122.5]", "images": [], "options": {"A": "11.42 moldm-3", "B": "8.80 moldm-3", "C": "1.14 moldm-3", "D": "0.88 moldm-3"}, "answer": "C", "explanation": "Given:  Volume of the saturated solution = 100cm3 = 0.1dm3  Mass of the salt recovered at 40°c = 14g  Molar mass of the salt = 122.5  Number of moles of the salt at 40°C = 14/122.5 = 0.114mole  Solubility=0.11420.1=1.142moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>28", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : PRACTICAL APPLICATION OF SOLUBILITY", "question": "The high solubility of ethanol in water is due to its", "images": [], "options": {"A": "low boiling point", "B": "low freezing point", "C": "covalent nature", "D": "hydrogen bonding"}, "answer": "D", "explanation": "Ethanol is highly soluble in water due to its ability to form hydrogen bonds with water. Ethanol has a hydroxyl group (-OH), which is polar and can form hydrogen bonds with water molecules. This interaction is stronger than the van der Waals forces that would be present in a solution of a nonpolar substance in water, leading to a higher solubility.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>29", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the equilibrium reaction represented by the equation:  2SO2(g) + O2(g) ↔ 2SO3(g); ΔH = -197 kJmol-1  At equilibrium, increase in the total pressure of the system brings about", "images": [], "options": {"A": "decrease in rate of the reaction of the system", "B": "decrease in temperature of the system", "C": "increase in concentration of SO3", "D": "increase in concentration of SO2"}, "answer": "C", "explanation": "Given:The equilibrium equation  2SO2(g) + O2(g) ↔ 2SO3(g) ΔH = -197kJmol-1  According to Le chatellier's principle, an increase in pressure of the system will increase the production of SO3(g).  → Since we have a greater number of mole of gaseous species at the reactant side (3 moles) than at the product side (2 moles).", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>30", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Consider the energy profile diagram below and use it to answer this question      Q represents", "images": ["Chemistry/imgs/2008/pix1.png"], "options": {"A": "activation energy", "B": "activated complex", "C": "enthalpy change", "D": "heat content of the reaction"}, "answer": "B", "explanation": "Q represents the activation complex of the energy profile diagram,", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>31", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Consider the energy profile diagram below and use it to answer this question    Enthalpy change of the reaction is represented by", "images": ["Chemistry/imgs/2008/pix1.png"], "options": {"A": "W", "B": "X", "C": "Z", "D": "Y"}, "answer": "B", "explanation": "The enthalpy change of the reaction is X. The enthalpy change of a reaction (  Δ  𝐻  ΔH) refers to the amount of heat energy absorbed or released during a chemical reaction at constant pressure. It can be positive or negative depending on whether the reaction is endothermic or exothermic", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>32", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "What type of reaction is represented by the energy diagram?", "images": ["Chemistry/imgs/2008/ssce2008chemq32.png"], "options": {"A": "Endothermic", "B": "Exothermic", "C": "Redox", "D": "Neutralization"}, "answer": "B", "explanation": "The reaction is exothermic, since the heat content of the product is less than that of the reactant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>33", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "In dry Leclanche cell, Manganese (IV) Oxide acts as", "images": [], "options": {"A": "a reducing agent", "B": "binding agent", "C": "catalyst", "D": "depolarizer"}, "answer": "D", "explanation": "Manganese dioxide is used in the dry le clanché cell as a depolarizer which absorbs the liberated hydrogen bubbles which would otherwise insulate the electrode from the electrolyte.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>34", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Oxidation takes place at the anode during electrolysis because the anode", "images": [], "options": {"A": "is deficient in electrons", "B": "is deficient in protons", "C": "has excess electrons", "D": "has attraction for positive ions"}, "answer": "C", "explanation": "Anode means anion electrode, this makes it to attract negative charges, hence having electrons in excess.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>35", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Calculate the quantity of electricity passed when 0.4A flows for 1 hour 20minutes through an electrolytic cell.", "images": [], "options": {"A": "4800C", "B": "3840C", "C": "1920C", "D": "32C"}, "answer": "C", "explanation": "Given:  The current, I = 0.4A  The time, t = 1 hour 20minutes  Q = It ......*  tin seconds = 3600s + 1200 seconds = 4800 seconds  Q = 0.4 × 4800 = 1920C", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2008>36", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "A mixture of kerosene and diesel oil can be separated by", "images": [], "options": {"A": "crystallization", "B": "distillation", "C": "precipitation", "D": "sublimation"}, "answer": "B", "explanation": "Diesel oil and kerosene are mixible liquids. The mixture of these liquids can be best separated through distillation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2008>37", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "Which of the following compounds would not give a precipitate with ammoniacal AgNO3 solution?", "images": [], "options": {"A": "CH3C ≡ CCH3", "B": "HC ≡ CH", "C": "CH3C ≡ CH", "D": "CH3CH2C ≡ CH"}, "answer": "A", "explanation": "Only terminal alkynes will give a precipitate on reacting with ammoniacal AgNO3 solutions. Terminal alkynes are alkynes that has triple bond at the end of their carbon chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>38", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "When ethanol is heated with excess concentrated tetraoxosulphate(VI)acid, the organic product formed is", "images": [], "options": {"A": "ethanal", "B": "ethanoic acid", "C": "ethane", "D": "ethene"}, "answer": "D", "explanation": "This is the total dehydration of alkanol. Total dehydration occurs when one molecule of an alkanol loses one molecule of H2O in the presence of excess H2SO4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>39", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "The hydrolysis of groundnut oil by potassium hydroxide is known as", "images": [], "options": {"A": "hydrogenation", "B": "saponification", "C": "esterification", "D": "neutralization"}, "answer": "B", "explanation": "The hydrolysis of groundnut oil by potassium hydroxide is known as saponification. Saponification is the process of making soap from fats or oils (in this case, groundnut oil) and a strong base (in this case, potassium hydroxide).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>40", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "What is the main type of reaction alkenes undergo?", "images": [], "options": {"A": "Addition", "B": "Condensation", "C": "Elimination", "D": "Substitution"}, "answer": "A", "explanation": "The main type of reaction that alkenes undergo is addition reaction. This is due to the degree of unsaturation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>41", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Arrange the following compounds in order of increasing boiling point  I. CH3CH2CH2OH   II. CH3CH2OH  III. CH3CH2CH2CH2OH  IV. CH3CH2CH2CH2CH3", "images": [], "options": {"A": "I", "B": "IV", "C": "I", "D": "IV"}, "answer": "D", "explanation": "For compounds that belong to the same homologous series as the molecular weight increases, the boiling increases. Hence, III > I > II . For compounds that belong to different homologous series, the degree of volatility depends on the strength of the attractive forces between the molecules. - OH - is greater than C - C in terms of B.P", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>42", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The organic compound with the following structure represents", "images": ["Chemistry/imgs/2008/s29.png"], "options": {"A": "primary alkanol", "B": "secondary alkanol", "C": "tertiary alkanol", "D": "an alkanal"}, "answer": "C", "explanation": "Given: The organic compound     Tertiary alkanols have the structure:", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>43", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Consider the organic compound X with the following structure.    The complete oxidation of X gives", "images": ["Chemistry/imgs/2008/pix3.png"], "options": {"A": "propanal", "B": "propanoic acid", "C": "propanone", "D": "propene"}, "answer": "B", "explanation": "X is an alkanol, propanol. When alkanol is oxidized, it gives alkanoic acid. Correspondingly, propanol is oxidized to give propanoic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>44", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "What is the IUPAC name of the compound with the following structure?", "images": ["Chemistry/imgs/2008/pix4.png"], "options": {"A": "2-methylbutene", "B": "2-methylprop-2-ene", "C": "2-methylprop-1-ene", "D": "but-1-ene"}, "answer": "C", "explanation": "Given: The organic compound below    2-methyl prop-1-ene.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>45", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "A hydrocarbon containing 88.9% carbon has the empirical formula [H = 1, C = 12]", "images": [], "options": {"A": "CH", "B": "CH2", "C": "C2H3", "D": "C2H5"}, "answer": "C", "explanation": "Given:  The percentage composition of carbon in the hydrocarbon = 88.9%  The percentage composition of hydrogen = (100 - 88.9)% = 11.1%    Empirical formula = C2H3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>46", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "A solution of a salt was acidified with HCl. When a few drops of BaCl2 solution were added, a white precipitate was formed. Which of the following anions is present in the salt?", "images": [], "options": {"A": "CO2-3", "B": "NO-3", "C": "SO2-4", "D": "SO2-3"}, "answer": "C", "explanation": "This is a confirmatory test for tetraoxosulphate (VI). In this test, the observation explained in the question infers the presence of SO42-.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>47", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following substances causes the depletion of the ozone layer in the atmosphere?", "images": [], "options": {"A": "Carbon(IV)oxide", "B": "Chlorofluorocarbon", "C": "Sulphur(IV)oxide", "D": "Hydrocarbons"}, "answer": "B", "explanation": "Chlorofluorocarbons (CFCs) are known to cause the depletion of the ozone layer. When CFCs are released into the atmosphere, they can reach the stratosphere where they are broken down by solar radiation, releasing chlorine atoms. These chlorine atoms can catalyze the destruction of ozone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2008>48", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Chemicals that are produced in small quantities and with very high degree of purity are", "images": [], "options": {"A": "bulk chemicals", "B": "fine chemicals", "C": "heavy chemicals", "D": "light chemicals"}, "answer": "B", "explanation": "Fine chemicals are chemicals that are produced in small quantities and with a high degree of purity. They are often used in research and development, and in the production of pharmaceuticals, agrochemicals, and specialty chemicals. Bulk chemicals, on the other hand, are produced in large quantities and are often used in the production of other chemicals or products. Heavy and light chemicals are not classifications based on quantity or purity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2008>49", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "Aluminium is a good roofing material because it", "images": [], "options": {"A": "is strong and does not conduct heat and electricity", "B": "readily absorbs light.", "C": "forms an oxide film over its surface which prevents corrosion", "D": "is flexible and can conduct heat"}, "answer": "C", "explanation": "Aluminium is a good roofing material because it forms an oxide film over its surface which prevents corrosion. Aluminium sheets are corrosion-free.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2008>50", "subject": "Chemistry", "year": "2008", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Which of the following alloys is mainly used in making statues?", "images": [], "options": {"A": "Brass", "B": "Bronze", "C": "Duralumin", "D": "Steel"}, "answer": "B", "explanation": "Bronze is the alloy that is mainly used in making statues. Bronze is a metal alloy consisting primarily of copper, usually with tin as the main additive, but sometimes with other elements such as phosphorus, manganese, aluminum, or silicon. It is strong and durable, which makes it suitable for statues that need to withstand the elements. Brass, duralumin, and steel are also alloys, but they are not primarily used for making statues.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>1", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "Which of the following scientists discovered the neutron?", "images": [], "options": {"A": "Ernest Rutherford", "B": "J. J. Thompson", "C": "James Chadwick", "D": "R. A. Millikan"}, "answer": "C", "explanation": "The neutron was discovered by James Chadwick in 1932. Neutrons are subatomic particles found in the nucleus of atoms. They have no electric charge and a mass slightly larger than that of a proton.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>2", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "How many protons does 4020Ca contain?", "images": [], "options": {"A": "20", "B": "30", "C": "40", "D": "60"}, "answer": "A", "explanation": "Given:  4020Ca. Calcium, Ca has an atomic number of 20, i.e it has a proton number which is equal to 20 (According Henry Mosley)", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>3", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.", "question": "If 100 atoms of element X contains 70 atoms of 9X and 30 atoms of 11X, calculate the relative atomic mass of X.", "images": [], "options": {"A": "9.6", "B": "10.6", "C": "11.6", "D": "20.0"}, "answer": "A", "explanation": "Given:  100 atoms of element X contains 70 atoms of 9X and 30 atoms of 11X.  R.A.M of X = m1α1 + m2α2  R.A.MofX=9×70100+11×30100  R.A.MofX=96100=9.6", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2009>4", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.", "question": "Consider the reaction represented by the equation:  2892U + 10n → 13956Ba + 9436Kr + 310n  The reaction represents a", "images": [], "options": {"A": "nuclear fission", "B": "nuclear fusion", "C": "radioactive decay", "D": "spontaneous disintegration"}, "answer": "A", "explanation": "Given: The nuclear reaction  2892 U + 10 n → 13956Ba + 9436Kr + 3 10n  The nuclear reaction represent nuclear fission, since a large atoms splits to form smaller ones and consequently with a release of energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>5", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "How many orbitals are associated with the p-sub energy level", "images": [], "options": {"A": "2", "B": "3", "C": "5", "D": "6"}, "answer": "B", "explanation": "The p-sub energy level, also known as the p-orbital, has three orbitals. Each orbital can hold up to two electrons, so the p-sub energy level can hold up to six electrons in total.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>6", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following elements has the electronic configuration: 1s2 2s2 2p6 3s2 3p1? [11Na, 13Al, 14N, 16S]", "images": [], "options": {"A": "Al", "B": "Na", "C": "N", "D": "S"}, "answer": "A", "explanation": "Given: The electronic configuration, 1s22s22p63s23p1  → The electronic configuration comprises (2 + 2 + 6 + 2 + 1) electrons = 13 electrons.  → Therefore, the E-configuration is for aluminium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>7", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "The following properties are characteristics of transition elements except", "images": [], "options": {"A": "formation of complex ions", "B": "fixed oxidation states", "C": "formation of coloured compounds", "D": "catalytic abilities"}, "answer": "B", "explanation": "Transition elements are known for their variable oxidation states, not fixed oxidation states. This is due to the fact that electrons in both the 4s and 3d sublevels can be used for bonding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>8", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following ions is isoelectronic with neon?  [3Li, 9F, 10Ne, 17Cl, 19K]", "images": [], "options": {"A": "Cl-", "B": "F-", "C": "K+", "D": "Li+"}, "answer": "B", "explanation": "Neon has 10 electrons.  F-: This is a fluoride ion which is formed when the neutral atom of fluorine gains an electron. The fluoride atom therefore has ten electrons, just like that of neon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>9", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following electronic configurations correctly represents an element in period 3 of the periodic table?", "images": [], "options": {"A": "1s2 2s2 2p3", "B": "1s2 2s2 2p6", "C": "1s2 2s2 2p6 3s2 3p4", "D": "1s2 2s2 2p6 3s2 3p6 4s1"}, "answer": "C", "explanation": "Given:   The electronic configuration of four elements as:   - 1s2 2s2 2p3   - 1s2 2s2 2p6  - 1s2 2s2 2p6 3s2 3p4 4s1  * The element that belongs to group 3 usually has 3 orbitals, also when distributed into sub orbitals like we have in the options, the highest number is usually 3. only option C matches this.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>10", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "An element Q forms a compound QCl5. In which group of the periodic table is Q?", "images": [], "options": {"A": "I", "B": "III", "C": "V", "D": "VII"}, "answer": "C", "explanation": "Given: An element Q which forms a compound: QCl5   QCl5 = Q5+ + Cl-  Q belongs to group 5.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>11", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PERIODICITY OF THE ELEMENTS", "question": "Which of the following statement about the behaviour of the atom is correct?", "images": [], "options": {"A": "Atomic size decreases down the group", "B": "Atomic size decreases across a period", "C": "Anion are smaller than the parent atom", "D": "Cations are smaller than the parent atom"}, "answer": "B", "explanation": "Atomic size decreases across a period. This is because as you move across a period, the number of protons in the nucleus increases, which increases the positive charge of the nucleus and pulls the electrons closer to the nucleus, thus decreasing the atomic size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>12", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PERIODICITY OF THE ELEMENTS", "question": "Which of the following arrangement is in order of increasing ionization energy?", "images": [], "options": {"A": "Al, Si, P, S", "B": "Si, Al, S, P", "C": "S, P, Si, Al", "D": "P, Si, S, Al"}, "answer": "A", "explanation": "Given: Four elements   i. Aluminium - Al  ii. Silicon - Si  iii. Phosphorus - P  iv. Sulphur - S  - These elements belong to the same period 'period 3'.  Coventionally, ionization energy increases across a period.  Al → Si → P → S ( In order of increasing ionization energy)  N.B: Ionization energy increases as the atomic number increases", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>13", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following properties of covalent compounds is not correct? They", "images": [], "options": {"A": "are non-electrolytes", "B": "are mostly gaseous and volatile liquids", "C": "have low melting points", "D": "have high boiling points"}, "answer": "D", "explanation": "Covalent compounds do not have high boiling points. This is because covalent compounds are held together by covalent bonds, which are weaker than ionic bonds. Therefore, less energy is required to break these bonds, resulting in lower boiling points.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>14", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "Which of the following molecules is not linear in shape?", "images": [], "options": {"A": "CO2", "B": "O2", "C": "NH3", "D": "HCl"}, "answer": "C", "explanation": "CO2 has a linear shape. It has a bond angle of 180°      NH3 is not linear using the VSEPR model", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>15", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "In bonded atoms, increase in electro negativity difference,", "images": [], "options": {"A": "increases polarity", "B": "decreases polarity", "C": "has no effect on polarity", "D": "brings the polarity to zero"}, "answer": "A", "explanation": "Increase in electronegativity difference increases polarity. This is because electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. The greater the difference in electronegativity, the more polar the bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>16", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The number of particles in one mole of a chemical compound is the", "images": [], "options": {"A": "atomic number", "B": "avogadro's number", "C": "mass number", "D": "oxidation number"}, "answer": "B", "explanation": "Avogadro's number is the number of particles in one mole of a chemical compound. This implies that one mole of a chemical compound contains avogadro's number of particle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>17", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many molecules are there in 14g of nitrogen at s.t.p?  [N = 14, avogadro's constant = 6.02 × 1023 mol-1]", "images": [], "options": {"A": "6.02 × 1023", "B": "3.01 × 1023", "C": "8.43 × 1024", "D": "1.20 × 1024"}, "answer": "B", "explanation": "Given: The mass of Nitrogen = 14g  - Nitrogen gas, N2 contains 1 molecule of the gas  - N2 has a mass of 28g  ∴ 28g of N2 contains 1 molecule of the gas.  Recall that: 1 molecule of any gas contains 6.02 × 1023 particles,  ∴ 28g of N2 contains 6.02 × 1023 molecules  14g of N2 contains x molecules   2814=6.02 × 1023x  28x = 14 × 6.02 × 1023  2x = 6.02 × 1023  x = 3.01 × 1023 molecules.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2009>18", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.", "question": "Consider the reaction represented by the equation:  2NaHCO3 → Na2CO3 + H2O + CO2.  What is the mass of sodium trioxocarbonate (IV) produced by the complete decomposition of 33.6g of sodium hydrogen trioxocarbonate(IV)?  [NaHcO3 = 84, Na2CO3 = 106]", "images": [], "options": {"A": "10.6g", "B": "16.8g", "C": "21.2g", "D": "42.4g"}, "answer": "C", "explanation": "Given: The equation of the reaction  2NaHCO3 → Na2CO3 + H2O + CO2  - The mass of 1 mole of NaHCO3 is 84g.  168g of NaHCO3 produces 106g of Na2CO3  33.6g of NaHCO3 produces xg of Na2CO3  16833.6=106x  5=106x  5x = 106  x = 21.2g", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>19", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is percentage by weight of calcium in Ca(OCl)2?  [Ca = 40, Cl = 35.5, O = 16]", "images": [], "options": {"A": "28.0%", "B": "31.6%", "C": "43.8%", "D": "44.5%"}, "answer": "A", "explanation": "Given: The inoroganic compound, Ca(OCl)2  The mass of Ca(OCl)2 = 40 + 2(16 + 35.5)  = 40 + 2(51.5)  = 40 + 103 = 143  %compositionofcalcium=MassofcalciumMassofcompound×1001  =40143×100  =4000143=28%", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>20", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases is lighter than air?", "images": [], "options": {"A": "HCl", "B": "CO2", "C": "SO2", "D": "NH3"}, "answer": "D", "explanation": "The molar mass of air is approximately 29g/mol. The molar masses of HCl, CO2, SO2, and NH3 are 36.5g/mol, 44g/mol, 64g/mol, and 17g/mol, respectively. Therefore, NH3 is the only gas that is lighter than air, which corresponds to option 4.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>21", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "What is the value of -14°C on the Kelvin temperature scale?", "images": [], "options": {"A": "259K", "B": "259°K", "C": "287K", "D": "287°K"}, "answer": "A", "explanation": "Given:  The temperature in °C = -14°c  Recall that: T in k = T in °c  + 273  T in k = -14°c + 273°c  T in k = 259K", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>22", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "Which of the following expressions correctly represents Charle's law?", "images": [], "options": {"A": "PV = K", "B": "R α 1/&radic;p&nbsp;", "C": "PV = RT", "D": "V = KT"}, "answer": "D", "explanation": "Charles's law, or the law of volumes, describes how gases tend to expand when heated. It is represented as V = KT, where V is the volume, K is a constant, and T is the temperature. Therefore, option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>23", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "In a mixture of gases which do not react chemically together, the pressure exerted by the individual gases is called", "images": [], "options": {"A": "atmospheric pressure", "B": "partial pressure", "C": "total pressure", "D": "vapour pressure"}, "answer": "B", "explanation": "In a mixture of gases which do not react chemically together, the pressure exerted by gas is the partial pressure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>24", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "Consider the changes in state of matter as represented in the sketch.    Stage X represent the process of", "images": ["Chemistry/imgs/2009/pix1.png"], "options": {"A": "boiling", "B": "condensation", "C": "melting", "D": "sublimation"}, "answer": "C", "explanation": "Given: The heating graph  X is between the solid and liquid states of matter. This is melting, as melting is the process that takes place when a solid is heated to its liquid form.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>25", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "In the chemical reaction, ΔH is positive when", "images": [], "options": {"A": "H(product) > H(reactants)", "B": "H(product) (reactant)", "C": "H(product) = H(reactant)", "D": "H(product) = Zero"}, "answer": "A", "explanation": "ΔH is the enthalpy change. Enthalpy change could be positive or negative.  When it is positive, the reaction that takes place is endothermic, the heat content of the product, Hproduct is greater than that of the reactant, Hreactant.   Hproduct > Hreactant  When it is negative, the reaction that takes place is exothermic; the heat content of the product, Hproduct is less than that of the reactant, Hreactant . Hproduct reactant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>26", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Consider the reaction represented by the following equation   H2(g) + 1/2 O2(g) → H2O(g); ΔH = -285.8 kJmol-1  ΔH represents the enthalpy of", "images": [], "options": {"A": "formation", "B": "hydration", "C": "neutralization", "D": "solution"}, "answer": "A", "explanation": "Given: The equation of the reaction.  H2(g) + 1/2 O2(g) → H2O(g) Δ = -285kJmol-1  - ΔH represents the enthalpy of formation of H2O(g)  - ΔH can also represent the enthalpy of combustion of hydrogen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>27", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "Salt that contain water of crystallization are said to be", "images": [], "options": {"A": "anhydrous", "B": "deliquescent", "C": "efflorescent", "D": "hydrated"}, "answer": "C", "explanation": "Salt that contains water of crystallization is said to be efflorescence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>28", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following dilute acids does not react with metals to liberate hydrogen?", "images": [], "options": {"A": "CH3COOH(aq)", "B": "HCl(aq)", "C": "H2SO4(aq)", "D": "HNO3(aq)"}, "answer": "D", "explanation": "HNO3 does not react with metal to produce hydrogen gas because of its high oxidizing ability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>29", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following compound is not a double salt?", "images": [], "options": {"A": "Zn(OH)NO3", "B": "KAl(SO4)2", "C": "KCr(SO4)2", "D": "(NH4)2Fe(SO4)2"}, "answer": "A", "explanation": "Zn(OH)NO3 is not a double salt but a basic salt because of the presence of OH- (hydroxyl ion).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>30", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Which of the following hydroxides will readily dissolve in water?", "images": [], "options": {"A": "Cu(OH)2", "B": "NaOH", "C": "Pb(OH)2", "D": "Zn(OH)2"}, "answer": "B", "explanation": "The options give are all bases, i.e oxides of metals. NaOH is an alkali. Alkalis are water-soluble bases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>31", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following acids forms normal salt only?", "images": [], "options": {"A": "Tetraoxosulphate (VI) acid", "B": "Tetraoxosulphate (V) acid", "C": "Trioxonitrate (V) acid", "D": "Trioxosulphate (IV) acid"}, "answer": "C", "explanation": "Trioxonitrate (V) acid, HNO3 has only one ionizable hydrogen atom. Therefore, its reaction with a base (XOH) will form a normal salt (X+NO3-) and H2O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>32", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "A solution that contains as much solute as it can dissolve at a given temperature is said to be", "images": [], "options": {"A": "concentrated", "B": "saturated", "C": "supersaturated", "D": "unsaturated"}, "answer": "B", "explanation": "A solution that contains as much solute as it can dissolve at a given temperature is said to be saturated. The other options describe different states of a solution in relation to the amount of solute it contains.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>33", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following salts is insoluble in water?", "images": [], "options": {"A": "PB(NO3)2", "B": "Na2CO3", "C": "AgNO3", "D": "AgCl"}, "answer": "D", "explanation": "All common trioxonitrate(V) are water soluble. Hence, Pb(NO32 nd AgNO3 are water-soluble. AgCl is not water-soluble, Na2CO3 is water-soluble.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>34", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following statements is correct? The solubility of", "images": [], "options": {"A": "gases increases with increase in temperature", "B": "gases decreases with increase in temperature", "C": "most solid solutes decreases  with increase in temperature", "D": "most solid solutes is constant"}, "answer": "B", "explanation": "The solubility of most solid solutes increases with a rise in temperature. The solubility of most common gases however decreases with a rise in temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>35", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "A catalyst increase the rate of chemical reaction by", "images": [], "options": {"A": "decreasing the temperature of the reaction", "B": "decreasing the activation energy of the reaction", "C": "increasing the surface area of the reactants", "D": "decreasing the surface area of the products"}, "answer": "B", "explanation": "A catalyst increases the rate of a chemical reaction by decreasing the activation energy of the reaction. Activation energy is the minimum amount of energy required for a chemical reaction to occur. By lowering this energy, a catalyst allows the reaction to proceed more quickly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>36", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following factors will affect the rate of the reaction represented by the equation?  2HCl(aq) + CaCO3(s) → CaCl2(aq) + H2O(l) + CO2(g)  I. Pressure II. Concentration III. Nature of reactants IV. Temperature", "images": [], "options": {"A": "I and II only", "B": "II, III and IV only", "C": "I, II and III only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "Given: The equation of the reaction.  2HClaq + CaCO_(3(s) → CaCl2(aq) + H2O(l) + CO2(g)  The reaction above can be affected by concentration, temperature and nature or reactants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>37", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following substance is the dry Leclanche cell?", "images": [], "options": {"A": "Carbon rod", "B": "Muslin bag", "C": "The seal", "D": "Zinc container"}, "answer": "D", "explanation": "The zinc container is the outermost portion of the leclanche' cell. The muslin bag houses the manganese (iv) oxide which is the depolarizer. The carbon rod is the cathode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>38", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Consider the reaction represented by the equation:  2H2SO4(aq) + C(s) → 2H2O(l) + 2SO2(g) + CO2(g).  H2SO4 is acting as", "images": [], "options": {"A": "a catalyst", "B": "an oxidizing agent", "C": "a reducing agent", "D": "a sulphonating agent"}, "answer": "B", "explanation": "Given: The equation of the Reaction  2H2SO4(aq) + C(s) → CO2(g) + 2H2O(l) + SO2(g)  H2SO4 is functioning as the oxidizing agent. H2SO4 is reduced to SO2. The oxidation number of sulphur is reduced from +6 to +4.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>39", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following oxides of nitrogen has oxidation number of +1?", "images": [], "options": {"A": "KNO3", "B": "N2O", "C": "N2O3", "D": "NO"}, "answer": "B", "explanation": "- In N2O, the oxidation number of Nitrogen is 1  - 2x - 2 = 0  2x = 2; x = 1  - N2O is pronounced, 'Nitrogen(I)Oxide'", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>40", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "The separation of petroleum fractions depends on the differences in their", "images": [], "options": {"A": "boiling points", "B": "molar masses", "C": "melting points", "D": "solubilities"}, "answer": "A", "explanation": "The separation of petroleum fractions depends on the differences in their boiling points. The separation of petroleum fractions is by fractional distillation. The physical property considered in fractional distillation is boiling point.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>41", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following raw materials is used in the plastic industry?", "images": [], "options": {"A": "Calcium", "B": "Ethene", "C": "Hydrogen", "D": "Methane"}, "answer": "B", "explanation": "Ethene is used as a raw material in the plastic industry. It is a hydrocarbon that is used in the production of polyethylene, a common plastic material. Polyethylene is used in a wide variety of applications, including packaging, plastic bags, and plastic bottles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>42", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The product of the reaction between C2H5OH and concentrated H2SO4 at 170°C is", "images": [], "options": {"A": "(C2H5)2SO4", "B": "CH3CH2HSO4", "C": "(C2H5)2O", "D": "CH2 = CH2"}, "answer": "D", "explanation": "This is reaction is the total dehydration of C2H5OH, ethanol. This is usually takes place at a temperature of 170°c or 180°c with excess conc. H2SO4. The product of this dehydration is C2H4 or CH = CH which is ethene", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2009>43", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS", "question": "When Protein is heated to a high temperature it under goes", "images": [], "options": {"A": "condensation", "B": "denaturation", "C": "hydrolysis", "D": "polymerization"}, "answer": "B", "explanation": "When proteins are heated to high temperatures, they undergo a process called denaturation. Denaturation is a process where proteins lose their structure (secondary, tertiary, and quaternary structures) due to the application of some external stress or compound, such as a strong acid or base, a concentrated inorganic salt, an organic solvent, radiation, or heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>44", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "What is the molecular formular of a compound with empirical formular CH2O and vapour density of 90?  [H = 1, C = 12, O = 16]", "images": [], "options": {"A": "C4H8O2", "B": "C4H8O3", "C": "C6H10O5", "D": "C6H12O6"}, "answer": "D", "explanation": "Given:  - The empirical formula of the compound = (CH2O)  - The vapour density = 90  * Recall that: The Relative Molecular Mass = Vapour Density × 2  RMM = 90 × 2 = 180  * Recall that: RMM (Emperical formula)n = RMM (Molecular formula) ..... (1)  (Empirical formula)n = Molecular formula ..... (2)  from (1)  (12 + 2 + 16)n = 180  30n = 180  n = 6  from 2,  (CH2O)n = Molecular formula  (CH2O)6 = C6H12O6", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2009>45", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "What is the product of the reaction between propene and 1 mole of hydrogen iodide?", "images": [], "options": {"A": "CH3CHICH3", "B": "CH3CH2CHI2", "C": "CH3CH2Cl3", "D": "CH3CHICH2I"}, "answer": "A", "explanation": "The reaction between propene (C₃H₆) and hydrogen iodide (HI) is an example of an electrophilic addition reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>46", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Ethanol reacts with excess acidified K2Cr2O7 to produce", "images": [], "options": {"A": "ethanal", "B": "ethane", "C": "ethanoic acid", "D": "ethylethanoate"}, "answer": "C", "explanation": "Ethanoic acid when ethanol reacts excess acidified K2Cr2O2, it produces Ethanoic acid. It is an oxidation reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>47", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN CHLORIDE GAS", "question": "Dry hydrogen chloride when dissolved in methylbenzene", "images": [], "options": {"A": "turns blue litmus paper red", "B": "turns red litmus paper blue", "C": "does not affect litmus paper", "D": "bleaches litmus paper"}, "answer": "C", "explanation": "Dry hydrogen chloride readily dissolves in methylbenzene and does not conduct electricity and has no acidic properties.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>48", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "A consequence of global warming is", "images": [], "options": {"A": "pollution", "B": "flooding", "C": "increased humidity", "D": "low rainfall"}, "answer": "B", "explanation": "One of the consequences of global warming is flooding. As global temperatures rise, ice caps and glaciers melt, causing sea levels to rise. This can lead to increased flooding, particularly in low-lying areas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2009>49", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "The major product in the solvay process is", "images": [], "options": {"A": "NaOH", "B": "Na2CO3", "C": "NH3", "D": "H2SO4"}, "answer": "B", "explanation": "The Solvay process is a method for producing sodium carbonate (Na2CO3) from sodium chloride (NaCl) and ammonia (NH3). This process is named after its inventor, Ernest Solvay. Therefore, the major product of the Solvay process is sodium carbonate (Na2CO3).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2009>50", "subject": "Chemistry", "year": "2009", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Which of the following alloys does not contain copper?  I. Brass  II. Bronze  III. Steel", "images": [], "options": {"A": "I only", "B": "II only", "C": "III only", "D": "II and III only"}, "answer": "C", "explanation": "Brass is an alloy that is composed of copper and zinc. Bronze is and alloy that is composed of copper and tin. Steel is an alloy that is composed of iron and carbon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>1", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The electron configuration of carbon atom in its excited state is [6C]", "images": [], "options": {"A": "1s2 2s2 2px1 2py1", "B": "1s2 2s2 2px2 2py0", "C": "1s1 2s2 2px1 2py1 2pz1", "D": "1s2 2s1 2px1 2py1 2pz1"}, "answer": "D", "explanation": "The electronic configuration of carbon in its excited state is 1s2 2s2 2px1 2py1 2pz1. Carbon in its ground state has the electronic configuration: 1s2 2s2 2p2 . Carbon in its excited state has the electronic configuration: 1s2 2s1 2p3. In 2p3 we have 2px1, 2py1 and 2pz1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>2", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "RADIAOACTIVITY", "question": "An important medical use of nuclear radiations is", "images": [], "options": {"A": "activation analysis", "B": "carbon dating", "C": "radiotherapy", "D": "tissue regeneration"}, "answer": "C", "explanation": "Nuclear radiations are used in medicine for a variety of purposes. One of the most important uses is in radiotherapy, a treatment method for cancer and other diseases. In radiotherapy, nuclear radiations are used to kill or damage cancer cells, preventing them from growing and dividing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>3", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Which of the following elements exhibits the same chemical properties as the atom 3517X? An element with", "images": [], "options": {"A": "atomic number 17", "B": "atomic number 18", "C": "mass number 35", "D": "mass number 52"}, "answer": "A", "explanation": "Given: An element 3517X. The element that has the same chemical properties with the element given, 3517X will also belong to the same group with X or it will have the same atomic number as X.  - Hence, it is either the element belongs to group 7 or it has an atomic number of 17.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>4", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following noble gases has electronic structure similar to that of N in NH3?  [147N]", "images": [], "options": {"A": "2He", "B": "10Ne", "C": "18Ar", "D": "36Kr"}, "answer": "B", "explanation": "In NH3, N has 10 electrons. 10Ne also has 10 electrons.  ∴ 10Ne is isoelectronic with the N in NH3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>5", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Which of the following equations represents beta decay?", "images": [], "options": {"A": "23892U → 23490Th + 42He", "B": "147N + 42He → 178O + 11H", "C": "23992U → 23993Np + 0-1e", "D": "137N + 42He → 168O + 11H"}, "answer": "C", "explanation": "Beta decay is a type of radioactive decay where a beta particle (an electron or a positron) is emitted. In the given options, the equation 23992U → 23993Np + 0-1e represents beta decay. Here, Uranium-239 decays into Neptunium-239 by emitting an electron (beta particle).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>6", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The energy change which accompanies the addition of an electron to a gaseous atom is", "images": [], "options": {"A": "atomization", "B": "electron affinity", "C": "electronegativity", "D": "ionization"}, "answer": "B", "explanation": "The energy change which accompanies the addition of an electron to a gaseous atom is called electron affinity. Electron affinity is the amount of energy released or spent when an electron is added to a neutral atom to form a negative ion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>7", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Which of the following elements is a d-block element?", "images": [], "options": {"A": "Calcium", "B": "Iron", "C": "Lithium", "D": "Silicon"}, "answer": "B", "explanation": "Iron is a d-block element. The d-block elements are found in the middle of the periodic table and are often referred to as transition metals. They include elements from groups 3 to 12.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>8", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Calcium and magnesium belongs to the same group in the periodic table because both", "images": [], "options": {"A": "are metals", "B": "form cations", "C": "form colourless salts", "D": "have the same number of valence electrons"}, "answer": "D", "explanation": "Calcium and magnesium belong to the same group in the periodic table because they have the same number of valence electrons. Both Calcium and Magnesium have two valence electrons. This is the most important factor in determining their chemical properties and the reason why they are in the same group.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>9", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : OXYGEN", "question": "Which of the following element is diatomic?", "images": [], "options": {"A": "Iron", "B": "Neon", "C": "Oxygen", "D": "Sodium"}, "answer": "C", "explanation": "Oxygen is a diatomic element. Diatomic elements are elements that exist in their natural form as a molecule composed of two atoms. Oxygen exists as O2 in its natural state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>10", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Which of the following statements about chlorine and iodine at room temperature is correct?", "images": [], "options": {"A": "Chlorine is a gas and iodine is solid", "B": "Chlorine is a liquid and iodine is gas", "C": "Chlorine and iodine are gases", "D": "Chlorine is solid and iodine is liquid"}, "answer": "A", "explanation": "At room temperature, chlorine is a gas and iodine is a solid. This is due to the differences in their atomic structures and the strength of the intermolecular forces between their atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>11", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "If X is a group III element, its oxide would be represented as", "images": [], "options": {"A": "X3O2", "B": "X3O", "C": "X2O3", "D": "XO3"}, "answer": "C", "explanation": "If X is a group III element than the ion of X would be X3+. If X combines with O2, i.e X3+ +O2- then we will have X2O3.  N.B: Conventionally, Xn^+ + Yp- = XpYn.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>12", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Which of the following species correctly represents an ion of M with 13 protons and 10 electrons?", "images": [], "options": {"A": "10M3-", "B": "10M3+", "C": "13M3+", "D": "13M3-"}, "answer": "C", "explanation": "Given:  M which as 13 protons and 10 electrons  * Since M has 13 protons, it means that the neutral atom of M also has 13 electrons.  * Therefore, M has lost 3 electrons to have 10 electrons left.  That is M(s) - 3e- → M3+(aq) ......(1)  M(s) → M3+(aq) + 3e- ...... (2)  ∴ The ion of M is 13M3+", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>13", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "A solid substance with high melting and boiling points is likely to be a/an", "images": [], "options": {"A": "covalent compound", "B": "dative covalent compound", "C": "electrovalent compound", "D": "non-metal"}, "answer": "C", "explanation": "High boiling and melting points is a characteristic of electrovalent compounds. Since electrovalent compounds are non-volatile.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>14", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "Which of the following molecules has a linear shape?", "images": [], "options": {"A": "CH4", "B": "CO2", "C": "H2S", "D": "NH3"}, "answer": "B", "explanation": "CO2 has a linear shape. A molecule with a linear shape usually has a bond angle of 180°", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>15", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Which type of bond is represented by the dotted lines in the following structure?", "images": ["Chemistry/imgs/2010/s5.png"], "options": {"A": "Covalent bond", "B": "Dative bond", "C": "Electrovalent bond", "D": "Hydrogen bond"}, "answer": "D", "explanation": "The type of bond represented by the dotted lines is the hydrogen bond, since hydrogen bond is found between hydrogen and a strong electronegative element like fluorine, oxygen, nitrogen etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>16", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following molecules has a triple bond in its structure?", "images": [], "options": {"A": "CH4", "B": "NH3", "C": "N2", "D": "O2"}, "answer": "C", "explanation": "The molecule N2 has a triple bond in its structure. This is because Nitrogen has 5 valence electrons and needs 3 more to complete its octet. Therefore, two Nitrogen atoms can share 3 electrons each, forming a triple bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>17", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "The bonds in crystalline ammonium chloride are", "images": [], "options": {"A": "covalent and dative", "B": "ionic and covalent", "C": "ionic, covalent and dative", "D": "ionic, covalent and hydrogen bond"}, "answer": "C", "explanation": "The bonds we have in crystalline ammonium chloride include: Ionic and covalent bond. The covalent bond is present the hydrogen from hydrogen chloride and the ammonia molecule, so as to form the ammonium ion, NH4+. Ionic bond exist between NH4+ and chloride ion in HCl, Cl-.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>18", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Consider the neutralization reaction represented by the following equation :  Na2CO3 + 2HNO3 → 2NaNO3 + H2O + CO2  The stoichiometric ration of acid to base is", "images": [], "options": {"A": "2:2", "B": "2:1", "C": "1:2", "D": "1:1"}, "answer": "B", "explanation": "Given: The neutralization reaction  Na2CO3 (Base) + 2HNO3 (Acid) → 2NaNO3 + H2O + CO2  * The stoichiometric ratio of acid to base is 2:1", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2010>19", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "A solution of sodium trioxocarbonate(IV) contains 10.6g in 250cm3 of solution. Calculate the concentration of the solution.  [Na2CO3 = 106.0]", "images": [], "options": {"A": "0.4 moldm-3", "B": "1.0 moldm-3", "C": "10.6 moldm-3", "D": "25.0 moldm-3"}, "answer": "A", "explanation": "Given:  The mass of Na2CO3 = 10.6g; the volume of solution = 250cm3  * The molar concentration of Na2CO3 = 106.0 gmol-1  ∴ The number of mole = 10.6/10.6 = 0.1mole  Recall that 1000cm3 = 1 dm3, therefore, 250cm3 = 0.25dm3  0.1 mole is present in 0.25dm3  x mole is present in 1dm3  0.1x=0.251  x=0.10.25=0.4moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>20", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "What is the volume occupied by 2 moles of ammonia at s.t.p", "images": [], "options": {"A": "44.8 dm-3", "B": "22.4 dm-3", "C": "11.2 dm-3", "D": "5.6 dm-3"}, "answer": "A", "explanation": "1 mole of any gas occupies 22.4dm3 at s.t.p. 2 moles of ammonia gas will occupy 2 × 22.4 dm3 at s.t.p which is equal to 44.8dm3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>21", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : MEASUREMENT OF PHYSICAL QUANTITIES.", "question": "Which of the following apparatus can be used to measure accurately a specific volume of a liquid?", "images": [], "options": {"A": "Beaker", "B": "Conical flask", "C": "Measuring cylinder", "D": "Pipette"}, "answer": "D", "explanation": "A pipette is a laboratory tool commonly used in chemistry to transport a measured volume of liquid. It is designed to measure and deliver accurate volumes of liquid. The other options like beaker, conical flask and measuring cylinder are not as accurate as a pipette.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>22", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases can be collected by the set-up illustrated below?", "images": ["Chemistry/imgs/2010/s6.png"], "options": {"A": "H2", "B": "HCl", "C": "NH3", "D": "N2"}, "answer": "B", "explanation": "The set-up is for gases that are usually collected by upward displacement of air. These gases are usually denser than air. They include: NO2, CO2, SO2, HCl etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>23", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "A given volume of oxygen diffused through a porous partion in 8 seconds. How long would it take the same volume of carbon (IV) oxide to diffuse under the same condition?  [C = 12.0, O = 16.0]", "images": [], "options": {"A": "5.8 seconds", "B": "6.8 seconds", "C": "9.4 seconds", "D": "11.0 seconds"}, "answer": "C", "explanation": "t2t1=√m2m1  where t1 = Time taken for oxygen to diffuse  t2  = time taken for CO2 to difuse   t2 = time taken for CO2 to diffuse   M1 = molar mass of oxygen,  M2 = molar mass of CO2  t1 = 8, t2 = ? , M1 = 32 , M2 = 44  t28=√4432  t2 = 8 x 1.173 ,   t2 = 9.4 seconds", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>24", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Which of the following gases contains the highest number of atoms at s.t.p?", "images": [], "options": {"A": "6 moles of neon", "B": "3 moles of oxygen", "C": "2 moles of chlorine", "D": "1 mole of ethane"}, "answer": "D", "explanation": "Neon is a monoatomic gas.  6 moles contains 6 atoms.   Number of atoms = 6 x 6.02 x 1023=3.613 x 1024 atoms    Oxygen is diatomic gas.  3 moles contains (3x2)=6 atoms  Number of atoms = 6 x 6.02 x 1023=3.613 x 1024 atoms    Chlorine is diatomic gas  2 moles contains (2x2)=4 atoms  Number of atoms = 4 x 6.02 x 1023=2.4 x 1024 atoms    A molecule of ethane (C2H6) contains 8 atoms.   Number of atoms = 8 x 6.02 x 1023=4.81 x 1024 atoms", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>25", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "Given that r is rate and p is density, the expression r α 1/&radic;P&nbsp; represents", "images": [], "options": {"A": "Boyle's Law", "B": "Charles' Law", "C": "Dalton's Law", "D": "Graham's Law"}, "answer": "D", "explanation": "Graham's law of diffusion the rate of diffusion of a gas is inversely proportional to the square root of its vapour density. Mathematically: rα1&radic;p&nbsp;", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>26", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "The determination of heat of combustion is carried out with", "images": [], "options": {"A": "a thermometer", "B": "a bomb calorimeter", "C": "an evaporating dish", "D": "a boiling tube"}, "answer": "B", "explanation": "The heat of combustion is determined using a bomb calorimeter. A bomb calorimeter is a type of constant-volume calorimeter used in measuring the heat of combustion of a particular reaction. The other options like a thermometer, an evaporating dish, and a boiling tube are not used to determine the heat of combustion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>27", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The minimum amount of energy required for effective collisions between reacting particles is known as", "images": [], "options": {"A": "activation energy", "B": "bond energy", "C": "kinetic energy", "D": "potential energy"}, "answer": "A", "explanation": "Activation energy is the minimum amount of energy required for effective collisions between reacting particles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>28", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Which of the following oxides is basic?", "images": [], "options": {"A": "NO2", "B": "Al2O3", "C": "SO2", "D": "CaO"}, "answer": "D", "explanation": "Calcium oxide, CaO is a basic oxide. It reacts with acid to form salt and water during neutralization reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>29", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following equimolar solutions would have the highest conductivity?", "images": [], "options": {"A": "NH4NO3(aq)", "B": "NaNO3(aq)", "C": "Mg(NO3)2(aq)", "D": "Al(NO3)3(aq)"}, "answer": "D", "explanation": "The conductivity of a solution depends on the number of ions present in the solution. Al(NO3)3(aq) will dissociate into four ions (one Al3+ and three NO3-), thus it will have the highest conductivity among the given options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>30", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "The following substances are normal salts except", "images": [], "options": {"A": "Al(NO3)3", "B": "FeSO4", "C": "Mg(OH)NO3", "D": "NaCl"}, "answer": "C", "explanation": "Normal salts are formed from complete neutralization of an acid by a base. Mg(OH)NO3 is not a normal salt because it is formed from the partial neutralization of nitric acid by magnesium hydroxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>31", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following chlorides is insoluble in water?", "images": [], "options": {"A": "AgCl", "B": "KCl", "C": "NH4Cl", "D": "ZnCl2"}, "answer": "A", "explanation": "All common chloride salts are water-soluble except: AgCl, PbCl2 and Hg2Cl2. In view of this, AgCl is the only salt in the options that is water-insoluble.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>32", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following factors would not affect the solubility of a gas?", "images": [], "options": {"A": "Concentration", "B": "Nature of solvent", "C": "Pressure", "D": "Temperature"}, "answer": "A", "explanation": "The solubility of most common gases, however, decreases with a rise in temperature. The solubility of a gas is directly proportional to the gas pressure. Gases which do not react with water are only slightly soluble in water.  Concentration will not affect the solubility of a gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>33", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the equilibrium reaction represented by the following equation:  2SO2(g) + O2(g) ↔ 2SO3(g) ; ΔH = 395.7 kJmol-1  Which of the following statements about the equilibrium system is correct?", "images": [], "options": {"A": "Addition of catalyst changes the equilibrium position", "B": "Decrease in pressure increases the yield of SO3", "C": "Decrease in pressure increases the equilibrium concentration of O2", "D": "Increase in temperature favours the forward reaction"}, "answer": "C", "explanation": "Given: The equilibrium reaction  2SO(g) + O2(g) → 2SO3(g) ΔH = 395. kJmol-1  We have 3 moles of gaseous species on the reactant side and 2 moles of gaseous species on the product side. A decrease in pressure will favour the backward reaction. An increase in pressure will favour the forward reaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2010>34", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The rate of chemical reaction of solids are not affected by", "images": [], "options": {"A": "catalyst", "B": "pressure", "C": "particle size", "D": "temperature"}, "answer": "B", "explanation": "The rate of a chemical reaction involving solids is not affected by pressure. This is because solids are not compressible, so changes in pressure do not affect the concentration of the reactants. However, the rate of reaction can be affected by the presence of a catalyst, the particle size of the solid (as this affects the surface area available for reaction), and the temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>35", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following statements about the cell notation Mg / Mg2+ // Cu2+ / Cu is correct?", "images": [], "options": {"A": "Copper is the anode", "B": "Magnesium is reduced", "C": "Magnesium is the anode", "D": "The double line represents the electrodes"}, "answer": "C", "explanation": "Given: The cell notation  Mg/Mg2+//Cu2+/Cu. In general cell notation is given as: Anode/Anode electrolyte // cathode electrolyte / cathode. Therefore, magnesium is the anode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>36", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of the following statements about the electrolysis of CuSO4(aq) using copper cathode and platinum anode is not correct?", "images": [], "options": {"A": "Copper is deposited at the cathode", "B": "Oxygen is liberated at the anode", "C": "It is used for the purification of copper", "D": "The solution becomes acidic"}, "answer": "C", "explanation": "The electrolysis of Copper(II) Tetraoxosulphate (VI) using copper electrodes is used for the purification of copper, not using different electrodes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>37", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What is change in oxidation number of manganese in the reaction represented by the following equation?  MnO-4(aq) + 8H+(aq) + 5e- → Mn2+(aq) + 4H2O(l)", "images": [], "options": {"A": "+3 to +2", "B": "+4 to +2", "C": "+5 to +2", "D": "+7 to +2"}, "answer": "D", "explanation": "Given: The redox reaction  MnO-4(aq) + 8H+(aq) + 5e- → Mn(aq)2+ + 4H2O(l)  At the reactant side, the oxidation number of Mn (manganese) is +7, at the product side, the oxidation number of manganese is +2.  ∴ The oxidation number of manganese has changed from +7 to +2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>38", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The quantity of electricity required to discharge 1 mole of univalent ion is", "images": [], "options": {"A": "9,600C", "B": "48,250C", "C": "96,500C", "D": "193,000C"}, "answer": "C", "explanation": "The quantity of electricity Q required to discharge 1 mole of a univalent ion is 1 farad which is equal to 96500C..", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>39", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "Fats and oils are used as raw materials in the following industries except", "images": [], "options": {"A": "paint industry", "B": "plastic industry", "C": "margarine industry", "D": "cosmetics industry"}, "answer": "B", "explanation": "Fats and oils are not typically used as raw materials in the plastic industry. They are used in the paint industry (for making oil-based paints), margarine industry (for making margarine), and cosmetics industry (for making various cosmetic products).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>40", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : ALCOHOLS", "question": "Which of the following substances is trihydic?", "images": [], "options": {"A": "Ethanol", "B": "Glycol", "C": "Glycerol", "D": "Phenol"}, "answer": "C", "explanation": "Glycerol is propan - 1, 2, 3 - triol. It is trihydric since it has 3 OH group in its structure", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>41", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "An advantage of detergent over soap is that detergents", "images": [], "options": {"A": "are readily available", "B": "are in powdered form", "C": "are non-biogradable", "D": "lather readily with water"}, "answer": "D", "explanation": "Detergent lather readily with water. Soap does not lather readily with water. Soap is a good cleansing agent in soft water, in hard water it forms scum.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>42", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "The products of fermentation of sugar are", "images": [], "options": {"A": "carbon(IV)oxide and water", "B": "ethanol and carbon(IV)oxide", "C": "ethanol and water", "D": "ethanol and enzymes"}, "answer": "B", "explanation": "A solution of glucose in water is fermented by the enzyme, Zymase in yeast to give ethanol, Carbon(iv) Oxide and energy.  C6H12O6 → 2C2H5OH + 2CO2 + Energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>43", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "The IUPAC name of C2H5COOC2H5 is", "images": [], "options": {"A": "ethylethanoate", "B": "ethylpropanoate", "C": "propylethanoate", "D": "propylpropanoate"}, "answer": "B", "explanation": "C2H5COOC2H5 is ethyl propanoate. It is an ester formed from the reaction between propanoic acid and ethanol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>44", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "An organic compound contains 40.0% carbon, 6.7% hydrogen and 53.3% oxygen. What is the empirical formula of the compound?  [O = 16.0, C = 12.0, H = 1.0]", "images": [], "options": {"A": "C2HO", "B": "CHO", "C": "CH2O", "D": "CHO2"}, "answer": "C", "explanation": "Given:  The percentage compositions of carbon, Hydrogen and oxygen respectively: 40.0%, 6.7% and 53.3% in a compound. The empirical formula of the compound is unknown.    ∴ the empirical formulas CH2O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>45", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Consider the reaction represented by the following equation:    X and Y respectively are", "images": ["Chemistry/imgs/2010/pix4s.png"], "options": {"A": "ethene and ethane", "B": "ethane and ethene", "C": "ethyne and ethene", "D": "ethene and propene"}, "answer": "A", "explanation": "The reaction:    The reaction given is addition reaction and hydrogenation to be precise.  H - C ≡C - H is an alkyne it needs 2 moles of H2 to become saturated, i.e to become an alkane.  1 mole of H2 will change it to an alkene in the first part of the reaction and 1 mole of H2 will change it to alkane in the second part of the reaction.  ∴ X is ethene and Y is ethane.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>46", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Compound *₦* reacts with sodium metal to produce a gas that gives a 'pop' sound with a burning splint. *₦* also reacts with ethanoic acid to give a sweet smelling liquid. Compound *₦* is an", "images": [], "options": {"A": "alkanol", "B": "alkanoate", "C": "alkane", "D": "alkanoic acid"}, "answer": "A", "explanation": "N is an alkanol. An alkanol will react with sodium metal to liberate H2 gas, an alkanol will react with alkanoic acid to produce alkanoates. Alkanoates are sweet smelling liquids.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2010>47", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following structures represents that of ethylethanoate?", "images": ["Chemistry/imgs/2010/pix3.png", "Chemistry/imgs/2010/pix4.png", "Chemistry/imgs/2010/pix5.png", "Chemistry/imgs/2010/pix6.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "Ethyl ethanoate, commonly known as ethyl acetate, is an ester with the chemical formula C4H8O2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>48", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The main function of limestone in the blast furnace is to", "images": [], "options": {"A": "act as a reducing agent", "B": "act as a catalyst", "C": "remove impurities", "D": "supply carbon(IV)oxide"}, "answer": "C", "explanation": "The main function of limestone in the blast furnace is to remove impurities. Limestone (calcium carbonate) is added to the blast furnace to remove silicon dioxide, which is present as an impurity in the iron ore. The limestone reacts with the silicon dioxide to form calcium silicate (slag), which floats on the surface of the molten iron and can be removed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>49", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following substances cannot be classified as a heavy chemical?", "images": [], "options": {"A": "AgNO3", "B": "CaO", "C": "CaOCl2", "D": "H2SO4"}, "answer": "C", "explanation": "CaOCl2 is not a heavy chemical as it is not produced in large quantity in the chemical industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2010>50", "subject": "Chemistry", "year": "2010", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF SODIUM AND ITS COMPOUNDS.", "question": "Which of the following metals exists as liquid at ordinary temperature?", "images": [], "options": {"A": "Copper", "B": "Gold", "C": "Mercury", "D": "Silver"}, "answer": "C", "explanation": "Mercury is the only metal that exists as a liquid at ordinary temperature. It has a melting point of -38.83 degrees Celsius and a boiling point of 356.73 degrees Celsius, which means it is in the liquid state at room temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>1", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "How many isotopes has hydrogen?", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "B", "explanation": "Hydrogen has three known isotopes: Hydrogen (11H), Deuterium (21H) and Tritium (31H)", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>2", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following electron configurations correctly represents an inert elements?", "images": [], "options": {"A": "1s22p24p4", "B": "1s22s22p63s2", "C": "1s22s22p63s23p4", "D": "1s22s22p6"}, "answer": "D", "explanation": "An inert element will have 8 electrons in its outermost shell in the correct order except Helium which has 2 electrons in its outermost shell (Duplet structure).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>3", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What type of reaction is represented by the following equation?    21D + 31H → 42He + 10n + energy", "images": [], "options": {"A": "Nuclear fission", "B": "Nuclear fusion", "C": "Radioactive decay", "D": "Spontaneous decay"}, "answer": "B", "explanation": "The nuclear reaction is a nuclear fusion which involves the fusion of two smaller fragments to form a large nuclide (Parent nuclide). N.B: Energy produced from Nuclear Fusion is usually higher than Nuclear Fission.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2011>4", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following ions has the electron configuration 2, 8, 8?", "images": [], "options": {"A": "Na+", "B": "Mg2+", "C": "F-", "D": "Cl-"}, "answer": "D", "explanation": "Cl- has the configuration of 2, 8, 8. A neutral chlorine atom has an atomic number of 17, which means it has 17 electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>5", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "An element with the electron configuration 1s22s22p6 would have a combining power of", "images": [], "options": {"A": "0", "B": "6", "C": "8", "D": "1"}, "answer": "A", "explanation": "Noble gases do not combine.  The element with electronic configuration 1S22S22P6 is neon . it has no combining power because noble gases have no combining power", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>6", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "PERIODIC CHEMISTRY : THE NOBLE GASES", "question": "Rare gases are stable because they", "images": [], "options": {"A": "contain equal number of protons and neutrons", "B": "contain more electrons than protons", "C": "are chemically active", "D": "have octet structure"}, "answer": "D", "explanation": "Rare gases, also known as noble gases, are stable because they have an octet structure. This means they have a full set of electrons in their outermost energy level, which makes them chemically stable and inert. The octet rule is a chemical rule of thumb that reflects the theory that main-group elements tend to bond in such a way that each atom has eight electrons in its valence shell, giving it the same electronic configuration as a noble gas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>7", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Which of the following elements would produce coloured ions aqueous solutions?", "images": [], "options": {"A": "Calcium", "B": "Iron", "C": "Magnesium", "D": "Sodium"}, "answer": "B", "explanation": "Iron (Fe) is known to produce coloured ions in aqueous solutions. This is due to the d-d transitions of the d-electrons. When light passes through these solutions, certain wavelengths are absorbed by these transitions. The remaining light gives the solution its characteristic colour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>8", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The energy charge that accompanies the addition of an electron to an isolated gaseous atom is", "images": [], "options": {"A": "bond energy", "B": "electronegativity", "C": "electron affinity", "D": "ionization energy"}, "answer": "C", "explanation": "Electron affinity is usually exothermic and it involves the addition of electrons while Ionization Energy is usually endothermic and it involves the removal of electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>9", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following hydrohalic acids is the weakest?", "images": [], "options": {"A": "HBr", "B": "HCl", "C": "HF", "D": "HI"}, "answer": "D", "explanation": "The strength of hydrohalic acid decreases down the group: HF > HCl > HBr > HI", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>10", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following arrangements is order of increasing metallic property?", "images": [], "options": {"A": "Li", "B": "Na", "C": "K", "D": "K"}, "answer": "A", "explanation": "The metallic property increases down the group in the periodic table. Therefore, the order of increasing metallic property among Lithium (Li), Sodium (Na), and Potassium (K) is Li", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>11", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Chlorine, Bromine and Iodine belong to the same group and", "images": [], "options": {"A": "are gaseous at room temperature", "B": "form white precipitate with AgNO3aq", "C": "react violently with Hydrogen without heating", "D": "react with alkali"}, "answer": "D", "explanation": "Chlorine, Bromine and Iodine belong to the same group (Group 17, Halogens) in the periodic table. They all react with alkalis to form salts. The other options are incorrect because not all of them are gaseous at room temperature (Iodine is a solid), they do not all form white precipitates with AgNO3 (Chlorine forms a white precipitate, Bromine a cream one, and Iodine a yellow one), and they do not react violently with Hydrogen without heating.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>12", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC LAW", "question": "Which of the following elements can conveniently be placed in two groups in the periodic table?", "images": [], "options": {"A": "Carbon", "B": "Copper", "C": "Hydrogen", "D": "Oxygen"}, "answer": "C", "explanation": "Hydrogen is the only element that can be placed in two groups in the periodic table. It can be placed in Group 1 (Alkali metals) because it has one electron in its outermost shell, similar to the elements in this group. It can also be placed in Group 17 (Halogens) because it needs one electron to complete its outermost shell, similar to the elements in this group. The other elements listed can only be placed in one group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>13", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "The bond formed when two electrons that are shared between two atoms are donated by only one of the atoms is", "images": [], "options": {"A": "covalent", "B": "dative", "C": "ionic", "D": "metallic"}, "answer": "B", "explanation": "Dative (or Co-ordinate Covalent bond) is the bond shared by two atoms in which one of the bonding atoms contriibute its own lone pair of electrons to form that bond. e.g NH4+", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>14", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "When elements 20A combines with 8Y,", "images": [], "options": {"A": "a covalent compound, AY is formed", "B": "an ionic compound, AY is formed", "C": "an ionic compound A2Y is formed", "D": "a covalent compound, AY2 is formed"}, "answer": "B", "explanation": "20A is Ca2+  8A is O2-    CaO an ionic compound (because it is the bond between a metal and a non-metal) with the formular AY.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>15", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "In metallic solids, the forces of attraction are between the mobile valence electrons and", "images": [], "options": {"A": "atoms", "B": "neutrons", "C": "the negative ions", "D": "positively charged nuclei"}, "answer": "D", "explanation": "The metallic bond is been described by an  electron sea model  in which the bond is between the mobile electrons that moves around the center volume of the metal and  the positively charged nuclei", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>16", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Which of the following statements about displacement reaction is correct", "images": [], "options": {"A": "a more electropositive element displaces a less electropositive one", "B": "a less electropositive element displaces a more electropositive one", "C": "The position of elements in the reactivity series has no effect on the reaction", "D": "It only occurs when the reaction is at equilibrium"}, "answer": "A", "explanation": "Displacement reaction involves an MORE electropositive/electronegative element displacing a corresponding Less electropositive/electronegative element in a reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>17", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The volume occupied by 17g of H2S at s.t.p is [H = 1.00, S = 32.00, Molar Volume = 22.4dm-3]", "images": [], "options": {"A": "11.2dm2", "B": "17.0dm3", "C": "34.0dm3", "D": "44.8dm-3"}, "answer": "A", "explanation": "At s.t.p, 1 mole of gas occupies 22.4dm3  17gofH2S=1734mol=0.5molofH2S  0.5 × 22.4 = 11.2dm3 volume", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>18", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Consider the reaction represented by the following equation:   xKMnO4(aq) + ySO2(g) + zH2O(l) → K2SO4(aq) + 2MnSO4(aq) + 2H2SO4(aq)   x, y and z are respectively", "images": [], "options": {"A": "2, 5 and 2", "B": "2, 2 and 5", "C": "5, 1 and 2", "D": "1, 5 and 2"}, "answer": "A", "explanation": "xKMnO4 + ySO2 + zH2O → K2SO4 + 2MnSO4 + 2H2SO4  x will 2 become the number of K and Mn on the product   Side is 2  y will 5 because of the number of S on the Product  Side is 5  z will 2 because of the number of H on the product is 4  ∴ x, y, z → 2, 5 and 2", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2011>19", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is the amount of magenesium that would contain 1.20 x 1024 particles? [Mg = 24, Avogadro's constant = 6.02 x 1023]", "images": [], "options": {"A": "0.5 moles", "B": "2.0 moles", "C": "12.0 moles", "D": "24.0 moles"}, "answer": "B", "explanation": "1 mole = 6.02 × 1023  x mole ≡ 1.204 × 1024  ↑  Calculation from the First principle  x=1.204 × 10246.02 × 1023  x = 2 moles", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>20", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The number of atoms in one mole of a substance is equal to the", "images": [], "options": {"A": "mass number", "B": "oxidation number", "C": "atomic number", "D": "Avogadro's number"}, "answer": "D", "explanation": "One mole of any substance contains Avogadro's number (6.02 x 10^23) of particles (atoms, molecules, ions, etc.). Therefore, the number of atoms in one mole of a substance is equal to Avogadro's number.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>21", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "A gas that is collected by upward delivery is likely to be", "images": [], "options": {"A": "heavier than air", "B": "insoluble in water", "C": "lighter than air", "D": "soluble in water"}, "answer": "C", "explanation": "A gas that is collected by upward delivery is likely to be lighter than air. This is because lighter gases rise above heavier gases due to their lower density.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>22", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Bubbling excess Carbon (IV) Oxide into Calcium Hydroxide solution results in the formation of", "images": [], "options": {"A": "CaCO3", "B": "CaO", "C": "Ca(HCO3)2", "D": "H2CO3"}, "answer": "C", "explanation": "This is a practical test of CO2  CO2 + Ca(OH)2 → CaCO3 + H2O  CaCO3 + CO2 + H2O → Ca(HCO3)2 [when there is excess CO2]", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>23", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "The equation P = K/V illustrates", "images": [], "options": {"A": "Boyle's law", "B": "Dalton's law", "C": "Daltaniel's law", "D": "Gay lussac's law"}, "answer": "A", "explanation": "The equation P = K/V illustrates Boyle's law. Boyle's law, a principle in physics, states that the pressure (P) and volume (V) of a gas, at constant temperature, are inversely proportional. When volume increases, pressure decreases and vice versa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>24", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "The initial volume of a gas at 300k was 220cm3 . Determine its temperature if the volume became 250cm3 .", "images": [], "options": {"A": "183K", "B": "264K", "C": "300K", "D": "341K"}, "answer": "D", "explanation": "FromCharle'slaw,V1T1=V2T2(whereTisinKelvin)  220300=250T2  T2=300×250220=341K", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2011>25", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Consider the following energy profile diagram      X represents", "images": ["Chemistry/imgs/2011/chem1126.png"], "options": {"A": "activated complex", "B": "activation energy", "C": "enthalpy change", "D": "energy of reactant"}, "answer": "B", "explanation": "Activation energy = Activation complex - Enthalphy of reactants", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>26", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "Which of the following equimolar solutions has the highest conductivity?", "images": [], "options": {"A": "CH3COOH4(aq)", "B": "H2CO3(aq)", "C": "H2SO4(aq)", "D": "NaOH(aq)"}, "answer": "C", "explanation": "Electrical conductivity of electrolyte increases from weak acid/Base to Strong acid / Strong Base.  N.B: For Strong acid and strong Base, the one that has the highest number of ions will be the strongest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>27", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "The colour of phenolphthalein indicator in alkaline solution at the end-point of an acid-base titration is", "images": [], "options": {"A": "colourless", "B": "orange", "C": "pink", "D": "yellow"}, "answer": "C", "explanation": "Phenolphthalein is a chemical compound often used as a pH indicator in titrations. In a neutral or acidic solution, it is colorless. However, in an alkaline or basic solution, it turns pink. Therefore, at the end-point of an acid-base titration, if the solution is alkaline, phenolphthalein will turn pink.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>28", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following statements about enthalpy of neutralization is correct? It", "images": [], "options": {"A": "is constant for a strong acid and a strong base", "B": "cannot be determined using calorimeter", "C": "has a positive value", "D": "is higher for strong acid and a weak base"}, "answer": "A", "explanation": "The enthalpy of neutralization is the heat evolved when one mole of water is formed from the reaction of an acid and a base. It is constant for a strong acid and a strong base, typically -57.1 kJ/mol. This is because strong acids and bases completely dissociate in water, so the reaction is essentially the same each time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>29", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "When NH4Cl(s) was dissolved in water, the container was cold to touch. This implies that", "images": [], "options": {"A": "the process is endothermic", "B": "the process is exothermic", "C": "NH4Cl is highly soluble in water", "D": "NH4Cl forms a saturated solution"}, "answer": "A", "explanation": "When a substance dissolves in water and the process is accompanied by a cooling effect, it means that the process is endothermic. An endothermic process is one that absorbs heat from the surroundings. In this case, the dissolution of NH4Cl in water absorbs heat from the surroundings (making the container feel cold), hence it is an endothermic process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>30", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "Which of the following metallic oxides is amphoteric", "images": [], "options": {"A": "Al2O3", "B": "Fe2O3", "C": "MgO", "D": "Na2O"}, "answer": "A", "explanation": "Al2O3 and BeO are amphoteric oxides. amphoteric oxides are oxides hat can acts as basic and aciic oxides.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>31", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "On evaporation to dryness, 250cm3  of saturated solution of salt X with relative molar mass 101 gave 50.5g of the salt. What is the solubility of the salt?", "images": [], "options": {"A": "1.0moldm-3", "B": "2.0moldm-3", "C": "4.0moldm-3", "D": "5.0moldm-3"}, "answer": "B", "explanation": "The answer should be 2.0 moldm-3 from:  Solubility=n (mol)V (cm3)×1000  n(mol)=50.5101=0.5mol  ∴S=0.5250×1000=2moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>32", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the following reaction equation:  X(g) + Y(g) ⇔  XYg  , ΔH = +220kJmol dm-1   If the temperature of the system is increased, the", "images": [], "options": {"A": "backward reaction would be favoured", "B": "forward reaction would be favoured", "C": "reaction would stop", "D": "reaction would be at equilibrium"}, "answer": "B", "explanation": "According to Le Chatelier's principle, if a system at equilibrium is subjected to a change in temperature, pressure, or concentration of components, the system will shift its equilibrium position to counteract the effect of the disturbance. In this case, the reaction is endothermic (ΔH is positive), so increasing the temperature will provide the system with the additional heat it needs to proceed, thus favoring the forward reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>33", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following conditions would lead to an increase in the rate of a reaction?", "images": [], "options": {"A": "Increase in temperature and decrease in the surface area of reactants", "B": "Increase in both temperature and concentration of reactants", "C": "Decrease in  temperature and increase in concentration of reactant", "D": "Decrease in temperature and increase in the surface area of reactants"}, "answer": "B", "explanation": "Increasing temperature, Pressure (for gases), concentration, (solids and liquids), surface area all increase the rate of chemical reaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>34", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "What is the value of n in the following equation?    Cr2O72- + 14H+ + ne- → 2Cr3+ + 7H2O", "images": [], "options": {"A": "2", "B": "3", "C": "6", "D": "7"}, "answer": "C", "explanation": "The Number of charge on the Reactant side ≡ The number of charge on the product side.   -2 + 14 + n(-) = 2(3) + 0    -2 + 14 - n = 6    -n = -6    n = 6", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>35", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "What mass of copper would be formed when a current of 10.0A is passed through a solution of CuSO4 for 1 hour? {Cu = 63.5, 1F = 96500C]", "images": [], "options": {"A": "5.9g", "B": "11.8g", "C": "23.7g", "D": "47.3g"}, "answer": "B", "explanation": "The amount of substance produced in electrolysis is directly proportional to the quantity of electricity passed through the solution. This is Faraday's first law of electrolysis. The quantity of electricity (in coulombs) is given by the product of the current (in amperes) and time (in seconds). Given that 1 Faraday (96500C) will deposit 1 mole of copper (63.5g), a current of 10A for 1 hour (3600 seconds) will deposit (10*3600/96500)*63.5g = 11.8g of copper.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2011>36", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following metals could be used as sacrificial anode for preventing the corrosion of iron?", "images": [], "options": {"A": "Copper", "B": "Lead", "C": "Magnesium", "D": "Silver"}, "answer": "C", "explanation": "A sacrificial anode is a metal that is more reactive than the metal it is protecting. It is connected to the metal it is protecting and corrodes in preference to the protected metal. Magnesium is more reactive than iron and so can act as a sacrificial anode for iron.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>37", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Consider the following electrochemical cell notation:   Ms/M2+(aq) // H+(aq) / H2(g)   the value of the electrode potential is positive when", "images": [], "options": {"A": "electrons flow from the metal electrodes, M(s) to hydrogen  electrode, H2(g)", "B": "electrons flow from hydrogen electrodes, H2(g) to metal electrode, Ms", "C": "the flow of current is high", "D": "there is equilibrium between the flow of electrons from the hydrogen electrode, H2(g) to metal electrodes M(s)"}, "answer": "A", "explanation": "For an electrode being positive means electrons move from that electrode to the hydrogen.  The value of the electrode potential is positive when electrons flow from the metal electrodes Ms to the hydrogen electrode, H2(g).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>38", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Which of the following compounds determines the octane rating of petrol?", "images": [], "options": {"A": "1, 2, 3 - trimethylpentane", "B": "2, 3, 5 - trimethyloctane", "C": "2, 3, 5 - trimethyl pentane", "D": "2, 2, 4 - trimethylpentane"}, "answer": "D", "explanation": "The octane rating of petrol is determined by 2, 2, 4 - trimethylpentane. The octane rating is a standard measure of the performance of an engine or aviation gasoline. The higher the octane number, the more compression the fuel can withstand before detonating. In broad terms, fuels with a higher octane rating are used in high-performance gasoline engines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>39", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "Which of the following compounds would react with ethanoic acid to give a sweet smelling liquid?", "images": [], "options": {"A": "Alkane", "B": "Alkanol", "C": "Alkanal", "D": "Alkyne"}, "answer": "B", "explanation": "Ethanoic acid is a carboxylic acid, the sweet smelling  liquid is an esther which can be produced when carboxylic acids react with alkanol.  The process is called Esterification.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>40", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following separation techniques would show that black ink is a mixture of chemical compunds?", "images": [], "options": {"A": "Crystallization", "B": "Chromatography", "C": "Filtration", "D": "Sublimation"}, "answer": "B", "explanation": "Chromatography would show that black ink is a mixture of chemical compounds. Chromatography is a laboratory technique for the separation of a mixture. The mixture is dissolved in a fluid called the mobile phase, which carries it through a structure holding another material called the stationary phase. The various constituents of the mixture travel at different speeds, causing them to separate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>41", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "The following substances are examples of addition polymer except", "images": [], "options": {"A": "nylon", "B": "perspex", "C": "polyethane", "D": "polychloroethane"}, "answer": "A", "explanation": "Nylon is an example of a condensation polymer, not an addition polymer. Addition polymers are a type of polymer that results from the addition of monomer molecules with no loss of atoms in the process. In contrast, condensation polymers form when two monomers combine with the loss of a small molecule, often water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>42", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "When bromine is added to ethane at room temperature the compound formed is", "images": [], "options": {"A": "1, 1 - dibromoethane", "B": "1, 1 - didibromoethene", "C": "1, 2 - dibromoethane", "D": "1, 2 - dibromoethene"}, "answer": "C", "explanation": "C2H4 + Br2(g) → CH2BrCH2Br or C2H4Br2 (1, 2 - dibromoethane)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>43", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following organic compounds would react with sodium trioxocarbonate (IV) to liberate carbon(IV)oxide?", "images": ["Chemistry/imgs/2011/chem1144a.png", "Chemistry/imgs/2011/chem1144b.png", "Chemistry/imgs/2011/chem1144c.png", "Chemistry/imgs/2011/chem1144d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "Alcohol reacts with Na2CO3 to produce CO2 ↑", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2011>44", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The compound that makes palm wine taste sour after exposure to the air for few days is", "images": [], "options": {"A": "ethanol", "B": "ethanoic acid", "C": "methanol", "D": "methanoic acid"}, "answer": "B", "explanation": "Ethanoic acid is the compound that makes palm wine taste sour after exposure to the air for a few days. Ethanoic acid, also known as acetic acid, is a sour-tasting compound best known for the sour taste and pungent smell in vinegar, pickles, and sourdough bread. Its presence in palm wine is due to the fermentation process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2011>45", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "The reagent that can be used to distinguish ethene from ethyne is", "images": [], "options": {"A": "ammoniacal silver trioxonitrate (V) solution", "B": "Benedict solution", "C": "bromine water", "D": "Fehling's solution"}, "answer": "A", "explanation": "Terminal alkyne undergoes substitution with AgNO3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>46", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The following substances are ores of metal except", "images": [], "options": {"A": "bauxite", "B": "cuprite", "C": "cassiterite", "D": "graphite"}, "answer": "D", "explanation": "Graphite is not an ore of metal. It is a form of carbon, which is a non-metal. The other options, bauxite, cuprite, and cassiterite, are all ores of metals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>47", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following processes does not involve the use of limestone?", "images": [], "options": {"A": "Extraction of iron in the blast furnace", "B": "Manufacture of tetraoxosulphate(VI) acid by Contact process.", "C": "Production of washing soda by Solvay process", "D": "Production of cement."}, "answer": "B", "explanation": "The manufacture of tetraoxosulphate(VI) acid by Contact process does not involve the use of limestone. The other processes listed do use limestone in some way.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>48", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following substances is mainly responsible for the depletion of the ozone layer?", "images": [], "options": {"A": "Chlorofluorocarbon", "B": "Carbon(IV) Oxide", "C": "Nitrogen", "D": "Oxygen"}, "answer": "A", "explanation": "Chlorofluorocarbons (CFCs) are mainly responsible for the depletion of the ozone layer. They contain chlorine, which can catalyze the breakdown of ozone into oxygen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>49", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Aluminium is extracted by electrolysis from", "images": [], "options": {"A": "bauxite", "B": "cryolite", "C": "duralumin", "D": "kaolin"}, "answer": "A", "explanation": "Aluminium is extracted by electrolysis from bauxite. Bauxite is the principal ore of aluminium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2011>50", "subject": "Chemistry", "year": "2011", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "Which of the following statements about a molar solution is correct?.", "images": [], "options": {"A": "is a supersaturated solution", "B": "cannot dissolve more of the solute at that temperature", "C": "contains any amount of solute in a given volume of solution", "D": "contains one mole of the solute in 1dm3 of solution"}, "answer": "D", "explanation": "A molar solution is a solution that contains one mole of a solute in 1dm3 of solution. This is a standard definition in chemistry. The other options are incorrect because they describe other types of solutions, not specifically a molar solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>1", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "The number of orbitals in a p - sub level of an atom is", "images": [], "options": {"A": "2", "B": "3", "C": "5", "D": "6"}, "answer": "B", "explanation": "In atomic physics and quantum chemistry, the electron configuration is the distribution of electrons of an atom or molecule in atomic or molecular orbitals. For example, the electron configuration of the neon atom is 1s2 2s2 2p6. The p sublevel has 3 orbitals, each of which can hold 2 electrons, for a total of 6 electrons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>2", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following electron configuration represents that of an atom in its ground state?", "images": [], "options": {"A": "1s22s22p63s13p1", "B": "1s22s12p1", "C": "1s22s12p3", "D": "1s22s22p63s0"}, "answer": "D", "explanation": "Ground-state configuration means the electrons hasn't been excited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>3", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.", "question": "A beam of particles was passed between charged plates as illustrated in the diagram beside.    X, Y and Z are respectively.", "images": ["Chemistry/imgs/2012/s7.png"], "options": {"A": "electron, neutron and proton", "B": "electron, proton and neutron", "C": "proton, neutron and electron", "D": "proton, electron and neutron"}, "answer": "C", "explanation": "Electron (-ve) attracted to +ve changed plate.  Proton (+ve) attracted to -ve charged plate  Neutron (no charge)", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2012>4", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following ions has an electron configuration different from the others?", "images": [], "options": {"A": "17Cl-", "B": "8O2-", "C": "12Mg2+", "D": "13Al3+"}, "answer": "A", "explanation": "Cl-1 has 18 electrons which has an electron configuration different from the others", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>5", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The atomic radii of metals are usually", "images": [], "options": {"A": "greater than their ionic radii", "B": "equal to their ionic radii", "C": "less than their ionic radii", "D": "less than those of non-metals in the same period"}, "answer": "A", "explanation": "Atomic radii are usually greater than ionic radii → For metals   Atomic radii are usually lesser than ionic radii → For non-metals", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>6", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Two elements, X and Y are in the same group on the periodic table because they both have the same", "images": [], "options": {"A": "number of electronic shells", "B": "number of valence electrons", "C": "atomic size", "D": "atomic number"}, "answer": "B", "explanation": "Elements in the same group on the periodic table have the same number of valence electrons. Valence electrons are the electrons in the outermost shell of an atom and determine an atom's ability to form bonds with other atoms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>7", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "The d-block elements are paramagnetic because they", "images": [], "options": {"A": "contain paired electrons which are repelled by magnetic field", "B": "contain unpaired electrons in the partially filled 3d-orbital", "C": "form coloured complex ions that attract magnetic lines of force", "D": "have delocalized valence electrons"}, "answer": "B", "explanation": "The d-block elements are paramagnetic because they contain unpaired electrons in the partially filled 3d-orbital. Paramagnetism refers to the magnetic state of an atom with one or more unpaired electrons. The unpaired electrons are attracted by a magnetic field due to the electron's magnetic dipole moment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>8", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.", "question": "Which of the following statements about a radioactive substance is/are correct?   I. It emits radiation continuously and spontaneously   II. The emitted radiations are affected by temperature and pressure   III The radiation can penetrate opaque matter.", "images": ["Chemistry/imgs/2012/s7.png"], "options": {"A": "II only", "B": "I and II only", "C": "I and III only", "D": "II and III only"}, "answer": "C", "explanation": "A radioactive substance will emit radiations spontaneously    * The emission of radiations by a radioactive substance should not be affected by temperature    * Radiations have different penetrating powers and can pass through opaque materials.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>9", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Which of the following elements is a metalloid?", "images": [], "options": {"A": "Carbon", "B": "Oxygen", "C": "Silicon", "D": "Sodium"}, "answer": "C", "explanation": "Silicon is a metalloid. Metalloids have properties of both metals and non-metals. Silicon, for example, has lustrous shine like a metal, is a good conductor of electricity like a metal, but is brittle and not malleable like a non-metal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>10", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following halogens is liquid at room temperature?", "images": [], "options": {"A": "Chlorine", "B": "Fluorine", "C": "Iodine", "D": "Bromine"}, "answer": "D", "explanation": "Bromine is the only halogen that is liquid at room temperature. Halogens are the elements in Group 17 of the periodic table. They include fluorine, chlorine, bromine, iodine, and astatine. All halogens have 7 valence electrons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>11", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "The shape of a graphite crystal is", "images": [], "options": {"A": "tetrahedral", "B": "pyramidal", "C": "hexagonal", "D": "octahedral"}, "answer": "C", "explanation": "The shape of a graphite crystal is hexagonal. Graphite is an allotrope of carbon where the carbon atoms are arranged in a hexagonal manner. This arrangement results in layers or sheets of carbon atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>12", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The compound formed by the combination of two elements with a large electronegativity difference is likely to be", "images": [], "options": {"A": "polar covalent", "B": "giant molecular", "C": "covalent", "D": "ionic"}, "answer": "D", "explanation": "When two elements with a large electronegativity difference combine, they form an ionic compound. This is because the element with the higher electronegativity will attract the electrons from the other element, resulting in the formation of ions. These ions then attract each other to form an ionic compound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>13", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "The complex compound formed when Aluminium dissolves in aqueous Sodium Hydroxide is", "images": [], "options": {"A": "Na3Al(OH)4", "B": "NaAl(OH)4", "C": "NaAl(OH)3", "D": "Na2Al(OH)3"}, "answer": "B", "explanation": "When aluminium dissolves in aqueous sodium hydroxide, the complex compound formed is NaAl(OH)4. This is because aluminium reacts with sodium hydroxide to form a complex ion, Al(OH)4-, which then combines with the sodium ions to form the compound.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2012>14", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "The vapour pressure of a liquid depends on    I. temperature    II. rate of condensation    III. cohesive forces holding the particles together.", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "I and III only", "D": "II and III only"}, "answer": "C", "explanation": "Vapour pressure depends on temperature and the intermolecular forces holding the individual atoms together", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>15", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "MgO does not readily dissolve in water because", "images": [], "options": {"A": "of its high melting point", "B": "it is a covalent compound", "C": "it forms a hydroxide when dissolved in water", "D": "its lattice energy is higher than its hydration energy"}, "answer": "D", "explanation": "MgO does not readily dissolve in water because its lattice energy is higher than its hydration energy. Lattice energy is the energy required to separate the ions in an ionic compound, while hydration energy is the energy released when the ions are surrounded by water molecules. If the lattice energy is higher than the hydration energy, the compound will not dissolve readily in water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>16", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Consider the following reaction equation:   CaCO3(s) + 2HCl(aq) → CaCl2(aq) + H2O(l) + CO2(g)    What mass of CaCl2would be obtained when 25.0g of CaCO3(s)is reacted with excess HClaq? [CaCO3 = 100, CaCl2 = 111]", "images": [], "options": {"A": "4.00g", "B": "4.44g", "C": "18.9g", "D": "27.8g"}, "answer": "D", "explanation": "CaCO3(s) + 2HCl(aq) → CaCl2(aq) + H2O(l) + CO2(g)   1 mole of CaCO3 ≡ 1 mol of CaCl2  100g of CaCO3 ≡ 111g of CaCl2  25g of CaCO3 ≡ xg of CaCl2  x=25×111100  x = 27.8g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2012>17", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The number of sulphur atoms in 3.20g of SO2(g) is    [O = 16.0; S = 32.), Avogadro constant = 6.02 x 1023]", "images": [], "options": {"A": "3.01 x 1022", "B": "6.02 x 1022", "C": "6.02 x 1023", "D": "1.20 x 1024"}, "answer": "A", "explanation": "The molar mass of SO2 is 64g/mol (32g for S and 16g for each O). Therefore, 3.20g of SO2 is 0.05 moles (3.20g / 64g/mol). Since each molecule of SO2 contains one S atom, there are 0.05 moles of S atoms in 3.20g of SO2. Using Avogadro's number (6.02 x 10^23), we find that 0.05 moles of S atoms is 3.01 x 10^22 atoms (0.05 x 6.02 x 1023.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2012>18", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Consider the reaction represented by the following equation: xCH3OH + yO2 → 2CO2 + zH2O.    The value of x, y and z respectively are", "images": [], "options": {"A": "2, 3 and 4", "B": "2, 4 and 3", "C": "1, 2 and 3", "D": "1, 3 and 5"}, "answer": "A", "explanation": "The balanced chemical equation for the reaction is 2CH3OH + 3O2 → 2CO2 + 4H2O. Therefore, the values of x, y, and z are 2, 3, and 4 respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>19", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The formular of mercury (1)dioxonitrate (III) is", "images": [], "options": {"A": "HgNO3", "B": "Hg2NO3", "C": "Hg(NO2)2", "D": "Hg2(NO3)2"}, "answer": "C", "explanation": "Hg2+ &nbsp &nbsp &nbsp &nbsp NO2-  +2 &nbsp &nbsp &nbsp &nbsp 1  Hg(NO2)2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>20", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "A sample of a gas may be identified as chlorine if it turns", "images": [], "options": {"A": "damp blue litmus paper red", "B": "lime water milky", "C": "lead ethanoate  paper black", "D": "starch iodine paper blue-black"}, "answer": "D", "explanation": "Oxidation ability of Cl2, chlorine turns moist starch-iodide paper blue because it laces iodine from the iodide, The iodine liberated hen turns he starch blue black. 2Klaq + Cl2g → 2KCl2 + l2g", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>21", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "A metal M forms two types of chlorine, MCl2 and MCl3 . Which of the following laws best explains the relationship between the chlorides? Law of", "images": [], "options": {"A": "conservation of mass", "B": "definite proportion", "C": "multiple proportion", "D": "reciprocal proportion"}, "answer": "C", "explanation": "The law of multiple proportions states that when one element combines with another to form more than one compound, the mass ratios of the elements in the compounds are simple whole numbers of each other. In this case, the metal M forms two compounds with chlorine, MCl2 and MCl3. The ratio of chlorine to M in the two compounds is 2:1 and 3:1, which are simple whole numbers of each other. Therefore, the law of multiple proportions best explains the relationship between the chlorides.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>22", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Which of the following metals would readily displace hydrogen from steam?", "images": [], "options": {"A": "Copper", "B": "Lead", "C": "Magnesium", "D": "Silver"}, "answer": "C", "explanation": "Magnesium is a more reactive metal and can readily displace hydrogen from steam. This is based on the reactivity series of metals, where magnesium is higher than hydrogen, meaning it can displace hydrogen from its compounds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>23", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The volume occupied by 0.4g of hydrogen gas at s.t.p is   [H = 1.00, Molar volume at s.t.p = 22.4dm3]", "images": [], "options": {"A": "2.24dm3", "B": "4.48dm3", "C": "22.4dm3", "D": "44.8dm3"}, "answer": "B", "explanation": "H2 → 2g (1 mol)  2g = 22.4dm3  6.4g ≡x  x=22.4×0.42=4.48dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>24", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "When a substance changes directly from the solid state to the gaseous state without forming a liquid, the substance is said to", "images": [], "options": {"A": "condense", "B": "evaporate", "C": "sublime", "D": "precipitate"}, "answer": "C", "explanation": "When a substance changes directly from the gaseous state to the solid state without forming a liquid, the substance is said to sublime. This is a type of phase transition called sublimation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>25", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION", "question": "At ordinary temperature H2O is a liquid while H2S is a gas. This is because H2O has", "images": [], "options": {"A": "weak intermolecular forces holding its molecules together", "B": "strong hydrogen bonds holding its molecules together", "C": "induced dipole-induced dipole forces between its molecules", "D": "ionic forces between its molecules"}, "answer": "B", "explanation": "H2O is a liquid at ordinary temperature because it has strong hydrogen bonds holding its molecules together. These bonds require a significant amount of energy to break, which is why water remains a liquid at higher temperatures compared to H2S, which only has weak Van der Waals forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>26", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "The postulate that molecules are in constant random mention best explains why liquids", "images": [], "options": {"A": "can undergo solidification", "B": "maintain their volumes", "C": "are incompressible", "D": "have no characteristic shape"}, "answer": "B", "explanation": "Liquids are able to maintain their volumes because the molecules are in constant random motion. This motion allows the molecules to move freely within the liquid while remaining in close proximity to each other. Unlike gases, where molecules move freely and independently, liquid molecules are still closely packed together but have enough kinetic energy to move past each other, allowing liquids to flow and take the shape of their container.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>27", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases has the lowest rate of diffusion under the same condition?    [H = 1.00, He = 4.00, O = 16.0; Cl = 35.5]", "images": [], "options": {"A": "Cl2", "B": "H2", "C": "He", "D": "O2"}, "answer": "A", "explanation": "From Graham's law,  Rateofdiffusionα1&radic;Molar mass&nbsp;  Cl2 will have the lowest rate.  Cl2=35.5x2=1;rate=1√7=0.12  H2=1x2=2;rate=1√2=0.7071  O2=16x2=32;rate=1√32=0.18", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>28", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "The energy evolved when magnesium burns in air is in the form of", "images": [], "options": {"A": "heat", "B": "heat and sound", "C": "light and heat", "D": "sound"}, "answer": "C", "explanation": "When magnesium burns in air, it reacts with oxygen to form magnesium oxide. This reaction is exothermic, meaning it releases energy in the form of heat and light. Therefore, the energy evolved when magnesium burns in air is in the form of light and heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>29", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A substance L reacts with NH4NO3(aq) to generate ammonia gas L is likely to be", "images": [], "options": {"A": "HCl", "B": "NaOH", "C": "CH3COOH", "D": "CaSO4"}, "answer": "B", "explanation": "NaOH reacting with NH4NO3 (which is a salt of strong acid and weak base)  NH4NO3 + NaOH → NaNO3 + NH3 + H2O", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>30", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "On heating, the following trioxocarbonate (IV) salts decompose to give solid residue except", "images": [], "options": {"A": "ammonium trioxocarbonate (IV)", "B": "calcium trioxocarbonate (IV)", "C": "lead(II)trioxocarbonate(IV)", "D": "zinc trioxocarbonate(IV)"}, "answer": "A", "explanation": "Ammonium trioxocarbonate (IV) decomposes to give nitrogen, water and carbon dioxide gases with no solid residue. The other trioxocarbonate (IV) salts decompose to give a solid residue (metal oxide) and carbon dioxide gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>31", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Which of the following pH values indicates that a solution is a strong base?", "images": [], "options": {"A": "1", "B": "5", "C": "9", "D": "13"}, "answer": "D", "explanation": "The pH scale ranges from 0 to 14. A pH value of 7 indicates a neutral solution. pH values less than 7 indicate acidic solutions, and pH values greater than 7 indicate basic or alkaline solutions. Therefore, a pH value of 13 indicates a strong base.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>32", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "The hydrolysis of NH4Cl gives", "images": [], "options": {"A": "an acidic solution", "B": "an alkaline solution", "C": "a buffer solution", "D": "a neutral solution"}, "answer": "A", "explanation": "Hydrolysis of NH4Cl gives NH3 solution and HCl which is a solution of weak base and strong acid therefore gives an overall acidic solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>33", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : SEPARATION AND PURIFICATION OF ORGANIC COMPOUNDS", "question": "A spot of oil paint on a shirt can best be removed using", "images": [], "options": {"A": "brine", "B": "detergent", "C": "kerosene", "D": "warm water"}, "answer": "C", "explanation": "Oil-based paints are best removed using kerosene. This is because oil and kerosene are both non-polar substances and according to the principle of 'like dissolves like', non-polar substances dissolve in non-polar solvents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>34", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following deductions could be correctly made from the graph?", "images": ["Chemistry/imgs/2012/chem1233.png"], "options": {"A": "The solubility of U is not affected by change in temperature", "B": "The solubility of S decreases with increasing temperature", "C": "T is most soluble among the salts", "D": "S is least soluble among the salts"}, "answer": "A", "explanation": "The straight line result obtained for U indicates that its solubility is unaffected by temperature change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>35", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Consider the reaction represented by the following equation:  CuOs + H2SO4(aq) → CuSO4(aq) + H2O(l)   Which of the following factors will not affect the rate of the reaction?", "images": [], "options": {"A": "Particle size CuO(s)", "B": "Concentration of H2SO4(aq)", "C": "Temperature of the reacting mixture", "D": "Pressure of reaction system"}, "answer": "D", "explanation": "The pressure of the reaction system will not affect the rate of the reaction. This is because the reaction does not involve any gases. The rate of a reaction involving gases can be affected by pressure, but in this case, all reactants and products are either solids, liquids, or aqueous solutions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>36", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Use the following graph to answer this question       The activation energy for the reaction is", "images": ["Chemistry/imgs/2012/chem1236.png"], "options": {"A": "40 kJ", "B": "60 kJ", "C": "80 kJ", "D": "120 kJ"}, "answer": "A", "explanation": "Activation energy is ( Activated complex - Reactant Energy) = 120 - 80 = 40kJ", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>37", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Use the following graph to answer this question     The type of reaction represented by the graph is", "images": ["Chemistry/imgs/2012/chem1236.png"], "options": {"A": "endothermic", "B": "exothermic", "C": "catalytic", "D": "spontaneous"}, "answer": "B", "explanation": "It is exothermic because ΔHproduct reactant", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>38", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following devices function on redox reaction?  I. Dry cell   II. Car battery    III. Electric generator", "images": [], "options": {"A": "I and III only", "B": "II and III only", "C": "I and II only", "D": "I, II and III"}, "answer": "C", "explanation": "Dry cell and car battery function on redox reactions. A redox reaction is a type of chemical reaction that involves a transfer of electrons between two species. In both a dry cell and a car battery, there is a transfer of electrons from one species to another, which generates an electric current. An electric generator, on the other hand, operates on the principle of electromagnetic induction, not redox reactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>39", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of Fe in [Fe(CN60]3- is", "images": [], "options": {"A": "+3", "B": "+2", "C": "-2", "D": "-3"}, "answer": "A", "explanation": "The oxidation number of Fe in [Fe(CN6)]3- is +3. The oxidation number is a concept in chemistry that helps in balancing redox reactions. It represents the number of electrons that an atom can gain, lose, or share when chemically bonded with another atom. In this case, the overall charge of the complex ion is -3, and since each CN- ion has a charge of -1, the oxidation number of Fe must be +3 to balance the charge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>40", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Consider the following reaction equation:   C16H34 → C5H12 + C11H22    The process represented by the equation is", "images": [], "options": {"A": "cracking", "B": "fermentation", "C": "polymerization", "D": "reforming"}, "answer": "A", "explanation": "The process is cracking which involves the breakdown on higher hydrocarbon into smaller hydrocarbon fragment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>41", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "Consider the following structures of organic compounds:      Which of the following statements about the structure is not correct?", "images": ["Chemistry/imgs/2012/s8.png"], "options": {"A": "are geometric isomers", "B": "are saturated hydrocarbons", "C": "have similar physical properties", "D": "are members of the same homologous series"}, "answer": "B", "explanation": "It is unsaturated due to the presence of multiple bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>42", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : ALCOHOLS", "question": "Which of the following substances would not produce ethanol when fermented?", "images": [], "options": {"A": "Cane sugar", "B": "Glucose", "C": "Starch", "D": "Vinegar"}, "answer": "D", "explanation": "Vinegar would not produce ethanol when fermented. Fermentation is a process where sugars are converted into alcohol and carbon dioxide by the action of yeast or bacteria. Cane sugar, glucose, and starch are all sources of sugar that can be fermented to produce ethanol. Vinegar, on the other hand, is a product of fermentation (it's essentially fermented ethanol) and cannot be further fermented to produce ethanol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>43", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "An alkanol can be prepared by the reaction of an alkene with", "images": [], "options": {"A": "concentrated tetraoxosulphate (VI) acid", "B": "bromine in tetrachloroethene", "C": "aqueous potassium tetraoxomanganate(VII)", "D": "sodium hydroxide solution"}, "answer": "A", "explanation": "Alkene + Concentrated H2SO4 at 180°C → Alkanol  N:B: If the reaction takes place at 140°C, it will produce an ether.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>44", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "A compound contains 7.75% Hydrogen, 37.21% Carbon and 55.04% Chlorine. Determine the empirical formular of the compound. [H = 1.00; C = 12.0, Cl = 35.5]", "images": [], "options": {"A": "C3H3Cl", "B": "C2H5Cl", "C": "C3H8Cl", "D": "C5H2I"}, "answer": "B", "explanation": "H  C  Cl  7.751:37.2112:55.04335.5  7.75: 3.10: 1.55; divide by the smallest ratio    7.751.55:3.101.55:1.551.55   5:2:1   empirical formula is C2H5Cl", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2012>45", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "A tertiary alkanol has a molecular formular C4H10O. What is the structural formula of the compound?", "images": [], "options": {"A": "(CH3)2CHCH2OH", "B": "CH3CH2CH(OH)CH3", "C": "(CH3)3COH", "D": "CH3CH2CH2CH2OH"}, "answer": "C", "explanation": "Tertiary alkanol has 3 alkyl group attached to the carbon that is containing OH - functional group", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>46", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Which of the following industrial processes depends on the action of enzymes?", "images": [], "options": {"A": "Liquefaction of air", "B": "Manufacture of soap", "C": "Brewing of beer", "D": "Catalytic cracking"}, "answer": "C", "explanation": "The brewing of beer depends on the action of enzymes. Enzymes are biological catalysts that speed up chemical reactions. In the brewing process, enzymes in yeast convert the sugars in the grain into alcohol and carbon dioxide. The other options do not involve the use of enzymes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>47", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following pollutants is not usually recycled?", "images": [], "options": {"A": "Aluminium cans", "B": "Glass bottles", "C": "Nuclear wastes", "D": "Paper wastes"}, "answer": "C", "explanation": "Nuclear wastes are not usually recycled due to the high level of radioactivity and the potential danger they pose. The process of recycling nuclear waste is complex, expensive, and poses significant health and environmental risks. Therefore, nuclear wastes are typically stored in secure facilities rather than being recycled.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>48", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.", "question": "A metal that is widely used in the manufacture of paints and overhead electric cables is", "images": [], "options": {"A": "aluminium", "B": "Copper", "C": "Iron", "D": "Lead"}, "answer": "A", "explanation": "Aluminium can be used to make paints (due to non-corrosive ability) and for electrical cables (due to its electrical conductivity).", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2012>49", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Brass is a mixture of", "images": [], "options": {"A": "CU and Sn", "B": "Cu and Zn", "C": "CU and Mg", "D": "Cu and Pb"}, "answer": "B", "explanation": "Brass is an alloy made primarily of copper (Cu) and zinc (Zn). The proportions of the copper and zinc can be varied to create a range of brasses with varying properties. It is used for its bright gold-like appearance and its relative resistance to tarnishing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2012>50", "subject": "Chemistry", "year": "2012", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following substances is mainly responsible for the depletion of the ozone layer?", "images": [], "options": {"A": "Oxygen", "B": "Chlorofluorocarbon", "C": "Carbon(II)oxide", "D": "Nitrogen(II)oxide"}, "answer": "B", "explanation": "Chlorofluorocarbons (CFCs) are the main cause of ozone layer depletion. When CFCs are released into the atmosphere, they can reach the stratosphere where they are broken down by solar radiation, releasing chlorine atoms. These chlorine atoms can catalyze the breakdown of ozone into oxygen, depleting the ozone layer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>1", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : MEASUREMENT OF PHYSICAL QUANTITIES.", "question": "Which of the following instruments is used in detecting the presence of radiation?", "images": [], "options": {"A": "Cathode ray tube", "B": "Geiger-Muller counter", "C": "Mass spectrometer", "D": "X-ray tube"}, "answer": "B", "explanation": "A Geiger-Muller counter is an instrument used for detecting and measuring ionizing radiation. It is widely used in applications such as radiation dosimetry, radiological protection, experimental physics, and the nuclear industry. It detects radiation by ionization produced in a low-pressure gas in a Geiger–Müller tube. Each particle detected produces a discrete pulse of current.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>2", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "The molecule which has a linear shape is", "images": [], "options": {"A": "CH4", "B": "NH3", "C": "H2S", "D": "CO2"}, "answer": "D", "explanation": "The molecule CO2 has a linear shape. This is because the carbon atom forms double bonds with the two oxygen atoms, and these bonds are arranged in a straight line.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>3", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The formula of the compound formed between a trivalent metal, M and a divalent non-metal, Y is", "images": [], "options": {"A": "M2Y3", "B": "M3Y2", "C": "MY", "D": "M3Y"}, "answer": "A", "explanation": "The formula of the compound formed between a trivalent metal, M and a divalent non-metal is M2Y3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>4", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "An atom of an element X gains two electrons. The symbol of the ion formed is", "images": [], "options": {"A": "X+", "B": "X2+", "C": "X2-", "D": "X"}, "answer": "C", "explanation": "When an atom gains electrons, it becomes negatively charged. Therefore, if an atom of an element X gains two electrons, it will form an ion with a 2- charge, represented as X2-.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>5", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following statements is correct?", "images": [], "options": {"A": "Atomic size decreases down the group", "B": "Atomic size increases across the period", "C": "Anions are smaller than the parent atom", "D": "Cations are smaller than the parent atom"}, "answer": "D", "explanation": "Atomic size increases down the group (due to the increase in principal quantum number) and decrease across the period (due to increase in effective nuclear charge) and Note from 5 of 2012.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>6", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following arrangement represents the correct order of electronic energy level?", "images": [], "options": {"A": "1s 2p 2s 3p 3s 3d 4s", "B": "1s 2s 2p 3s 3p 3d 4s", "C": "1s 2s 2p 3s 3p 4s 3d", "D": "1s 2s 3s 2p 3p 4s 3d"}, "answer": "C", "explanation": "From Aufbau's principle 1S 2S 2P 3S 3P 4S 3d. Aufbau's Principle is a fundamental concept in quantum chemistry that describes how electrons are added to atomic orbitals in a specific order as the atomic number increases. According to this principle, electrons occupy the lowest-energy orbitals first before filling higher-energy ones.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>7", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "The element with electron configuration 1s2 2s2 2p6 3s2 3p1 belongs to", "images": [], "options": {"A": "s-block, period 3, group 1", "B": "p-block, period 3, group 2.", "C": "s-block, period 3, group 3", "D": "p-block, period 3, group 3"}, "answer": "D", "explanation": "Being in the third energy level means it belongs to period 3, and having 3 outermost electrons means it belongs to Group 3, and having the configuration of ns2 np1-6 is a P - block.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>8", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "In the periodic table, all the elements within the same group have the same.", "images": [], "options": {"A": "number of neutrons", "B": "number of valence electrons", "C": "number of isotopes", "D": "atomic number"}, "answer": "B", "explanation": "In the periodic table, elements in the same group have the same number of valence electrons. Valence electrons are the electrons in the outermost shell of an atom and they determine the chemical properties of an atom. Therefore, elements in the same group have similar chemical properties.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>9", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Which of the following halogens is liquid at room temperature?", "images": [], "options": {"A": "Iodine", "B": "Chlorine", "C": "Bromine", "D": "Fluorine"}, "answer": "C", "explanation": "Bromine is the only halogen that is liquid at room temperature. Halogens are the elements in Group VIIA of the periodic table. They include fluorine, chlorine, bromine, iodine, and astatine. Bromine is unique among the halogens in being a liquid at room temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>10", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "Rare gases are stable because they", "images": [], "options": {"A": "are chemically active", "B": "contain equal number of protons and neutrons", "C": "contain more electrons than protons", "D": "have octet structures"}, "answer": "D", "explanation": "The stability of rare gases and their inertness towards chemical reactions is due to the presence of the complete duplet (in helium) and octet configuration they usually have.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>11", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "In the periodic table , alkaline earth metals can be found in group", "images": [], "options": {"A": "I", "B": "II", "C": "VI", "D": "VII"}, "answer": "B", "explanation": "Group I: alkaline metals  Group II: alkaline Earth metals  Group VII: Halogens  Group VI: Chalcogons Group V: Protogens  Group IV: Carbon family  Group III: Aluminium family", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>12", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "In which of the following series are the atoms arranged in order of increasing ionization energy?", "images": [], "options": {"A": "Li, Na, K", "B": "B, Be, li", "C": "O, F, Ne", "D": "Be, Mg, Ca"}, "answer": "C", "explanation": "Ionization energy decreases down the group and Increases across the period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>13", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Which of the following bond types is responsible for the high boiling point of water?", "images": [], "options": {"A": "Metallic bond", "B": "Covalent bond", "C": "Ionic bond", "D": "Hydrogen bond"}, "answer": "D", "explanation": "The high boiling point of water is due to the hydrogen bonds between the water molecules. Hydrogen bonding is a special type of dipole-dipole attraction between molecules, when a hydrogen atom bonded to a strongly electronegative atom exists in the vicinity of another electronegative atom with a lone pair of electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>14", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "In metallic solid, the forces of attraction is between the mobile valence electrons and the", "images": [], "options": {"A": "atoms", "B": "neutrons", "C": "negative ions", "D": "positively charged nuclei"}, "answer": "D", "explanation": "The metallic bond is been described by an  electron sea model  in which the bond is between the mobile electrons that moves around the center volume of the metal and  the positively charged nuclei", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>15", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "The bonds in crystalline ammonium chloride are", "images": [], "options": {"A": "covalent and dative", "B": "ionic and covalent", "C": "ionic, covalent and dative", "D": "ionic, covalent and hydrogen bond"}, "answer": "C", "explanation": "Ammonium chloride (NH4Cl) is an example of a compound that contains all three types of bonds: ionic, covalent, and dative. The nitrogen and hydrogen atoms form covalent bonds, the nitrogen atom donates a pair of electrons to the hydrogen ion to form a dative bond, and the ammonium ion and chloride ion form an ionic bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>16", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "Which of the following elements is diatomic?", "images": [], "options": {"A": "Sodium", "B": "Oxygen", "C": "Iron", "D": "Neon"}, "answer": "B", "explanation": "Oxygen is a diatomic element. This means that oxygen naturally exists as a molecule containing two oxygen atoms. Other diatomic elements include hydrogen, nitrogen, fluorine, chlorine, iodine, and bromine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>17", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "Noble gas molecules are held together by", "images": [], "options": {"A": "van der waals forces", "B": "Hydrogen bonds", "C": "dative bonds", "D": "covalent bonds"}, "answer": "A", "explanation": "Noble gas molecules are held together by van der Waals forces. These are weak intermolecular forces of attraction that exist between noble gases and other non-polar molecules. They are named after Johannes Diderik van der Waals, the scientist who discovered them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>18", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.", "question": "Which of the following statements about nuclear reaction is correct? The reaction", "images": [], "options": {"A": "involves neutrons only", "B": "takes place inside the nucleus", "C": "is governed by temperature and pressure", "D": "involves protons and electrons only"}, "answer": "B", "explanation": "Nuclear reactions involve changes in the nucleus of an atom, which includes protons and neutrons. Therefore, the statement 'takes place inside the nucleus' is correct. The other options are incorrect because nuclear reactions are not governed by temperature and pressure, and they do not involve only neutrons or only protons and electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>19", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.", "question": "Consider the reaction represented by the following equation:    C2H2 + yH2 → C2H6   The value of y in the reaction is", "images": [], "options": {"A": "4", "B": "3", "C": "2", "D": "1"}, "answer": "C", "explanation": "2 + 2y = 6  2y = 6 - 2  y = 2   The value of y in the reaction is 2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>20", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "The volume of 0.25 moldm-3 solution of KOH that would yield 6.5g of solid KOH on evaporation is   [K = 39.0; O = 16.0; H = 1.00].", "images": [], "options": {"A": "464.30cm3", "B": "625.00cm3", "C": "1000.00cm3", "D": "2153.80cm3"}, "answer": "A", "explanation": "Solubility=n (mol)Volume (dm3)  Volume=nsolubility,n=massmolar mass=6.5(39+1+16)=6.556  =0.116mol,therefore,Volume=0.1160.25=0.4643dm3  0.4643dm3×1000cm31dm3=464.3cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2013>21", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The percentage by mass of Calcium in Ca(OCl)2 is   [Ca = 40.0, Cl = 35.5, O = 16.0]", "images": [], "options": {"A": "28.0%", "B": "31.6%", "C": "43.8%", "D": "44.5%"}, "answer": "A", "explanation": "%massofCa=Mass of CaTotal mass×100=40143×100=27.9%", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>22", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "The gas  law which describes the relationship between volume and temperature is", "images": [], "options": {"A": "Boyle's law", "B": "Charles's law", "C": "Dalton's law", "D": "Graham's law"}, "answer": "B", "explanation": "Charle's law shows the relationship between V and T  Boyle's law shows the relationship between P and V", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>23", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following phenomena leads to decrease in volume and temperature is", "images": [], "options": {"A": "Brownian motion", "B": "Diffusion", "C": "Evaporation", "D": "Sublimation"}, "answer": "C", "explanation": "Evaporation is the process that leads to a decrease in volume and temperature. It is a type of vaporization that occurs on the surface of a liquid as it changes into the gas phase. The energy for evaporation can come from the surroundings, including the air and the liquid itself. As molecules evaporate, they take away energy from the remaining liquid, which decreases its temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>24", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "The pressure exerted by a gas is a function of the", "images": [], "options": {"A": "total volume of the gas", "B": "speed of the gaseous molecules", "C": "mass of each gaseous molecule.", "D": "frequency of collision between gaseous molecules"}, "answer": "D", "explanation": "Frequency of collision of gas molecules and the walls of enclosed container is the determining function of pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>25", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases are arranged in increasing order of diffusion rate?   [H = 1.0, C = 12, N = 14, O = 16, S = 32]", "images": [], "options": {"A": "SO2, O2, NH3, H2", "B": "H2S, NH2, O2, SO2", "C": "CO2, N2O, O2, SO2", "D": "NH3, NO2, N2, CO2"}, "answer": "A", "explanation": "Rateofdiffusionα1&radic;Molar mass&nbsp;  SO2=32+(16x2)=64;Rate=1√64=0.125  O2=16x2=32;rate=1√32=0.18  NH3=14+(1x3)=17;Rate=1√17=0.24  H2=1x2=2;rate=1√2=0.71  increasing order of diffusion rate  = SO2, O2NH3, H2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>26", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following variables is a measure of the average kinetic energy of the molecule of a gas?", "images": [], "options": {"A": "Density", "B": "Pressure", "C": "Temperature", "D": "Volume"}, "answer": "C", "explanation": "FromKineticMoleculartheoryofgases,Temperatureofthegasisameasureoftheaveragekineticenergyofgasmoleculesfromtherelation:K.E=&radic;3RTM&nbsp;", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>27", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "When heat is absorbed during a chemical reaction, the reaction is said to be", "images": [], "options": {"A": "adiabatic", "B": "endothermic", "C": "exothermic", "D": "isothermal"}, "answer": "B", "explanation": "When heat is absorbed during a chemical reaction, the reaction is said to be endothermic. An endothermic process is one that absorbs heat from the surroundings. This is in contrast to an exothermic process, which releases heat to the surroundings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>28", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "The aqueous solution which has pH > 7 is", "images": [], "options": {"A": "FeCl3(aq)", "B": "CuSO4(aq)", "C": "KNO3(aq)", "D": "Na2CO3"}, "answer": "D", "explanation": "Na2CO3 is salt of strong base (NaOH( and a weak acid (H2CO3) so hydrolysis of this salt gives a basic solution which has pH value > 7.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>29", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following acids would readilyreact with CaCO3 to liberate CO2?", "images": [], "options": {"A": "CH3COOH", "B": "H2SO4", "C": "H2SO3", "D": "HNO3"}, "answer": "B", "explanation": "Calcium carbonate (CaCO3) reacts with strong acids to liberate carbon dioxide (CO2). Among the given options, sulfuric acid (H2SO4) is a strong acid and will readily react with CaCO3 to liberate CO2. Therefore, the correct answer is H2SO4.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>30", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following compounds crystallizes without water of crystallization?", "images": [], "options": {"A": "MgSO4", "B": "Na2CO3", "C": "NaCl", "D": "FeSO4"}, "answer": "C", "explanation": "Water of crystallization is the water molecules that are present in the crystal structure of a compound. Sodium chloride (NaCl) is a compound that crystallizes without water of crystallization. Therefore, the correct answer is NaCl.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>31", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CRITERIA FOR PURITY", "question": "A substance is said to be impure if", "images": [], "options": {"A": "its melting point range is wide", "B": "it dissolves in water with difficulty", "C": "it has a low melting point", "D": "it is coloured"}, "answer": "A", "explanation": "Test for Impurity/Purity are (1) The Melting Point must be sharp and definite (II) The Boiling Point must be sharp and definite (III) The density must be definite (IV) The freezing point must be sharp and definite  N.B: Presence of Impurity lowers the boiling point and Freezing point and raises the melting point and widens the temperature range of the pure substance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>32", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "The following factors affect the solubility of a solid in a given solvent except", "images": [], "options": {"A": "nature of solute", "B": "nature of solvent", "C": "pressure", "D": "temperature"}, "answer": "C", "explanation": "The solubility of a solid in a given solvent is affected by the nature of the solute, the nature of the solvent, and the temperature. However, pressure has little to no effect on the solubility of a solid in a liquid. Therefore, the correct answer is 'pressure'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>33", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the reaction represented by the equation:   N2O4(aq) ↔ 2NO2(g); ΔH = +x kjmol-1    What happens when the temperature is reduced at equilibrium?", "images": [], "options": {"A": "Concentration of N2O4(g) decreases", "B": "Concentration of N2O4(g) increases", "C": "Pressure exerted by the gases increase", "D": "Pressure exerted by the gases remains constant"}, "answer": "B", "explanation": "The reaction is endothermic (ΔH is positive), meaning it absorbs heat. According to Le Chatelier's principle, if you decrease the temperature, the equilibrium will shift in the direction that absorbs heat to try and counteract the change. In this case, it will shift to the left, meaning the concentration of N2O4(g) will increase.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2013>34", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following cells produce  electrical energy from the chemical reactions?  I. Lead-acid battery    II. Dry cell    III. Daniell cell    IV. Electrolytic cell", "images": [], "options": {"A": "I and II only", "B": "I, II and III only", "C": "II, III and IV only", "D": "I, III and IV only"}, "answer": "B", "explanation": "Electrochemical cell uses chemical reaction to produce electrical energy while electrolytic cell does the opposite.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>35", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "What happens at the cathode during electrolysis? The", "images": [], "options": {"A": "anion is oxidized", "B": "anion loses electrons", "C": "cation is oxidized", "D": "cation is discharged"}, "answer": "D", "explanation": "During electrolysis, the cathode is the site of reduction, where cations gain electrons. This process is often referred to as 'discharging' the cation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>36", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Which of  the following substances are electrolytes?  I. PbBr2(l)   II. NaCl(aq)   III. NaCl(s)   IV. C6H12O6(aq)", "images": [], "options": {"A": "I and II only", "B": "I, II and IV only", "C": "III and IV only", "D": "I and III only"}, "answer": "A", "explanation": "Electrolytes are substances that produce ions when dissolved in water, allowing the solution to conduct electricity. PbBr2(l) and NaCl(aq) are both electrolytes because they dissociate into ions in solution. NaCl(s) and C6H12O6(aq) do not dissociate into ions and therefore are not electrolytes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>37", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Consider the redox reaction as represented by the following equation:    I2(aq) + 2S2O32- → 2I-(aq) + S4O62-(aq)   Which of the species in the equation is reduced?", "images": [], "options": {"A": "S4O62-(aq)", "B": "S2O32-(aq)", "C": "I2(aq)", "D": "I-(aq)"}, "answer": "C", "explanation": "In a redox reaction, reduction is the gain of electrons. In the given equation, I2(aq) gains electrons to form I-(aq), so I2(aq) is the species that is reduced.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2013>38", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "The separation of petroleum fractions depends on the differences in their", "images": [], "options": {"A": "melting points", "B": "molar masses", "C": "solubilities", "D": "Boiling points"}, "answer": "D", "explanation": "Fractional distillation which is the main process of separation of fuel fraction is on the basis of boiling point differences.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>39", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "The major  product formed by the reaction between ethanoic acid and aqueous sodium hydroxide is", "images": [], "options": {"A": "soap", "B": "sodium ethanoate", "C": "sodium methoxide", "D": "water"}, "answer": "B", "explanation": "The reaction between ethanoic acid and aqueous sodium hydroxide forms sodium ethanoate and water. This is a type of acid-base reaction, where the acid (ethanoic acid) reacts with the base (sodium hydroxide) to form a salt (sodium ethanoate) and water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>40", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following organic compounds would decolourize bromine water?", "images": [], "options": {"A": "Benzene", "B": "Cyclobutane", "C": "Hexane", "D": "Pentane"}, "answer": "A", "explanation": "Benzene undergoes an aromatic Electrophillic substitution instead of addition reaction in order to keep its aromatism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>41", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "How many isomers has C3H6Cl2?", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "B", "explanation": "C3H6Cl2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>42", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP", "question": "The IUPAC name of the compound CH3CH(CH3)CH2CH(NH2)COOH is", "images": [], "options": {"A": "2-amino hexanoic acid", "B": "2-amino-4-methyl pentanoic acid", "C": "2, 4-dimethyl butanoic acid", "D": "4-amino pentanoic acid"}, "answer": "B", "explanation": "The IUPAC name of the compound CH3CH(CH3)CH2CH(NH2)COOH is 2-amino-4-methyl pentanoic acid. In IUPAC nomenclature, the longest carbon chain is identified and numbered such that the functional groups (in this case, the amino and carboxylic acid groups) have the lowest possible numbers. The methyl group is on the second carbon and the amino group is on the fourth carbon, hence the name 2-amino-4-methyl pentanoic acid.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2013>43", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following reactions is common to all hydrocarbons?", "images": [], "options": {"A": "Combustion", "B": "Addition", "C": "Polymerization", "D": "Condensation"}, "answer": "A", "explanation": "All hydrocarbons, regardless of their structure or type, will undergo combustion in the presence of oxygen. Combustion is a chemical reaction that produces heat and light energy, with the products being water and carbon dioxide (in complete combustion). The other reactions listed (addition, polymerization, condensation) are not common to all hydrocarbons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>44", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "A hydrocarbon compound contain 92.3% carbon. Determine its empirical formula. [H = 1.00; C = 12.0]", "images": [], "options": {"A": "CH", "B": "CH2", "C": "CH3", "D": "C2H3"}, "answer": "A", "explanation": "C  : H  92.312:7.71   7.7 : 7.7    7.77.7:7.77.7   1 : 1 (Empirical formula is CH)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>45", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The main function of limestone in the blast furnace is to .", "images": [], "options": {"A": "acts as catalyst", "B": "act a reducing agent", "C": "remove impurity", "D": "supply carbon(IV)oxide"}, "answer": "C", "explanation": "In the blast furnace, limestone (calcium carbonate) is added to the furnace to remove impurities in the iron ore. The limestone decomposes to form calcium oxide and carbon dioxide. The calcium oxide then reacts with the silica (sand) impurities in the ore, forming calcium silicate (slag) which is molten and can be drawn off from the bottom of the furnace.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>46", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Which of the following raw materials is used in a plastic industry?", "images": [], "options": {"A": "Ethene", "B": "Methane", "C": "Calcium", "D": "Hydrogen"}, "answer": "A", "explanation": "Ethene is a raw material used in the plastic industry. It is polymerized to form polyethene, a common plastic material. Methane, calcium, and hydrogen are not typically used as raw materials in the plastic industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>47", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Which of the following statements about thermoplastic materials is correct> They?", "images": [], "options": {"A": "do no melt on heating", "B": "harden on heating", "C": "decompose on heating", "D": "Soften and melt on heating"}, "answer": "D", "explanation": "Thermoplastic materials are a type of polymer that becomes pliable or moldable at a certain elevated temperature and solidifies upon cooling. They soften and melt on heating, which allows them to be reshaped and reused. They do not harden or decompose on heating.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>48", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Bronze is a mixture of", "images": [], "options": {"A": "CU and Mg", "B": "Cu and Sn", "C": "Cu and Zn", "D": "Cu and Pb"}, "answer": "B", "explanation": "Bronze is an alloy consisting primarily of copper, commonly with about 12–12.5% tin and often with the addition of other metals (such as aluminium, manganese, nickel or zinc) and sometimes non-metals or metalloids such as arsenic, phosphorus or silicon. So, the correct answer is Cu and Sn.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2013>49", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following statements about fine chemical is correct? it", "images": [], "options": {"A": "is injurious to health", "B": "has low degree of purity", "C": "is produced in relatively small amount", "D": "can be stored for a long time"}, "answer": "C", "explanation": "Fine chemicals are substances produced in relatively small quantities, through a series of complex, single, and multi-step batch chemical or biotechnological processes. They are described by exacting specifications, used in low volumes, and are high-priced.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2013>50", "subject": "Chemistry", "year": "2013", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following materials is classified as a non-biodegradable pollutant?", "images": [], "options": {"A": "Animal hide", "B": "Paper", "C": "Plastic", "D": "Wood"}, "answer": "C", "explanation": "Plastic is classified as a non-biodegradable pollutant. Non-biodegradable pollutants are substances that do not decompose naturally in the environment. This includes plastics, glass, metals, and many synthetic materials.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>1", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "The shape of CH4 is", "images": [], "options": {"A": "linear", "B": "Planar", "C": "Pyramidal", "D": "tetrahedral"}, "answer": "D", "explanation": "The shape of CH4 (methane) is tetrahedral. This is because carbon has four valence electrons and needs four more to achieve a noble gas configuration. It forms four bonds with four hydrogen atoms, and these bonds are arranged in a tetrahedral shape to minimize electron repulsion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>2", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "The crystal layers in graphite are held together by", "images": [], "options": {"A": "Covalent bond", "B": "Electrostatic forces", "C": "ionic bond", "D": "van der waal's forces"}, "answer": "D", "explanation": "The crystal layers in graphite are held together by van der Waals forces. Van der Waals forces are weak, short range electrostatic attractive forces between uncharged molecules, arising from the interaction of permanent or transient electric dipole moments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>3", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Hydrogen bonds are formed between molecules containing a hydrogen atom bonded to a", "images": [], "options": {"A": "strongly electronegative atom", "B": "non-polar species", "C": "diatomic element", "D": "complex ion"}, "answer": "A", "explanation": "Hydrogen bond is formed between Hydrogen and strong Electronegative atoms such as Fluorine, Oxygen and Nitrogen with a lone pair of electron.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>4", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The two elements 11X and 19Y are in the same group because they have the same.", "images": [], "options": {"A": "Valence electrons", "B": "ionization energy", "C": "number of shell", "D": "atomic size"}, "answer": "A", "explanation": "Elements in the same group of the periodic table have the same number of valence electrons. Valence electrons are the electrons in the outermost shell of an atom that are involved in chemical reactions. The number of valence electrons determines the bonding behavior of an element. Therefore, elements with the same number of valence electrons are grouped together.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>5", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Which of the following processes is used in food preservation in an industry?", "images": [], "options": {"A": "Carbon dating", "B": "Irradiation of gamma rays", "C": "Nuclear fission", "D": "Nuclear fusion"}, "answer": "B", "explanation": "Gamma Irradiation is used to preserve due to high penetration ability which makes it destroy any potential microorganism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>6", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following arrangement is in decreasing order of atomic radius?", "images": [], "options": {"A": "Li > Be > C > B", "B": "Li > B > Be > C", "C": "Li > Be > B > C", "D": "C > B > Be > Li"}, "answer": "C", "explanation": "Atomic size increases down the group (due to the increase in principal quantum number) and decrease across the period (due to increase in effective nuclear charge)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>7", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The electron configuration of 26Fe3+ is", "images": [], "options": {"A": "[Ar]4s23d6", "B": "[Ar]4s23d3", "C": "[Ar]4s13d4", "D": "[Ar]4so3d5"}, "answer": "D", "explanation": "The electron configuration of 26Fe3+ is [Ar]4so3d5. When iron loses three electrons to become Fe3+, it loses them from the 4s orbital first, then from the 3d orbital. This leaves it with 5 electrons in the 3d orbital and none in the 4s orbital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>8", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Which of the following transition metals is not attracted to external field?", "images": [], "options": {"A": "Cu", "B": "Fe", "C": "Ti", "D": "Zn"}, "answer": "D", "explanation": "Zn has a completely filled d-orbital which makes it Diamagnetic instead of paramagnetic like typical transition element.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>9", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "An atom W has 17 electrons and 18 neutrons. Which of the following representations of the atom is correct?", "images": [], "options": {"A": "1718W", "B": "1817W", "C": "3517W", "D": "3518W"}, "answer": "C", "explanation": "mass numberatomic numberW = 3517W    mass number = electros + neutrons = 17 + 18 = 35    electron = 17", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>10", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.", "question": "The relative atomic mass of Chlorine is not a whole number because", "images": [], "options": {"A": "it is the weighed average mass of all its various isotopes", "B": "it is the average mass of all the isotopes of the element", "C": "the element has strong oxidizing ability", "D": "the atom contains a higher number of neutrons than protons"}, "answer": "B", "explanation": "Because the average mass of all the isotopes of chlorine makes up for the relative atomic mass of chlorine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>11", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "NH4+ is formed from NH3 and H+ by", "images": [], "options": {"A": "covalent bonding", "B": "dative bonding", "C": "hydrogen bonding", "D": "ionic bonding"}, "answer": "B", "explanation": "NH4+ is formed from NH3 and H+ by dative bonding. In dative bonding, both electrons in the bond are donated by one atom. In this case, the lone pair of electrons on the nitrogen atom in NH3 is donated to the H+ ion, forming a dative bond and creating the NH4+ ion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>12", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "How many lone pair(s) of electrons is present in HF?", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": "C", "explanation": "In a molecule of HF (hydrogen fluoride), there is one lone pair of electrons. The fluorine atom has seven valence electrons, one of which is shared with hydrogen to form a covalent bond. The remaining six electrons exist as three lone pairs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>13", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "An aqueous solution of Na2CO3 is", "images": [], "options": {"A": "acidic", "B": "alkaline", "C": "amphoteric", "D": "neutral"}, "answer": "B", "explanation": "Hydrolysis of Na2CO3 gives a solution of NaOH + H2CO3 which overall an alkaline solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>14", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "A gaseous mixture contains 0.256g of hydrogen and 2.00g of oxygen. The mole ratio of hydrogen to oxygen in the mixture is  [H = 1.00, O = 16.0]", "images": [], "options": {"A": "1:1", "B": "2:1", "C": "1:4", "D": "8:1"}, "answer": "A", "explanation": "H2\"0.2562=0.128mol  O2:2g16gmol=0.125mol  mole - ratio : 0.128/0.125 ≈ 1 : 1", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>15", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "If 0.20 moldm-3 NaOH(aq) was evaporated to yield 5.0g of solid NaOH. Calculate the volume of NaOH(aq) used.  [Na = 23.0, O = 16.0, H = 1.00]", "images": [], "options": {"A": "600cm3", "B": "625cm3", "C": "1000cm3", "D": "1600cm3"}, "answer": "B", "explanation": "Solubility=Number of molesVolume (dm3)  Volume=Number of molessolubility  Numberofmoles=massmolar mass=5.040=0.125mol  Volume=0.1250.2×1000cm3=625cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2014>16", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of sulphur in Fe2(SO4)3 is", "images": [], "options": {"A": "+2", "B": "+3", "C": "+4", "D": "+6"}, "answer": "D", "explanation": "Fe2(SO4)3    2Fe3+ + 3(S + 402-) = 0    2 x 3 + 3(S - 8) = 0, 6 + 3S - 24 = 0    3S - 18 = 0,    3S = 18, S=+183  S = +6", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>17", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The mass of 800cm3 of a gas Q at s.t.p. is 1.0g. What is the molar mass of Q?  [Avogadro's constant = 22.4dm3 mol-1]", "images": [], "options": {"A": "18.0 gmol-1", "B": "22.4 gmol-1", "C": "28.0 gmol-1", "D": "36.0gmol-1"}, "answer": "C", "explanation": "1g = 800cm3  xg = 22,400cm3  x=22,400800=28g  Molar mass = 28g/mol", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>18", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "A compound U melts at 82oC and boils at 113oC. If U was found to be insoluble in water, a mixture of U in water could best be separated by", "images": [], "options": {"A": "chromatography", "B": "sublimation", "C": "filtration", "D": "the use of separating funnel"}, "answer": "C", "explanation": "A compound that is insoluble in water can be separated from water by filtration. Filtration is a mechanical or physical operation which is used for the separation of solids from fluids (liquids or gases) by interposing a medium through which only the fluid can pass. The fluid that passes through is called the filtrate. In this case, the compound U will be left on the filter paper while the water will pass through, effectively separating the two.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>19", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "The following set-up can be used to demonstrate", "images": ["Chemistry/imgs/2014/chem1.png"], "options": {"A": "diffusion", "B": "dissolution", "C": "evaporation", "D": "sublimation"}, "answer": "A", "explanation": "The set up is used to demonstrate Graham's law of diffusion", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>20", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Which of the following statements about a chemical system in equilibrium is correct? The", "images": [], "options": {"A": "reaction is irreversible", "B": "reaction goes to completion", "C": "equilibrium is re-established when a stress is applied", "D": "equilibrium position is affected by catalyst"}, "answer": "C", "explanation": "In a chemical system in equilibrium, if a stress is applied (like a change in concentration, temperature, or pressure), the system adjusts itself to minimize the effect of the stress and re-establish equilibrium. This is known as Le Chatelier's Principle. Therefore, the correct answer is 'equilibrium is re-established when a stress is applied'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>21", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "Which of the following relationship correctly expresses the Boyle's as?", "images": [], "options": {"A": "P ∝ V at constant T", "B": "V ∝ T at constant P", "C": "P ∝1/V at constant T", "D": "V ∝ 1/T at constant P"}, "answer": "C", "explanation": "Boyle's law, named after physicist Robert Boyle, states that at constant temperature, the pressure and volume of a gas have an inverse relationship. When one increases, the other decreases. Hence, the correct relationship is 'P ∝1/V at constant T'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>22", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "The vapour pressure of a given volume of liquid increases when the", "images": [], "options": {"A": "liquid becomes saturated with a salt", "B": "volume of the liquid increases", "C": "temperature of the liquid falls.", "D": "temperature of the liquid rises"}, "answer": "D", "explanation": "Vapour pressure as the temperature rises because it increases the average kinetic molecular energy of individual gas molecule therefore increasing the frequency of collision.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>23", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "Which of the following statements about volatile liquids is correct? They have", "images": [], "options": {"A": "high vapour pressure and low boiling point", "B": "high vapour pressure and high boiling point", "C": "low vapour pressure and low boiling point", "D": "low vapour pressure and high boiling point"}, "answer": "A", "explanation": "Volatile liquids are those that evaporate readily at normal temperatures and pressures. This is due to their high vapour pressure, which is a measure of the tendency of a substance to transition into the gaseous phase. As a result, volatile liquids also have a low boiling point, because boiling point is the temperature at which the vapour pressure of a liquid equals the external pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>24", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "The type of energy changes that  accompany the mixing of a strong acid to a strong base is", "images": [], "options": {"A": "electrical", "B": "heat", "C": "light", "D": "sound"}, "answer": "B", "explanation": "When a strong acid reacts with a strong base, the reaction is exothermic, meaning it releases heat. This is because the formation of water from the hydrogen ions of the acid and the hydroxide ions of the base releases energy. The other options (electrical, light, sound) are not typically associated with this type of reaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>25", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Zinc oxide is said to be amphoteric because it", "images": [], "options": {"A": "forms an acid salt", "B": "is an insoluble base", "C": "forms a double salt", "D": "reacts with a base or an acid"}, "answer": "D", "explanation": "An amphoteric substance is one that can react as both an acid and a base. Zinc oxide is amphoteric because it can react with both acids and bases. When it reacts with an acid, it behaves like a base, and when it reacts with a base, it behaves like an acid. The other options do not accurately describe the amphoteric nature of zinc oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>26", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Which of the following substances with the corresponding pH value is our alkali?", "images": [], "options": {"A": "Lime  2.4", "B": "Banana  4.6", "C": "Distilled water  7.0", "D": "Milk of magnesia   10.5"}, "answer": "D", "explanation": "An alkali is a substance that has a pH greater than 7. The pH scale ranges from 0 to 14, with 7 being neutral. Substances with a pH less than 7 are acids, while those with a pH greater than 7 are bases (alkalis). Among the given options, 'Milk of magnesia' has a pH of 10.5, which is greater than 7, hence it is an alkali.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>27", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The gases produced when Cu(NO3)2(s) was heated are", "images": [], "options": {"A": "NO and NO2", "B": "O2 and NO2", "C": "O2 and NO", "D": "NO2 and N2O4"}, "answer": "B", "explanation": "The gases produced when Cu(NO3)2(s) was heated are    Cu(NO3)2 → CuO + NO2 + O2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>28", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following salts on hydrolysis would give an alkaline solution?", "images": [], "options": {"A": "NH4Cl(s)", "B": "AlCl3(s)", "C": "CH3COONa(s)", "D": "NH4NO3(s)"}, "answer": "C", "explanation": "Hydrolysis of a salt is a reaction with water. In this reaction, water molecules cause a salt to split into its constituent ions. If the salt is derived from a strong base and a weak acid, the solution will be alkaline due to the presence of the basic ion. Sodium acetate (CH3COONa) is a salt of a strong base (NaOH) and a weak acid (CH3COOH), so its hydrolysis results in an alkaline solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>29", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Consider the reaction represented by the following equation:    Na2CO3(aq) + 2HCl(aq)⇒ 2NaCl(aq) + H2O(l) + CO2(g)    What volume of 0.02 mol dm-3 Na2CO3(aq) would be required to completely neutralize 40cm3 of 0.10mol dm-3 HCl(aq)?", "images": [], "options": {"A": "200cm3", "B": "100cm3", "C": "40cm3", "D": "20cm3"}, "answer": "B", "explanation": "FromCaVaCBVB=nanB  40 × 0.10VB × 0.02=21  VB=40 × 0.102 × 0.02=100cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2014>30", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "In which of the following experimental set-ups would be rate of evolution of hydrogen gas be fastest?", "images": ["Chemistry/imgs/2014/chem2.png", "Chemistry/imgs/2014/chem3.png", "Chemistry/imgs/2014/chem4.png", "Chemistry/imgs/2014/chem5.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "An higher surface Area increases the rate of chemical reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>31", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Which of the following factors would affect the equilibrium constant?", "images": [], "options": {"A": "Concentration", "B": "Temperature", "C": "Pressure", "D": "Volume"}, "answer": "B", "explanation": "The equilibrium constant (K) of a reaction is only affected by temperature. This is because the equilibrium constant is directly related to the change in Gibbs free energy (ΔG) for the reaction, which is a function of temperature. Changes in concentration, pressure, or volume do not affect the equilibrium constant, although they can shift the position of equilibrium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>32", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Consider the following energy profile diagram of exothermic reaction:     The enthalpy change, ΔH is", "images": ["Chemistry/imgs/2014/chem6.png"], "options": {"A": "120kJ mol-1", "B": "80kJmol-1", "C": "-60kJmol-1", "D": "40kjmol-1"}, "answer": "C", "explanation": "ΔHreaction = ΔHproducts - ΔHreactants = 20 - 80 = -60KJmol-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>33", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the reaction represented by the following equations:   N2(g) + 3H2(g) ↔2NH3(g); ΔHθ = -X kJ mol-1   Which of the following conditions would increase the yield of NH3?", "images": [], "options": {"A": "Addition of iron catalyst", "B": "Increase in the temperature of the system", "C": "Increase in the volume occupied by reactants", "D": "Increase in the total pressure of the system."}, "answer": "D", "explanation": "Increasing the pressure affects only gaseous species in chemical reaction and makes the reaction proceed to the side with the lowest number of gaseous molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>34", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What is the function of manganese(IV)oxide in the reaction represented by the following equation?   MnO2 + 4HCl → MnCl2 + 2H2O + Cl(2)", "images": [], "options": {"A": "Catalyst", "B": "Dehydrating agent", "C": "Oxidizing agent", "D": "Reducing agent"}, "answer": "C", "explanation": "MnO2 is the oxidizing agent as it is reduced to MnCl2. Manganese experiences a reduction in oxidation number from +4 in MnO2 to +2 in MnCl2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>35", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The reaction that occurs at the anode when CuSO4(aq) is electrolyzed using carbon electrodes is", "images": [], "options": {"A": "2H+(aq) + 2e → H2(g)", "B": "Cu2+(aq) + 2e → Cu(s)", "C": "4OH(aq) - 4e → 2H2O(l) + O2(g)", "D": "SO42(aq) - 2e → SO2(g) + O2(g)"}, "answer": "C", "explanation": "From the factors that affects the preferential discharge of ions, the relative placement of the ions in the electrochemical series greatly affects the discharge of ions and the rule is the ions low or bottom of the Activity series will be discharged first.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>36", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Reduction is the process of", "images": [], "options": {"A": "loss of electron", "B": "loss of hydrogen", "C": "loss of oxygen", "D": "addition of electro magnetic elements"}, "answer": "C", "explanation": "Reduction is the loss of electronegative elements and oxygen an electronegative element. Reduction means loss of oxygen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>37", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Ethene molecules can be added to one another to form a long chain compound called a", "images": [], "options": {"A": "dimer", "B": "Monomer", "C": "Polymer", "D": "Trimer"}, "answer": "C", "explanation": "Ethene molecules can be added to one another to form a long chain compound called a polymer. This process is known as polymerization. A polymer is a large molecule, or macromolecule, composed of many repeated subunits, known as monomers. Therefore, the correct answer is 'Polymer'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>38", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Which of the following compounds determines the octane rating of petrol?", "images": [], "options": {"A": "1, 2, 3 - trimethyl pentane", "B": "2, 3, 5 - trimethyl octane", "C": "2, 3, 5 - trimethyl pentane", "D": "2, 2, 4 - trimethyl pentane"}, "answer": "D", "explanation": "The octane rating of petrol is determined by the compound 2, 2, 4 - trimethyl pentane. The octane rating is a standard measure of the performance of an engine or aviation gasoline. The higher the octane number, the more compression the fuel can withstand before detonating. In broad terms, fuels with a higher octane rating are used in high-performance gasoline engines that require higher compression ratios. Therefore, the correct answer is '2, 2, 4 - trimethyl pentane'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>39", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Which type of reaction is illustrated by the following equation?   C12H26 → 5C2H4 + C2H6?", "images": [], "options": {"A": "Addition", "B": "Cracking", "C": "Hydrogenation", "D": "Polymerization"}, "answer": "B", "explanation": "This is the process that involves the thermal or catalytic break down of a very large molecule of hydrocarbon to form other useful simpler fractions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>40", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "The IUPAC name of the following organic compound is HOOC - COOH", "images": [], "options": {"A": "ethan - 1, 2 - dioic acid", "B": "ethanoic acid", "C": "oxalic acid", "D": "Propan - 1, 2 - dioic acid"}, "answer": "A", "explanation": "The IUPAC name of the following organic compound   HOOC - COOH is ethan - 1, 2 - dioic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>41", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : AMINO ACIDS", "question": "The enzyme that catalyses the conversion of glucose to ethanol and carbon(IV)oxide is", "images": [], "options": {"A": "diatase", "B": "maltase", "C": "ptyalin", "D": "zymase"}, "answer": "D", "explanation": "The enzyme that catalyses the conversion of glucose to ethanol and carbon(IV)oxide is 'zymase'. This process is part of fermentation, where zymase, found in yeast, breaks down glucose into ethanol and carbon dioxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>42", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "A colourless hydrocarbon with a sweet smell undergoes substitution reaction. The hydrocarbon is likely to be", "images": [], "options": {"A": "alkanol", "B": "benzene", "C": "ester", "D": "methane"}, "answer": "C", "explanation": "Only ester has a sweet-smells. Esters are well-known for their sweet, fruity smells. They are often responsible for the pleasant aromas in fruits and flowers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>43", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "Consider the reaction represented by the following equation    C2H4(g) + 3O2(g) → 2CO2(g) + 2H2O(g)    How many moles of ethene would be burnt to produce 0.1 mole of water?", "images": [], "options": {"A": "0.05 mole", "B": "0.10 mole", "C": "0.20mole", "D": "2.00 moles"}, "answer": "A", "explanation": "1 mole of C2H4 ≡ 2 mol of H2O  x mole ≡ 0.1mol of H2O  x=0.12=0.05molofC2H4", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>44", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "The liquid hydrocarbon likely to be found in the fraction of crude oil used for domestic cooking is .", "images": [], "options": {"A": "C3H8", "B": "C5H12", "C": "C13H28", "D": "C20H42"}, "answer": "B", "explanation": "C5 - C10 : liquids  C1 - C4 : gases  > C11 are solids", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2014>45", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "Which of the following organic compounds could be represented by the empirical formula CH2O?", "images": [], "options": {"A": "Ethanal", "B": "Ethane", "C": "Ethanol", "D": "Ethanoic acid"}, "answer": "A", "explanation": "CH2O →    (Aldehyde Functional group) could be represented by the empirical formula CH2O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>46", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "The production of biogas from the fermentation of waste  materials is an example of", "images": [], "options": {"A": "combustion", "B": "incineration", "C": "refining", "D": "recycling"}, "answer": "D", "explanation": "Biogas production from the fermentation of waste materials is an example of recycling. This is because the waste materials are being reused to produce a useful product (biogas), rather than being discarded. This process reduces the amount of waste that goes to landfill and also provides a renewable source of energy. Hence, the correct answer is option 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>47", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CRITERIA FOR PURITY", "question": "The purity of a solid  sample can best be determined by its", "images": [], "options": {"A": "Boiling point", "B": "Melting point", "C": "Conductivity", "D": "Solubility"}, "answer": "B", "explanation": "The purity of a solid sample can best be determined by its melting point. Pure substances have a sharp, well-defined melting point, while impure substances melt over a range of temperatures. This is because impurities disrupt the regular arrangement of particles in the solid, allowing it to start melting at a lower temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>48", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "Which of the following gases is used to retard the vapourization of the filament in a light bulb?", "images": [], "options": {"A": "Argon", "B": "Helium", "C": "Hydrogen", "D": "Oxygen"}, "answer": "A", "explanation": "Argon gas is used to retard the vaporization of the filament in a light bulb. The filament in a light bulb is typically made of tungsten, which has a very high melting point. However, when the filament is heated to produce light, it also produces a lot of heat, which can cause the tungsten to vaporize. Argon is an inert gas, which means it does not react with the tungsten filament. This helps to prevent the filament from vaporizing and extends the life of the bulb.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>49", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The most common process in the extraction of metals from their ore is", "images": [], "options": {"A": "Catalysis", "B": "Electrolysis", "C": "Oxidation", "D": "Reduction"}, "answer": "D", "explanation": "Most metals are extracted from their ores through REDUCTION which can now be Catalytic, Electrolytic and Thermal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2014>50", "subject": "Chemistry", "year": "2014", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "The oxide from electric power station is", "images": [], "options": {"A": "carbon(IV)oxide", "B": "copper(II)oxide", "C": "nitrogen(IV)oxide", "D": "sulphur (IV)oxide"}, "answer": "D", "explanation": "The oxide from electric power stations is sulphur (IV) oxide. This is because the burning of fossil fuels, such as coal, in power stations releases sulphur dioxide (SO2) into the atmosphere. This sulphur dioxide is a type of sulphur (IV) oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>1", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "The negatively charged particle in an atom is the", "images": [], "options": {"A": "electron", "B": "neutron", "C": "positron", "D": "proton"}, "answer": "A", "explanation": "Electron are the negatively charged particle in atom. Neutron are uncharged, while Proton are positively charged.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2015>2", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "How many orbitals are contained in an atom with atomic number 13?", "images": [], "options": {"A": "7", "B": "5", "C": "3", "D": "4"}, "answer": "A", "explanation": "An atom with atomic number 13 has 7 orbitals. The atomic number of an atom is equal to the number of protons in its nucleus. In a neutral atom, the number of protons is also equal to the number of electrons. The distribution of these electrons into various orbitals of an atom is done based on the energy levels and the Pauli exclusion principle, which states that each orbital can hold a maximum of two electrons. For an atom with atomic number 13, the electron configuration would be 1s2 2s2 2p6(2px,2py,2pz) 3s2 3p1. This gives a total of 7 orbitals", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>3", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "The compound formed between 14X and 16Y is", "images": [], "options": {"A": "XY", "B": "XY2", "C": "X2Y", "D": "X4Y6"}, "answer": "B", "explanation": "The compound formed between 14X and 16Y is  → XY2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>4", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "The Van der Waals' forces are dominant intermolecular forces in", "images": [], "options": {"A": "Ammonium Chloride", "B": "Chlorine", "C": "Sodium chloride", "D": "Water"}, "answer": "B", "explanation": "The Van der Waals' forces are dominant intermolecular forces in Chlorine. Van der Waals' forces are weak, short range electrostatic attractive forces between uncharged molecules, arising from the interaction of permanent or transient electric dipole moments. Chlorine, being a non-polar molecule, primarily interacts with other molecules through these weak Van der Waals' forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>5", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "The shape of a molecule of water is", "images": [], "options": {"A": "non-linear", "B": "octahedral", "C": "pyramidal", "D": "tetrahedral"}, "answer": "A", "explanation": "Water (H2O) has tetrahedral arrangement but the presence of two lone pairs of electrons gives it a V-shape.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2015>6", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "A metallic ion Z2+ with an inert gas structure contains 18 electrons. How many protons are contained in this ion?", "images": [], "options": {"A": "20", "B": "18", "C": "16", "D": "2"}, "answer": "A", "explanation": "The metallic ion Z2+ has lost 2 electrons to achieve an inert gas structure with 18 electrons. Since the number of protons in an atom is equal to the number of electrons in a neutral atom, the original atom must have had 20 protons. Therefore, the ion still contains 20 protons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>7", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "Which of the following pairs of compounds belongs to the same homologous series?", "images": [], "options": {"A": "C3H8 and C3H6", "B": "C4H10 and C5H10", "C": "C2H4 and C4H10", "D": "C2H6 and C4H10"}, "answer": "D", "explanation": "Homologous series differs by a -CH2 group. A homologous series is a group of organic compounds that share a common functional group and have similar chemical properties, but differ from each other by a -CH₂", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>8", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following pairs of elements forms amphoteric oxides?", "images": [], "options": {"A": "Be and Mg", "B": "Na and K", "C": "B and Al", "D": "Si and Pb"}, "answer": "C", "explanation": "Amphoteric oxides are oxides that can act as both acids and bases. Beryllium (Be) and Aluminum (Al) are known to form amphoteric oxides.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>9", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "The following transition metal ions would be coloured in aqueous solution except", "images": [], "options": {"A": "Cr3+", "B": "Fe3+", "C": "Mn3+", "D": "Sc3+"}, "answer": "D", "explanation": "Transition metal ions are often colored in aqueous solution due to d-d transitions. However, Sc3+ does not have any d electrons to undergo d-d transitions, so it is colorless in aqueous solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>10", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The gas given off when ethanol reacts with Sodium is", "images": [], "options": {"A": "Carbon(IV) Oxide", "B": "Hydrogen", "C": "Methane", "D": "Oxygen"}, "answer": "B", "explanation": "When ethanol reacts with Sodium, it produces Sodium ethoxide and Hydrogen gas. Therefore, the gas given off is Hydrogen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>11", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following halogens is solid at room temperature?", "images": [], "options": {"A": "Bromine", "B": "Chlorine", "C": "Flourine", "D": "Iodine"}, "answer": "D", "explanation": "Iodine is a halogen that is solid at room temperature. Halogens are elements in group 17 of the periodic table. They exist in all three states of matter at room temperature: Fluorine and Chlorine are gases, Bromine is a liquid, and Iodine is a solid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2015>12", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "The alkaline earth metals have similar chemical properties because", "images": [], "options": {"A": "they are in the same period", "B": "their salts are colourless", "C": "they have same number of valence electrons", "D": "they are very reactive"}, "answer": "C", "explanation": "Alkaline earth metals have similar chemical properties because they have the same number of valence electrons. Alkaline earth metals are in group 2 of the periodic table and they all have two valence electrons. The chemical properties of an element are largely determined by the number of valence electrons it has.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>13", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The number of unpaired electrons in an atom of an element 8Q is", "images": [], "options": {"A": "2", "B": "4", "C": "6", "D": "8"}, "answer": "A", "explanation": "8Q - 1s2, 2s2, 2p4 :    ∴ 2 unpaired", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2015>14", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "The bond formed when ammonia reacts with hydrogen ion to form ammonium ion is", "images": [], "options": {"A": "covalent", "B": "dative", "C": "hydrogen bond", "D": "ionic"}, "answer": "B", "explanation": "The bond formed when ammonia reacts with hydrogen ion to form ammonium ion is a dative bond. A dative bond, also known as a coordinate covalent bond, is a type of covalent bond where the shared pair of electrons comes from only one of the atoms involved in the bonding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>15", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "To which group and period respectively does an element with 15 electrons belong?", "images": [], "options": {"A": "3 and 3", "B": "3 and 5", "C": "5 and 3", "D": "5 and 5"}, "answer": "C", "explanation": "1s2 2s2 2p6 3s2 3p3 belongs to period 3 and group V.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>16", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "The shape of a graphite crystal is", "images": [], "options": {"A": "tetrahedral", "B": "pyramidal", "C": "octahedral", "D": "hexagonal"}, "answer": "D", "explanation": "Graphite has only an hexagonal crystal structure with intermolecular force of Van der Waal in its crystal lattice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>17", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following oxides is ionic?", "images": [], "options": {"A": "P4O10", "B": "MgO", "C": "Al2O3", "D": "SO2"}, "answer": "B", "explanation": "Ionic compounds are formed from a metal and a non-metal. Among the given options, MgO (Magnesium Oxide) is the only compound formed from a metal (Magnesium) and a non-metal (Oxygen), hence it is the ionic oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>18", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS~~BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "Which of the following substances when boiled with aqueous solution of sodium hydroxide would be hydrolysed?  I. Protein    II. Fat   III. Polythene", "images": [], "options": {"A": "I", "B": "II", "C": "I and II", "D": "II and III"}, "answer": "D", "explanation": "Fats and Polythene when boiled with solution of NaOH would be hydrolysed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>19", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Which of the following trioxonitrate(V) salts would decompose on heating to form a metal?", "images": [], "options": {"A": "CU(NO3)2", "B": "AgNO3", "C": "Pb(NO3)2", "D": "KNO3"}, "answer": "B", "explanation": "Upon heating, Silver Nitrate (AgNO3) decomposes to form a metal (Silver). The reaction is as follows: 2AgNO3(s) → 2Ag(s) + O2(g) + 2NO2(g). Hence, AgNO3 is the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2015>20", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Consider the following reaction equation:    C2H4(g) + 3O2(g) → 2CO2(g)+ 2H2Og   The volume of CO2(g) produced at s.t.p when 0.05 moles of C2H4(g) was burnt in O2(g) is    [molar volume of gas = 22.4dm3]", "images": [], "options": {"A": "1.12dm3", "B": "2.24dm3", "C": "3.72dm3", "D": "4.48dm3"}, "answer": "B", "explanation": "1 mole of C2H4 ≡ 2 mol of CO2  0.05mol of C2H4 ≡ 0.1 mol of CO2  Therefore,0.1molofCO2×22.4dm31mol=2.24dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>21", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The number of oxygen molecules present in 16.0g of the gas is [Avogadro's number = 6.02 x 1023]", "images": [], "options": {"A": "6.02 x 1022", "B": "6.02 x 1023", "C": "3.01 x 1023", "D": "1.51 x 1023"}, "answer": "C", "explanation": "1 mole of O2 (32g) = 6.02 × 1023 molecules  16g ≡ x molecules   x=1632×6.02×1023=3.01×1023molecules", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>22", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Consider the following reaction equation:    SO4(aq)2- + 2H+aq + ye- → SO32-(aq) + H2O(l)    The value of y in the equation is", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "6"}, "answer": "A", "explanation": "-2 + 2 + y(-1) = -2  0 - y = -2  y = +2  The value of y in the equation is +2", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2015>23", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "The general gas equation was derived from", "images": [], "options": {"A": "Boyle's and Gay Lussac's laws", "B": "Boyle's and Graham's laws", "C": "Boyle's and Charles' laws", "D": "Dalton's atomic theory"}, "answer": "C", "explanation": "The general gas equation (PV = nRT) was derived from Boyle's Law (at constant temperature, the volume of a given mass of a gas is inversely proportional to its pressure) and Charles' Law (at constant pressure, the volume of a given mass of a gas is directly proportional to its absolute temperature). Therefore, the correct answer is Boyle's and Charles' laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>24", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "The vapour pressure of a liquid depends on   I. Temperature   II. Rate of condensation   III. Cohesive forces holding the particles together", "images": [], "options": {"A": "I", "B": "I and II", "C": "I and III", "D": "II and III"}, "answer": "C", "explanation": "Vapour pressure depends on temperature and the intermolecular forces holding the individual atoms together", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>25", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases will diffuse most rapidly?   [H = 1.00, C = 12.0, O = 16.0, S = 32.0, Cl = 35.5]", "images": [], "options": {"A": "Cl2", "B": "SO2", "C": "CH4", "D": "C2H6"}, "answer": "C", "explanation": "The rate of diffusion of a gas is inversely proportional to the square root of its molar mass. Therefore, the gas with the lowest molar mass will diffuse most rapidly. The molar masses of Cl2, SO2, CH4, and C2H6 are approximately 71, 64, 16, and 30 respectively. Therefore, CH4, which has the lowest molar mass, will diffuse most rapidly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>26", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "When a reaction is endothermic", "images": [], "options": {"A": "enthalpy change, ΔH is negative", "B": "heat content of product is less than the heat content of reactant", "C": "heat content of  reactants is less than the heat content of product", "D": "the reaction is non-spontaneous"}, "answer": "C", "explanation": "In an endothermic reaction, energy is absorbed from the surroundings. This means that the heat content (or enthalpy) of the products is greater than the heat content of the reactants. Therefore, the correct answer is 'heat content of reactants is less than the heat content of product'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>27", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following statements about intermolecular distances and cohesive forces between gas is correct? They are", "images": [], "options": {"A": "both large", "B": "both negligible", "C": "constant and negligible", "D": "large and negligible"}, "answer": "D", "explanation": "Based on Kinetic Molecular Theory of Gases, the intermolecular distance between gas molecules are large and no attractive force is in existence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>28", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The following diagram illustrates the rate curve that was obtained when Mg reacted with excess dilute HCl.    The diagram became horizontal at X because", "images": ["Chemistry/imgs/2015/chem1.png"], "options": {"A": "the reaction was slowed down", "B": "all the dilute HCl has reacted", "C": "all the Mg has reacted", "D": "Hydrogen gas is produced at a steady rate"}, "answer": "B", "explanation": "It means that the reaction has gone into completion i.e all the specified reactant has reacted.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2015>29", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "An example of an acid salt is", "images": [], "options": {"A": "CH3COOONa", "B": "Mg(OH)Cl", "C": "NaHSO4", "D": "(NH4)2SO4"}, "answer": "C", "explanation": "An acidic salt are formed when the replaceable hydrogen ions in the acid are only partially replaced by a metal", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>30", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following oxides can be reduced by hydrogen?", "images": [], "options": {"A": "Aluminium oxide", "B": "Magnesium Oxide", "C": "Sodium oxide", "D": "Silver oxide"}, "answer": "D", "explanation": "Silver oxide can be reduced by hydrogen. The reaction is 2Ag2O + H2 -> 4Ag + H2O. This means that silver oxide reacts with hydrogen to form silver and water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>31", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : PRACTICAL APPLICATION OF SOLUBILITY", "question": "Solubility is practically applied in", "images": [], "options": {"A": "fractional distillation", "B": "the determination of pH", "C": "the determination of saturation in hydrocarbons", "D": "solvent extraction"}, "answer": "D", "explanation": "Solubility is practically applied in solvent extraction. Solvent extraction is a method to separate a compound into its parts based on the solubility of its parts. It's a method used in laboratories to purify or concentrate a substance or remove impurities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>32", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following compounds is the least soluble in water?", "images": [], "options": {"A": "CaCl2", "B": "CaSO4", "C": "NaCl", "D": "Na2SO4"}, "answer": "B", "explanation": "CaSO4, also known as Calcium sulfate, is the least soluble in water among the given options. This is due to its strong ionic bonds which require more energy to break than the hydration energy released when the ions interact with water molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>33", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "A substance which dissolves readily in organic solvent would", "images": [], "options": {"A": "be a covalent compound", "B": "have strong electrostatic forces of attraction", "C": "have a high melting point", "D": "conduct electricity in molten state."}, "answer": "A", "explanation": "Only covalent compound dissolves in organic solvent as a result of the solubility rule: \" Like dissolves Like\".", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2015>34", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the following equilibrium system:    2SO2(g) + O2(g) ⇔ 2SO3(g)   The addition of more O2(g) to the system will shift the equilibrium position to the   .", "images": [], "options": {"A": "right leading to the production of more SO3(g)", "B": "right leading to the production of more SO2(g)", "C": "left leading to the production of more SO2(g)", "D": "left leading to the production of more SO3(g)"}, "answer": "A", "explanation": "According to Le Chatelier's principle, if a dynamic equilibrium is disturbed by changing the conditions, the position of equilibrium moves to counteract the change. In this case, adding more O2(g) would disturb the equilibrium, causing it to shift to the right to consume the excess O2(g), leading to the production of more SO3(g).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>35", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "A change in the temperature of a saturated solution disturbs the equilibrium between the", "images": [], "options": {"A": "undissolved solute and the solvent", "B": "dissolved solute and the solvent", "C": "dissolved solute and the undissolved solute", "D": "dissolved solute and the solution"}, "answer": "C", "explanation": "A change in temperature of a saturated solution disturbs the equilibrium between the dissolved solute and the undissolved solute. In a saturated solution, the process of dissolution and crystallization of solute occur at the same rate, creating an equilibrium. If the temperature changes, it can affect the solubility of the solute, thus disturbing this equilibrium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>36", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following statements about an electrochemical cell is correct? Oxidation occurs.", "images": [], "options": {"A": "at the anode", "B": "at the cathode", "C": "through the salt bridge", "D": "in the aqueous solution"}, "answer": "A", "explanation": "Oxidation occurs at the anode   Reduction occurs at the cathode  ∴ Same for both Electrochemical cell and Electrolytic cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>37", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Consider the following reaction equation:    CuO(s) + H2(g) → Cu(s) + H2O(l)    Which substance is oxidized?", "images": [], "options": {"A": "Cu", "B": "CuO", "C": "H2", "D": "H2O"}, "answer": "C", "explanation": "In the given reaction, H2(g) is oxidized. Oxidation is a process that involves the loss of electrons. In this reaction, hydrogen (H2) loses electrons to become water (H2O), while copper oxide (CuO) gains electrons to become copper (Cu). Therefore, H2 is the substance that is oxidized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>38", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Which of the following metals is the strongest reducing agent?", "images": [], "options": {"A": "Sodium", "B": "Silver", "C": "Potassium", "D": "Copper"}, "answer": "C", "explanation": "The strength of a reducing agent is determined by its ability to lose electrons. Among the given options, Potassium is the strongest reducing agent because it has the highest tendency to lose electrons. This is due to its position in the periodic table, where it is located in the first group (alkali metals) which are known for their high reactivity and strong reducing properties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>39", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : BENZENE", "question": "The complete hydrogenation of benzene gives", "images": [], "options": {"A": "cyclohexene", "B": "cyclohexane", "C": "hexene", "D": "hexane"}, "answer": "B", "explanation": "Hydrogenation is a chemical reaction between molecular hydrogen (H2) and another compound or element, usually in the presence of a catalyst. The process of hydrogenation involves the addition of hydrogen (H2). When benzene undergoes complete hydrogenation, it becomes cyclohexane. This is because the benzene ring is fully saturated with hydrogen atoms, converting the ring structure into a cyclohexane structure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>40", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "A compound has an empirical formula CH2O and molecular mass of 90.  [ H = 1.00, C = 12.0, O = 16.0]", "images": [], "options": {"A": "C4H10O2", "B": "C3H10O2", "C": "C3H6O3", "D": "C2H2O4"}, "answer": "C", "explanation": "n[CH2O] = 90  n(12 + 2 + 16) = 90  30n = 90  n = 3  Therefore, 3[CH2O]  C3H6O3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2015>41", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Which of the following reactions would take place when concentrated Sodium Hydroxide solution is added to hot palm oil?", "images": [], "options": {"A": "Esterification", "B": "Neutralization", "C": "Polymerization", "D": "Saponification"}, "answer": "D", "explanation": "When concentrated Sodium Hydroxide solution is added to hot palm oil, a process called saponification occurs. Saponification is a process that involves the conversion of fat, oil, or lipid, into soap and alcohol by the action of heat in the presence of aqueous alkali (e.g. NaOH). Soaps are sodium or potassium salts of long chain fatty acids. When triglycerides in fat/oil react with aqueous NaOH or KOH, they are converted into soap and glycerol. This is called alkaline hydrolysis of esters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>42", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Starch could be converted to glucose by the process of", "images": [], "options": {"A": "condensation", "B": "dehydration", "C": "fermentation", "D": "hydrolysis"}, "answer": "D", "explanation": "Starch can be converted to glucose by the process of hydrolysis. Hydrolysis is a reaction involving the breaking of a bond in a molecule using water. The reaction generally leads to the formation of a smaller molecule. In the case of starch, it is a large molecule made up of many glucose units. When hydrolyzed, these glucose units are broken down into individual glucose molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>43", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following compounds is a secondary alkanol?", "images": [], "options": {"A": "Ethanol", "B": "2-methylbutan-2-ol", "C": "3-methylpentan-2-ol", "D": "Propan-1-ol"}, "answer": "C", "explanation": "A secondary alkanol is an alcohol where the carbon atom of the hydroxyl group is attached to two other carbon atoms. In the given options, 3-methylpentan-2-ol is a secondary alkanol because the hydroxyl group is attached to a carbon atom that is connected to two other carbon atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>44", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following substances is a heavy chemical?", "images": [], "options": {"A": "Ammonia", "B": "Barium hydroxide", "C": "Hydrochloric acid", "D": "Tetraoxosulphate(VI)acid"}, "answer": "D", "explanation": "Heavy chemical has low degree of purity and it is produced in large quantities e.g H2SO4, CaO etc", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2015>45", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following process does not take place in domestic water treatment?", "images": [], "options": {"A": "Chlorination", "B": "Flocculation", "C": "Neutralization", "D": "Sedimentation"}, "answer": "C", "explanation": "Neutralization is not a process that takes place in domestic water treatment. Neutralization is a chemical reaction in which an acid and a base react quantitatively with each other. In water treatment, the processes that take place include coagulation, sedimentation, filtration, and disinfection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>46", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Which of the following products of biotechnology can be used as a fuel in place of petrol?", "images": [], "options": {"A": "Butane", "B": "Ethanol", "C": "Ethene", "D": "Propanol"}, "answer": "A", "explanation": "Butane can also be used as fuel. Butane is a major component of liquefied petroleum gas (LPG), which is a mixture of propane and butane. LPG is widely used for cooking, heating, and as fuel for vehicles in many countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>47", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Which of the following products of biotechnology can be used as a fuel in place of petrol?", "images": [], "options": {"A": "Butane", "B": "Ethanol", "C": "Ethene", "D": "Propanol"}, "answer": "A", "explanation": "Butane can also be used as fuel. Butane is a major component of liquefied petroleum gas (LPG), which is a mixture of propane and butane. LPG is widely used for cooking, heating, and as fuel for vehicles in many countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>48", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "Which of the following polymers is thermosetting?", "images": [], "options": {"A": "Bakelite", "B": "Nylon", "C": "Polypropene", "D": "Polystyrene"}, "answer": "A", "explanation": "Note:Thermosets plastics are plastics that cannot be soften by heat and cannot also be remoulded and Bakelite is a thermoset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2015>49", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The correct balanced equation for the reaction between Aluminium metal and hot concentrated Tetraoxosulphate (VI) acid is", "images": [], "options": {"A": "2Al(s) + 6H2SO4(l) → Al2(SO4)3(aq) + 6H2O(l) + 3SO2(g)", "B": "2Al(s) + 3H2SO4(l) → Al2(SO4)3(aq) + 6H2O(l) + 3SO2(g)", "C": "2Al(s) + 4H2SO4(l) → Al2(SO4)3(aq) + 8H2O(l) + 3SO2(g)", "D": "2Al(s) + 5H2SO4(l) → Al2(SO4)3(aq) + 6H2O(l) + 3SO2(g)"}, "answer": "A", "explanation": "Concentrated (Hot) H2SO4 reacting with Aluminium metal  2Al(s) + 6H2SO4(l) → Al2(SO4)3(aq) + 6H2O(l) + 3SO2(g)   but dilute cold H2SO4 produces otherwise.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2015>50", "subject": "Chemistry", "year": "2015", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "Which of the following gases is monoatomic?", "images": [], "options": {"A": "Argon", "B": "Chlorine", "C": "Nitrogen", "D": "Oxygen"}, "answer": "A", "explanation": "Argon is a monoatomic gas. Monoatomic gases are gases that consist of single atoms instead of molecules. Argon is a noble gas and like all noble gases, it is monoatomic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>1", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The following atoms of Carbon 126C, 136C and 146C can be described as", "images": [], "options": {"A": "allotropes", "B": "isomers", "C": "isotopes", "D": "isotones"}, "answer": "C", "explanation": "Isotopes: This is a phenomenon whereby an element have the same atomic number but different mass number due to the variation in their neutron numbers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>2", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "An atoms X consists of 6 protons, 6 electrons and 7 neutrons. Which of the following representations of the atoms is  correct?", "images": [], "options": {"A": "136X", "B": "137X", "C": "196X", "D": "197X"}, "answer": "A", "explanation": "Protons; P = 6, Electrons, E = 6, neutron, n = 7  Atomic mass = Proton + neutron  = 6 + 7  = 13  P + NP X = 136 X", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>3", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "How many electrons are presenting 94Be2+?", "images": [], "options": {"A": "2", "B": "4", "C": "5", "D": "6"}, "answer": "A", "explanation": "94Be2+  From the above, the element has lost two electrons. The electron number will be 4 - 2 = 2", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>4", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.~~CHEMICAL BONDS : IONIC COMPOUNDS", "question": "When elements 20Y combines with element 8Z", "images": [], "options": {"A": "a covalent compound YZ is formed", "B": "a covalent compound ZY is formed", "C": "an ionic compound, YZ is formed", "D": "an ionic compound, ZY is formed"}, "answer": "C", "explanation": "When elements combine, they form compounds. The type of compound formed depends on the type of bonding between the elements. In this case, element 20Y likely represents a metal (since it has a higher atomic number), and element 8Z likely represents a non-metal. Metals and non-metals typically form ionic compounds, not covalent compounds. Therefore, an ionic compound, YZ, is formed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>5", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "The boiling points of HF, H2O and NH3 increase in the order of", "images": [], "options": {"A": "NH3 2O", "B": "H2O 3", "C": "HF 3 2O", "D": "NH3 2O"}, "answer": "D", "explanation": "HF, H2O and NH3  H2O has the highest boiling point due to the present of hydrogen bond in it. Also, HF has a boiling point greater than that of NH3 because of the covalent bond in it.  ∴ NH3 2O", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>6", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Chemicals that are produced in small quantities and with very high degree of purity are", "images": [], "options": {"A": "bulk chemicals", "B": "fine chemicals", "C": "heavy chemicals", "D": "light chemicals"}, "answer": "B", "explanation": "Fine chemicals are chemicals that are produced in small quantities and with very high degree of purity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>7", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "The mass of potassium hydroxide required to make 300.0cm3 of 0.4moldm-3 solution is [KOH = 56.0]", "images": [], "options": {"A": "26.88g", "B": "13.44g", "C": "6.72g", "D": "3.36g"}, "answer": "C", "explanation": "Given that,  Molar Concentration of KOH, CKOH = 0.4moldm-3  Volume of KOH, VKOH = 300cm3 = 0.3dm3  Molar mass of KOH, M.MKOH = 56g/mol  Mass of KOH; MKOH = ?  Recall that;  C = n/v  n = CV  n = 0.4 × 0.3  n = 0.12 mole  Also, recall that  n = m/m.m  m = n × m.m  m = 0.12 × 56  m = 6.72g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2016>8", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Metals can be stretched into wires because they are", "images": [], "options": {"A": "ductile", "B": "good conductors", "C": "lustrous", "D": "malleable"}, "answer": "A", "explanation": "Metals can be stretched into wires because they are ductile. Ductility is a physical property of a material associated with the ability to be hammered thin or stretched into wire without breaking. Therefore, the correct answer is 'ductile'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>9", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "Aluminium is used in the manufacture of aircraft because it", "images": [], "options": {"A": "is hard and brittle", "B": "is light and resists corrosion", "C": "has high density and conducts electricity", "D": "is malleable and ductile"}, "answer": "B", "explanation": "Aluminium is used in the manufacture of aircraft because it is light and resists corrosion. The lightness of aluminium reduces the weight of the aircraft, making it more fuel-efficient. Its resistance to corrosion helps to maintain the integrity of the aircraft structure over time. Therefore, the correct answer is 'is light and resists corrosion'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>10", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "An  unsaturated solution differs  from a  saturated solution  at a given temperature because it", "images": [], "options": {"A": "cannot dissolve more solute", "B": "can hold more solute than it can actually dissolve", "C": "can still dissolve more solute at given temperature", "D": "form crystal more easily on cooling"}, "answer": "C", "explanation": "Unsaturated solution is a type of solution that can still dissolve more solute at a given temperature while saturated solution is a type of solution that can the equal amount of solute that can be dissolve at that temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>11", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the following arrangements shows  increasing  order of reactivity of the halogens?", "images": [], "options": {"A": "F2 > Cl2 > Br2 > I2", "B": "I2 2 2", "C": "F2 2 2 2", "D": "I2 > Br2 > Cl2 > F2"}, "answer": "B", "explanation": "It should be noted that halogens are electronegative elements. Hence, their reactivity is a function of their electronegativity. In order of increasing electronegativity, we have: I2 2 2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>12", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "The shape of the water molecule is", "images": [], "options": {"A": "linear", "B": "pyramidal", "C": "tetrahedral", "D": "V-shaped"}, "answer": "D", "explanation": "The shape of the water molecule is V-shaped. This is due to the bent shape caused by the unshared electron pairs on the oxygen atom. Therefore, the correct answer is 'V-shaped'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>13", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Which of the following elements would produce coloured aqueous solution?", "images": [], "options": {"A": "Calcium", "B": "Copper", "C": "Magnesium", "D": "Sodium"}, "answer": "B", "explanation": "Copper is the correct answer because it forms a blue-colored aqueous solution when dissolved in water. This is due to the d-d transition of electrons in the copper ion which absorbs light in the red region of the spectrum, making the solution appear blue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>14", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The minimum amount of energy required for effective collisions between reacting particles is known as", "images": [], "options": {"A": "activation energy", "B": "bond energy", "C": "kinetic energy", "D": "potential energy"}, "answer": "A", "explanation": "Activation energy can be defined as the minimum amount of energy required for effective collisions between reacting particles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>15", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "The bond formed between H2O and H+ to form the hydroxonium ion H3O+ is", "images": [], "options": {"A": "dative", "B": "covalent", "C": "electrovalent", "D": "ionic"}, "answer": "A", "explanation": "The bond between H2O and H+ to form H3O+ is co-ordinate covalent bond or dative bond.  - Dative bond is a bond between two atoms chemical species such that the shared pair of electron(s) is/are usually donated by one of the participating atoms.  H2O + H+ ⇋ H3O+  This type of bond is called Dative bond", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>16", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "An element X forms the following oxides X2O, XO and XO2. This phenomenon illustrates the law of", "images": [], "options": {"A": "conservation of mass", "B": "definite proportion", "C": "mass action", "D": "multiple proportions"}, "answer": "D", "explanation": "X2O, XO, XO2  The variation in the composition the element and its oxides is the phenomenon that illustrates the Law of Multiple Proportions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>17", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many moles of oxygen would contain 1.204 × 1024 molecules?  [Avogadro's constant (NA) = 6.02 × 1023]", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": "B", "explanation": "1 mole of a substance contain 1 Avogadro's Constant  ∴ 1 mole of O2 contain 6.02 × 1023  x mole of O2 will contain 1.204 × 1024  1x=6.02 × 10231.204 × 1024  x = 2", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>18", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STATES OF MATTER : SOLIDS", "question": "Which of the following statements about solids is correct?", "images": [], "options": {"A": "Solid particles are less orderly than those of a liquid", "B": "Solids have lower densities than liquids", "C": "Solid particles have greater kinetic energies than those of liquids", "D": "Solid particles cannot be easily compressed"}, "answer": "D", "explanation": "The correct statement about solids is that solid particles cannot be easily compressed. This is because the particles in a solid are closely packed together and have little space to move, making solids rigid and hard to compress.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>19", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : MEASUREMENT OF PHYSICAL QUANTITIES.", "question": "Which of the following apparatus can be used to measure a specific volume of a liquid accurately?", "images": [], "options": {"A": "Beaker", "B": "Conical flask", "C": "Measuring cylinder", "D": "Pipette"}, "answer": "D", "explanation": "A pipette is an apparatus used in chemistry to transport a measured volume of liquid. It is designed to measure a specific volume of a liquid accurately, unlike a beaker, conical flask, or measuring cylinder which are not as precise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>20", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "The general gas equation PV/T = K is a combination of", "images": [], "options": {"A": "Boyle's and Charles' laws", "B": "Boyle's and Graham's laws", "C": "Charle's and Graham's laws", "D": "Dalton's and Graham's laws"}, "answer": "A", "explanation": "The general gas equation PV/T = K is a combination of Boyle's and Charles' laws. Boyle's law states that the pressure and volume of a gas have an inverse relationship when temperature is held constant. Charles' law states that volume and temperature of a gas have a direct relationship when the pressure is held constant. When these two laws are combined, we get the general gas equation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>21", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "The spreading of the scent of a flower in a garden is an example of", "images": [], "options": {"A": "Brownian motion", "B": "Diffusion", "C": "Osmosis", "D": "Tyndal effect"}, "answer": "B", "explanation": "Diffusion is the movement of atoms or molecules from an area of higher concentration to an area of lower concentration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>22", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Propane and Carbon (IV) Oxide diffuse at the same rate because [H = 1.00, C = 12.0, O = 16.0]", "images": [], "options": {"A": "they are both gases", "B": "their molecules contain carbon", "C": "they have the same relative molecular mass", "D": "both are denser than air"}, "answer": "C", "explanation": "Propane, C3H8  Carbon (IV) Oxide, CO  R.M.M of C3H8 = 3 × 12 + 8 × 1   = 36 + 8 = 44gmol-1  Also,  R.M.M of CO2 = 12 + 2 × 16   = 12 + 32 = 44gmol-1  Both gases diffuse at the same rate because they have the same relative atomic mass.  From Graham's Law  RC3H8RCO2&radic;&nbsp;R.M.M of CO2R.M.M of C3H6  RC3H8RCO2&radic;&nbsp;4444    RC3H8RCO2&radic;&nbsp;1  ∴ RC3H8 = RCO2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>23", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The energy which accompanies the addition of an electron to an isolated gaseous atoms is", "images": [], "options": {"A": "atomization", "B": "electronegativity", "C": "electron affinity", "D": "ionization"}, "answer": "C", "explanation": "Electron affinity is the energy which accompanies the addition of an electron to an isolated gaseous atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>24", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "An aqueous solution of (NH4)2SO4 is", "images": [], "options": {"A": "acidic", "B": "alkaline", "C": "amphoteric", "D": "neutral"}, "answer": "A", "explanation": "An aqueous solution of (NH4)2SO4 is acidic. This is because when (NH4)2SO4 is dissolved in water, it dissociates into NH4+ and SO4- ions. The NH4+ ion is a weak acid and can donate a proton (H+) to the water, making the solution acidic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>25", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "When NH4Cl(s) is dissolved in water, the container feels cold to touch. This implies", "images": [], "options": {"A": "the process is endothermic", "B": "this is exothermic", "C": "NH4Cl forms a saturated solution", "D": "NH4Cl is highly soluble in water"}, "answer": "A", "explanation": "When NH4Cl(s) is dissolved in water, the container feels cold to touch. This implies that the process is endothermic. An endothermic process is one that absorbs heat from its surroundings. In this case, the heat is absorbed from the surroundings (including your hand), making the container feel cold.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>26", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "The pH of four solutions, M, N, Q and R are 2, 6, 8 and 11 respectively. Which of the following deductions about the solution is correct?", "images": [], "options": {"A": "The pH of N is increased when the solution is diluted", "B": "The pH of Q is increased when the solution is diluted", "C": "M is the most alkaline solution", "D": "R is the most acidic solution"}, "answer": "A", "explanation": "Diluting N by adding more water increases the pH of the solution towards 7 making it less acidic. M is the most acidic while R is the most alkaline.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>27", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Consider the following reaction equation:  H3O+(aq) + OH-(aq) → 2H2O(l)  The reaction represents", "images": [], "options": {"A": "esterification", "B": "hydrolysis", "C": "neutralization", "D": "redox"}, "answer": "C", "explanation": "H3O+(aq) + OH-(aq) → 2H2O(l)  A reaction between an acid and a base to form water is called a neutralization reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>28", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "The refreshing characteristic drinks is due to the presence of", "images": [], "options": {"A": "carbon(IV)oxide", "B": "glucose", "C": "hydrogen", "D": "sodium citrate"}, "answer": "A", "explanation": "The refreshing characteristic of drinks is due to the presence of carbon(IV)oxide. Carbon(IV)oxide, also known as carbon dioxide, is what gives drinks their fizziness or effervescence, which is often associated with a refreshing sensation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>29", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Chemical equilibrium is attained when", "images": [], "options": {"A": "all the reactants have been completely used up", "B": "the reaction goes to completion", "C": "the concentration of reactants and products remain constant", "D": "the concentration of reactants and products are equal"}, "answer": "D", "explanation": "Chemical equilibrium is attained when the rate of production of the reactant is equal to the rate of production of the products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>30", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following factors will affect the rate of the reaction represented by the following equation?  2HCl(aq) + CaCO3(s) → CaCl2(aq) + H2O(l) + CO2(g)  I. Pressure  II. Concentration  III. Nature of reactants  IV. Temperature", "images": [], "options": {"A": "I and II only", "B": "II, III and IV only", "C": "I, II and III only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "2HCl(aq) + CaCO3 → CaCl2 + H2O + CO2(g)  * Concentration * Nature of reactant * Temperature are the only factor that can affect the rate of the reaction while pressure can not affect because the compounds are not all in the gaseous state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>31", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "On evaporation to dryness, 350cm3 of saturated solution of salt Z gave 55.5g of salt. What is the solubility of the salt?  [Z = 101]", "images": [], "options": {"A": "1.57 moldm-3", "B": "3.14 moldm-3", "C": "6.28 moldm-3", "D": "12.56 moldm-3"}, "answer": "A", "explanation": "Given that:  Volume of saturated solution of z = 350cm3 ≡0.35dm3  Mass of salt z, M2 = 55.5g  Molar mass of z, M.Mz = 101gmol-1  Solubility of z in moldm-3 = ?  Recall that,  n = m/m.m  n = 55.5/101   = 0.55mol  Also, recall that  c=nv  c=0.550.35   = 1.57 moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>32", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following salts when dissolved in water will form a solution that will change blue litmus to red?", "images": [], "options": {"A": "CH3COONa", "B": "NH4Cl", "C": "NaCl", "D": "KCl"}, "answer": "B", "explanation": "NH4Cl is an ammonium salt and when dissolved in water, it forms a solution that is acidic. This is because the ammonium ion (NH4+) can donate a proton (H+) to water, forming NH3 and H3O+. The presence of H3O+ ions will change blue litmus paper to red, indicating an acidic solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>33", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following bonds are broken when Ethanol is boiled?  I. Covalent bonds  II. Ionic bonds  III. Hydrogen bonds", "images": [], "options": {"A": "I only", "B": "II only", "C": "III only", "D": "I, II and III"}, "answer": "C", "explanation": "When ethanol is boiled, only the hydrogen bonds between ethanol molecules are broken. The covalent bonds within the ethanol molecules and any ionic bonds (which are not present in ethanol) remain intact. Therefore, only hydrogen bonds are broken when ethanol is boiled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>34", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP", "question": "A compound with molecular formular CH2O2 is", "images": [], "options": {"A": "a carbohydrate", "B": "a carboxylic acid", "C": "an alkanal", "D": "an ester"}, "answer": "B", "explanation": "This compound are also called Carboxylic acid ROOH.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>35", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "The quantity of electricity required to discharge 1 mole of univalent ion is", "images": [], "options": {"A": "9600 C", "B": "48250 C", "C": "96500 C", "D": "193000 C"}, "answer": "C", "explanation": "The quantity of electricity required to discharge 1 mole of univalent ion is 96500 C. This is known as Faraday's First Law of Electrolysis which states that the amount of substance deposited or liberated at any electrode is directly proportional to the quantity of electricity passed through the electrolyte (solution or molten compound).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>36", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "Chlorine water is used as a bleaching agent because it is", "images": [], "options": {"A": "an acidic solution", "B": "an alkaline solution", "C": "an oxidizing agent", "D": "a reducing agent"}, "answer": "C", "explanation": "Chlorine water is used as a bleaching agent because it is an oxidizing agent.  2HOCl → Cl2 + 2H2O", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>37", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the following substances is a non-electrolyte?", "images": [], "options": {"A": "H2SO4", "B": "CH3COOH", "C": "C6H12O6", "D": "NH4Cl"}, "answer": "C", "explanation": "Glucose, C6H12O6, is a non-electrolyte; it does not readily ionize when dissolved or melted and is a poor conductor of electricity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2016>38", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of Sulphur is +4 in", "images": [], "options": {"A": "Na2S2O3", "B": "H2SO3", "C": "H2SO4", "D": "SO3"}, "answer": "B", "explanation": "The oxidation number of Sulphur is +4 in H2SO3 (Sulphurous acid). The oxidation state of an atom is the charge of this atom after ionic approximation of its heteronuclear bonds. In H2SO3, oxygen has an oxidation state of -2 and hydrogen has an oxidation state of +1. Since the molecule is neutral, the sum of oxidation states should be zero. Therefore, the oxidation state of sulphur in H2SO3 is +4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>39", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Consider the following ionic equation:  Cr2O72- + 14H+ + ne- → 2Cr3+ + 7H2O  The value of n in the equation is", "images": [], "options": {"A": "7", "B": "6", "C": "3", "D": "2"}, "answer": "B", "explanation": "Cr2O2-7 + 14H+ + ne- → 2Cr3+ + 7H2O  -2 + 14 + ne- →  +6 + 0  +12 + ne- → +6  ne- → 6 - 12  ne- → -6  ∴ 6 electron will be added", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2016>40", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Consider the following half-cell reactions:  Al(s) → Al3+(aq) + 3e-;  Cu2+(aq) + 2e- → Cu(s)  The overall equation for the reaction is", "images": [], "options": {"A": "Al(s) + Cu2+(aq) → Al3+(aq) + Cu(s)", "B": "2Al(s) + Cu2+(aq) → 2Al3+(aq) + Cu(s)", "C": "2Al(s) + 3Cu2+(aq) → 3Cu(s) + 2Al3+(aq)", "D": "3Al(s) + 2Cu2+(aq) → 2Cu(s) + 3Al3+(aq)"}, "answer": "C", "explanation": "Al(s) → Al3+(aq) + 3e-  Cu2+(aq) + 2e- → CU(s)  Balance the charge of each reaction such that they have equal charge  Al(s) → Al3+(aq) + 3e-  Cu2+(aq) + 2e- → Cu(s)  2Al → 2Al3+ + 6e-  3Cu2+(aq) + 6e- → 3Cu(s)  Add both reactions together in such a way that shows the reactant with reactant and product with product.  2Al(s) + 3Cu2+ + 6e- → 2Al3+ + 3Cu(s)", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2016>41", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : AMINO ACIDS", "question": "Amino acids are obtained from proteins by", "images": [], "options": {"A": "hydrolysis", "B": "oxidation", "C": "polymerization", "D": "reduction"}, "answer": "A", "explanation": "Amino acids are obtained from proteins by hydrolysis. Hydrolysis is a chemical reaction in which a molecule is split into two parts by the addition of a water molecule. In the case of proteins, they are broken down into their constituent amino acids through hydrolysis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>42", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES~~CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS~~CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS~~CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "When a compound X is heated with concentrated tetaoxosulphate (VI) acid, it produces an alkene. X is an", "images": [], "options": {"A": "alkane", "B": "alkanol", "C": "alkanoate", "D": "alkyne"}, "answer": "B", "explanation": "The dehydration reaction of alkanols or alcohols to generate alkene proceeds by heating the alcohols in the presence of a strong acid, such as sulfuric or phosphoric acid, at high temperatures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>43", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Ripening of fruits is hastened by using", "images": [], "options": {"A": "ethanol", "B": "ethylene", "C": "methanol", "D": "methanoic acid"}, "answer": "B", "explanation": "Ethylene is responsible for the changes in texture, softening, color, and other processes involved in ripening.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>44", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The compound that makes palmwine taste sour after exposure to the air for few days is", "images": [], "options": {"A": "ethanol", "B": "ethanoic acid", "C": "methanol", "D": "methanoic acid"}, "answer": "B", "explanation": "The compound that makes palmwine taste sour after exposure to the air for few days is ethanoic acid. When palmwine is exposed to air, the ethanol in it is oxidized by the bacteria present in the air to form ethanoic acid, which gives the palmwine a sour taste.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>45", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following compounds is/are secondary alkanols?  I. CH3CH(CH3)CH3OH  II. CH3CH2CH(OH)CH3  III. CH3C(OH)(CH3)CH3", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and III only", "D": "II and III only"}, "answer": "B", "explanation": "Secondary alkanols are alkanols that have 2-alkyl groups directly link to the alpha carbon  I. CH3CH(CH3)CH3OH    II. CH3CH2CH(OH)CH_(    III. CH3C(OH)CH3CH3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>46", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Consider the following reaction equation:  C2H4(g) + 3O2(g) → 2CO2(g) + 2H2O(l)  The volume of oxygen at s.t.p that will be required to burn 14g of Ethene is [C2H4 = 28, Molar volume of gas at s.t.p. = 22.4dm3]", "images": [], "options": {"A": "67.2 dm3", "B": "33.6 dm3", "C": "11.2 dm3", "D": "3.73 dm3"}, "answer": "B", "explanation": "C2H4(g) + 3O2(g) → 2CO2(g) + 2H2O(l)  Given that   Mass of ethene = 14g  Molar mass of Ethene = 28gmol-1  Molar volume at s.t.p = 22.4dm3  From the reaction the mole ratio is 1:3  no of mole of ethene = mass of ethene/molar mass of ethene  n = 14/28 = 0.5 mol  If 1 mol of C2H4 produced 3 mol of O2  ∴ 0.5mol of C2H4 will produced x mol of O2  10.5=3x  x = 3 × 0.5  x = 1.5 mol  Also, recall that  n = v/m.v  1.5 = v/22.4  v = 22.4 × 1.5  v = 33.6dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>47", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following sources of energy contributes to the  green-house effect?", "images": [], "options": {"A": "Natural gas", "B": "Nuclear", "C": "Wind", "D": "Solar"}, "answer": "A", "explanation": "The greenhouse effect is caused by the release of greenhouse gases into the atmosphere, which trap heat from the sun and cause the Earth's temperature to rise. Natural gas, when burned, releases carbon dioxide, a greenhouse gas, into the atmosphere. Therefore, the use of natural gas as a source of energy contributes to the greenhouse effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>48", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "A consequence of global warming is", "images": [], "options": {"A": "air pollution", "B": "flooding", "C": "increased humidity", "D": "water pollution"}, "answer": "B", "explanation": "Global warming is the long-term warming of the planet. Global warming happens when greenhouse gases (like carbon dioxide) trap heat in the earth's atmosphere. This can lead to a host of changes in the earth's climate, including more frequent and severe flooding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>49", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : ALLOYS", "question": "Which of the following metals is common to both brass and bronze?", "images": [], "options": {"A": "Aluminium", "B": "Copper", "C": "Lead", "D": "Iron"}, "answer": "B", "explanation": "Brass is an alloy of copper and zinc, while bronze is an alloy of copper and tin. Therefore, copper is the metal that is common to both brass and bronze.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2016>50", "subject": "Chemistry", "year": "2016", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The alkanol obtained from the production of soap is", "images": [], "options": {"A": "dihydric alkanol", "B": "tertiary alkanol", "C": "trihydric alkanol", "D": "monohydric alkanol"}, "answer": "C", "explanation": "Trihydric alkanol contain 3 OH groups. It obtained during a process of Saponification.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>1", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "Which of the following species determines the chemical properties of an atom?", "images": [], "options": {"A": "Electron", "B": "Neutron", "C": "Nucleus", "D": "Proton"}, "answer": "A", "explanation": "The chemical properties of an atom are determined by the number and arrangement of its electrons. This is because electrons are involved in chemical reactions and bond formation. Neutrons and protons, which are located in the nucleus of the atom, do not participate in chemical reactions under normal conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>2", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : MEASUREMENT OF PHYSICAL QUANTITIES.", "question": "The following glasswares are used to measure the volume of liquids except", "images": [], "options": {"A": "graduated beaker", "B": "pipette", "C": "test tube", "D": "burette"}, "answer": "C", "explanation": "Test tube is not used in the measurement of the volume of a liquid rather it is used to contain reagent for chemical reactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>3", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RULES AND PRINCIPLES FOR FILLING IN ELECTRONS.", "question": "Pauli exclusion principle is related to", "images": [], "options": {"A": "quantity of electrons in the valence shell", "B": "filling the orbitals with lower energy first", "C": "the filling of degenerated orbitals", "D": "quantum numbers of electrons"}, "answer": "D", "explanation": "Quantum numbers of electrons, pauli's expclusion principle states that no two electron can be identified by the same set of quantum numbers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>4", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "The species with no electron in the 3d - orbitals is", "images": [], "options": {"A": "Zn2+", "B": "Sc2+", "C": "Cu", "D": "Mn"}, "answer": "B", "explanation": "We have to draw the E-configuration of the secies presented in the option  - Zn2+  ne = 28e-  Zn2+ : 1s22s22p63s23p64s23d8    - Sc2+  ne = 19e-  Sc2+ : 1s2 2s2 2p6 3s2 3p6 4s1    - Cu  ne = 29e-  Cu = 1s2 2s2 2p6 3s2 3p6 4s2 3d9  1s2 2s2 2p6 3s2 3p6 4s1 3d10    - Mn  ne = 25e-  Mn = 1s2 2s2 2p6 3s2 3p6 4s2 3d5  From the analysis above, only Sc2+ lacks the 3d-orbital in its configuration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>5", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "The separation of oxygen from nitrogen by fractional distillation of air is possible because", "images": [], "options": {"A": "nitrogen is less dense than oxygen", "B": "oxygen is more reactive than nitrogen", "C": "of the difference in their boiling points", "D": "they belong to the same period"}, "answer": "C", "explanation": "In fractional distillation, success of separation is achieved if the substances to be separated have different boiling points.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>6", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CRITERIA FOR PURITY", "question": "The purity of a solid sample can best be determined by its", "images": [], "options": {"A": "boiling point", "B": "melting point", "C": "conductivity", "D": "solubility"}, "answer": "B", "explanation": "The purity of a solid can best be determined by its melting point.  It should be noted that a pure solid sample usually has a fixed melting but impurities depress the melting point of a hither to pure solid substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>7", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The mass of one mole of (NH4)2CO3 is   [O = 16.0, N = 14.0, C = 12.0, H = 1.0]", "images": [], "options": {"A": "66.0g", "B": "76.0g", "C": "80.0g", "D": "96.0g"}, "answer": "D", "explanation": "The mass of mole of (NH4)2CO3 = The molar mass of (NH4)2CO3  =(14+4)2+12+(16)3=36+12+48=96gmol-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>8", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "Atomic orbital is", "images": [], "options": {"A": "the circular path through which electrons revolve round the nucleus", "B": "a region around the nucleus where electrons are most likely to be found", "C": "the path around the nucleus through which electrons move", "D": "the path around the nucleus through which protons move"}, "answer": "B", "explanation": "Atomic orbital is the region of maximum probability of locating an electron.  N.B: Atomic orbital = Electron cloud", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>9", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The property of elements which increases down a group of the Periodic Table is", "images": [], "options": {"A": "electronegativity", "B": "electron affinity", "C": "ionic radius", "D": "ionization energy"}, "answer": "C", "explanation": "The ionic radius tends to increase down a group. This is because electron shells are added as you move down a group. Each new electron shell is further from the nucleus than the last, so the size of the atom (and its ion) increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>10", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The reason for the decrease in the atomic size of elements across a period is that", "images": [], "options": {"A": "nuclear charge increases while the outermost electrons are drawn close to the nucleus", "B": "nuclear charge decreases while the outermost electrons are drawn closer to the nucleus", "C": "valence electrons increase across the period while the valence shell remains constant", "D": "nuclear charge decreases while the distance of the valence shell from the nucleus is increasing"}, "answer": "A", "explanation": "Atomic size decreases across a period because of the progressive increase in the nuclear charges of the elements in a period. It should be noted that this increase leads to a \"shielding effect\" which pulls the electrons close to the nucleus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>11", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of nitrogen in Pb(NO3)2 is", "images": [], "options": {"A": "+2", "B": "+3", "C": "+4", "D": "+5"}, "answer": "D", "explanation": "The oxidation number of nitrogen in Pb(NO3)2 is +5. In the nitrate ion (NO3-), the sum of the oxidation numbers must equal the charge on the ion. The oxidation number of oxygen is typically -2, and since the nitrate ion has a charge of -1, this means that the oxidation number of nitrogen is +5.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>12", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following arrangements indicates the correct decreasing order of ionization energy of period 3 elements?", "images": [], "options": {"A": "Na, Al, P, Cl", "B": "Cl, P, Al, Na", "C": "Na, P, Cl, Al", "D": "Al, Na, P, Cl"}, "answer": "B", "explanation": "N.B: Ionization energy increases across a period, hence we have:  Na → Al → P → Cl, in order of increasing ionization energy and Cl → P → Al → Na in order of decreasing ionization energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>13", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "Which of the following metals has the strongest metallic bond?", "images": [], "options": {"A": "19K", "B": "13Al", "C": "12Mg", "D": "11Na"}, "answer": "A", "explanation": "metallicity increases down a group and decreases across a period. the choice of answer is between the elements of group one that are in the options, potassium has a higher number of electronic shell, hence the highest metallicity as far as the options are concerned", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>14", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Which of the following substances does not have van der Waals' force?", "images": [], "options": {"A": "Copper", "B": "Graphite", "C": "Neon", "D": "Iodine Crystals"}, "answer": "A", "explanation": "Van der Waals' forces are the weakest of the weak chemical forces. They are present between all types of molecules, whether ionic or covalent—polar or nonpolar. However, they are not present in metals. Therefore, copper, being a metal, does not have van der Waals' forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>15", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of X in XO43-  is", "images": [], "options": {"A": "+1", "B": "+3", "C": "+4", "D": "+5"}, "answer": "D", "explanation": "The oxidation number of an atom in a compound represents the number of electrons that an atom has lost (if the number is positive) or gained (if the number is negative) when the compound is formed. In the compound XO43-, the oxidation number of X is +5 because the compound has a charge of 3- and each oxygen atom has a charge of -2. Therefore, the total charge of the four oxygen atoms is -8. To balance this charge, the oxidation number of X must be +5.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>16", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The ionization energy is affected by the following factors except", "images": [], "options": {"A": "distance of the outermost electron(s) from the nucleus", "B": "size of the positive nuclear charge", "C": "ability to attract shared electron(s)", "D": "screening effect of the inner electron(s)"}, "answer": "C", "explanation": "Ionization energy is the energy required to remove an electron from an atom or ion. It is affected by the distance of the outermost electrons from the nucleus (the further the electron, the less energy is needed to remove it), the size of the positive nuclear charge (the larger the charge, the more energy is needed to remove an electron), and the screening effect of the inner electrons (the more inner electrons, the less energy is needed to remove an outer electron). However, the ability to attract shared electrons, which is a property related to electronegativity, does not affect ionization energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>17", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following statements is correct?", "images": [], "options": {"A": "Covalent compounds would readily ionize in solution", "B": "Covalent compounds consist of ions", "C": "Hydrogen bond is formed between a metal and a non-metal", "D": "Ionic compounds in solution would conduct electricity"}, "answer": "D", "explanation": "Ionic compounds in solution would conduct electricity. This is because when ionic compounds dissolve in water, they dissociate into ions. These ions are charged particles that can move freely in solution, allowing the solution to conduct electricity. Covalent compounds, on the other hand, do not readily ionize in solution and do not consist of ions. A hydrogen bond is a type of dipole-dipole interaction that occurs between molecules, not between a metal and a non-metal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>18", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMICAL BONDS : SHAPES OF MOLECULAR COMPOUNDS.", "question": "The bond angle in tetrahedral molecules such as tetrachloromethane is", "images": [], "options": {"A": "180.0°", "B": "109.5°", "C": "105.5°", "D": "90.0°"}, "answer": "B", "explanation": "The bond angle in tetrahedral molecules is 109.5°    {tetrachloromethane}    The bond angle in tetra chloromethane is 109.5∘. Since it has tetrahedral molecular geometry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>19", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "The properties of a good primary standard solution include the following except", "images": [], "options": {"A": "high molecular mass", "B": "low molecular mass", "C": "high degree of purity", "D": "readily available"}, "answer": "B", "explanation": "A good primary standard should have high molecular mass.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>20", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "The use of diamond in abrasives is due to its", "images": [], "options": {"A": "high melting point", "B": "hardness", "C": "octahedral shape", "D": "durabillity"}, "answer": "B", "explanation": "DIamond is useful as abrasive owing totally to its hardness.  N.B: Diamond is the hardest known substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>21", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following statement about the endothermic reaction is correct?", "images": [], "options": {"A": "Activation energy is high", "B": "A catalyst is required", "C": "It occurs reversibly", "D": "Heat energy is absorbed"}, "answer": "D", "explanation": "An endothermic reaction is a chemical reaction that absorbs heat energy from its surroundings. This is because the energy needed to break the bonds in the reactants is greater than the energy released when new bonds form in the products. Therefore, 'Heat energy is absorbed' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>22", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "A 0.1moldm-3 solution of sodium hydroxide was diluted with distilled water to 0.001 moldm-3. What is the dilution factor?", "images": [], "options": {"A": "1000.00", "B": "100.00", "C": "10.00", "D": "0.01"}, "answer": "D", "explanation": "Molar concentration of concentrated solution = 0.1moldm-3   Molar concentration of diluted solution = 0.001moldm-3  Recall:Dilutionfactor=molar concentration of diluted solutionmolar concentration of concentrated solution  Df=0.0010.1=0.01", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>23", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "Graphite and diamond are similar in that they", "images": [], "options": {"A": "have octahedral shape", "B": "have same density", "C": "form carbon (iv) oxide on combustion", "D": "conduct electricity"}, "answer": "C", "explanation": "Graphite and Diamond being allotropes of carbon, have the same chemical properties. One of these is, the formation of carbon (iv) oxide during combustion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>24", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "In a saturated solution at a given temperature, the undissolved solutes are in equilibrium with", "images": [], "options": {"A": "the solvent", "B": "dissolved solute particles", "C": "the saturated solution", "D": "insoluble solute particles"}, "answer": "C", "explanation": "According to Le Chatelier's principle in a saturated solution, (at a given temperature) the undissolved solute particles are in equilibrium with the solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>25", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The number of atoms present in 2.5 moles of a triatomic gas is equivalent to   [1 mole = 6.0 × 1023]", "images": [], "options": {"A": "2.5 × 1023", "B": "1.5 × 1023", "C": "1.5 × 1024", "D": "2.5 × 1024"}, "answer": "C", "explanation": "Let the triatomic gas be X3  X3 has 3 atoms   1 molecule of X3 = 3 atoms of X  N.B: No of molecules α Number of moles  1 mole of X3 = 3 × 6.02 × 1023 atoms   2.5 mole of X3 = x  12.5=3 × 6.02 × 1023x  x = 2.5 × 6.02 × 1023 atoms   x = 15 × 1023atoms = 1.5 × 1024 atoms", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>26", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "When magnesium reacts with oxygen, heat is", "images": [], "options": {"A": "absorbed and the reaction is endothermic", "B": "evolved and the reaction is endothermic", "C": "evolved and the reaction is exothermic", "D": "absorbed and the reaction is exothermic"}, "answer": "C", "explanation": "The reaction of magnesium with oxygen is a combustion reaction.  It should be noted that the heat of combustion always takes a negative value, i.e, Δ = -ve  It follows that on combustion, heat is released to the surrounding. Hence, the reaction is said to be exothermic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>27", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Which of the following gases is not acidic?", "images": [], "options": {"A": "NO2", "B": "SO2", "C": "CO2", "D": "CO"}, "answer": "D", "explanation": "Carbon monoxide (CO) is not an acidic gas. Acidic gases are those that react with water to form an acidic solution. Nitrogen dioxide (NO2), sulfur dioxide (SO2), and carbon dioxide (CO2) can all react with water to form their respective acids. However, carbon monoxide does not react with water and hence is not an acidic gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>28", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "A hydrocarbon contained 14.3% hydrogen. The empirical formula of the hydrocarbon would be   [C = 12, H = 1]", "images": [], "options": {"A": "CH", "B": "CH2", "C": "CH3", "D": "CH4"}, "answer": "B", "explanation": "HydrogenCarbon%comp14.3%85.7%mass14.3g85.7gnumber of moles14.37.14mole ratio21  Empirical formula = CH2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>29", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following statements is not a chemical property of an acid?", "images": [], "options": {"A": "Evolution of ammonia gas when heated with ammonium salts", "B": "Evolution of CO2 gas when added to a trioxocarbonate (IV) salts", "C": "Formation of salt and water with alkalis", "D": "Formation of salt and hydrogen gas with reactive metals"}, "answer": "A", "explanation": "The evolution of ammonia gas upon reaction with ammonium salts is a property of bases and not acids.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>30", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "PERIODIC CHEMISTRY : REACTIONS BETWEEN ACIDS AND METALS, THEIR OXIDES AND TRIOXOCARBONATES (IV).", "question": "Halogens generally react with metals to form", "images": [], "options": {"A": "alkalis", "B": "acids", "C": "bases", "D": "salts"}, "answer": "D", "explanation": "Halogens are non-metals and when they react with metals, they form ionic compounds known as salts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>31", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Potassium chloride solid does not conduct electricity because", "images": [], "options": {"A": "it is a covalent compound", "B": "strong cohesive forces make its ions immobile", "C": "strong cohesive forces make its molecules immobile", "D": "each of potassium and chlorine ions has noble gas structure"}, "answer": "B", "explanation": "Potassium chloride is an electrovalent compound though, it can not conduct electricity if it is not in aqueous solution because the cohesive force of attraction makes its ion immobile.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>32", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "When water was added to a white anhydrous substance X, the colour changed to blue, X is", "images": [], "options": {"A": "CuSO4", "B": "FeSO4", "C": "Na2SO4", "D": "PbSO4"}, "answer": "A", "explanation": "This is one of the tests for water:  CuSO4 + 5H2O → CuSO4 . 5H2O  CuSO4 → White copper sulphate  5H2O → Water  CuSO4.5H2O → Blue hydrated salt", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>33", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Solubility curve can be applied in the determination of the", "images": [], "options": {"A": "amount of crystals formed", "B": "amount of solvent that can be recovered", "C": "amount of solid drugs in a given solution", "D": "temperature of the solution"}, "answer": "C", "explanation": "Solubility curve can be applied in the determination of the amount of solid particles in a given solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>34", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "If 0.2g of a salt is required to saturate 200cm3 of water at room temperature, what is the solubility of the salt?", "images": [], "options": {"A": "0.2gdm-3", "B": "1.0gdm-3", "C": "2.0gdm-3", "D": "5.0 gdm-3"}, "answer": "B", "explanation": "mass, m = 0.2g  volume, v = 200cm3 = 0.2dm3  Solubility = /  Recall:Solubility=mass of solutevolume of solution  =0.2g0.2dm3=1.0gdm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>35", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The property of a chemical reaction that is affected by a catalyst is the", "images": [], "options": {"A": "activation energy", "B": "free energy", "C": "equilibrium position", "D": "enthalpy change"}, "answer": "A", "explanation": "Catalyst alters the activation energy of a reaction, it creates an alternate pathway for the reaction to take place.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>36", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Soluble salts can be prepared by the following methods except", "images": [], "options": {"A": "neutralization", "B": "reaction of an acid with trioxocarbonate (IV) salt", "C": "double decomposition", "D": "reaction of an acid with electropositive metals"}, "answer": "C", "explanation": "Soluble salts are not produced by double decomposition, as this is a displacement reaction. It is only used for the displacement reaction. It is only used for the preparation of insoluble salts  E.g:  NaCl + AgNO3 → AgCl + NaNO3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>37", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Chemical reactions occurs when the colliding reactants have energy that is", "images": [], "options": {"A": "less than the activation energy", "B": "greater than the activation energy", "C": "greater than the energy of the product", "D": "less than the energy of effective collusion"}, "answer": "B", "explanation": "Chemical reaction occurs when colliding reactants have energy that is greater than the activation energy. This is a statement of Arrhenius Theory", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>38", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The common feature of reactions at the anode is that", "images": [], "options": {"A": "electrons are consumed", "B": "ions are reduced", "C": "oxidation is involved", "D": "the electrode dissolves"}, "answer": "C", "explanation": "The common feature of reactions at the anode is that oxidation is involved. In electrochemistry, oxidation is the loss of electrons. At the anode, the substance loses electrons and is therefore oxidized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>39", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Consider the following reaction equation: 2NO(g) + O2(g) → 2NO2(g). What is the change in the oxidation number of nitrogen?", "images": [], "options": {"A": "+2 to 0", "B": "+2 to -2", "C": "+2 to +4", "D": "+4 to +2"}, "answer": "C", "explanation": "2NO + O2 → 2NO2  In NO, the oxidation number of nitrogen is 2. That is ;  x + (-2) = 0  x = 2  In NO2, the oxidation number of nitrogen is 4. That is   x + 2(-2) = 0  x - 4 = 0  x = 4  The oxidation number of nitrogen has changes from +2 to +4", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>40", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "Which of the following factors characterize members of the same homologous series?", "images": [], "options": {"A": "The chemical properties change gradually throughout the series", "B": "Physical properties of members are similar", "C": "They have the same molecular formula", "D": "Successive members undergo changes in molecular formular by CH2"}, "answer": "D", "explanation": "Members of the same homologous series have the same functional group. Hence, they posses the chemical properties.  However, because they have different molecular masses, they possess different physical properties.  N.B: Two successive members of a homologous series differ in molecular mass by - CH2 - group", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>41", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Calculate the mass of copper deposited if a current of 0.45 ampere flows through CuSO4 solution for 1 hour 15 minutes.   [Cu = 64.0, S = 32.0, O = 16.0, 1F = 96500C]", "images": [], "options": {"A": "6.40g", "B": "0.67g", "C": "0.64g", "D": "0.45g"}, "answer": "B", "explanation": "The anodic reaction is represented as thus:  Cu2+ + 2e- → Cu(s)  From the reaction given:  2F of electricity produces 64g of Cu  I = 0.45A; t = 1 hour 15 minutes  = 4500 seconds  N.B: 1F = 96,500C  2F = 193,000C  193,000C produces 64g of Copper  Recall: Q = It  Q = 0.45 × 4500  = 2025C  193000C = 64gCu  1C=64/193000  2025C=64/193000 x 2025  =0.6715g  ≃0.67g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2017>42", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Classification of alkanols is based on the", "images": [], "options": {"A": "number of carbon atoms present in the compound", "B": "molecular mass of the compound", "C": "molecular formula of the compound", "D": "number of alkyl groups bonded to the carbon having the hydroxyl group"}, "answer": "D", "explanation": "The classification of alkanols is based on the number of alkyl grops bonded to the carbon having the hydroxyl group.        N.B: R means alkyl group", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>43", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "The name of the compound C4H9COOC3H7 is", "images": [], "options": {"A": "propyl pentanoate", "B": "pentyl propanoate", "C": "butyl propanoate", "D": "propyl butanoate"}, "answer": "A", "explanation": "The above structure is propyl pentanoate  N.B: \"Propyl\" because we have 3 carbon atoms after the second oxygen atom (- O -) and \"pentanoate\" because we have 5 carbon atoms attached to 2 atoms of oxygen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>44", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "Which of the following pairs of gases are pollutants from car exhaust?", "images": [], "options": {"A": "Nitrogen (II) oxide and Carbon (IV) oxide", "B": "Carbon (IV) oxide and Nitrogen", "C": "Carbon (II) oxide and Sulphur (IV) oxide", "D": "Carbon (II) oxide and oxygen"}, "answer": "C", "explanation": "Carbon (II) oxide and sulphur (IV) oxide are generated from car exhausts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>45", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "Fats and oil can be obtained from any of the following sources except", "images": [], "options": {"A": "paraffin oil", "B": "animals", "C": "groundnuts", "D": "palm kernel"}, "answer": "A", "explanation": "Fats and oils are organic compounds that are naturally occurring in animals and plants. They are not obtained from paraffin oil. Paraffin oil, also known as mineral oil, is a by-product of petroleum. It is not a source of fats and oils.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2017>46", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "The condensation of two units of glucose will produce a disaccharide with the formula C12H22O11 which is", "images": [], "options": {"A": "sucrose", "B": "maltose", "C": "galactose", "D": "mannose"}, "answer": "B", "explanation": "C6H12O6 + C6H12O6 → C12H22O11  C12H22O11 → Maltose  C6H12O6 → Glucose", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>47", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The IUPAC name for the compound ClCH2CH2OH is", "images": [], "options": {"A": "1-chloropropanol", "B": "2-chloropropanol", "C": "1-chloroethanol", "D": "2-chloroethanol"}, "answer": "D", "explanation": "ClCH2CH2OH ------------ *    The functional group is -OH, hence it is an alkanol  It has a chlorine atom on the second carbon (counting from Right to Left), hence it is 2-chloro.  The longest continuous carbon chain is 2, hence, it is an \"eth\"  ∴ The name of the given compound is 2 - chloroethanol", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2017>48", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "The real harmful effect of the release of chloroflorocarbons into the atmosphere is that it eventually causes", "images": [], "options": {"A": "excessive ultraviolet light from the sun to reach the earth surface", "B": "excessive release of infrared light from the sun to the earth surface", "C": "corrosive effect of the chemicals on human and animals", "D": "acidic effect of chemicals on humans"}, "answer": "A", "explanation": "An excessive release of chlorofluorocarbon damages the ozone layer, and, hence increases the penetrating strength of ultraviolets coming from the sun.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2017>49", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "A primary alkanol has a molecular mass of 60. What is the structural formula of the compound?[C=12.0, H=1.0, O=16.0]", "images": ["Chemistry/imgs/2017/pix49a.png", "Chemistry/imgs/2017/pix49b.png", "Chemistry/imgs/2017/pix49c.png", "Chemistry/imgs/2017/pix49d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "Alkanols have the formula CnH2n+1OH  12n + (1 x (2n + 1)) + 16  + 1=60  12n + 2n + 1 + 16  + 1=60  14n + 18 =60  14n =60 - 18  14n=42  n=42/14  n=3  The alkanol is C3H7OH", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2017>50", "subject": "Chemistry", "year": "2017", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Petroleum is a non-renewable source of energy because it", "images": [], "options": {"A": "is formed naturally", "B": "is cheap", "C": "can be recycled after use", "D": "cannot be regenerated once used up"}, "answer": "D", "explanation": "Petroleum is considered a non-renewable source of energy because it cannot be regenerated once used up. Non-renewable resources are those that do not replenish in a short period of time. The process of formation of petroleum takes millions of years, involving the decomposition of dead organisms under high pressure and temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>1", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following raw materials is used in the plastic industry?", "images": [], "options": {"A": "ethene", "B": "methane", "C": "sulphur", "D": "hydrogen"}, "answer": "A", "explanation": "Ethene is useful in the plastic industry for the production of polythene which is a major component of plastic material    However, most plastics are made from petrochemicals including natural gas. Plastics are organic materials that contain such elements as carbon (C), hydrogen (H), nitrogen (N) chlorine (Cl) and sulfur (S). They are made from raw materials such as oil, natural gas and coal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>2", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : BENZENE", "question": "Which of the following organic compounds can undergo both addition and substitution reactions?", "images": [], "options": {"A": "pentane", "B": "benzene", "C": "propane", "D": "hexane"}, "answer": "B", "explanation": "Benzene can undergo both addition and substitution reactions. An addition reaction is a reaction in which atoms or groups of atoms are added to a molecule, while a substitution reaction is a reaction in which one atom or group of atoms in a molecule is replaced by another atom or group of atoms. Benzene, due to its aromatic nature, can undergo electrophilic substitution reactions. However, under certain conditions, it can also undergo addition reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>3", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Which of the following equations represents a redox reaction?", "images": [], "options": {"A": "AgNO3(aq)+KCI(ag) → AgCI(S) + KNO3(aq)", "B": "HNO3(aq)+NaOH(ag) → NaNO3(aq) + H2O1", "C": "CaCO(S) → CaO(S) + CO2(g)", "D": "2H2S(g)+SO2(g)→2H2 O1 + 3S(g)"}, "answer": "D", "explanation": "In option, the oxidation number of sulphur in hydrogen sulphide is -2; this is oxidized to zero (0) in 3s. Also the oxidation number of sulphur in SO2 is +4, therefore this is reduced to zero (0) in 3s.       ≕ 2H2S + SO2  →   3S + 2H2O         R.A             O.A", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>4", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The process of extracting of iron from its ore is", "images": [], "options": {"A": "decomposition", "B": "oxidation", "C": "reduction", "D": "sublimation"}, "answer": "C", "explanation": "Iron is extracted from its ore by reduction    Iron is extracted from iron ore in a huge container called a blast furnace. Iron ores such as haematite contain iron(III) oxide, Fe 2O 3. The oxygen must be removed from the iron(III) oxide in order to leave the iron behind. Reactions in which oxygen is removed are called reduction reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>5", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "What is the solubility of z salt if 0.4g of it is obtained on evaporating 200cm3 of its saturated solution to dryness?", "images": [], "options": {"A": "0.08 gdm-3", "B": "2.00 gdm-3", "C": "8.00gdm-3", "D": "80.00gdm-3"}, "answer": "B", "explanation": "Parameters given:  Mass of salt = 0.4g  Volume of solution = 200cm3 = 0.2dm3  Solubility = unknown     Recall: Solubility=mass of solutevolume of solution  ∴ Solubility=0.40.2   =2.00gdm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>6", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "An acidic salt has", "images": [], "options": {"A": "a double anions in its aqueous solution", "B": "a single cation in its aqueous solution", "C": "hydrogen ions in its aqueous solution", "D": "hydrogen atoms in its aqueous solution"}, "answer": "C", "explanation": "Acidic salt usually undergoes hydrolysis to yield hydrogen ions in its aqueous solution    Acid salts are a class of salts that produce an acidic solution after being dissolved in a solvent. ... A half-neutralization occurs due to the remaining of replaceable hydrogen atoms from the partial dissociation of weak acids that have not been reacted with hydroxide ions (OH−) to create water molecules.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>7", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "A reaction is endothermic if the", "images": [], "options": {"A": "reaction vessel feels cool during the reaction", "B": "enthalpy change is negative", "C": "bond forming energy exceeds bond breaking energy", "D": "heat of formation of reactants exceeds heat of formation of products"}, "answer": "A", "explanation": "A reaction is said to be endothermic, if the heat content of the product is greater than that of the reactant. In this case, heat is usually absorbed by the system making the reaction vessel (surrounding) cool during the reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>8", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "In which of the following compounds does hydrogen form ionic compound ?", "images": [], "options": {"A": "CH4", "B": "HCI", "C": "NH3", "D": "NaH"}, "answer": "D", "explanation": "Hydrogen forms ionic compound when it goes into chemical bonding with metals e.g sodium in NaH (sodium hydride)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>9", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "Consider the following reaction equation: Br2 +2KI → 2KBr + I2, Bromine is reacting as", "images": [], "options": {"A": "an oxidizing agent", "B": "a reducing agent", "C": "an acid", "D": "a base"}, "answer": "A", "explanation": "Given the reaction below     Br2 + 2KI → 2KBr + I2  It should be noted that in Br2, the oxidation number of bromine is zero(0); this is reduced to -1 in KBr. It implies that bromine (Br2) is acting as an oxidizing agent since it is reduced in the chemical reaction above.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>10", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "An organic compound has the empirical formula CH2, If its molar mass is 42gmol-1, what is its molecular formula?   [H=1.0, C=12.0]", "images": [], "options": {"A": "C2 H4", "B": "C3 H4", "C": "C3 H6", "D": "C4 H8"}, "answer": "C", "explanation": "Parameters given:  empirical formula → CH2  Molar mass = 42gmol-1  Molecular formula = unknown    Recall :    a--- (empirical mass)n = Molecular mass ------(1)  b---(empirical formula)n= Molecular formula ------(2)    from (1)  (12+2(1))n=42  14n=42  n=3    from (2)  (CH2)3 = Molecular formula    → Molecula formula = C3H6 (propene)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>11", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Ethene is produced from ethanol by", "images": [], "options": {"A": "decomposition", "B": "hydrolysis", "C": "ozonolysis", "D": "dehydration"}, "answer": "D", "explanation": "Ethene is produced from ethanol by dehydration      C2H5OH(Ethanol) →H2SO4/1800C→C2H4(Ethene)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>12", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the following equilibrum reaction.    2AB(g) + B2(g) ⇌ 2 AB3(g) ∆H = XKJmol-1    the backward reaction will be favoured by", "images": [], "options": {"A": "a decrease in pressure", "B": "an increase in pressure", "C": "a decrease in temperature", "D": "an introduction of a positive catalyst"}, "answer": "A", "explanation": "Given the reaction below:    2A B(g)+B2(g)  ⇌ 2AB 3(g) ∆H = -xKJmol-1    The backward reaction will be favoured by a reaction since we have more moles of gaseous reactant (3) than produce (2)", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2018>13", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is the mass of solute in 500cm3 of 0.005moldm-3 H2SO4?  [H=1.0, O=16.0 S= 32.0]", "images": [], "options": {"A": "0.490g", "B": "0.049", "C": "0.245", "D": "0.0245"}, "answer": "C", "explanation": "Parameters given:  Volume of solution = 500cm3 = 0.5dm3  Concentration of solution = 0.005 moldm-3  Number of moles = unknown  Mass of solute = unknown   Molar mass of H2SO4 = 98gmol-1  Recall:   CV =n -------(1)  ∴(0.005)(0.5)=n  n= 25 × 10 -4 moles  Recall :   n=mm.m-----(2)  ∴2.5×10-3g=m98  ⇒ m= 98×2.5×10-3  m=245 × 10-3g  m=0.245g", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>14", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "Pure water can be made to boil at a temperature lower than 0 by", "images": [], "options": {"A": "reducing it quantity", "B": "decrease the external pressure", "C": "distilling it", "D": "increasing the external pressure"}, "answer": "B", "explanation": "Pure water can be made to boil at a temperature lower than 100oC by decreasing the external(atmospheric) pressure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>15", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Consider the following sketch of the solubility curve of some substance    At what temperature does the solubility of KNO3 equal that of NaNO3?", "images": ["Chemistry/imgs/2018/k7.png"], "options": {"A": "00C", "B": "200C", "C": "300C", "D": "400C"}, "answer": "B", "explanation": "The solubility of KNO3 equals that of NaN03 at 20o C, because the temperature at which the two curves intercept is seen", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>16", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "When a salt added to its saturated solution, the salt", "images": [], "options": {"A": "dissolves and the solution becomes super saturated", "B": "dissolves and the solution remains unchanged", "C": "precipitates and the solution remains unchanged", "D": "dissolves and crystals are formed"}, "answer": "C", "explanation": "Since the solution is saturated, any salt added to it will form precipitate while the solution remains unchanged.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>17", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKYNES", "question": "When substance X was added to a solution of bromine water, the solution becomes colourless. X is likely to be", "images": [], "options": {"A": "propane", "B": "propanoic acid", "C": "propyne", "D": "propanol"}, "answer": "C", "explanation": "Bromine water is used as a test for unsaturated hydrocarbons, such as alkenes and alkynes. When an unsaturated hydrocarbon is added to bromine water, the solution becomes colourless. This is because the bromine reacts with the carbon-carbon double or triple bond, forming a dibromo compound and decolourising the solution. Therefore, substance X is likely to be propyne, which is an alkyne with a carbon-carbon triple bond.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>18", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The preferential discharge of ions during electrolysis is influenced by the", "images": [], "options": {"A": "mechanism of electrolysis", "B": "electrolytic reactions", "C": "nature of the electrode", "D": "type of electrolytic cell"}, "answer": "C", "explanation": "The preferential discharge of ions during electrolysis is influenced by:  - Nature of electrode  - Concentration of the electrolyte  - Position of ions in the electrochemical series", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>19", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The valence eletrons of 12Mg are in the", "images": [], "options": {"A": "3s orbital", "B": "2px orbital", "C": "2s orbital", "D": "1s orbital"}, "answer": "A", "explanation": "The electronic configuration of magnesium is given below:  1s2 2s2 2P6 3S2    ⇒ the valence electrons of 12Mg are in the 3S orbital", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2018>20", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "An organic compound contains 40.0% carbon, 6.7% hydrogen and 53.3% oxygen. What is the empirical formula of the compound?  [O = 16.0, C = 12.0, H = 1.0]", "images": [], "options": {"A": "C2HO", "B": "CHO", "C": "CH2O", "D": "CHO2"}, "answer": "C", "explanation": "Given:  The percentage compositions of carbon, Hydrogen and oxygen respectively: 40.0%, 6.7% and 53.3% in a compound. The empirical formula of the compound is unknown.    ∴ the empirical formulas CH2O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>21", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The number of hydrogen ions in 1.0dm3 of 0.02moldm-3 tetraoxosulphate(VI) acid is  [NA=6.02 × 1023]", "images": [], "options": {"A": "1.2 ×1022", "B": "1.2 × 1023", "C": "2.4 × 1022", "D": "2.4 × 1023"}, "answer": "C", "explanation": "Parameters given:    Volume of solution = 1.0dm3  Concentration of solution = 0.02 moldm-3  Number of moles (n) = unknown  Number of particles, H+ = ?    The ionization of H2SO4 is given:  H2SO4 → 2H+ + SO42-    Recall: n=cv ------(1)  ∴ n=(0.02)(1.0)  n=0.02 moles    1-----2 H+  0.02 ------- x  x=0.04H+    Recall:   n=NpNA    0.04=NP6.02×1023    NP = 6.02 × 1023 × 0.04   NP = 6.02 × 4×10-2×1023  NP = 24.08×1021  NP = 2.408 ×1022", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2018>22", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "The most suitable substance for putting out petrol fire is", "images": [], "options": {"A": "water", "B": "carbon(IV)oxide", "C": "fire blanket", "D": "sand"}, "answer": "B", "explanation": "Carbon (IV) oxide does not support combustion. This is why it is used in the manufacture of fire extinguisher", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>23", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "The following factors would contribute to enviromental pollution except", "images": [], "options": {"A": "production of amonia", "B": "manufacture of cement", "C": "photosynthesis", "D": "combustion"}, "answer": "C", "explanation": "Photosynthesis does not contribute to environmental pollution because it produces oxygen (O2) as a by product which is used by animals for respiration, it should also be noted that photosynthesis makes use of CO2, thereby reducing the level of CO2 in the atmosphere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>24", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "The position of equilibrium in a reversible reaction is affected by", "images": [], "options": {"A": "particle size of the reactant", "B": "vigorous stirring of the reaction mixture", "C": "presence of a catalyst", "D": "change in concentration of reactant"}, "answer": "D", "explanation": "The position of the Equilibrium in reversible reaction is affected by :    a. change in concentration of reactants  b. change in pressure (if gaseous)  c. change in temperature    NB: Addition of catalyst does not affect the position of Equilibrium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>25", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "In which of the following experimental set-ups would the rate of evolution of hydrogen gas be fastest?", "images": ["Chemistry/imgs/2018/chem2.png", "Chemistry/imgs/2018/chem3.png", "Chemistry/imgs/2018/chem4.png", "Chemistry/imgs/2018/chem5.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "An higher surface Area increases the rate of chemical reaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2018>26", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following statement best explains the differences between a gas and a vapour?", "images": [], "options": {"A": "unlike gases, vapours are liquids at room temperature", "B": "unlike gases, vapour can easily be condensed into liquids", "C": "unlike gases, vapour is readily converted into solids", "D": "vapours are generally denser than gases"}, "answer": "D", "explanation": "It should be noted that vapours are generally denser than gases.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2018>27", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Consider the following reaction equations: 2HCI + Ca(OH)2→CaCI2H2O. What is the volume of 0.1moldm-3. HCI that would completely neutralize 25cm3 of 0.3  moldm-3 Ca(OH)?", "images": [], "options": {"A": "150cm3", "B": "75 cm3", "C": "30cm3", "D": "25 cm3"}, "answer": "A", "explanation": "Given: The equation below   2HCI + Ca(OH)2 → CaCI2 + 2H2O  Recall:   CAVACBVB=nAnB  0.1 × VA0.3 × 2.5=21  0.1VA = 2 ×7.5  0.1VA = 15  VA= 150cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>28", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "Cu and HNO3 are not suitable for preparing hydrogen gas because of their", "images": [], "options": {"A": "reactivity and oxidation respectively", "B": "conductivity and corrosiveness respectively", "C": "melting point and reduction respectively", "D": "electronegativity and solubility respectively"}, "answer": "A", "explanation": "CU and HNO3 are not suitable for preparing hydrogen gas because of their reactivity and oxidation respectively. It should be noted that CU is less reactive than hydrogen, hence it cannot displace hydrogen in any chemical reaction.    Also, HNO3 is a strong oxidizing agent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>29", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Which of the following metals is the strongest reducing agent?", "images": [], "options": {"A": "Sodium", "B": "Silver", "C": "Potassium", "D": "Copper"}, "answer": "C", "explanation": "Reducing ability down the group (Increases) and across the period (decreases). Therefore, Potassium (K) is a strong reducing agent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>30", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CRITERIA FOR PURITY", "question": "One of the criteria for confirming the purity of benzene is to determine its", "images": [], "options": {"A": "heat capacity", "B": "boiling point", "C": "mass", "D": "colour"}, "answer": "B", "explanation": "The purity of a substance can be confirmed by determining its boiling point. Pure substances have a specific boiling point. If the boiling point of the substance matches the known boiling point of benzene, then it can be confirmed that the benzene is pure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>31", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "When chlorine is passed through a sample of water, the pH of the water sample would be", "images": [], "options": {"A": "", "B": "> 7", "C": "= 7", "D": "0"}, "answer": "A", "explanation": "Given: the information in the question     H2O + CL2 → HOCL(hypochlorous acid) + HCL(hydrochloric acid)    Therefore, the resulting solution is acidic i.e PH", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>32", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many atoms are contained in 0.2 moles of nitrogen?  [NA = 6.02× 1023 ]", "images": [], "options": {"A": "1.20× 1022", "B": "2.41× 1022", "C": "3.62× 1022", "D": "4.82× 1022"}, "answer": "A", "explanation": "Parameters given:  Number of moles = 0.2 moles  Avogadro's number, NA = 6.02 × 1023  Number of atoms = unknown    Recall:   no of moles=No of particlesAvogadro Numbers    ⇒0.2=NP6.02×1023  ∴ 1.204 × 1022 atoms", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>33", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Consider the reaction represented by the following equation:  CuOs + H2SO4(aq) → CuSO4(aq) + H2O(l)   Which of the following factors will not affect the rate of the reaction?", "images": [], "options": {"A": "Particle size CuO(s)", "B": "Concentration of H2SO4(aq)", "C": "Temperature of the reacting mixture", "D": "Pressure of reaction system"}, "answer": "D", "explanation": "The rate of a chemical reaction can be influenced by the particle size of the reactants, the concentration of the reactants, and the temperature of the reaction mixture. However, the pressure of the reaction system will not affect the rate of the reaction in this case because the reaction does not involve any gases. Therefore, changing the pressure will not affect the frequency or energy of collisions between particles, which are the key factors that determine the rate of a reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>34", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following organic compounds could be represented by the empirical formula CH2O?", "images": [], "options": {"A": "Ethanal", "B": "Ethane", "C": "Ethanol", "D": "Ethanoic acid"}, "answer": "A", "explanation": "The empirical formula of a compound is the simplest whole number ratio of atoms of each element in a compound. The empirical formula CH2O represents a compound with one carbon atom, two hydrogen atoms, and one oxygen atom. Ethanal (also known as acetaldehyde) has the molecular formula C2H4O, which can be simplified to the empirical formula CH2O. The other options (ethane, ethanol, and ethanoic acid) do not have this empirical formula.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>35", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "The empirical formula of a compound containing 0.067 mol Cu and 0.066 mol O is   [Cu= 63.5, O=16.0]", "images": [], "options": {"A": "Cu2O", "B": "CuO", "C": "CuO2", "D": "Cu2O2"}, "answer": "B", "explanation": "Parameters given:    No of moles of oxygen (O) = 0.066mol  No of moles of copper (Cu)= 0.067mol  mole ratio of Cu to 0 = 1.1  ⇒ The empirical formula of the compound  = CuO", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>36", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "When NH4Cl(s) is dissolved in water, the container feels cold to touch. This implies", "images": [], "options": {"A": "the process is endothermic", "B": "this is exothermic", "C": "NH4Cl forms a saturated solution", "D": "NH4Cl is highly soluble in water"}, "answer": "A", "explanation": "When NH4Cl is dissolved in water, the container feels cold to touch because the process is endothermic. An endothermic process is one that absorbs heat from its surroundings. This is why the container feels cold to touch, as heat is being absorbed from the surroundings (including your hand) into the solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>37", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following methods can be used to separate blood cells from plasma?", "images": [], "options": {"A": "centrifugation", "B": "filtration", "C": "chromatography", "D": "distillation"}, "answer": "A", "explanation": "Centrifugation is the method that can be used to separate blood cells from plasma. This is because centrifugation separates substances based on their densities. When blood is centrifuged, the denser blood cells are forced to the bottom of the centrifuge tube, while the less dense plasma remains on top.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>38", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following about ionic radius is correct? Ionic radius", "images": [], "options": {"A": "increase as nuclear charge increase", "B": "decrease as nuclear charge increase", "C": "decrease as nuclear charge decreases", "D": "remains constant as nuclear charge increases"}, "answer": "B", "explanation": "Ionic radius decreases as nuclear charge increases. This is because as the nuclear charge (the charge of the nucleus, or the number of protons) increases, the electrons are pulled closer to the nucleus, causing the ionic radius (the size of the ion) to decrease.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>39", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "Analysis of a hydrocarbon shows that it contains 0.93g of carbon per gram of the compound. The mole ratio of carbon to hydrogen in the compound is [H=1.0, C=12.0]", "images": [], "options": {"A": "1:1", "B": "1:2", "C": "2:1", "D": "2:3"}, "answer": "A", "explanation": "Given: the information in the question   In 1g of the  hydrocarbon, there is 0.93g of carbon   N.B: A hydrocarbon is an organic compound which is composed of carbon and hydrogen only.    Ig = 0.93 + hydrogen   ∴ mass of hydrogen = 0.07g    carbon(C) Hydrogen(H)mass(g) 0.93 0.07no of moles=mass/molar mass 0.93/12 0.07/1mole ratio 0.070.07mole ratio 1 1   From the mole ratio (1:1), the empirical formula is CH", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>40", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "The law of definite proportions states that", "images": [], "options": {"A": "pure samples of substances are in the same proportion by mass", "B": "pure samples of substances are not in the same proportion by mass", "C": "chemical compounds are pure because they contain the same elements", "D": "matter can neither be created or destroyed"}, "answer": "A", "explanation": "The law of definite proportion or constant composition states that all pure samples of a chemical compound contains the same elements in the same proportion by mass", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>41", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "What is relative molecular mass of a compound which has empirical formula CH2O?  [H=1.0, C=12.0, O=16.0]", "images": [], "options": {"A": "42", "B": "45", "C": "126", "D": "180"}, "answer": "D", "explanation": "Parameters given:  Empirical formula: CH2O    N.B: The empirical mass = 30g mol-1, it implies that the molecular mass will be a multiple of 30, the most plausible option is 180gmol-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>42", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "Atoms are electrically neutral because they", "images": [], "options": {"A": "they do not conduct electricity", "B": "contain equal number of protons and electrons", "C": "are composed of neutrons and electrons", "D": "cannot be attracted by electromagnetic field"}, "answer": "B", "explanation": "Atoms are electrically neutral because they contain an equal number of protons and electrons. Protons carry a positive charge and electrons carry a negative charge. When the number of protons and electrons are equal, their charges cancel out, making the atom electrically neutral.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>43", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CRITERIA FOR PURITY", "question": "Common  salt (NaCI) is used for preserving foods. Which of the following properties could be used to determine its purity before use?", "images": [], "options": {"A": "solubility in water", "B": "melting point", "C": "relative density", "D": "crystalline nature"}, "answer": "B", "explanation": "The purity of a substance can be determined by its melting point. A pure substance has a specific melting point. If the substance is impure, its melting point will be lower than the expected value and the melting range will be broader. Therefore, the melting point of common salt (NaCl) can be used to determine its purity before use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>44", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "Which of the following electrons configuration represents the transition element chromium(24Cr)?", "images": [], "options": {"A": "1S2 2S2 2P6 3S2 3P6 4S2 3d1", "B": "1S2 2S2 2P6 3S2 3P6 3d6", "C": "1S2 2S2 2P6 3S2 3P4 4S1", "D": "1S2 2S2 2P6 3S2 3P6 4S1 3d5"}, "answer": "D", "explanation": "The electron configuration of chromium (24Cr) is 1S2 2S2 2P6 3S2 3P6 4S1 3d5. This is because chromium is a transition metal and it prefers to half-fill or completely fill its d-orbital. Therefore, one electron from the 4s orbital is promoted to the 3d orbital, resulting in a half-filled 3d orbital, which is more stable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2018>45", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The atomic number of an isotope of hydrogen is equal to its mass number because it", "images": [], "options": {"A": "has a totally filled valence shell", "B": "has a higher charge to mass ratio", "C": "does not contain neutrons", "D": "exhibits isotopy"}, "answer": "C", "explanation": "The atomic number of an isotope of hydrogen is equal to its mass number because it does not contain neutron. It should be noted that this isotope is called protium (11H)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>46", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The number of shared pair of electrons in the compound below is", "images": ["Chemistry/imgs/2018/chem201846.png"], "options": {"A": "5", "B": "6", "C": "10", "D": "12"}, "answer": "B", "explanation": "The compound given is a covalent compound, which is formed by the sharing of electron pairs by the participating atoms.    N.B Each line in the lewis structure of any covalent compound represents  a shared electrons pair.         The compound given has 6 lines, hence 6 shared pair of electrons.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2018>47", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The bonding pair of electrons in a hydrogen chloride molecule is pulled towards the chlorine atom because", "images": [], "options": {"A": "chlorine has a larger atomic size", "B": "chlorine has a larger atomic mass", "C": "chlorine is more electronegative", "D": "there is no bonding orbitals within the hydrogen atom"}, "answer": "C", "explanation": "The bonding pair of electrons in a hydrogen chloride molecule is pulled towards the chlorine atom because chlorine is more electronegative. Electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. The more electronegative atom attracts the bonding pair of electrons more towards itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>48", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "The solubility of CO2 in water can be accounted for by", "images": [], "options": {"A": "van der waal's force", "B": "ionic attraction", "C": "dipole attraction", "D": "covalent bonding"}, "answer": "A", "explanation": "The solubility of CO2 in water can be accounted for by Van der Waal's forces.  N.B: Van der Waal's forces (London Dispersion force to be precise) makes non polar compounds soluble in water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2018>49", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Which of the following properties would not influence electrovalent bond formation?", "images": [], "options": {"A": "electronegativity", "B": "electron affinity", "C": "ionization potential", "D": "catalytic ability"}, "answer": "D", "explanation": "Electrovalent bond formation is influenced by electronegativity, electron affinity, and ionization potential. These properties determine how easily an atom can gain or lose electrons to form ions, which then bond together to form an ionic or electrovalent compound. Catalytic ability, on the other hand, is a property that influences the rate of a chemical reaction but does not directly influence the formation of electrovalent bonds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2018>50", "subject": "Chemistry", "year": "2018", "type": "Objective", "topic": "STATES OF MATTER : KINETIC THEORY OF MATTER.", "question": "Particles in a solid exhibit", "images": [], "options": {"A": "vibrational motion only", "B": "vibrational and translational", "C": "vibrational and random motion", "D": "random and translational motion"}, "answer": "A", "explanation": "Molecular motion for the particles in a solid is confined to very small vibrations of the atoms around their fixed positions; therefore, solids have a fixed shape that is difficult to change. Solids also have a definite volume; that is, they keep their size no matter how you try to change them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>1", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC LAW", "question": "The periodic table is an arrangement of elements according to their", "images": [], "options": {"A": "oxidation number", "B": "atomic number", "C": "mass number", "D": "number of neutrons"}, "answer": "B", "explanation": "According to the modern periodic law which states that \"the properties of the elements are periodic functions of their atomic number\". This is the modification to Mendeleev's law  by Henry Moseley since atomic number is the only unique property distinguishing an element from another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>2", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "A solid substance with high melting and boiling points is likely to be", "images": [], "options": {"A": "a covalent compound.", "B": "a dative covalent compound.", "C": "an electrovalent compound.", "D": "a non-metal."}, "answer": "C", "explanation": "Characteristics of electrovalent compounds   - They have high melting point  - They have high boiling point  - They are soluble in water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>3", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Which of the following metals reacts slowly with cold water?", "images": [], "options": {"A": "Iron", "B": "Silver", "C": "Calcium", "D": "Potassium"}, "answer": "C", "explanation": "Calcum reacts slowly with cold water and rapidly with warm water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>4", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following elements has the highest ionization energy?", "images": [], "options": {"A": "Calcium", "B": "Chlorine", "C": "Fluorine", "D": "Magnesium"}, "answer": "C", "explanation": "ionization energy is the energy required to remove an electron from a neutral atom to form a positively charged ion. It increases across the period and decreases down the group. It is easier to remove an electron from group I element than to remove from group 7.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>5", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The bleaching action of chlorine is through the process of", "images": [], "options": {"A": "hydration", "B": "hydrolysis", "C": "reduction", "D": "oxidation"}, "answer": "D", "explanation": "Chlorine reacts with water to form hydrochloric acid and hypochlorous acid.  Cl2 + H2O → HCl + HClO  Chlorine acts with water to produce nascent oxygen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>6", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "If 6.5g of magnesium ribbon reacts completely with hydrochloric acid, how many grams of hydrogen gas would be liberated?  Mg(s) + 2HCl(aq) → MgCl2(aq) + H2(g)  [H = 1.0, Mg = 24.0]", "images": [], "options": {"A": "0.54g", "B": "0.70g", "C": "1.08g", "D": "1.40g"}, "answer": "A", "explanation": "Mg + 2HCl → MgCl2 + H2  1 &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp 2 &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp 1 &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp 1  1 mole of Mg → 1 mole of H2  No.ofmoleofMg=mass of Mgmolar mass of Mg  mass, m = 6.5g  Molar mass of Mg = 24.0gmol-1  NoofmoleofMg=6.524 = 0.271 mol  1 mole of Mg → 1 mole of H2  0.271mol of Mg → x  x = 0.271 mole of H2  Molar mass of H2 = 1× 2 = 2 gmol-1  NoofmoleofH2=mass of H2molar mass of H2  0.271=m2  m = 2 × 0.271 = 0.542g of H2", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2019>7", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Calcium and magnesium belong to the same group of the periodic table because both", "images": [], "options": {"A": "are metals.", "B": "form cations.", "C": "form colourless salts.", "D": "have same number of valence electrons."}, "answer": "D", "explanation": "Valence electron is the electron in the outermost shell of an element and this determines the group an element belong. 20Ca - 2, 8, 8, 2 and 12Mg - 2, 8, 2 both have two electrons in their valence shell, hence, they both belong to the group 2 of the periodic table.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>8", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following substances is non-polar?", "images": [], "options": {"A": "Br2", "B": "NH3", "C": "H2O", "D": "HBr"}, "answer": "A", "explanation": "The difference in the electronegativity of the elements in a compound determines if it is polar or non polar. Polar compounds have slight charges (slightly positive and slightly negative) within the compounds. Non polar compounds have the electronegativities of the two elements equal. NH3, H2O and HBr have slightly positive and slightly negative charges while Br2 only has negative charge, hence, it is non polar.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>9", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following pairs of components have the same molecular mass?  [H = 1.0, C = 12.0, O = 16.0]", "images": [], "options": {"A": "Ethene and ethyne", "B": "Ethane and ethene", "C": "Carbon (II) oxide and ethene", "D": "Carbon (IV) oxide and ethyne"}, "answer": "C", "explanation": "Firstly, determine the molecular mass of each compound.  Ethene: C2H4  (12 × 2) + (1 × 4)  24 + 4  ⇒ 28gmol-1    Ethyne: C2H2  (12 × 2) + (1 × 2)  24 + 2  ⇒ 26gmol-1    Carbon II oxide: CO  12 + 16  ⇒ 28gmol-1    Carbon IV oxide: CO2  12 + (16 × 2)  12 + 32  44gmol-1    Ethane: C2H6  (12 × 2) + (1 × 6)  24 + 6  30gmol-1    It can be seen that only ethene and carbon II oxide that have the same molecular mass i.e 28gmol-1 each.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>10", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "When an equilibrium is established between dissolved and undissolved solutes, the solution is said to be", "images": [], "options": {"A": "saturated", "B": "unsaturated", "C": "concentrated", "D": "dilute"}, "answer": "A", "explanation": "A saturated solution is a solution that dissolves until it is unable to dissolve anymore, leaving the undissolved substance at the bottom. Hence, there is equilibrium dissolved and undissolved solutes in the solution.  An unsaturated solution has less solute than the saturated solution. Hence, it still has ability to still dissolve more of the solute.  A supersaturated solution contains more undissolved solute than the saturated solution.  A concentrated solution contains more solute than the solvent while a dilute solution contains more solvent than the solute.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>11", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many moles of carbon (IV) oxide contains 16.0g of oxygen?  [C = 12.0, O = 16.0]", "images": [], "options": {"A": "0.20 mol", "B": "0.25 mol", "C": "0.40 mol", "D": "0.50 mol"}, "answer": "D", "explanation": "Mass of O2 = 16g  Molar mass of O2 = 16 × 2 = 32gmol-1  No.ofmoleofO2=massmolar mass  =1632 = 0.5mol of O2  1 mole of CO2 → 1 mole of O2  y → 0.5mole of O2  y = 0.5mole of CO2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>12", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "Stoichiometry is based on the law of", "images": [], "options": {"A": "multiple proportion.", "B": "constant composition.", "C": "conservation of energy.", "D": "conservation of mass."}, "answer": "D", "explanation": "Stoichiometry is a section of chemistry that involves using the relationships between reactants and/or product in a chemical reaction to determine desired quantitative data. It is based on the law of conservation of mass, which states that matter is neither creaed nor destroyed in a chemical reaction. Every chemical reaction has the same elements in its reactants and product.  This explains why chemical reactions are usually balanced e.g 2Na + 2HCl → 2NaCl + H2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>13", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "What is the percentage by mass of hydrogen in CH3COOH?  [CH3COOH = 60]", "images": [], "options": {"A": "1.7%", "B": "5.0%", "C": "6.7%", "D": "7.1%"}, "answer": "C", "explanation": "Mass of CH3COOH: 60  Mass of Hydrogen: 4g [since there are four hydrogen atoms in the compound]  %bymass=460×100  =203=6.67%", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>14", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "Which of the following compounds has coordinate bonds in its structure?", "images": [], "options": {"A": "Al2Cl6", "B": "MgCl2", "C": "AgCl", "D": "NaCl"}, "answer": "A", "explanation": "In Al2Cl6, each aluminum atom is surrounded by four chlorine atoms. Two of these chlorine atoms form coordinate bonds with the other aluminum atom, resulting in a structure where coordinate bonds are present. MgCl2, AgCl and NaCl are all ionic  compounds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>15", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "The name of the compound CH3C(CH3)2CH2CH2CH3 is", "images": [], "options": {"A": "2 - methyl butane", "B": "2, 2- dimethyl butane", "C": "2 - methyl pentane", "D": "2, 2- dimethyl pentane"}, "answer": "D", "explanation": "CH3C(CH3)2CH2CH2CH3    There are five longest carbon - carbon continuous chain. Two methyl are on the second carbon if counted from the left and fourth carbon if counted from the right, but shorter number is chose.  Name: 2, 2 -dimethylpentane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>16", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "The properties of a good primary standard include the following except", "images": [], "options": {"A": "high molecular mass", "B": "low molecular mass", "C": "high degree of purity", "D": "readily available"}, "answer": "B", "explanation": "A primary standard is a reference chemical used to measure an unknown concentration of another known chemical. A primary standard is of known purity ans stability that can be measured accurately and used in its entirety requiring no additional measurement. It must be water soluble, and have high molar mass in order to minimize error.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>17", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "What is the solubility of a salt X at 25°C if the saturated solution of the salt contains 0.28g in 100cm3 of solution?  [X = 56.0g]", "images": [], "options": {"A": "0.05 moldm-3", "B": "0.10 moldm-3", "C": "2.60 moldm-3", "D": "2.80 moldm-3"}, "answer": "A", "explanation": "mass, m = 0.28g  Volume,V=1001000=0.1dm3  NoofmoleofX=massMolar Mass  =0.2856=0.005mol  SolubilityofX=no of molevolume  =0.0050.1 = 0.05 moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>18", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Vinegar is an aqueous solution of", "images": [], "options": {"A": "hydrochloric acid", "B": "ethanedioic acid", "C": "ethanoic acid", "D": "hydrofluoric acid"}, "answer": "C", "explanation": "Vinegar is an aqueous solution of ethanoic acid. Ethanoic acid, also known as acetic acid, is the main component of vinegar apart from water. It gives vinegar its characteristic sour taste and pungent smell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>19", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Which of the following solutions containing one mole per dm3 of the compound would have the lowest pH?", "images": [], "options": {"A": "Ethanoic acid", "B": "Hydrochloric acid", "C": "Sodium chloride", "D": "Sodium hydrogentrioxocarbonate (IV)"}, "answer": "B", "explanation": "Acids have pH values less than 7 and bases have pH values greater than 7, and neutral compounds have pH of 7. The lower the value below 7, the more the acidity of the acid, while the more the value beyond 7, the more the basicity/alkalinity of the base. Only ethanoic acid and hydrochloric acid have their values less than 7. Since hydrochloric acid is stronger than ethanoic acid, then HCl has a lower pH value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>20", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A sample of air was bubbled into water. The pH of the water slowly changed from 7 to 6. Which of the following gases in the sample caused the change?", "images": [], "options": {"A": "Carbon (IV) oxide", "B": "Carbon (II) oxide", "C": "Nitrogen", "D": "Oxygen"}, "answer": "A", "explanation": "A pH of 6 is acidic CO2 is a component of air which when reacted with water forms a weak acid. It is an acid, anhydride. CO, N2 and Oxygen are neutral.  CO2 + H2O → H2CO3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>21", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "The most suitable indicator for the reaction between NaOH(aq) and HCOOH(aq) is", "images": [], "options": {"A": "bromocresol", "B": "methyl orange", "C": "methyl red", "D": "phenolphthalein"}, "answer": "D", "explanation": "NaOH is a strong base while HCOOH is a weak acid. A reaction between a weak acid and a strong base uses phenolphthalein as indicator.  The table below shows the indicator used during titration.  AcidBaseIndicatorStrong  Strong  Weak  WeakStrong  Weak  Strong  WeakAny suitable indicator  Methyl orange  Phenolphtalein  No suitable indicator", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>22", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "Consider the following reaction equation:  2Al(OH)3 + 3H2SO4 → Al2(SO4)3 + 6H2O.  How many moles of tetraoxosulphate (VI) acid is needed to produce 0.5 mol of aluminium tetraoxosulphate (VI)?", "images": [], "options": {"A": "0.5", "B": "1.0", "C": "1.5", "D": "3.0"}, "answer": "C", "explanation": "2Al(OH)3 + 3H2SO4 → Al2(SO4)3 + 6H2O  From the equation,  3 moles of H2SO4 → 1 mole of Al2(SO4)3  Then, x → 0.5 moles of Al2(SO4)3  x = 3 × 0.5 = 1.5 moles of H2SO4", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>23", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following pairs of substances has the highest heat of neutralization?", "images": [], "options": {"A": "Strong acid and strong base", "B": "Weak acid and weak base", "C": "Strong acid and weak base", "D": "Weak acid and strong base"}, "answer": "A", "explanation": "- The neutralization reaction between a strong acid and a strong base has the highest heat  of neutralization, which is -57.1kg/mol.    - For strong acid Vs Weak base, strong base Vs Weak acid and weak acid Vs weak base, it is always less than that.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>24", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "When quicklime dissolves in water,", "images": [], "options": {"A": "heat is absorbed", "B": "heat is evolved", "C": "oxygen is liberated", "D": "hydrogen is given off"}, "answer": "B", "explanation": "When quicklime (calcium oxide, CaO) is added to water, it forms calcium hydroxide (slaked lime) and a large amount of heat is released in the process. This is an exothermic reaction, meaning heat is evolved.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>25", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "If the value of ΔH is positive for a reaction, it means that the reaction is", "images": [], "options": {"A": "exothermic", "B": "endothermic", "C": "spontaneous", "D": "slow"}, "answer": "B", "explanation": "An endothermic reaction is a reaction that gains heat from the surrounding. Therefore, the heat of the product is greater than the heat of the reactant. Enthalpy change (ΔH) is the difference between the heat of the product (Hp) and the heat of the reactant (HR).  ΔH = HP - HR  Since HP > HR, then ΔH is positive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>26", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following compounds is formed by the oxidation of ethanol?", "images": [], "options": {"A": "C2H4CO2H", "B": "C2H5CO2H", "C": "CH3OH", "D": "CH3CO2H"}, "answer": "D", "explanation": "Ethanol is oxidized by sodium dichromate (Na2Cr2O7) acidified in dilute H2SO4 to form ethanol.    On further oxidation, ethanal is oxidized to ethanoic acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>27", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN CHLORIDE GAS", "question": "What is the characteristic of the gas liberated when dilute hydrochloric acid is added to iron (II) sulphide?", "images": [], "options": {"A": "Turns lime water milky", "B": "Decolorizes bromine water", "C": "Gives a pop sound", "D": "Turns lead (II) ethanoate paper black"}, "answer": "D", "explanation": "HCl + FeS → FeCl2 + H2S  Hydrochloric acid reacts with Iron II sulphide to give Iron II chloride and liberate hydrogen sulphide gas. H2S(g) reacts with lead ethanoate paper and turns it black as a result of the lead sulphide produced.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>28", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "An organic compound contains 72% carbon, 12% hydrogen and 16% oxygen by mass.   What is the empirical formula of the compound?  [H = 1.0, C = 12.0, O = 16.0]", "images": [], "options": {"A": "C3H8O", "B": "C6H12O", "C": "C6H12O2", "D": "C12H12O11"}, "answer": "B", "explanation": "CHO% by mass721216No of mole72/1212/116/166121  Emperical formula: C6H12O1  C6H12O", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2019>29", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "When excess chlorine is mixed with ethane at room temperature, the product formed is", "images": [], "options": {"A": "1, 2 - dichloroethane", "B": "1, 2 - dichloroethene", "C": "1, 1 - dichloroethane", "D": "1, 1 - dichloroethene"}, "answer": "C", "explanation": "C2H6 + Cl2 → C2H4Cl    1, 1 - dichloroethane", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>30", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following reagents could be used to distinguish between propan-1-ol and propan-2-ol?", "images": [], "options": {"A": "H+/K2Cr2O7", "B": "I2OH-", "C": "CH3COOH", "D": "NaCl"}, "answer": "A", "explanation": "With acidified potassium dichlorate H+/K2Cr2O7, propan - 1 - ol forms propanal   CH3CH2CH2OH + [ O ] → CH3CH2CHO + H2O  Propan-2-ol forms propanone  CH3CH(OH)CH3 + [ O ] → CH3COCH3 + H2O", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>31", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "If a catalyst is added to a system at equilibrium and the temperature and pressure remain constant, there would be no effect on the", "images": [], "options": {"A": "activation energy of the reaction.", "B": "rate of the forward reaction.", "C": "rate of the reverse reaction.", "D": "heat of reaction."}, "answer": "D", "explanation": "Catalyst doesn't affect the overall enthalpy of the reaction. It doesn't affect the energy of the reaction or the product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>32", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Consider the following reaction equation:  3CL2 + 2NH3 → N2 + 6HCl.  NH3 is acting as", "images": [], "options": {"A": "a reducing agent", "B": "a dehydrating agent", "C": "a drying agent", "D": "an oxidizing agent"}, "answer": "A", "explanation": "Removal of hydrogen is oxidation Hydrogen is removed from NH3 to form N2.  Hence, NH3 is a reducing agent. A reducing agent reduces other substance but itself gets oxidized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>33", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "The oxidation number of chromium in Cr2O72- is", "images": [], "options": {"A": "+ 4", "B": "+ 5", "C": "+ 6", "D": "+ 7"}, "answer": "C", "explanation": "Cr2O72-  The oxidation state of a radical is the charge on the radical, and that of Cr2O72- is -2.  The oxidation number of oxygen is -2  Cr2O72-  (Cr × 2) + (-2 × 7) = -2  2Cr + (-14) = -2  2Cr = -2 + 14  2Cr = 12  Cr=122=+6", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>34", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "The process by which alkanoic acid reacts reversibly with alkanols is known as", "images": [], "options": {"A": "saponification", "B": "esterification", "C": "carboxylation", "D": "halogenation"}, "answer": "B", "explanation": "Esterification is a reaction between alcohol and alkanoic acid in the presence of H2SO4 to give ester. It is a reversible reaction catalysed by acid.  ROH + RCOOH → RCOOR + H2O  where,  ROH - alcohol  RCOOH - alkanoic acid  RCOOR - ester  H2O - water  CH3COOH + C2H5OH → CH3COOC2H5 + H2O", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>35", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "If the oxidation potential of Mg and Al are +2.37 volts and +1.66 volts respectively, then Mg would", "images": [], "options": {"A": "not replace Al.", "B": "be replaced by Al.", "C": "remain in the solution.", "D": "replace Al."}, "answer": "D", "explanation": "Magnesium is more reactive than Aluminium in the activity series i.e it is higher than Aluminium in the series, hence, Magnesium will replace/displace Aluminium in a chemical reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>36", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the reaction represented by the following equation:  2SO2(g) + O2(g) ⇋ 2SO3(g)  A decrease in pressure of the reaction would", "images": [], "options": {"A": "decrease the concentration of SO2", "B": "have no effect on the reaction", "C": "shift the equilibrium position to the left", "D": "shift the equilibrium position to the right"}, "answer": "C", "explanation": "2SO2(g) + O2(g) ⇋ 2SO3(g)  An increase in pressure favours a side with lower number of moles of gases, while a decrease in pressure favours a side with higher number of moles of gases. Therefore, a decrease in pressure will shift the equilibrium position to the left (a side with higher number of moles of gaseous molecules) to favour more of production of SO2(g) and O2(g)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>37", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "In a mixture of gases which do not react chemically together, the pressure of the individual gas is", "images": [], "options": {"A": "atmospheric pressure", "B": "vapour pressure", "C": "total pressure", "D": "partial pressure"}, "answer": "D", "explanation": "Dalton's law of partial pressure states that for a mixture of gases which do not react chemically together, the total pressure exerted is equal to the sum of the partial pressures of the individual gases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>38", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Biotechnology is applied in the", "images": [], "options": {"A": "treatment of sewage", "B": "treatment of water", "C": "purification of chemicals", "D": "purification of metals"}, "answer": "A", "explanation": "Biotechnology is the use of living systems and organisms to develop or make products. It is applied in various fields including the treatment of sewage. In sewage treatment, biotechnology is used to degrade the organic matter present in the sewage, such as human waste, soaps and food waste, into harmless byproducts. This is usually done by using bacteria and other microorganisms to break down the organic matter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>39", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following organic compounds has the lowest boiling point?", "images": [], "options": {"A": "C6H14", "B": "C5H12", "C": "C4H10", "D": "(CH3)3CH"}, "answer": "D", "explanation": "Boiling point of members of a homologous series increases down the group i.e increases with increase in number of carbon. (CH3)3CH is a methane compound which is the first member of an alkane family. Hence, it has the lowest boiling point. C6H14 has 6 carbon atoms, C5H12 has 5 carbon atom while C4H10 has 4 carbon atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>40", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Consider the reaction represented by the following equation:    X and Y respectively are  X", "images": ["Chemistry/imgs/2019/ssce2019chemq40.png"], "options": {"A": "ethane and ethene", "B": "ethene and ethane", "C": "ethyne and ethene", "D": "ethane and ethyne"}, "answer": "B", "explanation": "The reaction is hydrogenation reacction", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2019>41", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following substances can be classified as heavy chemical?", "images": [], "options": {"A": "CaOCl2", "B": "H2SO4", "C": "AgNO3", "D": "CaO"}, "answer": "B", "explanation": "Heavy chemicals are chemicals used extensively in industries and are produced in very large quantities e.g H2SO4, NaOH, NH3, CaCO3, HNO3, HCl, Na2CO3 e.t.c.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>42", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "In Boyle's law,", "images": [], "options": {"A": "T is constant, while P varied directly with V.", "B": "P is constant, while V varies inversely with T.", "C": "V is constant, while P varies directly with T.", "D": "T is constant, while V varies inversely with P."}, "answer": "D", "explanation": "Boyle's law states that the volume of a given mass of gas is inversely proportional to its pressure provided that temperature is kept constant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>43", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Which of the following apparatus is not used in volumetric analysis?", "images": [], "options": {"A": "Pipette", "B": "Burette", "C": "Desiccator", "D": "Conical flask"}, "answer": "C", "explanation": "Volumetric analysis is also known as titration, and this is the experiment performed to determine the volume of the acid which will completely neutralized a fixed volume of base. The acid is usually contained in a burette, the base is measured with a pipette and the neutralization takes place in a conical flask.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>44", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "One of the deductions from Rutherford's alpha particle scattering experiment is that", "images": [], "options": {"A": "electrons are negatively charged.", "B": "electrons have negligible mass.", "C": "nuclei of atoms are positively charged.", "D": "protons are positively charged."}, "answer": "C", "explanation": "Rutherford's alpha particle scattering experiment led to the discovery of the atomic nucleus. One of the deductions from this experiment is that the nuclei of atoms are positively charged. This is because the alpha particles (which are positively charged) were deflected from their original paths when they approached the nucleus, indicating that the nucleus must also be positively charged (since like charges repel).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>45", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The atoms 6429Cu and 6530Zn have the same number of", "images": [], "options": {"A": "nucleons", "B": "electrons", "C": "neutrons", "D": "protons"}, "answer": "C", "explanation": "Mass number (M) = Proton number (P) + neutron number (N)  M = P + N  6429Cu → P + N = M  29 + N = 64  N = 64 - 29  N = 35    6530Zn → P + N = M  30 + N = 65  N = 65 - 30  N = 35", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>46", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The number of electrons in the 3d orbital of 24Cr is", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "D", "explanation": "The electron configuration of Chromium (Cr) is [Ar] 3d5 4s1. This is an exception to the Aufbau principle which would predict an electron configuration of [Ar] 3d4 4s2. This is because half-filled or completely filled subshell have extra stability. Therefore, the number of electrons in the 3d orbital of Chromium is 5.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>47", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STATES OF MATTER : LABORATORY PREPARATION AND PROPERTIES OF SOME GASES.", "question": "The method used to collect a gas in the laboratory depends on its   I. boiling point.  II. density.  III. smell.  IV. solubility in water.", "images": [], "options": {"A": "I and II only", "B": "II and IV only", "C": "III and IV only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "The method of collecting a gas by a chemical reaction depends on its solubility and its density.  - Downward delivery method is used for gases which are soluble in water but denser than air.  - Collection over water is for gases which are insoluble or slightly soluble and more dense or less dense than air.  - Upward delivery method is used for gases which are insoluble in water or less dense than air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>48", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following methods is not used for the separation of mixtures?", "images": [], "options": {"A": "Chromatography", "B": "Crystallization", "C": "Distillation", "D": "Electrolysis"}, "answer": "D", "explanation": "Electrolysis is not a separation technique but a chemical decomposition of a substance in molten or aqueous form when direct current is passed through it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>49", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The group to which elements belong in the periodic table is determined by the number of", "images": [], "options": {"A": "electrons", "B": "core electrons", "C": "valence shells", "D": "valence electrons"}, "answer": "D", "explanation": "Valence electron (the number of electrons in the outermost shell of an element) is used to determine the group an element belongs.   For instance, an element of 1 valence electron belongs to group 2 etc. The number of shells an element has determines it period. An element with one shell belongs to period 1 etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2019>50", "subject": "Chemistry", "year": "2019", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Kipps apparatus can be used to prepare", "images": [], "options": {"A": "H2.", "B": "NH3.", "C": "O2.", "D": "H2S."}, "answer": "D", "explanation": "Kipp's apparatus is also called Kipp's generator. It is used to produce H2S gas by the action of a liquid on a solid without heating.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>1", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Which of the following substance is an example of a fine chemical?", "images": [], "options": {"A": "Sodium hydroxide", "B": "Hydrochloric acid", "C": "Ethylene", "D": "Ammonia"}, "answer": "C", "explanation": "Fine chemicals are chemicals which are manufactured in small, limited quantities for specific purposes.  They have high degree of purity. Examples are laboratory reagents, drugs, dyes, perfumes, photographic reagent,addictives, cosmetics. On the other hand, heavy chemicals are chemicals which are produced in large quantities and used extensively in industries. Examples are Sodium hydroxide,hydrochloric acid, ammonia, tetraoxosulphate IV acid, Calcium trioxocarbonate IV etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>2", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "The IUPAC name of the compound represented by the structure below is", "images": ["Chemistry/imgs/2020/2020chemq2.png"], "options": {"A": "2-chloro but- 1,3-diene", "B": "But-1,3-chloro-diene", "C": "2-chloro but-diene", "D": "3 - Chloro but - 1, 3- diene"}, "answer": "A", "explanation": "The longest carbon to carbon continuous chain consists of four carbon i.e \"but\". \"Cl\" is the only attachment which is on the 2nd carbon atom when numbered from right to left and on the third carbon atom when numbered from left to right, but a smaller number is always chosen i.e \"2-chloro\". Finally, the functional group(double bond) is on the 1st and 3rd carbon atoms i.e \"but -1, 3- diene\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>3", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS", "question": "Which of the following substance is a polypeptide", "images": [], "options": {"A": "Starch", "B": "Glycogen", "C": "Protein", "D": "Fats"}, "answer": "C", "explanation": "Amino acids are the building blocks for the proteins. All amino acids contain an amino or NH2 group and a carboxyl(acid) or COOH group. A peptide is two or more amino acids joined together by peptide bonds, and polypeptide is a chain of many amino acids. Hence, protein are long chains of amino acids held together by peptide bonds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>4", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS", "question": "Which of the following products could be formed during incomplete combustion of a Hydrocarbon ?  I. Carbon   II. Hydrogen  III. Carbon(II) oxide", "images": [], "options": {"A": "I", "B": "I and II only", "C": "I and III only", "D": "II and III only"}, "answer": "C", "explanation": "Complete combustion of hydrocarbon yield carbondioxide and water.  Hydrocarbon + Oxygen→Carbondioxide + water  C3H8 + 5O2→3CO2 + 4H2O  incomplete combustion yield carbon monoxide pus carbon and water.  hydrocarbon+oxygen →carbon monoxide + carbon+water  C3H8+ 2O2→3C+4H2O  therefore, combustion of hydrocarbon could yield carbon or carbon II oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>5", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "What quantity of electrons is lost when one mole of iron (II) ions is oxidized to iron(III) ions?", "images": [], "options": {"A": "0 mole", "B": "1 mole", "C": "2 mole", "D": "3 mole"}, "answer": "B", "explanation": "Fe2+- e-→Fe3+  Fe2+→Fe3++e-  Hence, 1 mole of electrons (e-) is last when one mole of F2+ is oxidized to Fe3+", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>6", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "What is the mass of silver deposited when 24,125 C of electricity is passed through a solution of silver salt ?  [Ag = 108, IF = 96500 C]", "images": [], "options": {"A": "432g", "B": "108g", "C": "54g", "D": "27g"}, "answer": "D", "explanation": "Ag+ +e-→ Ag(s)  1 mole of e- i.e if deposits 108g of Ag  96500C → 108g  24,125C → x  96500  = 108 x 24125  x=108 x 2412596500  x =27g", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2020>7", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Equal masses of calcium Trioxocatbonate (IV) were added to dilute Hydrochloric acid at the temperature specified. Under which of the following conditon would the reaction be slowest ?", "images": [], "options": {"A": "Calcium trioxocarbonate (IV) chips at 20∘C", "B": "Calcium trioxocarbonate (IV) chips at 40∘C", "C": "Calcium trioxocarbonate (IV) Powder at 20∘C", "D": "Calcium trioxocarbonate (IV) powder at 40∘C"}, "answer": "A", "explanation": "Increase in temperature increases the rate of a chemical reaction while decrease in temperature decreases the rate of a chemical reaction.         Increase in particle size decreases reaction rate while decrease in particle size increases reaction rate. hence, calcium trioxocarbonate IV chips at 20∘C would have slowest  reaction rate due  to the fact that it is chip and has a lower reaction rate than power and also a low temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>8", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "The high solubility of ethanol in water is due to", "images": [], "options": {"A": "Its low boiling point", "B": "its low freezing point", "C": "its covalent nature", "D": "Hydrogen bonding"}, "answer": "D", "explanation": "Water and ethanol are polar solvent. Ethanol has high solubility in water because Ethanol has OH group capable of forming hydrogen bonds with the water molecules.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>9", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Which of the following metals reacts slowly with cold water ?", "images": [], "options": {"A": "Calcium", "B": "Silver", "C": "Iron", "D": "Potassium"}, "answer": "A", "explanation": "Calcum reacts slowly with cold water and rapidly with warm water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>10", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following pairs of properties of alkali metals decrease down the group ?", "images": [], "options": {"A": "First ionization energy and reactivity", "B": "Melting point and atomic radius", "C": "Reactivity and electronegativity", "D": "First ionization energy and melting point"}, "answer": "D", "explanation": "Group 1 elements are known as alkali metals. The members lithium, sodium, potassium, rubidium, caesium,  and francium. Among the metals, Lithium has the highest first ionization energy and frantium has the lowest. hence, ionization energy decreases down the group. Their melting and boiling point decrease down the group. Lithium has a melting point of 180∘ C while caesium  ahs a melting point of 28∘C. The reactivity and atomic radius increases down the group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>11", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "The most suitable process of obtaining water from an aqueous solution of sugar is", "images": [], "options": {"A": "crystallization", "B": "Distillation", "C": "filtration", "D": "Decantation"}, "answer": "B", "explanation": "Distillation is a separation technique used to recover solvent from a solution. Crystallization is used to separate  a thermolabile salt ( salt which decomposes upon heating) from its solution. Filtration is a separation technique used to separate insoluble solute from a solution, while decantation is used to recover solvent  from insoluble soluble which settles upon standing. Hence, distillation is the most suitable.     Distillation is the most suitable process for obtaining water from an aqueous solution of sugar. This is because distillation is a process of separating the components or substances from a liquid mixture by using selective boiling and condensation. In this case, water will be boiled off and then condensed back into liquid in a separate container, leaving the sugar behind.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>12", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Group VII elements in their combined states are called.", "images": [], "options": {"A": "Halogens", "B": "Anions", "C": "Halides", "D": "Cations."}, "answer": "C", "explanation": "Group VII elements are known as the halogen family. They are flourine, chlorine, Bromine, Iodine, and Astatine. Halides are binary compounds that are of which one part is an element, another part is the halogen atom. Some examples are KCL i.e potassium chloride, KBr i.e potassium bromide etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>13", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "When an ionic bond is broken , bonding electrons are", "images": [], "options": {"A": "Shared between participating atoms.", "B": "Gained by the most electropositive atom.", "C": "Gained by the most electronegativity atom", "D": "lost by both participating atoms."}, "answer": "C", "explanation": "When an ionic bond is broken, bonding electrons are gained by the most electronegative atom. In an ionic bond, one atom donates an electron to another atom. The atom that gains the electron is the one with higher electronegativity. When the bond is broken, the electron stays with the atom that originally gained it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>14", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation state of Chloride in NaCIO3 is", "images": [], "options": {"A": "+1", "B": "+3", "C": "+5", "D": "+6"}, "answer": "C", "explanation": "NaClO3  Na=+1, 0= -2  +1+Cl+(-2x3)=0  1+Cl - 6 = 0  Cl=6 - 1  Cl= +5", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>15", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "A balance chemical equation is based on the law of", "images": [], "options": {"A": "Periodicity", "B": "Constant composition", "C": "Multiple proportion", "D": "Conservation of mass"}, "answer": "D", "explanation": "The law of conservation of mass states that mass in an insolated system is neither created nor destroyed.      This implies that the mass of the reactants must be equal  to the mass of the product. This is why chemical equations are usually balanced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>16", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following pairs of elements has the greatest difference in electronegativity?", "images": [], "options": {"A": "Na and F", "B": "Na and Cl", "C": "Na and Br", "D": "Na and I"}, "answer": "A", "explanation": "Electronegativity is the ability of an atom to attract shared electrons in a convalent bond. The most electronegative element is flourine. Hence, sodium and fluorine have the greatedt difference in electronegativity in the options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>17", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "A factor that is considered most important when siting a chemical industry is", "images": [], "options": {"A": "Nearness to other industrial establishment", "B": "nearness to raw materials", "C": "Favourable climate conditions", "D": "Availablity of storage facilities"}, "answer": "B", "explanation": "Insiting  a chemical industry, the nearness to raw material source/ feedstock is most important as this enhances production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>18", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "The boiling point of pentane is higher than that of propane because", "images": [], "options": {"A": "Carbon-carbon single bonds are stronger than carbon-hydrogen bonds.", "B": "Pentane has more covalent bonds to break", "C": "Pentane does not burn easily as propane", "D": "The intermolecular forces in pentane are stronger than those of propane."}, "answer": "B", "explanation": "The boiling point of a substance is directly related to the strength of the forces between its molecules. In the case of pentane and propane, both are hydrocarbons and the primary intermolecular force is the London dispersion force. This force increases with the size and shape of the molecule, and since pentane is larger than propane, it has stronger intermolecular forces, hence a higher boiling point.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>19", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Which of the following solids would not decompose on heating", "images": [], "options": {"A": "Ammonium chloride", "B": "Lead (II) trixoxnitrate (V)", "C": "Potassium trioxocarbonate (IV)", "D": "Sodium hydrogen trioxocarbonate (IV)"}, "answer": "C", "explanation": "All trioxocarbonate IV salts decompose upon heating to release CO2 except that of Na and K. Hence, from the options only potassium trioxocarbonate IV would not decompose upon heating.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>20", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The following molecules have double covalent bonds between two atoms except", "images": [], "options": {"A": "Oxygen", "B": "Carbon(IV) oxide", "C": "Ethene", "D": "Water"}, "answer": "D", "explanation": "The shape of oxygen is linear,  and it can be represented as 0 = 0  carbon IV oxide is linear in shape and can be represented as 0 = C = 0  Ethene is planar shape  and its of the structure      water is an angular in shape  and has structure.    Among the options, only water doesn't  have double covalent bonds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>21", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "The type of isomerism exhibited by cis and transisomers is", "images": [], "options": {"A": "`Positional", "B": "geometrical", "C": "functional", "D": "optical"}, "answer": "B", "explanation": "Geometric (cis/ trans) isomerism occurs when there is restricted rotation somewhere in the molecule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>22", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following compound has the lowest boiling point?", "images": [], "options": {"A": "C4H10", "B": "CH3COOH", "C": "H2O", "D": "C2H5OH"}, "answer": "A", "explanation": "The boiling point of C4H10 is -0.4∘C  The boiling point of CH3COOH is 118∘C  The boiling point of H2O is 100∘C  The boiling point of C2H5OH is 78∘C  From above , the least boiling point belong to C4H10, In addition , alkanes have low melting and boiling points methane, ethane , propane and butane (C4H10) ar gasses at room temperature . This also explainsthe reason C4H10 has the lowest boiling point.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>23", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "An alkanol containing 60% carbon by mass  would have a molecular formula  [H = 1.0, C= 12.0, O = 16.0]", "images": [], "options": {"A": "CH3OH", "B": "C2H5OH", "C": "C3H7OH", "D": "C4H9OH"}, "answer": "C", "explanation": "The general molecule formula for alkanol is CnH2n+1OH  Mass of carbon = Cn  = 12n  Molecule mass = 12n +1 (2n+1)+16+1  =12n+2n+1+16+1  =14n +18   percentage by mass of carbon is 60%   therefore , 60100 x (14n +18) = 12n  3( 14n +18) = 60n  42n + 54 =60n   54 = 60n - 42n  54 = 18n  5418 = n   therefore n = 3   since n = 3, the formula of the alkanol    C3H7OH   (C)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>24", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "Which of the following compound would release hydrogen when reacted with sodium metals?  I. CH3COOH  II. CH3CH2OH  III. CH3COOCH3", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "II and III only", "D": "I and III only"}, "answer": "B", "explanation": "- 2CH3COOH + Na → 2CH3COONa + H2  - CH 3CH2OH +Na →CH3CH2ONa + H2  - CH3COOCH3 + Na → CH3COONa + CH3     only CH3COOH and CH3CH2OH would release hydrogen when reacted with sodium metal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>25", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Which of the following substance is not a reducing agent?", "images": [], "options": {"A": "C", "B": "CO", "C": "O2", "D": "H2"}, "answer": "C", "explanation": "A reducing agent is one of the reactants which reduces other reactant  and itself is oxidized.     Carbon is a reducing agent.      2CuO(s) + C(s) → 2Cu(s) + CO2(g)   Carbon reduces  CuO to Cu, as removal  of oxygen is term reduction   CO is a reducing agent  while O2 is an oxidizing agent              2CO(g) + O2(g)      From the above equation, CO has been oxidized to CO2 since addition of oxygen is oxidization. Hence, it is a reducing agent. Therefore, O2 is an oxidizing agent.  H2 is a reducing agent.     N2 + 3H2→2NH3    H2 is a reducing agent since it is oxidized i.e H2is oxidized to NH3 with the addition of electronegative element N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>26", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following statement is correct for a reaction at equilibrium ?", "images": [], "options": {"A": "All reaction cease to occur", "B": "The reaction has gone to completion", "C": "The rates of the forward and backward reaction are equal.", "D": "The amount of product equals the amount of reactants."}, "answer": "C", "explanation": "According to Berthollet, as reaction at equilibrium is one in its rate of forward reaction is equal to its rate of backward reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>27", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Which of the following reactions are always exothermic  I. Neutralization   II. Decomposition   III. Combustion", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "B", "explanation": "Neutralization is the reaction of an acid and a base to form salt and water. Enthalpy of neutralization is always constant for a strong acid  and a strong base. Heat is always given out, hence, it is exothermic.          Decomposition is a reaction in which a single compound splits into two or more simple substances under suitable conditions.  It can either be endothermic or exothermic depending upon the conditions.        Combustion is an oxidation reaction that produces heat and therefore, it is always exothermic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>28", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "Which of the following standard condition is not correct about energy changes", "images": [], "options": {"A": "Standard Temperature  is 298K", "B": "Stardard pressure is 1 atm", "C": "Concentration of solution must be 1 mol dm-3", "D": "∆Hθ at 298 k is the activation energy"}, "answer": "D", "explanation": "The standard condition for energy changes are   - Standard temperature is 298k  - Standard pressure is 1 amt  - Concentrated of the solution must be 1 moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>29", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "If 5.0cm3 of 0.200 mol dm-3 Na2CO3 was dilute to 250cm3 solution, what would be the concentration f the resulting solution ?", "images": [], "options": {"A": "0.004 mol dm-3", "B": "0.02 mol dm-3", "C": "0.200 mol dm-3", "D": "0.400 mol dm-3"}, "answer": "A", "explanation": "Initial volume, V1 = 5cm3  initial concentration, C1 = 0.2 moldm-3  Final volume, V2 = 250cm3  Final concentration, C2 = ?     Recall C1V1 = C2V2     5 x 0.2 = C2 x 250     C2=5 x 0.2250  C2 = 0.004moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>30", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "The initial volume and pressure of a given mass of gas is V and 3P. What is it pressure if it volume is increase to 2V at constant temperature?", "images": [], "options": {"A": "3P", "B": "2P", "C": "32P", "D": "23P"}, "answer": "C", "explanation": "Initial volume, V1 = V  Initial pressure, P1 = 3P  New volume, V2 = 2V  New pressure, P2 = ?   From Boyles' law  V1P1 = V2P2  V x 3P = 2V x P2  V x 3P2V = P2  P2= 32P", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>31", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.", "question": "What volume of oxygen at s.t.p is required to burn completely 7.5 dm3 of methane according to the following equation ?  CH4(g) + 2O2(g) → CO2(g) + H2O(g)", "images": [], "options": {"A": "3.75dm3", "B": "7.50dm3", "C": "15.0dm3", "D": "30.0dm3"}, "answer": "C", "explanation": "CH4 + 2O2→ CO2 + H2O  1,2,1,1  1mol of CH4  reacts with 2 moles of O2  1mole of CH4 → 2moles of O2  therefore, 7.5dm3 of CH4 → x moles of O2  According to Gay- lussac's law of combining volume   x = 2 x 7.5  x = 15.0dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>32", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "When 250cm3 of a saturated solution of CuSO4 at 30∘C was evaporated to dryness, 5.0g of the salt was obtained. What is the solubility of the salt at 30∘C ?  [CuSO4 = 160]", "images": [], "options": {"A": "0.031", "B": "0.125", "C": "0.640", "D": "1.560"}, "answer": "B", "explanation": "Solubilityofsalt=number of mole of salt,nvolume of solution,v   n = massmolar mass n = 5160 = 0.03125mol  V = 250cm3 = 2501000 = 0.25 dm3  solubilityofsalt=0.031250.25    =0.125 moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>33", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "The bond betweeen NH3 an H+ in NH4+ is", "images": [], "options": {"A": "Dative", "B": "covalent", "C": "hydrogen", "D": "electrovalent"}, "answer": "A", "explanation": "A dative  or co-ordinate covalent bonding is the covalent bond formed by two atoms such that only one participant donates the shared pair of electrons . in the bond between NH3 and H+,H+ has no electrons in its shell but NH3 donates the shared pair of electrons to give NH4+", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>34", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "Which of the following oxides has a giant covalent structure ?", "images": [], "options": {"A": "Al2O3", "B": "Na2O", "C": "P4O10", "D": "SiO2"}, "answer": "D", "explanation": "Electronegativity of element increases across the period, and by the time one get to silicon, there isn't enough electronegativity difference between silicon and oxygen to form an ionic bond silicon dioxide has a giant covalent structure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>35", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Which of the following hydroxides is not readily soluble in water", "images": [], "options": {"A": "NH4OH", "B": "Ca(OH)2", "C": "NaOH", "D": "KOH"}, "answer": "B", "explanation": "Most metals hydroxide are insoluble in water such as Ca(OH)2,Mg(OH)2, Fe(OH)2e.t.c. However alkaline metal hydroxide such as KOH, NaOH and NH4OH are soluble in water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>36", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : PRACTICAL APPLICATION OF SOLUBILITY", "question": "Which of the following statement about the solubility of a salt is correct ?", "images": [], "options": {"A": "A salt whose solubility increases with temperature would not crytalizes easily on cooling", "B": "A salt whose solubility is independent of temperature would normally crytallize out on cooling", "C": "Crystallization would be efficient in separating out a salt whose solubility increases considerably with temperature.", "D": "Solubility of a solid does not affect its crystallization."}, "answer": "C", "explanation": "Crystalization is a seperation techniques that uses difference in solubility of the component present in the solution . Increase in temperature leads to increase in solubility as the solution is allowed to cool, the solute is no longer soluble in the solvent", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>37", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many moles of H2SO4 are there in 50cm3 of 0.108 mol dm-3 solution of the acid?", "images": [], "options": {"A": "5.4 x 10", "B": "5.4 x 10-1", "C": "5.4 x 10-2", "D": "5.4 x 10-3"}, "answer": "D", "explanation": "number of moles , n = ?  Volume ,  V = 50cm3 = 50/100 = 0.05dm3  Concentration, C = 0.108moldm-3  recall   n = cv    = 0.108 x 0.05   = 0.0054  n = 5.4 x 10-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>38", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "If 20cm3 of sodium hydroxide was neutralized by 20cm3 of 0.01 mol dm-3 tetraoxosulphate(VI) acid, what is the concentration of the solution?", "images": [], "options": {"A": "0.010", "B": "0.020", "C": "0.100", "D": "0.150"}, "answer": "B", "explanation": "Number of mole of acid, nA = 1  Number of mole of base , nB = 2  Volume of acid, VA = 20cm3  Volume of base, VB = 20cm3  Concentration of acid, C = 0.01moldm-3  Concentration of base , CB = ?  Recall,nAnB=CAVACBVB  12=0.01x20CBx20  CB = 0.020moldm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>39", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RULES AND PRINCIPLES FOR FILLING IN ELECTRONS.", "question": "\"Electrons always occupy the lowest empty energy level \" is statement of", "images": [], "options": {"A": "Aufbau principle", "B": "Hunds rule", "C": "pauli excluision principle", "D": "periodic law"}, "answer": "A", "explanation": "The statement 'Electrons always occupy the lowest empty energy level' is a statement of the Aufbau principle. The Aufbau principle states that in the ground state of an atom or ion, electrons fill atomic orbitals of the lowest available energy levels before occupying higher levels. For example, the 1s shell is filled before the 2s subshell is occupied.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>40", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Which of the following metals does not react with water to produce hydrogen ?", "images": [], "options": {"A": "Lithium", "B": "Potassium", "C": "Sodium", "D": "Zinc"}, "answer": "D", "explanation": "Li + H2O →LiOH + H2  K + H2O →KOH + H2  Na + H2O →NaOH + H2  Zn + H2O →Zn(OH)2 + H2. (Elementary zinc does not react with water molecules . The ion does form a form a protective  water insoluble zinc hydroxide layer with dissolved hydrogen ions.)", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>41", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following arrangement of element is in decreasing order of electronegatively ?", "images": [], "options": {"A": "Na,Mg,Al, Si, P", "B": "Na,Al,Mg,P,Si", "C": "P, Mg,Na,Si,Al", "D": "P,Si,Al,Mg,Na"}, "answer": "D", "explanation": "Electronegativity increase across the period. Hence , group F element are most electronegative elements. Phosphorus , silicon, Aluminium, Magnesium and sodium are groups 5, 4 , 3 , 2 , 1 respectively. Among the elements, phosphorus is the most electronegative element while sodium is the least electronegative element. therefore in decreasing order, P,Si,Al,Mg,Na.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>42", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "The metallic bond in magnesium is stronger than that in calcium because magnesium has a", "images": [], "options": {"A": "larger atomic size", "B": "smaller atomic size", "C": "greater numbers of valence electrons", "D": "lower melting point"}, "answer": "B", "explanation": "Magnesium and calcium are both in group 2 of the perodic ,metallic bond decreases down the group due to increase in atomic size or radius. Magnesium is in period 2 while calcium is in period 3. Hence calcium has stronger metallic bond to its smaller atomic size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>43", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Consider the reaction represented by the following equation:  AgNo3(aq) + NaCl(aq) →AgCl(s) + NaNO3(aq)  The steps that could be taken to obtain pure dry sample of AgCls from the mixture includes", "images": [], "options": {"A": "Heating to saturation and drying", "B": "Filtering and evaporation to dryness", "C": "Filtering , washing and drying", "D": "Crytasllizing and allowing to cool."}, "answer": "C", "explanation": "AgNO3 + NaCl →Agcl(s) + NaNO3(aq)  AgCl is a insoluble solid (precipiatate) while NaNO3 is a soluble salt. Since AgCl is insoluble , it can be filtered  , washed and dried.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2020>44", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "How many electrons does 3115P3- contain ?", "images": [], "options": {"A": "12", "B": "15", "C": "16", "D": "18"}, "answer": "D", "explanation": "A netural atom has the same number of proton and electron . An atom becomes positively charged when it loses electron(s)  and it is negativey charged when it gains electron(s) . 3115P has 15 protons and 15 neutrons. 3115P3- means it has gained 3 more electrons which makes the number of electrons to be 18.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>45", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The atomic number of an atom would be equal to its mass number if it", "images": [], "options": {"A": "Has a totally filled valence shell", "B": "has a high charge to mass ratio", "C": "Does not contain neutrons.", "D": "exhibits isotopy"}, "answer": "C", "explanation": "Mass number , M = proton numbr, P + Neutron number, N  M = P + N  Where proton number is the same as atomic number   If P = 0; Then M = N  Therefore if an atom does'nt contain neutron(s) , then its atomic number would be equal to its mass number .", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>46", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "Which of the following processes is not exhibited by atoms in order to attain more stable electron confguration?", "images": [], "options": {"A": "Gaining of electrons", "B": "Hybridization of orbitals", "C": "losing electrons", "D": "Sharing electrons"}, "answer": "B", "explanation": "For an atom to attain a stable duplet or octet configuration, it either gains or losses electron(s), Hybridization of orbital invoves the blending or mixing of orbitals to form a new set of orbital called hybrid orbital, Hybridization explains the bonding in organic molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>47", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Which of the following quantities is a molar quantity ?", "images": [], "options": {"A": "mass Molarity", "B": "molar mass", "C": "mass concentration", "D": "Molality"}, "answer": "B", "explanation": "Molar quantity is expressed as the actual quantity per the amount of substance (number of mol). this could result could result to molar volume, molar enthalpy, molar mass e.t.c.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>48", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Dilution factor is the", "images": [], "options": {"A": "amount of distilled water that is added to the concentration solution to dilute it", "B": "quantity of distilled water added to 1 dm3 of the concentrated solution to give the dilute solution", "C": "number of times the volume of the concentrated solution is dilute to give the dilute solution.", "D": "act of diluting the concentration solution to obtain the dilute solution."}, "answer": "C", "explanation": "Dilution factor refers to the ratio of volume of the initial (concentrated ) solution to the volume of the final(dilute) solution. this is the number of times the volume of the concentrated solution is diluted to give the dilute solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2020>49", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Calcium chloride is an ionic compound. which pf the following statement account for its ionic character ?  I. Calcium has high ionization energy  II. Calcium has a low ionization energy  III.Chlorine has high electron affinity  IV. Chlorine has high ionization energy", "images": [], "options": {"A": "I and II only", "B": "I,II and IV only", "C": "II,III and IV only", "D": "I,II, III and IV"}, "answer": "C", "explanation": "Cacium has low ionization energy as it is in group 2 of the periodic table and ionization energy increase across the period. Chlorine has high electrons affinity as it in group 7 of the periodic table and eectron affinity increase across the period . Chlorine has high ionization energy as ionization energy increases  across the eriod.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2020>50", "subject": "Chemistry", "year": "2020", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "An examples of a biogradable pollutant is", "images": [], "options": {"A": "Plastic", "B": "sewage", "C": "carbon (II) Oxide.", "D": "Hydrogen sulphide."}, "answer": "B", "explanation": "Bio-degradable pollutant are pollutants which can be broken down into simpler, harmless substance in nature by the action of micro-organism. Examples are doestic waste (garbage), urine, sewage, faecal matter. e.t.c", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2021>1", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS", "question": "The hydrolysis of protein by dilute minerals acids produces", "images": [], "options": {"A": "sucrose", "B": "glucose", "C": "amino acids", "D": "fatty acids"}, "answer": "C", "explanation": "Proteins are large molecules made up of amino acids. When proteins are hydrolyzed, or chemically broken down, by dilute mineral acids, the result is a mixture of amino acids. Therefore, the correct answer is 'amino acids'. The other options (sucrose, glucose, and fatty acids) are not produced by the hydrolysis of proteins.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>2", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following oxides causes acids rain ?", "images": [], "options": {"A": "CO", "B": "NO", "C": "H2O2", "D": "NO2"}, "answer": "D", "explanation": "NO2 is an acidic gas i.e acid anhydride. It dissolve in rain (water) to give a mixed acid  NO2 + H2O → HNO3 + HNO2", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>3", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "The ratio of carbon atoms to hydrogen atoms in a hydrocarbon is 1:2, if its molecular mass is 56 what is the molecular formular?", "images": [], "options": {"A": "C3H6", "B": "C4H8", "C": "C2H4", "D": "CH2"}, "answer": "B", "explanation": "The ratio means the empirical fomula of the hyrocarbon  [CH2] = relative molecular mass (RMM)  (12 + 1 x 2) = 56  [12 + 2]n = 56  14n = 56  n = 56/14  n = 4  The molecular formula is (CH2)4  C4H8", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>4", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "what is the relative molecular mass of the compound below?    [H = 1, C = 12.0, O = 16.0]", "images": ["Chemistry/imgs/2021/m56.png"], "options": {"A": "137", "B": "136", "C": "64", "D": "59"}, "answer": "B", "explanation": "The molecular formular is C6H5COOCH3  RMM = (12x6) + (1x5) + 12 + 16 + 16 + 12 + (1x3)   = 72 + 5 + 12 + 32 + 12 + 3   = 136g/mol", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>5", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "Cathodic protection of metals is based on", "images": [], "options": {"A": "standard electrode potential of hydrogen", "B": "it electrical conductivity", "C": "nature of oxides formed", "D": "relative tendencies of oxidation"}, "answer": "D", "explanation": "corrosion is a destructive phenomenoen  that occur whe metals are exposed to the environment.the reaction between air, water and the metal form a stable compound of metal.  This reaction depends on the reactivity of the metal", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>6", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "If humid air is polluted by chlorine discharge the air can be restored by sprinkling", "images": [], "options": {"A": "solid MnO2", "B": "acidified KMnO4", "C": "acidified FeSO4", "D": "saturated NaCl"}, "answer": "B", "explanation": "Chlorine is a toxic gas and when it pollutes the air, it can be neutralized by using acidified KMnO4. The reaction between chlorine and acidified KMnO4 results in the formation of chloride ions, manganese(II) ions, and water, which are harmless. This is why acidified KMnO4 is used to restore air polluted by chlorine discharge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>7", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The alkanol represented by the structure below is", "images": ["Chemistry/imgs/2021/FJBRED.png"], "options": {"A": "primary and dihydric", "B": "secondary and monohydric", "C": "tertiary and dihydric", "D": "secondary and dihydric"}, "answer": "A", "explanation": "It has only one alkyl group and dihydric because it has two hydroxyl groups", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>8", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the pairs of compounds would form a precipitate when an aqueous solution is involved", "images": [], "options": {"A": "NaCl and KNO3", "B": "KCL and NaNO3", "C": "K2SO4 and BaCl2", "D": "NH2NO3 and NaCO3"}, "answer": "C", "explanation": "Double composition reaction is a reaction between two soluble salts to give on soluble and on insoluble salt is the precipitate   K2SO4 + BaCl2→KCl + Ba SO4  BaSO4 is insoluble because all trioxosulphate VI slats are soluble except Pb2+,Cu2+,Ca2+, Ba2+", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>9", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the graphs illustrates the variation of the rate of evolution of a gas from a given length of magnesium ribbon(y-axis) with increase in the concentration of the acid added (x-axis)", "images": ["Chemistry/imgs/2021/P66WMN.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Graph I illustrates the variation of the rate of evolution of a gas from a given length of magnesium ribbon(y-axis) with increase in the concentration of the acid added (x-axis).", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>10", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Which of the graphs illustrates the variation of the pH of a given volume of strong acid solution (y-axis) with the volume of strong base titrated against its (x-axis)?", "images": ["Chemistry/imgs/2021/P66WMN.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "Graph I. For a reaction between strong acid and strong base , there is a rapid change in PH from 3.5 to 9.5(y-axis) when the quantity of base (x-axis) is added", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>11", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Which of the graphs illustrates variation of the solubility of a salt in water (y-axis) with increase in temperature (x-axis) if the dissolution process is exothermic", "images": ["Chemistry/imgs/2021/P66WMN.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "D", "explanation": "Graph IV. Increase in temperature leads to increase in rate of reaction . increase in temperature will reduce the time in bond breaking which in turn leads to increase in solubility", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>12", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "The formation of ethene from dehydration of ethanol can be described as", "images": [], "options": {"A": "an addition reaction", "B": "an elimination reaction", "C": "an oxidation reaction", "D": "a substitution reaction"}, "answer": "B", "explanation": "C2H5 H2SO4→-H2O  C2H4  this is the removal of H2O from ethanol which is elimination method", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>13", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : NITROGEN", "question": "Which of the following gases is highly soluble in water at room temperature?", "images": [], "options": {"A": "Ammonia", "B": "carbon(IV) oxide", "C": "chlorine", "D": "Nitrogen"}, "answer": "A", "explanation": "Ammonia is highly soluble in water at room temperature. This is due to the fact that ammonia is a polar molecule and can form hydrogen bonds with water molecules, which leads to its high solubility.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2021>14", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "A molecule of phosphorus is", "images": [], "options": {"A": "diatomic", "B": "triatomic", "C": "tetra-atomic", "D": "monoatomic"}, "answer": "C", "explanation": "A molecule of phosphorus is tetra-atomic. This means it is composed of four atoms. In its most stable form, phosphorus exists as P4 molecules, where four phosphorus atoms form a tetrahedral structure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2021>15", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "The common method of preparing insoluble salts is by", "images": [], "options": {"A": "filtration", "B": "decomposition", "C": "neutralization", "D": "double decomposition"}, "answer": "D", "explanation": "Insoluble salts are prepared by  - direct combination of constituents elements   F3 + S →FeS    - Double decomposition reaction : this is a reaction between two soluble salts to give one soluble and one insoluble salt which is the precipate   K2SO4 + BaCl →KCl(soluble) + BaSO4(insoluble)", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>16", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "What is the number of moles of oxygen would exert a pressure of 10 atm at 320oK in an 8.2dm3 cylinder?  [R = 0.82 atm dm3 ml-1K-1]", "images": [], "options": {"A": "0.32", "B": "1.56", "C": "3.13", "D": "31.25"}, "answer": "C", "explanation": "n = ?, p = 10 atm, v = 8.2dm3, R = 0.082  T = 320k  recall, Pv = nKT  n=PVRT  =10x8.20.082x320  n = 3.13", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>17", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "The basic property of salt as a drying agent is", "images": [], "options": {"A": "efflorescence", "B": "high melting point", "C": "hygroscope", "D": "low solubility"}, "answer": "C", "explanation": "The basic property of salt as a drying agent is its hygroscopic nature. Hygroscopic substances have the ability to attract and hold water molecules from the surrounding environment. This is achieved through either absorption or adsorption of the water molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>18", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.", "question": "What would be observed when aqueous ammonia is added in drops and then in excess to a solution of copper(II)ions?", "images": [], "options": {"A": "Blue precipitate is formed which is soluble in excess ammonia", "B": "brick red precipitate is produced which is insoluble in excess ammonia", "C": "white precipitate is formed which is soluble in excess ammonia", "D": "green precipitate is formed wich is insoluble in excess ammonia"}, "answer": "A", "explanation": "CU2+ forms a deep blue precipitate which is soluble in excess NH4OH    Blue precipitate formed which dissolved in excess aqueous ammonia to form a dark blue solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>19", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "When CuSO4(aq) is added to Pb(NO3)(aq)", "images": [], "options": {"A": "There would be no visible change", "B": "a blue precipitate would be formed", "C": "The resulting solution would be colourless", "D": "A white precipitate would formed"}, "answer": "D", "explanation": "When CuSO4(aq) is added to Pb(NO3)2(aq), a white precipitate of lead(II) sulfate is formed. This is due to a double displacement reaction where lead ions (Pb2+) and sulfate ions (SO4 2-) combine to form the insoluble lead(II) sulfate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>20", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "How many carbon atoms does the parent chain contain?", "images": ["Chemistry/imgs/2021/m59.png"], "options": {"A": "5", "B": "4", "C": "3", "D": "2"}, "answer": "B", "explanation": "The largest carbon chain illustrated above is 4. The parent chain contain 4 carbon.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2021>21", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Under which condition of pressure(p) and temperature (T) would be volume of an inflated ballon increase? when", "images": [], "options": {"A": "Both T and P are increased", "B": "Both T and P decrease", "C": "T is increased and P is decreased", "D": "T is decreased and P is increased"}, "answer": "C", "explanation": "V x T, also V α 1/p  When volume increases, temperature also increases and pressure reduces as stated by charles and Boyle laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>22", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "The collision between ideal gas molecules are considered to be perfectly elastic because", "images": [], "options": {"A": "They collide without losing energy", "B": "They randomly in straight line", "C": "Their average kinetic energy is variables", "D": "The distance between them is large compared to their sizes"}, "answer": "A", "explanation": "Gas molecules collide with one another and separate after collision . Both their momentum and kinetic energy are conserved . This known as elastic collision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>23", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Elements with ionization energies would", "images": [], "options": {"A": "lose electrons easily", "B": "have large atomic radii", "C": "have effective nuclear charges", "D": "have low atomic numbers"}, "answer": "C", "explanation": "ionization energy required is the energy required to remove one mole of electron from a gaseous atom in order to make it a gaseous ion . It depends on nuclear shield and the electrostatic force of attraction between the nucleus (positive) and the outermost electron (negative ) element with higher nuclear charge have higher electrostatic force of attraction which leads to higher ionization energy", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>24", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Which of the following statement about Group VII elements is correct ?", "images": [], "options": {"A": "they are present in the same physical state", "B": "they are strong reducing agent", "C": "their reactivity decreases down the group", "D": "they exist as monoatomic molecules"}, "answer": "C", "explanation": "Group 7 element properties   - Diatomic   -highly oxidizing agent  - electronegativity decreases down the group (reactivity)  - Density increases down th group (physical property)  - colour darkens down the group", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>25", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following cell notation represents the diagram?", "images": ["Chemistry/imgs/2021/m72.jpg"], "options": {"A": "B2/B//AA3+", "B": "A3+/A//B/B+", "C": "B/B2+//A/A3+", "D": "A/A3-//B2+/B"}, "answer": "D", "explanation": "Oxidation takes place at the anode i.e is loss of electrons while reduction occur at the cathode i.e gain of electrons.  The electrochemical cell can be symbolically represented  as Anode /Anode solution//cathode solution /cathode A/A3-//B2+/B", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>26", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following half reaction equation represent the reaction at the cathode?", "images": [], "options": {"A": "A3+(aq) + 3e- →A(g)", "B": "B2+(aq) + 2e-→B(x)", "C": "A(g) → A+(aq) + 3e-", "D": "B(g) →B+(aq) + 2e-"}, "answer": "A", "explanation": "In electrochemistry, the cathode is the electrode where reduction occurs. Reduction is a process where a species gains electrons. Therefore, the correct half-reaction should depict a species gaining electrons. A3+(aq) + 3e- →A(g) correctly shows this process.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>27", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "The reactivity of the fluorine is high because of", "images": [], "options": {"A": "its high electronegativity", "B": "The small size of the fluorine atom", "C": "The availability of b-orbital", "D": "The Strong F-F bond"}, "answer": "A", "explanation": "Fluorine is the most electronegative element in the periodic table. Electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. The high electronegativity of fluorine makes it highly reactive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>28", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "How many coulombs of electricity would liberate 1.08g of Ag from a solution of silver salt?  [Ag = 108.0, 1F = 96500C]", "images": [], "options": {"A": "96500C", "B": "9650C", "C": "965C", "D": "9.65C"}, "answer": "C", "explanation": "Ag+ + e- →Ag  1 mole  of Ag+ requires 1 faraday(9650C)  108g →96500  1.08 →Q  Cross multiply108Q = 1.08 x 96500  C=1.08x965001.08  Q = 965C", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>29", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "Which of the following quantities is the same for one mole of Br2(l) and one mole of He(g)?", "images": [], "options": {"A": "Number of molecules", "B": "Number of atoms", "C": "Total mass of the particles", "D": "Volume occupied at s.t.p."}, "answer": "A", "explanation": "Number of molecules. The number of molecules in a given sample, you can use the relationship between moles, Avogadro's number, and the mass of the substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>30", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following acids is dibasic?", "images": [], "options": {"A": "hydrochloric acid", "B": "Trioxosulphate (IV) Acid", "C": "Dioxonitrate (III) acid", "D": "Ethanoic acid"}, "answer": "B", "explanation": "A dibasic acid has two replaceable hydrogen atoms. it gives two free hydrogen ions in solution for each molecule of acid ionized.  The correct is H2SO3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>31", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Bees inject an acidic substance when they sting. Which of the following chemical could be used to treat bee stings?", "images": [], "options": {"A": "CH3COOH", "B": "NaHCO3", "C": "C2H5OH", "D": "H2O2"}, "answer": "B", "explanation": "Bee stings are acidic in nature because they contain formic acid. To neutralize the effect of the sting, a basic substance should be used. Sodium bicarbonate (NaHCO3), also known as baking soda, is a basic substance and can neutralize the acidic effect of the bee sting. Therefore, the correct answer is 'NaHCO3'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>32", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : SOLUTIONS", "question": "What is the concentration of a solution which contains 0.28g of potassium hydroxide in 100cm3 of solution?", "images": [], "options": {"A": "0.01 mol dm-3", "B": "0.05mol dm-3", "C": "0.10 mol dm-3", "D": "0.50mol dm-3"}, "answer": "B", "explanation": "Conc. in g/dm3 =mass/volume   = 0.28/0.1 = 2.8g/dm3  concinmolddm3=conc.ing/dm3reactive molecular mass   = 2.8/58 = 0.05mol dm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>33", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "What is the empirical formula of hydrocarbon containing 0.160 moles of carbon and 0.640 moles of hydrogen?", "images": [], "options": {"A": "CH2", "B": "CH3", "C": "CH4", "D": "C2H4"}, "answer": "C", "explanation": "CHmoles0.160.64molar ratio0.16/0.160.64/0.1614  The empirical formular is CH4", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>34", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following has the highest ionic radius ?", "images": [], "options": {"A": "S2-", "B": "Cl-", "C": "K-", "D": "Ca2+"}, "answer": "A", "explanation": "The ionic radius of an ion is determined by the number of electron shells it has and the effective nuclear charge it experiences. Among the given options, S2- has the highest ionic radius because it has the most electron shells and the lowest effective nuclear charge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>35", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC LAW", "question": "Which of the following statement is correct about ionization energy? it", "images": [], "options": {"A": "decrease across the periods", "B": "result in the formation of an atom", "C": "causes metallic nuclei to disintegrate", "D": "decrease down the group"}, "answer": "D", "explanation": "ionization energy is the energy needed to remove one mole of electron from a gaseous atom in order to make it a gaseous ion. it increases  across the period and decreases down the group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>36", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Potassium Trioxonitrate (V) can be obtained from its solution by", "images": [], "options": {"A": "distillation", "B": "evaporation", "C": "crystallization", "D": "Filtration"}, "answer": "C", "explanation": "KNO3 is a soluble salt just as NaCl . NaCl can be recovered from a solution by evaporation to dryness because it is thermoresistant salt i.e normally stable . On the other hand KNO3 cannot be recovered through evaporation because it is decomposes upon heating  KNO3 ∆→heat  KNO2 + O2  hence is recovered through Crystallization", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>37", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "An element Q contains 69% of 63Q and 31% in 65Q. What is the relative atomic mass of Q?", "images": [], "options": {"A": "63.0", "B": "63.6", "C": "65.0", "D": "69.0"}, "answer": "B", "explanation": "The relative atomic mass of an element is calculated by taking the weighted average of the atomic masses of its isotopes. In this case, the element Q contains 69% of 63Q and 31% of 65Q. So, the relative atomic mass of Q is (0.69 * 63) + (0.31 * 65) = 63.62, which is approximately 63.6.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>38", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The following ions have the same electron configuration except 8O,12Mg, 13Al, 17Cl", "images": [], "options": {"A": "Cl-", "B": "O2-", "C": "Mg2+", "D": "Al3-"}, "answer": "A", "explanation": "8O2+:2,8  Mg3+: 2,8  12Al2+:2,8  Cl- :2,8,8  it is on Cl- has a different electronic configuration", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>39", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ORBITALS", "question": "The region around the nucleus where electrons can be located is called", "images": [], "options": {"A": "spectra", "B": "an orbital", "C": "a qaunta", "D": "a field"}, "answer": "B", "explanation": "The region around the nucleus where electrons can be located is called an orbital. An orbital is a region of space where there is a high probability of finding an electron.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2021>40", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.", "question": "Proton and electron are called fundamental particles because they", "images": [], "options": {"A": "are indivisible", "B": "have different changes", "C": "are the lightest particles", "D": "are found in all matter"}, "answer": "D", "explanation": "Proton and electron are called fundamental particles because they are found in all matter. Fundamental particles are particles that are not made up of other particles. Protons and electrons are examples of such particles. They are found in all matter because all matter is made up of atoms, and atoms are made up of protons, electrons, and neutrons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2021>41", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "The activation energy of the reaction is", "images": ["Chemistry/imgs/2021/m73.jpg"], "options": {"A": "EA", "B": "EB", "C": "EC", "D": "Ep"}, "answer": "B", "explanation": "Activation energy is the energy possessed by the reacting particles which must b sufficient to overcome the activated complex (energy) of a chemical reaction , hence , it start from the reactant to the activated complex.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>42", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "The enthalpy change of the reaction is", "images": ["Chemistry/imgs/2021/m73.jpg"], "options": {"A": "EA", "B": "EB", "C": "EC", "D": "EP"}, "answer": "D", "explanation": "Enthalpy change (∆H) i the heat change of a chemical reaction   ∆H = Hp - Hb  Hp - heat of product  Hb - heat of reactant", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2021>43", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "The energy profile diagram illustrates", "images": ["Chemistry/imgs/2021/m73.jpg"], "options": {"A": "an endothermic reaction", "B": "an exothermic reaction", "C": "a spontaneous reaction", "D": "a radius reaction"}, "answer": "B", "explanation": "∆H = Hp - Hb.An exothermic reactant is one which its enthalpy change in negative (-ve) i.e the heat of reactant is greater the heat of product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>44", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many molecules of oxygen would occupy a volume of 2.24 cm3 at s.t.p?  [Molar volume at s.t.p = 22,400cm3, Avogadro's number = 6.02 x 1023]", "images": [], "options": {"A": "3.01 x 1020", "B": "3.01 x 1023", "C": "6.02 x 1019", "D": "6.02 x 1027"}, "answer": "C", "explanation": "numberofmole=volumemolar mass volume  n = 2.24/22400 = 0.0001mol  Also  n=No of moleculesAvog . constant  0.0001=No of molecules6.02x1023  No of molecules = 6.02x1023 x 0.0001  No of molecules = 6.02 x 1019", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>45", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The isotopes of neon are represented by the symbols 20xNe , 21yNe and 22zNe, the relationship between x,y, and z is", "images": [], "options": {"A": "x>y>z", "B": "x", "C": "x = y = z", "D": "x"}, "answer": "C", "explanation": "isotopes are atoms of the same element having the atomic number bu different mass number , hence x,y,and z are the same", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>46", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Which of the following pairs of molecules form hydrogen bonds?", "images": [], "options": {"A": "C2H2OH and CH3OH", "B": "CH2OH and H2", "C": "H2S and CH3", "D": "NH3 and SO3"}, "answer": "A", "explanation": "Hydrogen bond exist between hydrogen and a highly electro negative non -metal such as nitrogen , chlorine , fluorine or chlorine", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>47", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "What is the product of the reaction between ethanol and excess acidified KMnO4 solution?", "images": [], "options": {"A": "CH2=CH2", "B": "CH3COOH", "C": "CH3-CH3", "D": "CH3OCH3"}, "answer": "B", "explanation": "Reaction between Alkanol and KMnO4 is oxidation reaction. they are oxidized to give Alkanol and finally Alkanoic acid.  C2H5OH + ([0]) → Ch3CHO →CH3COOH", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>48", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "Electrovalent compound normally", "images": [], "options": {"A": "have low boiling points", "B": "Have mobile electrons", "C": "conducts electricity in the solid state", "D": "dissolve in polar solvent"}, "answer": "D", "explanation": "electrovalent compounds   - have high density with high melting and boiling points   - are soluble in polar solvents  - are mostly crystalline in nature", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2021>49", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "A coordinate covalent bond can be formed between", "images": [], "options": {"A": "NH3 and PCl3", "B": "HCl3 and AlCl3", "C": "BCl3 and NH3", "D": "H+ and AlCl3"}, "answer": "C", "explanation": "A coordinate covalent bond, also known as a dative bond, forms when both electrons in the bond come from the same atom, donating a lone pair of electrons to another atom or molecule that needs electrons to form a bond. NH3 can donate a pair of electrons to form a coordinate bond with BCl3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2021>50", "subject": "Chemistry", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "Which of the following scientist discovered the electron?", "images": [], "options": {"A": "Joseph J. Thompson", "B": "James chadwick", "C": "Amedo Avogadro", "D": "Ernest Rutherford"}, "answer": "A", "explanation": "J.J thomas discovered the electron through his popular experiment called cathode ray experiment , He filled a discharge tube with gas and connected two parallel plates to an e.m.f . At high voltage and low pressure , he discovered a glow from the cathode which consist of beams of electrons", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>1", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "The by-product of fermentation of sugar is", "images": [], "options": {"A": "carbon(IV) oxide.", "B": "ethanoic acid.", "C": "propanol", "D": "propan-1, 2, 3- triol."}, "answer": "A", "explanation": "Ethanol fermentation, also called alcoholic fermentation, is a biological process which converts sugars such as glucose, fructose, and sucrose into cellular energy, producing ethanol and carbon dioxide as by-products", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>2", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES", "question": "Which of the following sugars is a product  of the condensation of monosaccharides?", "images": [], "options": {"A": "Galactose", "B": "Maltose", "C": "Glucose", "D": "Fructose"}, "answer": "B", "explanation": "Maltose is produced by the enzymatic hydrolysis of starch (a homopolysaccharide) catalyzed by the enzyme amylase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>3", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The cleansing effect of soap is low in acidic water because of", "images": [], "options": {"A": "the formation of unionized fatty acid.", "B": "increase in the pH of the soap molecules.", "C": "anti-biodegradable effect of hydrogen ions", "D": "the hardness of the acidic water."}, "answer": "A", "explanation": "Soaps cannot be used in acidic condition because they lose their cleansing effect due to the formation of long chain fatty acids", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>4", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "The following compounds are condensation polymers except", "images": [], "options": {"A": "nylon", "B": "protein", "C": "starch", "D": "polyethene"}, "answer": "D", "explanation": "condensation polymers are any kind of polymers whose process of polymerization involves a condensation reaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>5", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "What amount of electricity is required to deposit one mole of aluminium from a solution of AlCl3?", "images": [], "options": {"A": "One Faraday", "B": "One ampere", "C": "Three Faradays", "D": "Three amperes"}, "answer": "C", "explanation": "AlCl3 → Al3+ + 3Cl-  At cathode:   Al3+ +  3e- → Al  3 mole of electrons corresponds 3 F charge  So, required charge =3 F", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>6", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following compounds would react rapidly with bromine?", "images": [], "options": {"A": "Benzene", "B": "Hexane", "C": "Hexene", "D": "Hexanol"}, "answer": "C", "explanation": "The addition of bromine to most alkenes is so fast that when bromine is added dropwise to a solution of the alkene the red bromine color disappears almost immediately. In fact, this discharge of color is a useful qualitative test for alkenes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>7", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Alkanols can be manufactured from alkenes by the initial reaction of alkenes with", "images": [], "options": {"A": "bromine in tetrachloromethane", "B": "concentrated tetraoxosulphate(VI) acid", "C": "aqueous potassium tetraoxomanganate(VII).", "D": "sodium hydroxide solution."}, "answer": "B", "explanation": "An alkene reacts with conc. H2SO4 to yield an alkyl hydrogen tetraoxosulphate (VI). The compound formed undergoes hydrolysis when boiled with water to yield an alcohol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>8", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "Which of the following statements about the standard hydrogen electrode is not correct?", "images": [], "options": {"A": "The hydrogen gas is at a pressure of 1 atmosphere", "B": "A solution containing 1 mol dm-3  of H+ (aq) ions is used", "C": "A platinum electrode is used", "D": "The temperature is kept at 20 °C"}, "answer": "D", "explanation": "The standard hydrogen electrode is a reference electrode used in electrochemical measurements. The conditions for the standard hydrogen electrode are: the hydrogen gas is at a pressure of 1 atmosphere, a solution containing 1 mol dm-3 of H+(aq) ions is used, a platinum electrode is used, and the temperature is kept at 25 °C (298 K), not 20 °C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>9", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "If 60 g of M combines with 24 g of oxygen, what would the empirical formula of the oxide be?", "images": [], "options": {"A": "MO", "B": "MO2", "C": "MO3", "D": "MO4"}, "answer": "C", "explanation": "Data obtained from the question  M = 60 g  O = 24 g  Empirical formula =?  How to determine the empirical formula  Divide by their molar mass  M = 60÷120 = 0.5  O = 24 ÷16 = 1.5  Divide by the smallest  M = 0.5÷0.5 = 1  O = 1.5 ÷0.5 = 3  Thus, the empirical formula of the oxide is MO₃", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>10", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The products of the electrolysis of dilute sodium chloride using carbon electrodes are    Anode &nbsp&nbsp Cathode", "images": [], "options": {"A": "chlorine and sodium.", "B": "oxygen and hydrogen.", "C": "chlorine and hydrogen.", "D": "hydrogen and oxygen."}, "answer": "C", "explanation": "During electrolysis, positive ions migrate towards the cathode and negative ions towards the anode. Sodium chloride dissociates into sodium ions and chloride ions. Chloride ions being negative, migrate towards the anode and are discharged as chlorine gas. Hydrogen ions from the water migrate towards the cathode and are discharged as hydrogen gas. Sodium ions and hydroxide ions remain in the solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>11", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "Determine the quantity of electricity used  when a current of 0.20 amperes is passed through an electrolytic cell for 60 minutes.", "images": [], "options": {"A": "12C", "B": "120C", "C": "360C", "D": "720C"}, "answer": "D", "explanation": "The quantity of electricity is calculated using the formula Q = It, where Q is the charge, I is the current and t is the time. Here, I = 0.20A and t = 60 minutes = 3600 seconds. So, Q = 0.20 * 3600 = 720C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>12", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Oxochlorate(I) acid is used as a bleaching agent because it is", "images": [], "options": {"A": "a weak acid", "B": "a reducing agent.", "C": "an oxidizing agent", "D": "a strong acid."}, "answer": "C", "explanation": "HOCl is unstable and decomposes to release oxygen which oxidizes the dye to form a colourless compound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>13", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP", "question": "The IUPAC name for CH3CHCH3CHCLCHCH3CH2CH3 is", "images": [], "options": {"A": "2, 4 - dimethyl - 3 - chlorohexane", "B": "3, 5 - dimethyl - 4 - chlorohexane", "C": "4 - chloro - 3, 5 - dimethylhexane", "D": "3 - chloro - 2, 4 - dimethylhexane"}, "answer": "B", "explanation": "The IUPAC name for the given compound is determined by identifying the longest carbon chain and numbering it in such a way that the substituents (in this case, the chlorine atom and the methyl groups) get the lowest possible numbers. The longest carbon chain here is six carbons long (hexane), and numbering from the left gives the chlorine atom the number 4 and the methyl groups the numbers 3 and 5. Therefore, the correct IUPAC name is 3, 5 - dimethyl - 4 - chlorohexane.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>14", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A colourless gas with a pungent smell is evolved when dilute hydrochloric acid is added to a sample of a salt. The gas evolved could turn", "images": [], "options": {"A": "acidified K2Cr2O7 solution colourless", "B": "acidified KMnO4 solution colourless", "C": "Fe(NO3)2 solution green", "D": "Pb(NO3)2 paper black"}, "answer": "B", "explanation": "If the potassium manganate(VII) solution is acidified with dilute sulfuric acid, the purple solution becomes colourless.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>15", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "If 5.0 g of marble reacts with 25.0 cm3 hydrochloric acid, which of the following combinations has the fastest reaction rate?", "images": [], "options": {"A": "Marble chips and 2.0 mol dm-3 HCl(aq)", "B": "Marble chips and 2.5 mol dm-3 HCl(aq)", "C": "Powdered marble and 2.5 mol dm-3 HCl(aq)", "D": "Powdered marble and 2.0 mol dm-3 HCl(aq)"}, "answer": "C", "explanation": "Powdered marble reacts more rapidly with HCl than the chips of marble because:  Surface area of powdered marble is more that of chips of marble and hence there is more collisions between the molecules of reactants  Number of molecules increases.  Energy of activation decreases  Marble chips will not react with HCl", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>16", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "Increasing the temperature generally", "images": [], "options": {"A": "decreases the solubility of a solid in a liquid but increases the solubility of a gas in a liquid.", "B": "increases the solubility of a solid in a liquid but decreases the solubility of a gas in a liquid.", "C": "increases the solubility of both a solid and a gas in a liquid", "D": "decreases the solubility of both a solid and a gas in a liquid"}, "answer": "B", "explanation": "-The solubility of gases in liquids decreases with increasing temperature. Conversely, adding heat to the solution provides thermal energy that overcomes the attractive forces between the gas and the solvent molecules, thereby decreasing the solubility of the gas  -The solubility of most solid or liquid solutes increases with increasing temperature", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>17", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "A white precipitate was formed when BaCl2(aq) was added to an aqueous solution of a salt X. The precipitate dissolved in dilute HCl with rapid effervescence. Salt X is likely to contain", "images": [], "options": {"A": "SO42- ions", "B": "SO32- ions", "C": "NO3- ions", "D": "CO32- ions"}, "answer": "D", "explanation": "Effervescence is the formation of gas bubbles in a liquid by a chemical reaction. An example of effervescence is the release of carbon dioxide which bubbles as a gas from the liquid when limestone chips, which are composed of calcium carbonate, are added to dilute hydrochloric acid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>18", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Before a reaction could take place, there should be", "images": [], "options": {"A": "ionization of reactant particles", "B": "breakage of bonds of products", "C": "breakage of bonds of reactants", "D": "ionization of product particles"}, "answer": "C", "explanation": "Activation energy must be achieved before reaction begin. This is because in any chemical reaction, chemical bonds in the reactants are broken, and new bonds in the products are formed", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>19", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Consider the following reaction equation:  CaO    +    SiO2 →  CaSiO3  Silicon(IV) oxide is acting as", "images": [], "options": {"A": "a basic oxide", "B": "a reducing agent", "C": "an acidic oxide", "D": "an oxidizing agent"}, "answer": "C", "explanation": "Silicon dioxide is an acidic oxide. It will react with strong bases to form silicate salts, SiO2 is acidic oxide because Si is non-metal. Oxides of non-metals are acidic in nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>20", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following acids would form normal salt only?", "images": [], "options": {"A": "Tetraoxosulphate(VI) acid", "B": "Trioxonitrate(V) acid", "C": "Tetraoxophosphate(V) acid", "D": "Trioxosulphate(IV) acid"}, "answer": "B", "explanation": "Trioxonitrate(V) acid, also known as nitric acid (HNO3), forms only normal salts. A normal salt is a salt that is formed by complete replacement of the hydrogen ion in an acid by a metal or ammonium ion. Nitric acid is a monobasic acid, meaning it has only one replaceable hydrogen ion. Therefore, it can only form normal salts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>21", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "What is the partial pressure of oxygen at s.t.p. in a gaseous mixture containing 100 cm3 of oxygen and 900 cm3 of nitrogen gas?", "images": [], "options": {"A": "1.0 atm", "B": "0.1 atm", "C": "9.0 atm", "D": "0.9 atm"}, "answer": "B", "explanation": "Partial pressure is found by Dalton's Law:  Px = PTotal ( nx / nTotal )  where  Px = partial pressure of gas x  PTotal = total pressure of all gases  nx = number of moles of gas x  nTotal = number of moles of all gases  Step 1  Find PTotal  Standard pressure is 1 atm.  Step 2  Add up the number of moles of the component gases to find nTotal  nTotal = noxygen + nnitrogen  nTotal = 100 + 900  nTotal =1000cm3  Step 3  Now you have all the information needed to plug the values into the equation and solve for Poxygen  Poxygen = PTotal ( noxygen / nTotal )  Poxygen = 1 atm ( 100 / 1000 )  Poxygen= 0.1atm  Answer  The partial pressure of the oxygen is 0.1 atm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>22", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STATES OF MATTER : DIAMOND AND GRAPHITE", "question": "Graphite is used as a dry lubricant due to the presence of", "images": [], "options": {"A": "mobile electrons", "B": "free electrons", "C": "octahedral structures", "D": "layered structures"}, "answer": "D", "explanation": "Graphite is used as a dry lubricant due to its layered structure. The layers of carbon atoms in graphite are held together by weak Van der Waals forces, which allow the layers to slide over each other easily. This property makes graphite an excellent dry lubricant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>23", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Which of the following gases is alkaline?", "images": [], "options": {"A": "NO2", "B": "CO2", "C": "NH3", "D": "N2O"}, "answer": "C", "explanation": "NH3, also known as ammonia, is a weak base and therefore is alkaline. When dissolved in water, it reacts with water to form ammonium ions and hydroxide ions, increasing the pH of the solution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>24", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Which of the following statements about an equilibrium system is correct?", "images": [], "options": {"A": "Forward and backward reactions occur   at the same rate", "B": "The concentrations of reactants must   equal that of the products", "C": "The concentrations of, reactants and products can be changed by adding a catalyst,", "D": "The concentrations of reactants and   products are not affected by a change in temperature"}, "answer": "A", "explanation": "Equilibrium is a state of a system where there is no observable change in the properties of the system with respect to time", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>25", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM", "question": "Consider the following reaction equation  N2(g) + 3H2(g) ⇌ 2NH3; ∆H = -92kJ    Increasing the temperature of the reaction would", "images": [], "options": {"A": "shift the equilibrium to the right", "B": "increase the yield of ammonia", "C": "decrease the amount of hydrogen", "D": "decrease the yield of ammonia"}, "answer": "D", "explanation": "In this case, an increase in in temperature will cause the equilibrium position to shift to the left thereby decreasing the yield of ammonia.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>26", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "When air in a syringe is compressed such that there is no change in temperature, the", "images": [], "options": {"A": "air liquefies", "B": "pressure increases", "C": "intermolecular space increases", "D": "density decreases"}, "answer": "B", "explanation": "Since the temperature of air remain constant.So, it is a isothermal process.    PV=K  This eq. shows that on increasing pressure, the volume gets reduced and vice-versa.  Since the syringe is slowly compressed, volume is decreasing.  Therefore, the pressure inside the syringe will increases because the molecules now hit the syringe walls more frequently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>27", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "Which of the following statements about liquids is/are true?  I.       Liquids maintain their volume at constant temperature.  II.     Liquids have fixed shape  III. Liquids do not diffuse  IV.   Change in pressure affects volume of liquids", "images": [], "options": {"A": "I only", "B": "IV only", "C": "I and IV only", "D": "II and III only"}, "answer": "A", "explanation": "A liquid is a nearly incompressible fluid that conforms to the shape of its container but retains a (nearly) constant volume independent of pressure", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>28", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "A hydrogen chloride gas reacted with oxygen gas to yield water and chlorine gas. The mole ratio of the hydrogen chloride gas to water is", "images": [], "options": {"A": "1:3", "B": "2:1", "C": "3:1", "D": "4:1"}, "answer": "B", "explanation": "The balanced chemical equation for the reaction of hydrogen chloride (HCl) with oxygen (O2) to yield water (H2O) and chlorine gas (Cl2) is 4HCl + O2 -> 2H2O + 2Cl2. From this equation, we can see that the mole ratio of HCl to H2O is 4:2, which simplifies to 2:1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>29", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "What number of moles of oxygen would exert a pressure of 10 atm at 320 K in an 8.2 dm3 cylinder?  [R=0.082 atm dm-3 mol-1 K-1]", "images": [], "options": {"A": "0.32", "B": "1.52", "C": "3.13", "D": "31.25"}, "answer": "C", "explanation": "P = 10atm,  T= 320K,   V= 8.2dm3  PV =nRT  n = P * V/R * T  10 * 8.2/0.082 * 320  = 82/26.24  n = 3.13", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>30", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "If 50 cm3 of a saturated solution of KNO3 at 40 °C contained 5:05 g of the salt, its solubility at the same temperature would be  [KNO3 = 101]", "images": [], "options": {"A": "1.0 mol dm-3", "B": "1.5 mol dm-3", "C": "2.0 mol dm-3", "D": "5.0 mol dm-3"}, "answer": "A", "explanation": "V= 50cm3  Mass= 5.05g  Relative molecular mass of KNO3 = (39+14+(3*16)) = 101  Convert 50cm3 to dm3 which is  1000cm³ = 1dm3  50cm³ = 50*1/1000  = 0.05dm3  Moles = mass/ molar mass  = 5.05/101 =0.05mole  Solubility= mole/volume  Solubility=0.05mol/0.05dm3  Solubility=1.0mol/dm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>31", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "PERIODIC CHEMISTRY : REACTIONS BETWEEN ACIDS AND METALS, THEIR OXIDES AND TRIOXOCARBONATES (IV).", "question": "Which of the following elements would displace copper from a solution of copper ions?", "images": [], "options": {"A": "Silver", "B": "Gold", "C": "Lead", "D": "Mercury"}, "answer": "C", "explanation": "The reactivity series allows us to predict how metals react. A more reactive metal displaces a less reactive metal from a compound. Lead is more reactive metal than copper hence, copper is displaced from copper solution by lead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>32", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "What is the percentage composition of carbon  in Ca(HCO3)2 ?  [ Ca = 40.0, 0= 16.0, C = 12.0, H= 1.0]", "images": [], "options": {"A": "22.2%", "B": "14.8%", "C": "7.4%", "D": "3.7%"}, "answer": "B", "explanation": ". % of C in Ca(HCO3)2   Molar mass of Ca(HCO3)2 = 40+(1+12+(16*3))2  =40+(13+48)2  =40+122  =162  C/Ca(HCO3)2 x 100  =12 * 2/162 * 100  =14.8%", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>33", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Which of the following bond types is intermolecular?", "images": [], "options": {"A": "Covalent bond", "B": "Hydrogen bond", "C": "Ionic bond", "D": "Metallic bond"}, "answer": "B", "explanation": "Hydrogen bond is an intermolecular force which arises when hydrogen is covalently linked to elements like nitrogen, oxygen and fluorine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>34", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The maximum number of covalent bonds formed by nitrogen is", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": "C", "explanation": "Nitrogen has five electrons in its outer shell and needs three more to complete its octet. Therefore, it can form three covalent bonds by sharing three of its electrons with other atoms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>35", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "The IUPAC name of the compound CH3CH(CH3)CHCH2 is", "images": [], "options": {"A": "2 - methyl but - 1 - ene", "B": "2 - methyl but - 2 - ene", "C": "3 - methyl but - 1 - ene", "D": "3 - methyl but - 2 - ene"}, "answer": "B", "explanation": "The longest carbon chain in the compound is four carbons long, which makes it a butene. The double bond is on the second carbon, hence the '2 - ene'. The methyl group (CH3) is also on the second carbon, hence the '2 - methyl'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>36", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Ionization energy increases across the period in the periodic table because", "images": [], "options": {"A": "atomic number increases", "B": "effective nuclear charge increases", "C": "mass number decreases", "D": "screening effect decreases"}, "answer": "B", "explanation": "As the nuclear charge increases, its attraction for the outermost electron increases and so more energy is required to remove the outermost electron. Hence, the ionization energy increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>37", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.", "question": "Which of the following properties indicate that an element is a metal. It   I.  reacts with oxygen to form an acidic oxide  II. forms ionic chlorides  III. has variable oxidation states  IV. displaces hydrogen from dilute HCl", "images": [], "options": {"A": "I and III only", "B": "I and II only", "C": "II and IV only", "D": "I, II, III and IV"}, "answer": "C", "explanation": "-ionization behaviour  The atoms of non-metals usually have four to seven valence electrons. They have a great tendency to ionize by accepting electrons to form negative ions.  - Reaction with acids  A metal which is more electro positive than hydrogen readily displaces the hydrogen ion, H+, from an acid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>38", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The electron configuration of carbon atom in its excited state is", "images": [], "options": {"A": "1s22s22px22py0", "B": "1s22s22px12py1", "C": "1s22s12px12py12pz1", "D": "1s12s22px12py12pz1"}, "answer": "C", "explanation": "-So any electron configuration in which the last electron (again, the valence electron) is in a higher energy orbital, this element is said to be in an excited state.   -When a carbon atom becomes excited by absorbing energy, one of its 2s electrons is promoted into the 2p sublevel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>39", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "An oxide has the following properties. It  I. is a white powder  II. reacts with HCl.  III. reacts with NaOH  IV. is insoluble in water  The oxide is", "images": [], "options": {"A": "alkaline", "B": "amphoteric", "C": "acidic", "D": "neutral"}, "answer": "B", "explanation": "An amphoteric oxide is an oxide that can act as either an acid or base in a reaction to produce a salt and water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>40", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.", "question": "Which of the following statements about atoms of a metal is correct? They", "images": [], "options": {"A": "readily accept electrons", "B": "are soft", "C": "are held together by covalent bond", "D": "are held together by a sea of electron cloud"}, "answer": "D", "explanation": "Metals are effectively lots of positively charged ions with a cloud/sea of delocalised electrons. This means the electrons are free to move throughout the metal, and is also why metals can conduct electricity as the electrons can move. The more delocalised electrons a metal has, the stronger it will be held together.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>41", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "Which of the following sketches is a graphical representation of Boyle's law?", "images": ["Chemistry/imgs/2022/optiona.png", "Chemistry/imgs/2022/optionb.png", "Chemistry/imgs/2022/optionc.png", "Chemistry/imgs/2022/optiond.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "Boyles law states that the volume of a given mass of gas is inversely proportional to pressure at constant temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>42", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The atom with the electron configuration   1s22s22p63s23p63d104s24p4 is in", "images": [], "options": {"A": "period 4, p- block", "B": "period 3, p- block", "C": "period 4, d- block", "D": "period 3, d- block"}, "answer": "A", "explanation": "The electron configuration 1s22s22p63s23p63d104s24p4 corresponds to a Selenium (Se) atom. Selenium is in the 4th period and in the p-block of the periodic table. The p-block elements are those in which the last electron enters the outermost p-orbital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>43", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Electropositivity of elements across the periodic table normally", "images": [], "options": {"A": "remains constant down the group", "B": "increases across the period", "C": "decreases across the period", "D": "decreases down the group"}, "answer": "C", "explanation": "Electropositivity is known to increase down groups and decrease across periods in the modern periodic table (i.e., electropositivity decreases from left to right and it increases from up to down).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>44", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STATES OF MATTER : LIQUIDS", "question": "Consider the following table   SubstanceMelting point / oCBoiling point / oCP-78-25Q-840R-6150S44280Which of the substances is a liquid at room temperature and rapidly evaporates on exposure to air?", "images": [], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "B", "explanation": "Substance Q has a melting point below room temperature and a boiling point above room temperature, which means it would be a liquid at room temperature and would evaporate when exposed to air.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>45", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following oxides is amphoteric?", "images": [], "options": {"A": "Carbon(II) oxide", "B": "Nitrogen(IV) oxide", "C": "Lead(II) oxide", "D": "Calcium oxide"}, "answer": "C", "explanation": "Aluminium oxide is an amphoteric oxide. With sodium hydroxide solution, it produces water and sodium aluminate (NaAlO2). The other common examples of amphoteric oxides include SnO, ZnO, and PbO. Al2O3 is an amphoteric oxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>46", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Which of the following processes occur during fractional distillation of petroleum?", "images": [], "options": {"A": "Condensation and diffusion", "B": "Diffusion and evaporation", "C": "Diffusion and sublimation", "D": "Evaporation and condensation"}, "answer": "D", "explanation": "Fractional distillation is a series of processes of evaporation and condensation at a number of points in a vertical column.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>47", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "If the molar mass of X(HCO3)2 is 162 g mol-1 , determine the relative atomic mass of X.  [H = 1.0, C = 12.0, 0 = 16.0]", "images": [], "options": {"A": "40", "B": "48", "C": "61", "D": "101"}, "answer": "A", "explanation": "The molar mass of X(HCO3)2 is given as 162 g mol-1. The molar mass of HCO3 is (1.0 + 12.0 + (3*16.0)) = 61.0 g mol-1. Since there are two HCO3 in the compound, the total molar mass of HCO3 in the compound is 2*61.0 = 122.0 g mol-1. Subtracting this from the total molar mass of the compound gives the relative atomic mass of X as 162.0 - 122.0 = 40 g mol-1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2022>48", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Charcoal is used in the decolourization of sugar because of its", "images": [], "options": {"A": "absorption property.", "B": "amorphous property.", "C": "oxidizing property.", "D": "adsorption property."}, "answer": "D", "explanation": "Wood charcoal is used to decolourise sugar because it has a highly porous structure, providing a large surface area for adsorption. Therefore, it adsorbs coloured material from sugar.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2022>49", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : SCIENTIFIC METHODS", "question": "The first definition of an element was made by", "images": [], "options": {"A": "J. Dalton.", "B": "A. Lavoisier.", "C": "R. Boyle.", "D": "J. J. Thompson."}, "answer": "C", "explanation": "The word element was first given by Rebert Boyle. It is defined as the simplest chemical substance that cannot be broken down during a chemical reaction", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2022>50", "subject": "Chemistry", "year": "2022", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.", "question": "Which of the following scientists formulated the law of conservation of mass?", "images": [], "options": {"A": "A. Lavoisier", "B": "J. Dalton", "C": "R. Boyle", "D": "J. Proust"}, "answer": "A", "explanation": "Law of conservation of mass was given by Antoine Lavoisier in 1744. According to this law, \"Matter can neither be created nor destroyed in a chemical reaction\".", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>1", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STATES OF MATTER : KINETIC THEORY OF MATTER.", "question": "Which of the following laws or theory cannot be explained by the application of the kinetic theory of gases?", "images": [], "options": {"A": "Dalton's atomic theory", "B": "Charles' law", "C": "Gay-lussac's law", "D": "Boyle's law"}, "answer": "A", "explanation": "Dalton's atomic theory cannot be explained by the application of the kinetic theory of gases because it deals with the atomic-level structure and behavior of matter, which is beyond the scope of the kinetic theory's focus on the macroscopic behavior of gas particles. The other laws (Charles' law, Gay-Lussac's law, and Boyle's law) can be well understood and explained by the kinetic theory of gases, as they relate to the macroscopic properties and behaviors of gases and their constituent particles.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2023>2", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "The primary component of natural gas", "images": [], "options": {"A": "butane", "B": "ethane", "C": "methane", "D": "propane"}, "answer": "C", "explanation": "Natural gas is a fossil fuel primarily composed of hydrocarbon gases. The primary component of natural gas is methane, which typically makes up a significant portion of the gas mixture. Methane is a simple hydrocarbon with one carbon atom and four hydrogen atoms (CH4). It is the main component of natural gas, often accounting for over 90% of its composition.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>3", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Thermal cracking of alkanes usually", "images": [], "options": {"A": "involves decomposition", "B": "is an exothermic process", "C": "produces only small alkanes", "D": "requires hydrogen"}, "answer": "A", "explanation": "Thermal cracking is a process used in the petroleum industry to break down long-chain alkanes (hydrocarbons) into smaller, more useful hydrocarbons. It involves the decomposition of high-molecular-weight hydrocarbons, such as heavy crude oil fractions or long-chain alkanes, into lower-molecular-weight hydrocarbons, like smaller alkanes and alkenes. During thermal cracking, high temperatures and sometimes pressure are applied to the feedstock (such as crude oil or natural gas) to initiate the decomposition reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>4", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL", "question": "Carbon is deposited in the exhaust pipes of cars because of", "images": [], "options": {"A": "contamination of petrol with diesel", "B": "presence of carbon in petrol", "C": "presence of additives in petrol", "D": "incomplete combustion of petrol"}, "answer": "D", "explanation": "Carbon is deposited in the exhaust pipes of cars primarily because of incomplete combustion of petrol. When the fuel (petrol) is burned in the engine's combustion chamber, ideally, it should be fully oxidized, resulting in the production of carbon dioxide (CO2) and water vapor. However, in real-world conditions, the combustion process may not be perfect, and some of the carbon in the petrol may not fully burn. As a result, carbon particles are formed and get carried through the exhaust system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>5", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROCHEMICAL CELLS", "question": "How many moles of copper would be deposited by passing 1 Faraday of electricity through a CuCl2 solution?", "images": [], "options": {"A": "2", "B": "1", "C": "0.5", "D": "0.25"}, "answer": "C", "explanation": "1 Faraday of electricity is equal to the charge of 1 mole of electrons, which is 96,485 coulombs. The reduction of copper(II) ions in solution to copper metal requires 2 electrons per ion, so 1 Faraday of electricity will deposit 0.5 moles of copper.  1 Faraday * (2 electrons/Cu ion) / (1 mole electrons/96,485 coulombs) * (1 mole Cu/2 electrons) = 0.5 moles Cu", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>6", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Alkenes can be manufactured by", "images": [], "options": {"A": "addition of hydrogen to unsaturated vegetable oils", "B": "the cracking of hydrocarbons", "C": "polymerization reactions", "D": "the combustion of alkanes"}, "answer": "B", "explanation": "Cracking is a chemical process in which larger hydrocarbon molecules are broken down into smaller and more useful ones. This process is commonly used in petroleum refining to convert heavy hydrocarbons into lighter fractions, including alkenes. During cracking, high-temperature and/or catalytic conditions are applied to break the long carbon chains of hydrocarbons into shorter ones. This process produces a mixture of products, including alkenes, which are unsaturated hydrocarbons containing carbon-carbon double bonds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>7", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Petrochemistry is an example of", "images": [], "options": {"A": "pure chemistry", "B": "applied chemistry", "C": "biochemistry", "D": "environmental chemistry"}, "answer": "B", "explanation": "Applied chemistry refers to the practical application of chemical principles and techniques to solve real-world problems and create useful products. Petrochemistry is a branch of applied chemistry that deals specifically with the chemical processes and transformations involved in the extraction, refining, and processing of petroleum and its derivatives.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>8", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Species that occur in a reaction pathway but not in the overall reaction are known as", "images": [], "options": {"A": "products", "B": "inhibitors", "C": "reactants", "D": "intermediates"}, "answer": "D", "explanation": "In a chemical reaction, intermediates are the chemical species that are formed during the reaction but are subsequently consumed in further steps, leading to the final products. They are transient species that exist momentarily during the reaction process and are not present in the initial reactants or the final products of the overall reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>9", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "Which of the following statements is correct?", "images": [], "options": {"A": "An alkane with 49 carbon atoms contain 100 hydrogen atoms", "B": "Addition reactions occur between alkanes and chlorine", "C": "Butane has a lower boiling point than propane.", "D": "Pentane has five isomers"}, "answer": "A", "explanation": "The general formula for alkanes is CnH2n+2. For an alkane with 49 carbon atoms (n = 49), the number of hydrogen atoms can be calculated as follows:    Number of hydrogen atoms (H) = 2n + 2  Number of hydrogen atoms (H) = 2 * 49 + 2  Number of hydrogen atoms (H) = 98 + 2  Number of hydrogen atoms (H) = 100    So, an alkane with 49 carbon atoms contains 100 hydrogen atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>10", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "The best indicator to use for the titration of ethanoic acid with sodium hydroxide is", "images": [], "options": {"A": "methyl red.", "B": "methyl orange.", "C": "phenolphthalein", "D": "screened methyl orange"}, "answer": "C", "explanation": "Phenolphthalein is an indicator that is commonly used in acid-base titrations. It is colorless in acidic solutions (pH below 8.2) and turns pink or magenta in alkaline solutions (pH above 10). In the titration of ethanoic acid (acetic acid) with sodium hydroxide (a strong base), the pH will change from acidic to alkaline as the acid is neutralized by the base.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>11", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "REDOX REACTIONS : REDOX EQUATIONS", "question": "The reduction half equation of the following reaction is:  Zn(s) + CuSO4(aq) → ZnSO4(aq) + Cu(s)", "images": [], "options": {"A": "CuSO4(s) + H2O(l)  → Cu2+(aq) + SO42-(aq)", "B": "Cu2+(aq)  + 2e- → Cu(s)", "C": "Cu2+(aq) + e- → Cu(s)", "D": "Zn(s) → Zn2+(aq) + 2e-"}, "answer": "B", "explanation": "he reduction half equation for the given reaction is:    Cu2+(aq) + 2e- → Cu(s)    In the overall reaction, copper(II) ions (Cu2+) gain two electrons (2e-) and get reduced to form solid copper (Cu) metal. This is the reduction half-reaction in the redox reaction between zinc (Zn) and copper(II) sulfate (CuSO4).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>12", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "If 100cm3 of a saturated solution of sodium tetraoxosulphate (VI) at 30 oC contains 10.5 g of the salt, what would be its solubility at this temperature? [Na2SO4 = 142]", "images": [], "options": {"A": "0.57 mol dm-3", "B": "0.60 mol dm-3", "C": "0.74 mol dm-3", "D": "2.15 mol dm-3"}, "answer": "C", "explanation": "Molar mass of Na2SO4 = 2(Na) + S + 4(O) = 2(23.0 g/mol) + 32.1 g/mol + 4(16.0 g/mol) = 46.0 g/mol + 32.1 g/mol + 64.0 g/mol = 142.1 g/mol    Now, we can calculate the number of moles of Na2SO4 in the solution:    Number of moles = Mass of the salt / Molar mass  Number of moles = 10.5 g / 142.1 g/mol ≈ 0.0739 mol    Next, we need to find the volume of the saturated solution, given as 100 cm³, and convert it to liters:    Volume of solution = 100 cm³ = 100 cm³ / 1000 cm³/dm³ = 0.1 dm³    Finally, we can calculate the solubility in mol/dm³:  Solubility = Number of moles / Volume of solution  Solubility = 0.0739 mol / 0.1 dm³ ≈ 0.739 mol/dm³    Rounded to two decimal places, the solubility of sodium tetraoxosulphate (VI) at 30°C is approximately 0.74 mol/dm³.  Therefore, the correct option is:  0.74 mol dm-3.  Solubility = 10.5 g / 100 cm3 * 142 g/mol = 0.739 mol/dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>13", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CRITERIA FOR PURITY", "question": "An example of a crystalline substance that does not possess water of crystallization is", "images": [], "options": {"A": "potassium trioxonitrate (V)", "B": "sodium trioxocarbonate (IV).", "C": "iron (II) tetraoxosulphate (VI).", "D": "sodium tetraoxosulphate (VI)."}, "answer": "A", "explanation": "The chemical formula for potassium trioxonitrate (V) is KNO3. It is also known as potassium nitrate. This compound does not have any water molecules as part of its crystal structure, making it anhydrous. So, it is an example of a crystalline substance that does not possess water of crystallization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>14", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "The salt solution formed from a reaction between ethanoic acid and sodium hydroxide solution would be", "images": [], "options": {"A": "basic", "B": "acidic", "C": "neutral", "D": "amphoteric"}, "answer": "A", "explanation": "Ethanoic acid is a weak acid, while sodium hydroxide is a strong base. When these two substances react, they neutralize each other, forming a salt and water. The salt is a compound of the cation from the base and the anion from the acid. In this case, the salt is sodium ethanoate, which is a basic salt.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>15", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following reactions represents the hydrolysis of an alkanoate?", "images": [], "options": {"A": "CH3COOH  + C2H5OH  ⇌H+⇌  CH3COOC2H5 + H2O", "B": "CH3COOC2H5 + H2O ⇌H+⇌  CH3COO- + CH3CH2OH", "C": "CH3COOCH2CH3 + H2O ⇌H+⇌  CH3COOH + CH3CH2OH", "D": "CH3COOH + OH-  ⇌H+⇌  CH3COO- + H2O"}, "answer": "B", "explanation": "The hydrolysis of an alkanoate is the reaction of an alkanoate with water to form a carboxylic acid and an alcohol. The correct reaction is:    CH3COOC2H5 + H2O ⇌H+⇌  CH3COO- + CH3CH2OH", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>16", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Which of the following statements about the collision theory is correct?", "images": [], "options": {"A": "All collisions bring about reactions.", "B": "Rate of reaction is proportional to the number of effective collisions", "C": "Collision of molecules will split the molecules to react", "D": "Ineffective collision brings about chemical reaction."}, "answer": "B", "explanation": "The rate of reaction is proportional to the number of effective collisions. This means that if the number of collisions increases, the rate of reaction will also increase. These successful collisions are known as effective collisions. The rate of reaction is directly proportional to the number of effective collisions between reactant molecules. In other words, the more frequent and successful the collisions, the faster the rate of the reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>17", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN", "question": "Why are H2SO4 and CaCl2, not suitable for drying ammonia gas? They", "images": [], "options": {"A": "are corrosive", "B": "are poisonous.", "C": "react with the gas", "D": "pollute the gas"}, "answer": "C", "explanation": "H2SO4 and CaCl2 are not suitable for drying ammonia gas because they react with the gas.    Ammonia is a basic gas, and both H2SO4 and CaCl2 are acidic. When these two substances react, they form salts that contain ammonia. This can contaminate the ammonia gas and make it unusable.    In addition, H2SO4 is a corrosive substance, and CaCl2 can be harmful to breathe in. Therefore, it is not safe to use these substances to dry ammonia gas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>18", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HALOGENS", "question": "Which of the following equations does not illustrate correctly one of the reactions of chlorine?", "images": [], "options": {"A": "H2S + Cl2 → 2HCl + S", "B": "Cl2 + 2NaOH → NaCl + NaClO + H2O", "C": "Cl2 + 2NaF → 2NaCl + F2", "D": "Ca(OH)2 + Cl2 → CaOCl2 + H2O"}, "answer": "C", "explanation": "The equation Cl2 + 2NaF → 2NaCl + F2 does not illustrate correctly one of the reactions of chlorine.    In this reaction, chlorine reacts with sodium fluoride to form sodium chloride and fluorine gas. However, this reaction is not possible because fluorine is a much more reactive element than chlorine. When chlorine and fluorine react, they form a compound called chlorine trifluoride (ClF3), which is a very powerful oxidizing agent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>19", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "How many unpaired electrons are present in 26Fe3+?", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "D", "explanation": "There are 5 unpaired electrons present in 26Fe3+.    The atomic number of iron is 26, so it has 26 electrons. When iron loses 3 electrons to form Fe3+, it loses 2 from the s orbital and 1 from the d orbital. This leaves 5 unpaired electrons in the d orbital.    The electron configuration of Fe3+ is [Ar]3d5. The 5 d electrons are all unpaired because Hund's rule states that electrons will occupy degenerate orbitals singly before they pair up. This is because unpaired electrons have a lower energy than paired electrons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>20", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Going down group II in the periodic table normally", "images": [], "options": {"A": "shielding effect decreases", "B": "melting point increases", "C": "ionization energy increases", "D": "electronegativity increases"}, "answer": "B", "explanation": "Melting point increases. This is because the atoms become larger as you go down the group, which means that the metallic bonds between them become stronger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>21", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following elements has its valence electrons in the s-orbital?", "images": [], "options": {"A": "Sodium", "B": "Carbon", "C": "Phosphorus", "D": "Aluminium"}, "answer": "A", "explanation": "Sodium is an alkali metal, and its atomic number is 11. This means that it has 11 electrons, and its electron configuration is 1s2 2s2 2p6 3s1. The valence electrons are the electrons in the outermost shell, which in this case is the 3s orbital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>22", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The periodic property that is used to determine whether a covalent molecule is polar or not is", "images": [], "options": {"A": "atomic radius.", "B": "electron affinity.", "C": "electronegativity", "D": "ionization energy"}, "answer": "C", "explanation": "The periodic property that is used to determine whether a covalent molecule is polar or not is electronegativity.    Electronegativity is a measure of the ability of an atom to attract electrons in a chemical bond. The greater the electronegativity of an atom, the more strongly it will attract electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>23", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : SCIENTIFIC METHODS", "question": "The following steps are scientific methods except", "images": [], "options": {"A": "analysis", "B": "open-mindedness", "C": "experimentation", "D": "problem identification."}, "answer": "B", "explanation": "From the given options, \"Open-mindedness\" is not a specific step in the scientific method. Open-mindedness is a general mindset that scientists should have throughout the entire process. It involves being receptive to new ideas, evidence, and interpretations, which helps scientists avoid biases and reach more accurate conclusions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>24", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Isoelectronic species have the same number of", "images": [], "options": {"A": "electrons", "B": "neutrons", "C": "protons", "D": "ions"}, "answer": "A", "explanation": "The term \"isoelectronic\" comes from the Greek words \"iso\" meaning \"equal\" and \"electron\" meaning \"electron\". Isoelectronic species are atoms, molecules, or ions that have the same number of electrons.  soelectronic species have the same number of electrons because they have the same electron configuration. The electron configuration of an atom is the arrangement of electrons in the atom's orbitals. The electron configuration of an atom determines the chemical properties of the atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>25", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.", "question": "An element X, has two isotopes, 6530X and 6630X with relative abundance of 60 % and 40% respectively. The relative atomic mass of X is", "images": [], "options": {"A": "65.00.", "B": "65.40", "C": "65.50", "D": "66.00"}, "answer": "B", "explanation": "Isotope 6530X (with a mass of 65 and an abundance of 60%):  Relative mass contribution = (65 * 60%) = 39.00  Isotope 6630X (with a mass of 66 and an abundance of 40%):  Relative mass contribution = (66 * 40%) = 26.40  Now, add the relative mass contributions of both isotopes:  Relative atomic mass (A_r) = 39.00 + 26.40 = 65.40  So, the relative atomic mass of element X is 65.40. The correct option is:  65.40", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2023>26", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "The pair of compounds that belongs to the same homologous series is", "images": [], "options": {"A": "C3H8 and C3H6", "B": "C4H10 and C5H10", "C": "C2H4 and C4H10", "D": "C2H6 and C4H10"}, "answer": "D", "explanation": "In the given options, C2H6 (ethane) and C4H10 (butane) both belong to the same homologous series, as they have the same alkane functional group (CnH2n+2) and differ by a CH2 group:  C2H6: Ethane  C4H10: Butane  Both of these compounds are members of the alkane homologous series.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>27", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION", "question": "A consequence of global warming is", "images": [], "options": {"A": "flooding", "B": "water pollution", "C": "air pollution", "D": "high humidity."}, "answer": "A", "explanation": "Flooding is a major consequence of global warming because as the Earth's ice caps and glaciers melt, sea levels rise. This can cause flooding in coastal areas and low-lying islands. For example, in 2019, the Netherlands experienced its worst flooding in decades, with over 10,000 homes damaged and thousands of people evacuated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>28", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases has the lowest rate of diffusion?  [H=1.0, C=12.0, N = 14.0, O= 16.0]", "images": [], "options": {"A": "Nitrogen", "B": "Ammonia", "C": "Oxygen", "D": "Methane"}, "answer": "C", "explanation": "The rate of diffusion of a gas is inversely proportional to the square root of its molar mass (Graham's law). This means that gases with a higher molar mass will diffuse more slowly than gases with a lower molar mass. Given the molar masses of the gases in the options, Oxygen (O=16.0) has the highest molar mass and therefore the lowest rate of diffusion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>29", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "The gas that is less dense than air is", "images": [], "options": {"A": "carbon (IV) oxide", "B": "nitrogen", "C": "chlorine", "D": "oxygen"}, "answer": "B", "explanation": "The density of a gas is directly proportional to its molar mass. This means that gases with a lower molar mass will be less dense than gases with a higher molar mass. Nitrogen (N2) has a molar mass of 28 g/mol, which is less than that of air (approximately 29 g/mol), making it less dense than air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>30", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Which of the following equimolar solutions has the highest conductivity?", "images": [], "options": {"A": "H2CO3(aq)", "B": "H2SO4(aq)", "C": "NaOH(aq)", "D": "CH3COONa(aq)"}, "answer": "B", "explanation": "H2SO4(aq) is a strong acid that dissociates into two hydrogen ions (H+) and one sulfate ion (SO42-) when dissolved in water. This leads to a higher concentration of ions in solution, resulting in higher conductivity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>31", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "What takes place at the cathode during electrolysis?", "images": [], "options": {"A": "Anions lose electrons", "B": "Anions are oxidized", "C": "Cations are discharged", "D": "Cations are oxidized"}, "answer": "C", "explanation": "Cations are discharged at the cathode during electrolysis.    Electrolysis is the process of using an electric current to cause a chemical reaction to take place. The cathode is the negative electrode in an electrolytic cell. It is where cations (positively charged ions) are discharged.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>32", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many grammes of NaOH(s) would be needed to produce 100.0 cm3 of a 0.20 mol dm-3 NaOH, (aq)? [NaOH = 40.0]", "images": [], "options": {"A": "0.02 g", "B": "0.80 g", "C": "20.0 g", "D": "800.0"}, "answer": "B", "explanation": "Amount (in moles) = Molarity × Volume  Amount (in moles) = 0.20 mol/dm³ × 100.0 cm³ / 1000 cm³/dm³ = 0.020 moles  Now, we can calculate the mass using the formula:  Mass = Amount × Molar Mass  Mass = 0.020 moles × 40.0 g/mol = 0.80 g  So, the correct answer is:0.80 g", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>33", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The formation of a bond between hydrogen and a highly electronegative atom results in", "images": [], "options": {"A": "polarity", "B": "dipole", "C": "metallic bond", "D": "electrovalent bond"}, "answer": "A", "explanation": "The formation of a bond between hydrogen and a highly electronegative atom results in polarity because the electronegative atom will attract the shared pair of electrons more than the hydrogen atom, creating a dipole with a partial negative charge on the electronegative atom and a partial positive charge on the hydrogen atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>34", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "The molecule that has a non-polar covalent bond is", "images": [], "options": {"A": "H2O", "B": "HCl", "C": "NH3", "D": "Cl2"}, "answer": "D", "explanation": "In Cl2, the two chlorine atoms are identical and have the same electronegativity. Since both atoms have the same electronegativity, the electrons in the covalent bond are shared equally, resulting in a non-polar covalent bond. The molecule does not have a significant separation of charge and lacks a permanent dipole moment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>35", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I", "question": "Which of the elements in the table below would react more readily with chlorine?  ElementIonization energy (KJ mol-1 x 10-3W12.0X21.0Y106.0Z200.0", "images": [], "options": {"A": "W and X only", "B": "W and Z only", "C": "X and Z only", "D": "Y and Z only"}, "answer": "A", "explanation": "Among the given elements, W has the lowest ionization energy (12.0 KJ mol^-1 x 10^-3), indicating that it would be more likely to react with chlorine. X has a higher ionization energy (21.0 KJ mol^-1 x 10^-3), so it would be less reactive with chlorine compared to W.  Based on ionization energy values, the elements that would react more readily with chlorine are W and X.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>36", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "The relative molar mass of a gaseous hydrocarbon is 30. Determine its vapour density.", "images": [], "options": {"A": "15", "B": "30", "C": "60", "D": "45"}, "answer": "A", "explanation": "Vapour density = Relative molar mass / 2  Vapour density = 30 / 2 = 15  Therefore, the vapour density of the gaseous hydrocarbon is 15.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>37", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Consider the following reaction equation:  2SO3(g) → 2SO2(g) + O2(g)  ∆H = +198 kJ mol-1  Which of the following statements about the reaction is correct?", "images": [], "options": {"A": "The reaction is exothermic", "B": "The reaction container would feel warm.", "C": "198 kJ of energy is given off", "D": "198 kJ of energy is absorbed"}, "answer": "D", "explanation": "A positive value of ∆H (+198 kJ mol-1) indicates that the reaction is endothermic, meaning it requires an input of energy to proceed. In this case, the reaction absorbs 198 kJ of energy per mole of reactants to convert 2 moles of SO3 into 2 moles of SO2 and 1 mole of O2. This means that the reaction container would need to be supplied with energy, and it would feel cooler rather than warmer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>38", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STATES OF MATTER : KINETIC THEORY OF MATTER.", "question": "Which of the following properties does not give evidence of the kinetic theory of matter?", "images": [], "options": {"A": "Evaporation", "B": "Diffusion", "C": "Polymerization", "D": "Melting"}, "answer": "C", "explanation": "Polymerization is a process in which small molecules combine to form larger molecules. This process is not consistent with the kinetic theory of matter because it does not involve the movement of particles. The particles in a polymer are not moving randomly. They are bonded together in a fixed structure.  Therefore, the property that does not give evidence of the kinetic theory of matter is polymerization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>39", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "A compound that could be dried by using conc. tetraoxosulphate (VI) acid and not by calcium oxide is likely to be", "images": [], "options": {"A": "an alkaline gas", "B": "a neutral salt", "C": "a deliquescent salt", "D": "an acid anhydride"}, "answer": "D", "explanation": "The compound that could be dried by using conc. tetraoxosulphate (VI) acid and not by calcium oxide is an acid anhydride.  Acid anhydrides are compounds that can react with water to form acids. When acid anhydrides are exposed to air, they will absorb water from the air and become hydrated. This can make them difficult to dry with calcium oxide, which is a base.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>40", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "Positive ions in a sea of electrons are found in", "images": [], "options": {"A": "covalent bonds.", "B": "dative bonds", "C": "ionic bonds", "D": "metallic bonds."}, "answer": "D", "explanation": "In metallic bonding, positive metal ions (cations) are surrounded by a \"sea\" of delocalized electrons that move freely throughout the metal lattice. This arrangement creates a cohesive force that holds the metal atoms together. The mobile electrons contribute to the unique properties of metals, such as high electrical and thermal conductivity, malleability, and ductility.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2023>41", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Dilute trioxonitrate (V) acid does not produce hydrogen when it reacts with metals because", "images": [], "options": {"A": "it is a strong oxidizing agent", "B": "it reacts with the product", "C": "there is no visible reaction", "D": "it is highly corrosive"}, "answer": "A", "explanation": "Dilute trioxonitrate (V) acid does not produce hydrogen when it reacts with metals because it is a strong oxidizing agent.    Trioxonitrate (V) acid, also known as nitric acid, is a strong oxidizing agent. This means that it can easily oxidize metals, which means that it can remove electrons from metals. When nitric acid oxidizes a metal, it forms a salt and water. The salt does not contain hydrogen, so no hydrogen gas is produced", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>42", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "How many moles are there in 3.0 g of O2? [O = 16.0]", "images": [], "options": {"A": "0.0093", "B": "0.0930", "C": "0.6250", "D": "0.0625"}, "answer": "B", "explanation": "Number of moles = Mass / Molar mass    Given that the molar mass of oxygen (O2) is 32.0 g/mol (2 × 16.0 g/mol), you can calculate the number of moles:    Number of moles = 3.0 g / 32.0 g/mol = 0.09375 moles    Rounded to four significant figures, the number of moles in 3.0 g of O2 is approximately 0.0938 moles.    Therefore, the closest answer choice is:  0.0930 moles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>43", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "Copper (II) ions are able to participate in co-ordinate covalent bonding because they", "images": [], "options": {"A": "are coloured.", "B": "have unpaired electrons", "C": "have vacant d-orbital", "D": "are positively charged"}, "answer": "C", "explanation": "Copper (II) ions have vacant d-orbitals. This means that they can accept a pair of electrons from a donor atom. When a copper (II) ion accepts a pair of electrons, it forms a co-ordinate covalent bond with the donor atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>44", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE TITRATION", "question": "Determine the volume of 0.100 mol of HCl in 0.250 mol dm3 of solution.", "images": [], "options": {"A": "20 cm3", "B": "100 cm3", "C": "200 cm3", "D": "400 cm3"}, "answer": "D", "explanation": "Molarity = 0.100 mol / 0.250 mol dm3  = 0.100 mol / 0.250 dm3 * 1000 cm3/dm3  = 400 cm3  Volume (V) = Amount (n) / Concentration (C)  Given that the amount of HCl is 0.100 mol and the concentration of the solution is 0.250 mol/dm³, you can calculate the volume:  Volume (V) = 0.100 mol / 0.250 mol/dm³ = 0.4 dm³  Since 1 dm³ is equal to 1000 cm³, you can convert the volume from dm³ to cm³:  Volume (V) = 0.4 dm³ × 1000 cm³/dm³ = 400 cm³  Therefore, the volume of 0.100 mol of HCl in a 0.250 mol/dm³ solution is 400 cm³.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>45", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the statements about gases is not correct?", "images": [], "options": {"A": "The total kinetic energy of the gas is not affected by collision.", "B": "Molecules of the gas are in constant motion", "C": "Gases have low densities compared to solids and liquids of equal mass.", "D": "Gases are highly soluble in water at high temperatures"}, "answer": "D", "explanation": "The statement that is not correct about gases is Gases are highly soluble in water at high temperatures.    Gases are not highly soluble in water at high temperatures. In fact, the solubility of gases in water decreases as the temperature increases. This is because the kinetic energy of the gas molecules increases as the temperature increases. The increased kinetic energy of the gas molecules makes it more difficult for them to be dissolved in water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>46", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Arrange the following compounds in decreasing order of their boiling points: NH3, HF, SiH4, CH4", "images": [], "options": {"A": "NH3,CH4, SiH4, HF", "B": "CH4, SiH4, NH3, HF", "C": "HF,NH3, SiH4, CH4", "D": "CH4, SiH4, HF, NH3,"}, "answer": "C", "explanation": "The correct order of boiling points of the compounds NH3, HF, SiH4, and CH4 is HF, NH3, SiH4, CH4.    The boiling point of a compound is the temperature at which the vapor pressure of the liquid is equal to the atmospheric pressure. The stronger the intermolecular forces, the higher the boiling point.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>47", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STATES OF MATTER : CHANGES OF STATE OF MATTER.", "question": "The following statements are correct except", "images": [], "options": {"A": "energy is released when liquids change to solids", "B": "particles move faster in the gaseous state than in the liquid state.", "C": "carbon atoms in gaseous methane are further apart than those in solid diamond.", "D": "there is large decrease in the volume of a solid metal when pressure is applied to it."}, "answer": "D", "explanation": "In general, solids are relatively incompressible compared to liquids and gases. When pressure is applied to a solid, there is typically only a small change in volume. Solids have tightly packed particles with strong intermolecular forces, making them less responsive to changes in pressure. Liquids and gases, on the other hand, can undergo larger volume changes in response to pressure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>48", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS", "question": "The vapour density of an organic compound with the molecular formula C2H4O2, is  [H=1.0, C=12.0, O= 16.0]", "images": [], "options": {"A": "120", "B": "65", "C": "40", "D": "30"}, "answer": "D", "explanation": "Molar mass of C2H4O2,= (12 × 2) + (1 × 4) + (16 × 2)= 60 g/mol  Vapour density = RMM/2  =60/2=30", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>49", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "A mixture containing two salts of different solubility can be separated by", "images": [], "options": {"A": "chromatography.", "B": "distillation", "C": "crystallization", "D": "evaporation"}, "answer": "C", "explanation": "Crystallization is a separation technique that exploits differences in the solubilities of components in a solution. When a solution is allowed to cool or evaporate under controlled conditions, one of the salts may begin to crystallize out of the solution before the other due to its lower solubility. This process can be used to separate the salts based on their differing solubilities and crystal formation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2023>50", "subject": "Chemistry", "year": "2023", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CLASSIFICATION OF MIXTURES", "question": "The separation technique that is suitable for separating iodine from tetrachloromethane is", "images": [], "options": {"A": "solvent extraction", "B": "fractional distillation", "C": "decantation", "D": "filtration"}, "answer": "A", "explanation": "Solvent extraction, also known as liquid-liquid extraction, is a technique used to separate substances based on their differential solubilities in two immiscible liquids. In this case, since iodine and tetrachloromethane have different solubilities in certain solvents, you can use solvent extraction to selectively dissolve one of the substances while leaving the other behind. Iodine is a non-polar molecule, while tetrachloromethane is a polar molecule. This means that iodine will dissolve in a non-polar solvent, while tetrachloromethane will dissolve in a polar solvent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>1", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following gases could be collected by downward displacement of air?", "images": [], "options": {"A": "Chlorine", "B": "Hydrogen", "C": "Hydrogen chloride", "D": "Sulphur(IV) oxide"}, "answer": "B", "explanation": "Downward displacement of air is a method used to collect gases that are less dense than air. This method involves directing the gas into an inverted container, which allows the gas to displace the air inside. Hydrogen is less dense than air. Therefore, it can be collected by downward displacement of air. This is because it rises above air and can push the air out of an inverted container.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>2", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STATES OF MATTER : GASES", "question": "Which of the following substances has the lowest boiling point?", "images": [], "options": {"A": "Aqueous sodium chloride", "B": "Ethanol", "C": "Tetrachloromethane", "D": "Water"}, "answer": "C", "explanation": "Aqueous Sodium Chloride: The boiling point is elevated compared to pure water.  Ethanol: Boiling point is around 78.37°C.  Tetrachloromethane: Boiling point is approximately 76.7°C.  Water: Boiling point is 100°C.  Among the substances listed, tetrachloromethane (carbon tetrachloride) has the lowest boiling point at approximately 76.7°C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>3", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY", "question": "The branch of science that deals with the nature and properties of substances and how one substance can be converted to another is known as", "images": [], "options": {"A": "biology", "B": "chemistry", "C": "geography", "D": "physics"}, "answer": "B", "explanation": "Chemistry focuses on the nature, properties, and composition of substances, as well as the changes they undergo during chemical reactions. It involves studying how substances interact, combine, and change to form new substances.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>4", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE~~PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "The electron configuration 1s22s22p2x contravenes the", "images": [], "options": {"A": "Pauli's exclusion principle", "B": "Aufbau's principle", "C": "Octet rule", "D": "Hund's rule"}, "answer": "D", "explanation": "Hund's Rule: This rule states that electrons will fill degenerate orbitals (orbitals with the same energy) singly as far as possible. Each orbital in a given subshell (like 2p) gets one electron before any orbital gets a second electron, and all single electrons in degenerate orbitals have the same spin.    Analysis:  The given electron configuration 1s22s22p2x suggests that two electrons are placed in the 2px orbital while the 2py and 2pz orbitals remain empty. According to Hund's rule, the correct filling for the 2p orbitals should be:  1s22s22p1x2p1y   Each 2p orbital should get one electron before any pairing occurs. Thus, the configuration 1s22s22p2x violates Hund's rule by not distributing the electrons singly across the degenerate 2p orbitals.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2024>5", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of chromium in Na2Cr2O7 is", "images": [], "options": {"A": "+2", "B": "+6", "C": "+7", "D": "+12"}, "answer": "B", "explanation": "Oxidation state of Na is +1 and oxygen is -2.  Thus,  2 * (+1) + 2 * (x) + 7 * (-2) = 0  2 + 2x -14 = 0  2x -12=0  2x=12  x= +6", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>6", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "The most important ore of aluminium is", "images": [], "options": {"A": "bauxite", "B": "haematite", "C": "magnetite", "D": "monazite"}, "answer": "A", "explanation": "Bauxite is the primary ore of aluminium. It consists mainly of aluminium oxides and hydroxides, along with various impurities. The extraction of aluminium from bauxite is achieved through the Bayer process, where bauxite is refined to produce alumina (aluminium oxide), which is then smelted using the Hall-Héroult process to produce aluminium metal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>7", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : BASES", "question": "Bases normally", "images": [], "options": {"A": "are corrosive", "B": "turn litmus paper from blue to red", "C": "turn litmus paper from red to blue", "D": "are non-metal oxides"}, "answer": "C", "explanation": "The property that accurately describes bases is that they turn litmus paper from red to blue.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>8", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "The product of the reaction between ethanol and excess acidified K2Cr2O7 is", "images": [], "options": {"A": "CH2=CH2", "B": "CH3OCH3", "C": "CH3COOH", "D": "CH3CH3"}, "answer": "C", "explanation": "When ethanol is oxidized by excess acidified potassium dichromate (K₂Cr₂O₇), it first gets oxidized to ethanal (CH₃CHO) and then further oxidized to ethanoic acid (CH₃COOH).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>9", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "The product formed when concentrated sodium chloride solution is electrolysed using carbon electrodes is", "images": [], "options": {"A": "chloride water", "B": "hydrochloric acid", "C": "sodium hydroxide", "D": "sodium oxochlorate (I)"}, "answer": "C", "explanation": "When concentrated sodium chloride solution (brine) is electrolyzed using carbon electrodes, the products formed are chlorine gas, hydrogen gas, and sodium hydroxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>10", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Which of the following statements about ammonium salt is correct? It", "images": [], "options": {"A": "dissolves in water to form solution of pH>7", "B": "dissolves in water to form solution of pH", "C": "does not decompose on heating", "D": "is insoluble in water"}, "answer": "B", "explanation": "When ammonium salts dissolve in water, they form ammonium ions (NH₄⁺) and the corresponding anions. The NH₄⁺ ion is acidic and can release a proton (H⁺), thus lowering the pH of the solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>11", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Ethanedioic acid is an organic solid that can be purified by", "images": [], "options": {"A": "decantation", "B": "distillation", "C": "crystallization", "D": "filtration"}, "answer": "C", "explanation": "This is an effective method for purifying solids. In this process, the solid is dissolved in a suitable solvent to form a solution. As the solution cools, the pure solid crystallizes out, leaving impurities in the solution. Ethanedioic acid can be purified using this method by dissolving it in hot water and then allowing it to recrystallize upon cooling.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>12", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS~~CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION", "question": "Which of the following functional groups is present in alkanoic acid?", "images": [], "options": {"A": "-COOH", "B": "-OH", "C": "-COOR", "D": "-CHO"}, "answer": "A", "explanation": "This is the carboxyl group, which is the defining functional group of carboxylic acids (alkanoic acids). It consists of a carbonyl group (C=O) and a hydroxyl group (OH) bonded to the same carbon atom.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>13", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "In ethanol, the attractive forces between adjacent molecules are", "images": [], "options": {"A": "covalent bonds only", "B": "hydrogen bonds only", "C": "hydrogen bonds and van der Waal's forces", "D": "van der Waal's forces only"}, "answer": "C", "explanation": "Hydrogen Bonds: Ethanol molecules can form hydrogen bonds because they have a hydroxyl group (-OH). The hydrogen atom in the -OH group of one ethanol molecule can form a hydrogen bond with the oxygen atom in the -OH group of another ethanol molecule.    Van der Waals Forces: Van der Waals forces (also known as London dispersion forces) are weak intermolecular forces that are present between all molecules, including ethanol. These forces arise due to temporary dipoles that occur when electron distribution within a molecule becomes asymmetrical.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>14", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "At 25oC, the saturated solution of a salt in water was found to contain 0.24g of the salt in 100cm3. What is the solubility of the salt in gdm-3?", "images": [], "options": {"A": "0.024", "B": "0.240", "C": "2.40", "D": "24.0"}, "answer": "C", "explanation": "The solution contains 0.24 g of salt in 100 cm³ of water.  1 dm³ (cubic decimeter) = 1000 cm³  Concentration in g/dm3 = (0.24g/100cm3)/1000cm3/dm3  Concentration in g/dm3 = 0.24g x 10 = 2.4g/dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>15", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "The reaction represented by the equation:  Ni2+aq + Fes → Nis + Fe2+aq is a redox reaction because", "images": [], "options": {"A": "Ni2+ ions are oxidized and Fe acts as an oxidizing agent", "B": "Ni2+ ions are oxidized and Fe acts as a reducing agent", "C": "Ni2+ ions are reduced and Fe acts as an oxidizing agent", "D": "Ni2+ ions are reduced and Fe acts as a reducing agent"}, "answer": "D", "explanation": "Ni²⁺ ions gain electrons and are reduced to Ni.  Fe loses electrons and is oxidized to Fe²⁺.  Therefore, Fe acts as the reducing agent, facilitating the reduction of Ni²⁺ ions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>16", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Which of the following statements describes transition elements? They", "images": [], "options": {"A": "are very reactive", "B": "have low melting points", "C": "possess variable oxidation state", "D": "form colourless salts"}, "answer": "C", "explanation": "Transition elements are characterized by their ability to exhibit multiple oxidation states. This property arises from the similar energies of their 3d and 4s orbitals, allowing for the loss and sharing of different numbers of electrons in chemical reactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>17", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "Aluminium is suitable for making alloys for aircraft construction because it", "images": [], "options": {"A": "is hard and brittle", "B": "is light and very resistant to corrosion", "C": "has high density and also a non-conductor of electricity", "D": "is amphoteric and allotropic"}, "answer": "B", "explanation": "Aluminium's lightweight nature and excellent resistance to corrosion make it an ideal material for aircraft construction, where minimizing weight and ensuring durability in various environmental conditions are paramount.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>18", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "Which of the following arrangements of elements is in order of increasing ionization energy?", "images": [], "options": {"A": "Si, Al, S, P", "B": "S, P, Si, Al", "C": "Al, Si, P, S", "D": "P, Si, S, Al"}, "answer": "C", "explanation": "The arrangement Al, Si, P, S is in the correct order of increasing ionization energy, consistent with the periodic trends across Period 3 elements.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2024>19", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.~~STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "Consider the reaction represented by the equation:  C3H8(g) + 5O2(g) → 3CO2(g) + 6H2O(l)  If 0.1 mole of C3H8(g) was completely burnt, what volume of CO2(g) would be produced at stp?  [volume at stp = 22.4 dm-3mol-1]", "images": [], "options": {"A": "6.72 dm3", "B": "2.24 dm3", "C": "0.30 dm3", "D": "0.10 dm3"}, "answer": "A", "explanation": "C3H8(g) + 5O2(g) → 3CO2(g) + 6H2O(l)  1 mole of C3H8(g) produces 3 moles of CO2  Moles of CO2 = 0.1 mole of C3H8 x 3 moles of CO2/1 mole of C3H8= 0.3 moles of CO2  Volume of CO2 = Moles of CO2 x Molar volume at STP  Volume of CO2 = 0.3 moles x 22.4 dm3/mol  Volume of CO2 = 6.72 dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>20", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.~~STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.", "question": "Naturally occurring Boron is made up of 19.9% 10B and 80.1% 11B. The relative atomic mass of Boron is", "images": [], "options": {"A": "21.0", "B": "10.8", "C": "10.5", "D": "10.0"}, "answer": "B", "explanation": "(10B= 19.9/100 x 10)    +  (11B = 80.1/100 x 11)  =1.99 + 8.811  =10.801", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>21", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANES", "question": "The number of shared pair of electrons in a molecule of methane is", "images": [], "options": {"A": "2", "B": "4", "C": "6", "D": "8"}, "answer": "B", "explanation": "Carbon has 4 valence electrons.  Each hydrogen atom has 1 valence electron.  In methane, each hydrogen atom forms a single covalent bond with the carbon atom.  A covalent bond consists of a pair of shared electrons. Since methane has 4 covalent bonds", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>22", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Isotopes of the same element have similar chemical properties because they have the same number of", "images": [], "options": {"A": "nuclides", "B": "protons", "C": "neutrons", "D": "atoms"}, "answer": "B", "explanation": "Isotopes of the same element have similar chemical properties because they have the same number of protons, which determines their chemical behavior and reactivity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>23", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : CONCEPT OF PH", "question": "Which of the following household liquids would be effective in treating someone with too much acid in the stomach?", "images": [], "options": {"A": "Strong salt solution with pH 7.0", "B": "Tomato juice with pH 4.1", "C": "Milk of magnesia with pH 10.5", "D": "Black coffee with 5.0"}, "answer": "C", "explanation": "When treating someone with excess stomach acid (acid indigestion), a substance with a basic (alkaline) pH is required to neutralize the acid. Milk of magnesia, with its alkaline pH of 10.5, is effective in neutralizing excess stomach acid, providing relief from acid indigestion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>24", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS~~STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The percentage by mass of oxygen in MgSO4.7H2O is  [Mr=246]", "images": [], "options": {"A": "26.0%", "B": "45.5 %", "C": "71.5%", "D": "84.0%"}, "answer": "C", "explanation": "Mass of oxygen atoms:  In MgSO4, there are four oxygen atoms: 4 x 16 =64g/mol  In 7H2O, there are 7 x 1 = 7 oxygen atoms: 7 x16=112g/mol  Total mass of oxygen: 64  + 12=176g/mol  Percentage by mass of oxygen = (Mass of oxygen/Total molar mass) x 100  =176/246 x 100  =71.54%", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2024>25", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "RATE OF CHEMICAL REACTION", "question": "Catalysts alter reaction rates by", "images": [], "options": {"A": "providing an alternative reaction pathway", "B": "lowering the energy of reaction", "C": "increasing the surface area of reactants", "D": "aligning the reactant molecules properly"}, "answer": "A", "explanation": "Catalysts work by providing an alternative reaction pathway that has a lower activation energy, thereby increasing the reaction rate without being consumed in the process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>26", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "Ethane of volume 400 cm3 was completely burnt in excess oxygen according to the following equation:  2C2H6(g) + 7O2(g) →  6H2Og + 4CO2(g)  Calculate the volume of steam that would be produced", "images": [], "options": {"A": "200 cm3", "B": "400 cm3", "C": "600 cm3", "D": "1200 cm3"}, "answer": "D", "explanation": "2C2H6(g) + 7O2(g) →  6H2Og + 4CO2(g)  2 volumes of C2H6 produce 6 volumes of H2O  Therefore, 1 volumes of C2H6 produce 3 volumes of H2O  Given that 400 cm3 of C2H6 is completely burnt:  The volume of H₂O produced = 3 times the volume of C₂H₆ burnt.  Volume of H₂O = 3 x 400cm3 = 1200 cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2024>27", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "A saturated solution at 30 oC will normally produce crystals at a temperature of", "images": [], "options": {"A": "50 oC", "B": "40 oC", "C": "35 oC", "D": "20 oC"}, "answer": "D", "explanation": "A saturated solution at 30°C will normally produce crystals when the temperature is decreased to 20°C because the solubility of the solute decreases with the decrease in temperature, leading to the formation of crystals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>28", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS", "question": "The following organic compounds are polymers except", "images": [], "options": {"A": "rubber", "B": "starch", "C": "proteins", "D": "fats"}, "answer": "D", "explanation": "Fats, which are triglycerides, do not have repeating monomer units and therefore are not considered polymers. Rubber, starch, and proteins, on the other hand, are all polymers composed of repeating monomer units.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>29", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "RATE OF CHEMICAL REACTION", "question": "According to the collision theory of reaction rates, which of the following conditions is not required for two molecules to react? The molecules must", "images": [], "options": {"A": "come into contact without loss of energy on colliding with each other", "B": "collide with enough energy to overcome the activation energy barrier", "C": "collide in an orientation that makes formation of product possible", "D": "possess enough speed to overcome intermolecular forces of attraction"}, "answer": "D", "explanation": "While molecules must collide with sufficient energy and proper orientation for a reaction to occur, possessing enough speed specifically to overcome intermolecular forces of attraction is not a distinct requirement stated by the collision theory of reaction rates. The necessary condition is the energy to overcome the activation energy barrier, which can be a result of speed, but the theory doesn't separately require overcoming intermolecular forces beyond this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>30", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "A weak acid is one which", "images": [], "options": {"A": "is not corrosive", "B": "completely ionizes in water", "C": "does not produce salt with alkali", "D": "slightly ionizes in water"}, "answer": "D", "explanation": "A weak acid is characterized by its incomplete ionization in water, meaning it only partially dissociates into its ions when dissolved in water. A weak acid is defined by its slight ionization in water, meaning it does not completely dissociate into its ions. This results in a lower concentration of hydrogen ions in solution compared to a strong acid of the same concentration.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>31", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following conditions are necessary for the preparation of alkanoates from alkanols and alkanoic acids?", "images": [], "options": {"A": "Water and NaOH", "B": "Conc. H2SO4 and heat", "C": "NaOH and heat", "D": "Water and aqueous HCl"}, "answer": "B", "explanation": "The preparation of alkanoates from alkanols and alkanoic acids (esterification) requires concentrated sulphuric acid as a catalyst and heat to drive the reaction forward and to remove the water produced during the reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>32", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : MOLE RATIOS", "question": "The volume of 22g of CO2 at stp is equivalent to  [C=12, O=16, molar volume at stp = 22.4 dm3]", "images": [], "options": {"A": "22.0 dm3", "B": "22.4 dm3", "C": "11.2 dm3", "D": "5.6 dm3"}, "answer": "C", "explanation": "Carbon (C) = 12 g/mol  Oxygen (O) = 16 g/mol  Molar mass of CO₂ = 12 + (2 × 16) = 12 + 32 = 44 g/mol  Number of moles = mass/Molar mass  Number of moles of CO2= 22/44 = 0.5 moles  At STP, 1 mole of any gas occupies 22.4 dm³.  Volume of 0.5 moles of CO₂ = 0.5 moles x 22.4 dm3/mol = 11.2 dm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>33", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "Pairs of outermost shell electrons which are not used in bonding are", "images": [], "options": {"A": "lone pairs", "B": "bonding pairs", "C": "valence electrons", "D": "electrovalent electrons"}, "answer": "A", "explanation": "Lone pairs are the pairs of valence electrons that are not involved in chemical bonding and remain localized on a single atom. They can influence the shape and reactivity of molecules.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>34", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "8X2- and 10Y are", "images": [], "options": {"A": "isomers", "B": "isotopes", "C": "allotropes", "D": "isoelectronic"}, "answer": "D", "explanation": "8X2− has 8 protons (since the atomic number of X is 8) and has gained 2 electrons, giving it a total of 10 electrons.  10Y has 10 protons (since the atomic number of Y is 10) and has 10 electrons (neutral atom).  Both species have 10 electrons.  8X2- and 10Y are isoelectronic because they both have the same number of electrons, which is 10.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>35", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Pure water contaminated with quicklime will have a pH of", "images": [], "options": {"A": "1", "B": "6", "C": "7", "D": "8"}, "answer": "D", "explanation": "Calcium hydroxide dissociates in water to produce hydroxide ions (OH⁻), which increases the pH of the solution, making it basic. Pure water contaminated with quicklime (calcium oxide) will have a pH higher than 7 due to the formation of calcium hydroxide, which is a strong base. Therefore, the pH of the solution will be basic, around 8 or higher, depending on the concentration of the hydroxide ions produced.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>36", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION~~STRUCTURE OF THE ATOM : PERIODICITY OF THE ELEMENTS", "question": "The electron configuration of 29Cu is", "images": [], "options": {"A": "1s22s22p63s23p64s13d10", "B": "1s22s22p63s23p64s23d9", "C": "1s22s22p53s23p64s23d10", "D": "1s22s22p63s24s13d10"}, "answer": "A", "explanation": "The electron configuration for copper (Cu) is 1s22s22p63s23p64s13d10. This configuration reflects the stability provided by a filled 3d subshell and a half-filled 4s subshell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>37", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "When s and p block elements react, the bond formed is", "images": [], "options": {"A": "electrovalent", "B": "covalent", "C": "metallic", "D": "dative-covalent"}, "answer": "A", "explanation": "When s-block elements react with p-block elements, they typically form electrovalent (ionic) bonds due to the transfer of electrons from the metal (s-block) to the nonmetal (p-block), resulting in the formation of positive and negative ions that are held together by electrostatic forces.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>38", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CARBON", "question": "The hardest form of carbon is", "images": [], "options": {"A": "charcoal", "B": "coke", "C": "diamond", "D": "graphite"}, "answer": "C", "explanation": "Diamond is the hardest form of carbon due to its unique crystal lattice structure, which gives it exceptional strength and hardness. It is widely used in cutting, grinding, and drilling tools due to these properties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>39", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMICAL BONDS : METALLIC BONDING", "question": "The metallic bonding in aluminium is strong because of large number of", "images": [], "options": {"A": "delocalized electrons", "B": "immobile electrons", "C": "lone pair electrons", "D": "valence electrons"}, "answer": "A", "explanation": "The metallic bonding in aluminium is strong because of the large number of delocalized electrons that can move freely throughout the metal lattice. This creates a strong electrostatic attraction between the positively charged metal ions and the sea of electrons, leading to the characteristic properties of metals such as high strength, conductivity, and malleability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>40", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.", "question": "How many covalent bonds are formed by Nitrogen?", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": "C", "explanation": "Nitrogen forms three covalent bonds to complete its octet, achieving a stable electronic configuration. This is consistent with its tendency to share three of its five valence electrons with other atoms in various compounds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>41", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "ALLOTROPY", "question": "When an element exists in two or more forms in the same physical state, it exhibits", "images": [], "options": {"A": "isotopy", "B": "allotropy", "C": "isobars", "D": "isomerism"}, "answer": "B", "explanation": "Allotropy refers to the phenomenon where an element can exist in two or more different forms in the same physical state. These different forms are called allotropes and they have different physical and chemical properties. Examples include carbon (diamond, graphite) and oxygen (O₂, O₃).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>42", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES", "question": "An atom of an element in the ground state contain 8 valence electrons. The element is considered as a", "images": [], "options": {"A": "metal", "B": "semi-metal", "C": "noble gas", "D": "halogen"}, "answer": "C", "explanation": "Noble gases have a complete outer shell of 8 valence electrons (except helium, which has 2), making them stable and inert. An element with 8 valence electrons in its ground state fits this description, classifying it as a noble gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>43", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "The main function of limestone in the blast furnace during the extraction of iron is to", "images": [], "options": {"A": "act as a catalyst", "B": "remove impurities", "C": "act as a reducing agent", "D": "supply carbon(IV) oxide"}, "answer": "B", "explanation": "Limestone is added to the blast furnace to remove impurities from the iron ore. When limestone decomposes, it forms calcium oxide, which reacts with impurities like silica to form slag. The slag is less dense than molten iron and can be removed from the top of the molten iron.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>44", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following is a monomer of polythene?", "images": [], "options": {"A": "Ethanol", "B": "Vinyl chloride", "C": "Ethene", "D": "Ethane"}, "answer": "C", "explanation": "Polythene is produced by the polymerization of ethene (C₂H₄) molecules, where the double bonds in ethene open up and link together to form long chains of polyethylene.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>45", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS", "question": "Which of the following compounds is formed by the oxidation of ethanol?", "images": [], "options": {"A": "C2H4CO2H", "B": "C2H5CO2H", "C": "CH3OH", "D": "CH3CO2H"}, "answer": "D", "explanation": "When ethanol (CH₃CH₂OH) undergoes oxidation, it is first converted to ethanal (CH₃CHO) and then further oxidized to ethanoic acid (CH₃CO₂H). Therefore, acetic acid (CH₃CO₂H) is the final product of the complete oxidation of ethanol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>46", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Tetraoxosulphate(VI) acid is considered as a heavy chemical because", "images": [], "options": {"A": "its relative molecular mass is high", "B": "a high tonnage is produced every year", "C": "it is an inorganic chemical", "D": "it is used to manufacture heavy chemicals"}, "answer": "B", "explanation": "Tetraoxosulphate(VI) acid, or sulfuric acid, is considered a heavy chemical because it is produced in very large quantities annually. It is a key industrial chemical used in a wide range of processes, including fertilizer production, petroleum refining, wastewater processing, and chemical synthesis. The term \"heavy chemical\" refers to substances that are produced and consumed in large volumes, distinguishing them from \"fine chemicals,\" which are produced in smaller quantities and are typically more specialized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>47", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "ISOMERISM", "question": "How many isomers can be formed from a compound with molecular formular C5H12?", "images": [], "options": {"A": "One", "B": "Two", "C": "Three", "D": "Four"}, "answer": "C", "explanation": "The compound with the molecular formula C₅H₁₂ can form three structural isomers: n-pentane, isopentane, and neopentane. These isomers differ in the arrangement of their carbon atoms and branching of the carbon chain, leading to different structures while maintaining the same molecular formula.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2024>48", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "The oxidation number of iron in its free state is", "images": [], "options": {"A": "0", "B": "+1", "C": "+2", "D": "+3"}, "answer": "A", "explanation": "In its free or elemental state, the oxidation number of iron (or any element) is zero. This is a fundamental rule in assigning oxidation numbers. For example, in a piece of pure iron metal, the oxidation number of Fe is 0.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>49", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY", "question": "Water pipes are produced from", "images": [], "options": {"A": "polyethene", "B": "perspex", "C": "polystyrene", "D": "polyvinyl chloride"}, "answer": "D", "explanation": "Polyvinyl chloride (PVC) is widely used in the manufacturing of water pipes due to its durability, resistance to corrosion and chemicals, and its affordability. PVC pipes are suitable for both hot and cold water distribution, as well as for sewage and drainage systems", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2024>50", "subject": "Chemistry", "year": "2024", "type": "Objective", "topic": "CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS", "question": "Consider the reaction represented by the following equation:  xAl + yCIU2 → zAlCl3  The value of x, y and z respectively are", "images": [], "options": {"A": "2, 3 and 2", "B": "2, 2 and 3", "C": "1, 2 and 1", "D": "1, 1 and 1"}, "answer": "A", "explanation": "To balance the chemical reaction, we determined that 2 moles of aluminum (Al) react with 3 moles of chlorine gas (Cl2) to produce 2 moles of aluminum chloride (AlCl3). This ensures the number of atoms for each element is the same on both sides of the equation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>1", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "Which of the following pairs of gases cannot be collected by downward delivery?", "images": [], "options": {"A": "SO2 and NH3", "B": "CO and N2", "C": "Cl2 and H2S", "D": "SO2 and N2"}, "answer": "C", "explanation": "The gases Cl2 and H2S cannot be collected by downward delivery because both are denser than air. Downward delivery is typically used for gases that are lighter than air, such as hydrogen or methane. Since Cl2 and H2S are heavier, they would not rise and thus cannot be collected using this method.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>2", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Nickel is used in the hydrogenation of alkenes because it", "images": [], "options": {"A": "increases the yield of the product", "B": "lowers the activation energy of the reqaction", "C": "makes the reaction more exothermic", "D": "prevents a reverse reaction from occuring"}, "answer": "B", "explanation": "Nickel is used in the hydrogenation of alkenes primarily because it lowers the activation energy of the reaction. This catalytic property allows the reaction to proceed more quickly and efficiently, facilitating the addition of hydrogen to the alkene to form alkanes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>3", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Aluminium is extracted by", "images": [], "options": {"A": "electrolysis of purified ore", "B": "froth floatation of the smelted ore", "C": "reduction of the ore with coke in a furnace", "D": "roasting the ore in excess supply of air"}, "answer": "A", "explanation": "Aluminium is extracted by electrolysis of purified ore (bauxite). The process involves dissolving the ore in molten cryolite and then passing an electric current through it to reduce aluminium ions to aluminium metal. This method is necessary due to the high reactivity of aluminium, which makes it difficult to extract using traditional reduction methods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>4", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : HYDROGEN CHLORIDE GAS", "question": "Which of the following gases is used in fire extinguisher", "images": [], "options": {"A": "Carbon (IV) oxide", "B": "Nitrogen (IV) oxide", "C": "Carbon (II) oxide", "D": "Sulphur (IV) oxide"}, "answer": "A", "explanation": "Carbon (IV) oxide (CO2) is commonly used in fire extinguishers because it is effective at displacing oxygen, which is necessary for combustion. By reducing the concentration of oxygen around the fire, CO2 helps to suffocate the flames and extinguish the fire.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>5", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Both Na+ and K+ ions have", "images": [], "options": {"A": "tendency to give electrons", "B": "positive reduction potential", "C": "tendency to accept electrons", "D": "negative oxidation potential"}, "answer": "C", "explanation": "Tendency to accept electrons is correct because Na⁺ and K⁺ are stable cations. Since they already lost one electron, the only possible change is to gain electrons and return to their neutral state. Hence, they show a tendency to accept electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>6", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STATES OF MATTER : THE GAS LAWS", "question": "If a gas occupies a volume of 400 cm3 at a temperature of 400 K and a pressure of 1 atm, at what temperature and pressure would its volume be 200 cm3?", "images": [], "options": {"A": "800 K and 1 atm", "B": "800 K and 0.5 atm", "C": "200 K and 1 atm", "D": "200 K and 0.5 atm"}, "answer": "B", "explanation": "Using the ideal gas law, we can apply the combined gas law: (P1 * V1) / T1 = (P2 * V2) / T2. Given P1 = 1 atm, V1 = 400 cm³, T1 = 400 K, V2 = 200 cm³, we can rearrange to find T2. Solving gives T2 = 800 K and P2 = 0.5 atm. Therefore, the correct option is '800 K and 0.5 atm'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Chemistry>2025>7", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM", "question": "The nucleus of a hydrogen atom consists of", "images": [], "options": {"A": "one proton only", "B": "one proton and one neutron", "C": "one neutron only", "D": "one electron only"}, "answer": "A", "explanation": "The nucleus of a hydrogen atom consists of one proton only. Hydrogen is the simplest element, and its nucleus does not contain any neutrons or electrons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>8", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.", "question": "If acidified K2Cr2O7 acts as an oxidizing agent, the colour changes from", "images": [], "options": {"A": "orange to red", "B": "yellow to green", "C": "orange to green", "D": "yellow to red"}, "answer": "C", "explanation": "When acidified K2Cr2O7 (potassium dichromate) acts as an oxidizing agent, it changes color from orange to green due to the reduction of Cr(VI) to Cr(III). Therefore, the correct option is 'orange to green'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>9", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE", "question": "Which of the following elements is a metalloid?", "images": [], "options": {"A": "Aluminium", "B": "Selenium", "C": "Phosphorus", "D": "Sodium"}, "answer": "B", "explanation": "Selenium is classified as a metalloid, which has properties intermediate between metals and nonmetals. Aluminium and sodium are metals, while phosphorus is a nonmetal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>10", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES", "question": "Iodine could be separated from a mixture of iodine and calcium chloride by", "images": [], "options": {"A": "evaporation", "B": "sublimation", "C": "fractional distillation", "D": "fractional crystallization"}, "answer": "B", "explanation": "Iodine can be separated from a mixture of iodine and calcium chloride by sublimation, as iodine sublimates (changes from solid to gas) at room temperature, while calcium chloride remains solid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>11", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "Sodium chloride is used in the following processes except", "images": [], "options": {"A": "treatment of water", "B": "manufacturing of chlorine", "C": "preservation of food", "D": "separation of soap from glycerol"}, "answer": "D", "explanation": "Sodium chloride (NaCl) is commonly used in water treatment, manufacturing of chlorine, and food preservation. However, it is not used for the separation of soap from glycerol, which typically involves other methods such as distillation or solvent extraction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>12", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMICAL BONDS : INTER MOLECULAR BONDING", "question": "Which of the following bonds is not an intermolecular force?", "images": [], "options": {"A": "Hydrogen bond", "B": "van der Waal's", "C": "Dipole-dipole", "D": "Metallic bond"}, "answer": "D", "explanation": "Metallic bonds are not intermolecular forces; they are a type of intramolecular bond that occurs between metal atoms. Intermolecular forces include hydrogen bonds, van der Waals forces, and dipole-dipole interactions, which occur between molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>13", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "All the following compounds are ionic except", "images": [], "options": {"A": "AgCl", "B": "KNO3", "C": "NO_2)", "D": "(NH4)2"}, "answer": "C", "explanation": "NO2 is a covalent compound, not an ionic compound. The other options (AgCl, KNO3, and (NH42) are ionic compounds, as they consist of metal and non-metal ions or polyatomic ions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>14", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "The metal carbonate that would not decompose when heated strongly is", "images": [], "options": {"A": "Al2CO3", "B": "CaCO3", "C": "MgCO3", "D": "Na2CO3"}, "answer": "D", "explanation": "Sodium carbonate (Na2CO3) does not decompose when heated strongly, unlike other metal carbonates such as calcium carbonate (CaCO3), magnesium carbonate (MgCO3), and aluminum carbonate (Al2CO3), which decompose to form oxides and carbon dioxide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>15", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE INDICATORS", "question": "In the use of a universal indicator, red colour is an indication that the substance is a", "images": [], "options": {"A": "concentrated acid", "B": "concentrated alkali", "C": "dilute acid", "D": "dilute base"}, "answer": "C", "explanation": "In the use of a universal indicator, a red color indicates that the substance is a dilute acid. The color change in a universal indicator reflects the pH level of the solution, with red typically corresponding to a pH below 7, indicating acidity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>16", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE REACTIONS", "question": "Which of the following oxides would form two different types of acids when dissolved in water?", "images": [], "options": {"A": "CO2", "B": "NO2", "C": "SO2", "D": "SO3"}, "answer": "B", "explanation": "The oxide NO2 can form two different acids when dissolved in water: nitric acid (HNO3) and nitrous acid (HNO2). CO2 forms carbonic acid (H2CO3), SO2 forms sulfurous acid (H2SO3), and SO3 forms sulfuric acid (H2SO4). Therefore, the correct option is  (NO2).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>17", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : ALCOHOLS", "question": "Ethanol could be prepared in the laboratory by", "images": [], "options": {"A": "reduction of ethanoic acid", "B": "oxidation of primary alkanol", "C": "oxidation of alkenes", "D": "hydration of ethene"}, "answer": "D", "explanation": "Ethanol can be prepared in the laboratory by the hydration of ethene, which involves adding water (H2O) to ethene (C2H4) in the presence of an acid catalyst. This reaction results in the formation of ethanol (C2H5OH). Therefore, the correct option is hydration of ethene.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>18", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF SODIUM AND ITS COMPOUNDS.", "question": "Alkali metals are good conductors of heat and electricity because they", "images": [], "options": {"A": "contain delocalised electrons", "B": "are found in the d-block", "C": "have vibrating ions", "D": "are all metals"}, "answer": "A", "explanation": "Alkali metals are good conductors of heat and electricity because they contain delocalised electrons. These electrons can move freely, allowing for the conduction of electricity and heat. Therefore, the correct option is A (contain delocalised electrons).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>19", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "In a chemical reaction, ∆H is positive when", "images": [], "options": {"A": "∆Hproduct > ∆Hreactants", "B": "∆Hproduct", "C": "∆Hproduct = ∆Hreactants", "D": "∆Hproduct = zero"}, "answer": "A", "explanation": "In a chemical reaction, ∆H is positive when the enthalpy of the products (∆Hproduct) is greater than the enthalpy of the reactants (∆Hreactants). This indicates that the reaction is endothermic, meaning it absorbs heat. Therefore, the correct option is A (∆Hproduct > ∆Hreactants).", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>20", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "How many pi-bond(s) is/are present in propene?", "images": [], "options": {"A": "Three", "B": "Six", "C": "Two", "D": "One"}, "answer": "D", "explanation": "Propene (C3H6) has one double bond between two carbon atoms, which consists of one sigma bond and one pi bond. Therefore, there is one pi bond present in propene.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>21", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKENES", "question": "Which of the following compounds would readily undergo addition reaction?", "images": [], "options": {"A": "Ethane", "B": "Butene", "C": "Ethanol", "D": "Benzene"}, "answer": "B", "explanation": "Butene is an alkene, which contains a carbon-carbon double bond. Alkenes readily undergo addition reactions due to the presence of this double bond, allowing for the addition of atoms or groups across the double bond. Ethane is an alkane with only single bonds, ethanol is an alcohol, and benzene is an aromatic compound, which does not readily undergo addition reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>22", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.", "question": "The number of moles of KOH present in 200 cm3 of 5.6gdm-3 solution is  [KOH = 56gmol-1]", "images": [], "options": {"A": "2.01", "B": "1.12", "C": "0.02", "D": "0.01"}, "answer": "C", "explanation": "To find the number of moles of KOH in the solution, we use the formula:   moles = concentration (g/dm³) × volume (dm³)/Molar mass(g/mol). The concentration is 5.6 g/dm³ and the volume is 200 cm³, which is 0.2 dm³.   Therefore, moles = 5.6 g/dm³ × 0.2 dm³/56 = 0.02moles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>23", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION", "question": "A covalent hydride which does not exist as a gas at room temperature is", "images": [], "options": {"A": "H2O", "B": "BH3", "C": "HCl", "D": "H2"}, "answer": "A", "explanation": "H₂O (water) is a covalent hydride that exists as a liquid at room temperature, unlike the other options which are gases. BH₃ (borane) and HCl (hydrochloric acid) are gases at room temperature, and H₂ (hydrogen) is also a gas. Therefore, the correct answer is H₂O.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>24", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "REDOX REACTIONS : ELECTROLYSIS", "question": "In the electrolysis of dilute hydrochloric acid, at the anode", "images": [], "options": {"A": "oxygen gas is given off", "B": "hydrogen gas is given off", "C": "chlorine gas is given off", "D": "hydrogen chloride gas is given off"}, "answer": "C", "explanation": "During the electrolysis of dilute hydrochloric acid, at the anode, chlorine gas is produced. This occurs because the chloride ions (Cl⁻) are oxidized to form chlorine gas (Cl₂). Hydrogen gas is produced at the cathode, not the anode. Therefore, the correct option is chlorine gas is given off.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>25", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMICAL BONDS : IONIC COMPOUNDS", "question": "In which of the following arrangements are the ions arranged in decreasing order of ionic size?", "images": [], "options": {"A": "F-, Na+, Mg2+, Al3+", "B": "Na+, Mg2+, Al3+, F-", "C": "Al3+, Na+, Mg2+, F-", "D": "Al3+, Mg2+, Na+, F-"}, "answer": "A", "explanation": "Ionic size decreases with increasing positive charge and increases with negative charge. Therefore, the order of ionic size from largest to smallest is F⁻ (anion), Na⁺ (monovalent cation), Mg²⁺ (divalent cation), and Al³⁺ (trivalent cation). The correct arrangement is F⁻, Na⁺, Mg²⁺, Al³⁺.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>26", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.", "question": "The filter in a cigarrete reduces the amount of nicotine inhaled by", "images": [], "options": {"A": "adsorption", "B": "absorption", "C": "burning", "D": "evaporation"}, "answer": "B", "explanation": "The filter in a cigarette reduces the amount of nicotine inhaled by absorption. Absorption is the process by which one substance takes in another, in this case, the filter material absorbs some of the nicotine present in the smoke, reducing the amount that reaches the lungs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>27", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES", "question": "If 25cm3 of a saturated solution contains 0.02 moles of the solute, determine the solubility of the solute", "images": [], "options": {"A": "5.0 x 10-4 mol dm-3", "B": "0.8 mol dm-3", "C": "0.4 mol dm-3", "D": "5.0 x 10-2 mol"}, "answer": "B", "explanation": "To determine the solubility of the solute, we can use the formula: Solubility (mol/dm^3) = moles of solute / volume of solution in dm^3. Here, 25 cm^3 = 0.025 dm^3, and the moles of solute is 0.02. Thus, solubility = 0.02 moles / 0.025 dm^3 = 0.8 mol/dm^3. Therefore, the correct answer is 0.8 mol/dm^3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>28", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY", "question": "Biotechnology is applied in the following processes except", "images": [], "options": {"A": "baking of bread", "B": "production of wine", "C": "production of antibiotics", "D": "manufacturing of soap"}, "answer": "D", "explanation": "Biotechnology is applied in processes such as baking of bread, production of wine, and production of antibiotics, as these involve the use of living organisms or their products. However, manufacturing of soap does not typically involve biotechnology; it is a chemical process that does not rely on biological organisms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>29", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "The percentage by mass of water in Na2CO3.10H2O is   [Na2CO3.10H2O=286, H2O=18]", "images": [], "options": {"A": "68.4%", "B": "62.9%", "C": "9.7%", "D": "6.3%"}, "answer": "B", "explanation": "To find the percentage by mass of water in Na2CO3.10H2O , we calculate the mass of water and the total mass of the compound. The mass of water in the hydrate is 10 * 18 g = 180 g. The total mass of Na2CO3.10H2O  is 286 g. The percentage by mass of water = (mass of water / total mass) * 100 = (180 / 286) * 100 ≈ 62.9%. Thus, the correct answer is 62.9%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>30", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS", "question": "Which of the following conditions are necessary for the preparation of alkanoates from alkanols and alkanoic acids?", "images": [], "options": {"A": "Water and NaOH", "B": "Conc. H2SO4 and heat", "C": "NaOH and heat", "D": "Water and aqueous HCl"}, "answer": "B", "explanation": "The preparation of alkanoates from alkanols and alkanoic acids typically requires concentrated sulfuric acid (H2SO4) as a catalyst and heat to facilitate the esterification reaction. This process involves the reaction of an alcohol with a carboxylic acid to form an ester and water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>31", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.", "question": "All the following compounds are covalent except", "images": [], "options": {"A": "NO2", "B": "SO3", "C": "SO2", "D": "KNO3"}, "answer": "D", "explanation": "KNO3 (potassium nitrate) is an ionic compound, while NO2, SO3, and SO2 are covalent compounds. Ionic compounds are formed from the electrostatic attraction between oppositely charged ions, while covalent compounds are formed by the sharing of electrons between atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>32", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : SALTS", "question": "A salt that could be prepared by double decomposition is", "images": [], "options": {"A": "sodium trioxocarbonate(VI)", "B": "barium trioxonitrate(V)", "C": "lead (II) trioxonitrate(V)", "D": "silver chloride"}, "answer": "D", "explanation": "Silver chloride can be prepared by double decomposition (also known as double displacement) reaction, where two compounds exchange ions to form two new compounds. In this case, silver nitrate and sodium chloride can react to form silver chloride and sodium nitrate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>33", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL SYMBOLS", "question": "The IUPAC name of the compound CH3CHClCH2OH is", "images": [], "options": {"A": "chloropropanol", "B": "1-chloropropan-1-ol", "C": "2-chloropropan-3-ol", "D": "3-chloropropan-1-ol"}, "answer": "B", "explanation": "The IUPAC name of CH3CHClCH2OH is 2-chloropropan-1-ol. The numbering starts from the end of the chain closest to the hydroxyl (OH) group, which is at position 1, and the chlorine (Cl) is at position 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>34", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Neutral atom of neon with atomic number 10 is isoelectronic with", "images": [], "options": {"A": "K+", "B": "Mg2+", "C": "Ca2+", "D": "Li+"}, "answer": "B", "explanation": "Neon (Ne) has atomic number 10, so a neutral atom has 10 protons and 10 electrons.  Isoelectronic means \"having the same number of electrons.  Magnesium has atomic number 12 → neutral atom has 12 electrons.  Mg²⁺ means it loses 2 electrons → 10 electrons.  Isoelectronic with Ne.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>35", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.", "question": "Which of the following species is the most powerful reducing agent?", "images": [], "options": {"A": "Bromine atom", "B": "Chloride atom", "C": "Fluoride ion", "D": "Iodide ion"}, "answer": "D", "explanation": "Iodide ion (I-) is the most powerful reducing agent among the given options. Reducing agents donate electrons in a chemical reaction, and iodide is more willing to lose an electron compared to bromine, chloride, and fluoride ions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>36", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION", "question": "The electron configuration of element Y is 1s22s22p63s23p4. Y therefore", "images": [], "options": {"A": "has mass number of 16", "B": "has three unpaired electrons", "C": "belongs to period 4", "D": "belongs to group VI"}, "answer": "D", "explanation": "The electron configuration of element Y is 1s22s22p63s23p4, which indicates that it has 6 electrons in its outermost shell 3s23p4. This places element Y in group  6 of the periodic table, as it has 6 valence electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>37", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS", "question": "Which of the following alkanols is tertiary?", "images": [], "options": {"A": "2-methylpentan-2-ol", "B": "2-methylpentan-1-ol", "C": "Pentan-3-ol", "D": "Pentan-2-ol"}, "answer": "A", "explanation": "A tertiary alcohol is one where the hydroxyl (-OH) group is attached to a carbon atom that is connected to three other carbon atoms. In this case, 2-methylpentan-2-ol has the -OH group on the second carbon, which is attached to three other carbons (the two methyl groups and the rest of the pentane chain), making it a tertiary alcohol. Therefore, the correct option is 2-methylpentan-2-ol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>38", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS", "question": "Which of the following elements is commercially obtained by the electrolysis of its fused salt?", "images": [], "options": {"A": "Silver", "B": "Copper", "C": "Helium", "D": "Sodium"}, "answer": "D", "explanation": "Sodium is commercially obtained by the electrolysis of its fused salt, sodium chloride (NaCl). This process involves melting the salt and passing an electric current through it to separate sodium metal from chlorine gas. Therefore, the correct option is Sodium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>39", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF ALUMINIUM AND ITS COMPOUNDS", "question": "The lustre of a metal is due to its", "images": [], "options": {"A": "high density", "B": "refractive index", "C": "chemical inertness", "D": "free electrons"}, "answer": "D", "explanation": "The lustre of a metal is primarily due to the presence of free electrons. These electrons can move freely within the metal lattice and can absorb and re-emit light, giving metals their characteristic shiny appearance. Therefore, the correct option is free electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>40", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY", "question": "Exothermic reactions take place when energy given out in making bonds is", "images": [], "options": {"A": "less than energy taken in for breaking bonds", "B": "greater than energy taken in for breaking bonds", "C": "equal to the energy taken in for breaking bonds", "D": "remains the same as the energy taken in"}, "answer": "B", "explanation": "Exothermic reactions occur when the energy released during the formation of bonds in the products is greater than the energy required to break the bonds in the reactants. This results in a net release of energy, typically in the form of heat. Therefore, the correct option is that energy given out in making bonds is greater than energy taken in for breaking bonds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>41", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS", "question": "Which of the following metals would not release hydrogen when reacted with dilute HCl?", "images": [], "options": {"A": "Calcium", "B": "Silver", "C": "Iron", "D": "Zinc"}, "answer": "B", "explanation": "Silver does not react with dilute hydrochloric acid (HCl) to release hydrogen gas. This is because silver is a noble metal and is less reactive compared to the other metals listed (Calcium, Iron, and Zinc), which can displace hydrogen from acids.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>42", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.", "question": "Five d-orbitals having same energy level in an isolated transition metal are described as", "images": [], "options": {"A": "degenerate", "B": "non-degenerate", "C": "high-level orbital", "D": "low-level orbital"}, "answer": "A", "explanation": "The five d-orbitals in transition metals are described as 'degenerate' because they have the same energy level when the atom is in isolation. This means that they can hold electrons of the same energy without any energy difference between them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>43", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACIDS", "question": "Which of the following oxides is amphoteric?", "images": [], "options": {"A": "CaO", "B": "MgO", "C": "BaO", "D": "BeO"}, "answer": "D", "explanation": "BeO (Beryllium oxide) is amphoteric, meaning it can react with both acids and bases. In contrast, CaO, MgO, and BaO are basic oxides and do not exhibit amphoteric behavior.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>44", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ALLOTROPY", "question": "The allotrope of carbon used in the decolourization of sugar is", "images": [], "options": {"A": "charcoal", "B": "graphite", "C": "lampblack", "D": "soot"}, "answer": "A", "explanation": "Charcoal is the allotrope of carbon commonly used in the decolorization of sugar. It acts as an adsorbent, removing impurities and color from solutions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>45", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS", "question": "In the periodic table, valence electrons are indicated by", "images": [], "options": {"A": "group number", "B": "shell number", "C": "period number", "D": "atomic mass"}, "answer": "A", "explanation": "In the periodic table, valence electrons are indicated by the group number. The group number corresponds to the number of valence electrons in the outermost shell of the elements in that group.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>46", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.", "question": "Nucleons are sub-atomic particles which consist of", "images": [], "options": {"A": "protons and neutrons", "B": "neutrons and electrons", "C": "protons and electrons", "D": "neutrons, protons and electrons"}, "answer": "A", "explanation": "Nucleons are the particles found in the nucleus of an atom, which include protons and neutrons. Electrons are not considered nucleons as they are found in the electron cloud surrounding the nucleus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>47", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "ACIDS, BASES AND SALTS : ACID-BASE REACTIONS", "question": "A few drops of sodium hydroxide is added to an aqueous solution, a green precipitate is formed. The ion that may be present in the solution is", "images": [], "options": {"A": "Cu2+", "B": "Fe2+", "C": "NH4+", "D": "Fe3+"}, "answer": "B", "explanation": "The formation of a green precipitate upon adding sodium hydroxide indicates the presence of Fe2+ ions in the solution. This is because Fe2+ reacts with hydroxide ions to form iron(II) hydroxide, which is a green precipitate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>48", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS", "question": "When C2H4 molecule is polymerized, the polymer formed is", "images": [], "options": {"A": "polyethyne", "B": "polyethene", "C": "polypropene", "D": "polybutene"}, "answer": "B", "explanation": "When ethylene (C2H4) is polymerized, it forms polyethene (also known as polyethylene). This is a common polymer used in various applications, including plastic bags and containers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Chemistry>2025>49", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO CHEMISTRY : SCIENTIFIC METHODS", "question": "When a hypothesis is proven within the limit of available evidence, it becomes a", "images": [], "options": {"A": "scope", "B": "theory", "C": "principle", "D": "law"}, "answer": "B", "explanation": "When a hypothesis is supported by sufficient evidence and is widely accepted, it is elevated to the status of a theory. A theory is a well-substantiated explanation of an aspect of the natural world that is based on a body of evidence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Chemistry>2025>50", "subject": "Chemistry", "year": "2025", "type": "Objective", "topic": "STOICHIOMETRY AND CHEMICAL REACTIONS : EMPIRICAL AND MOLECULAR FORMULAE.", "question": "Empirical formula is the", "images": [], "options": {"A": "simplest formula of a compound", "B": "molecular formula of a compound", "C": "chemical formula of a compound", "D": "structural formula of a compound"}, "answer": "A", "explanation": "The empirical formula of a compound represents the simplest whole-number ratio of the elements present in that compound. It does not provide information about the actual number of atoms in a molecule, which is given by the molecular formula.", "marks": "1", "difficulty": "1"}];